import React, { createContext, useContext, useEffect, useState } from "react";
import { apiFetch } from "./lib/api";

type User = { id: number; username: string; role?: string };

type AuthContextType = {
  user: User | null;
  setUser: (u: User | null) => void;
  loading: boolean;
  refresh: () => Promise<void>;
};

const AuthContext = createContext<AuthContextType>({
  user: null,
  setUser: () => {},
  loading: true,
  refresh: async () => {},
});

export const useAuth = (): AuthContextType => useContext(AuthContext);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  const refresh = async () => {
    try {
      const res = await apiFetch("/api/auth/me");
      if (!res.ok) {
        setUser(null);
        return;
      }
      const data = await res.json();
      setUser(data.user || null);
    } catch {
      setUser(null);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    refresh();
  }, []);

  return (
    <AuthContext.Provider value={{ user, setUser, loading, refresh }}>
      {children}
    </AuthContext.Provider>
  );
};

// CreateOrderModal.tsx - split for readability, keeping behavior unchanged.
import React, { useCallback, useEffect, useMemo, useState } from "react";
import { XMarkIcon } from "@heroicons/react/24/outline";
import {
  ORDER_CODE_PREFIXES,
  ORDER_FIELDS,
} from "../../../constants";
import {
  isImportOrderCodeOption,
  usePricingTiers,
} from "@/shared/hooks/usePricingTiers";
import * as Helpers from "../../../lib/helpers";
import {
  calculateExpirationDate,
} from "./helpers";
import useCreateOrderLogic from "./hooks/useCreateOrderLogic";
import { CreateOrderModalProps, Order } from "./types";
import { CreateOrderCustomerSection } from "./components/CreateOrderCustomerSection";
import { CreateOrderPricingSection } from "./components/CreateOrderPricingSection";
import { CreateOrderProductSection } from "./components/CreateOrderProductSection";
import { ModalPortal } from "@/components/ui/ModalPortal";
import { isMavrykShopSupplierName } from "@/shared/utils/supply";
import { formatCurrency } from "@/features/orders/utils/ordersHelpers";

/** Chỉ coi là đủ khi đúng dd/mm/yyyy (tránh parse lệch khi đang gõ). */
const isCompleteDMY = (value: string): boolean =>
  /^\d{2}\/\d{2}\/\d{4}$/.test((value || "").trim());

const CreateOrderModal: React.FC<CreateOrderModalProps> = ({
  isOpen,
  onClose,
  prefillContext,
  onSave,
  orderCreationKind = "sales",
}) => {
  const [customMode, setCustomMode] = useState(false);
  const { orderCodeOptions } = usePricingTiers();
  const {
    formData,
    updateForm,
    supplies,
    products,
    isLoading,
    selectedSupplyId,
    customerType,
    setIsDataLoaded,
    customProductTouched,
    setCustomProductTouched,
    clearSelectedSupplySelection,
    handleChange,
    handleProductSelect,
    handleSourceSelect,
    handleCustomerTypeChange,
    handleSubmit,
    creditMode,
    toggleCreditMode,
    availableCreditNotes,
    creditListLoading,
    selectedCreditNote,
    selectCreditNoteRow,
    clearSelectedCreditNote,
  } = useCreateOrderLogic(isOpen, onSave, customMode, prefillContext, orderCreationKind);

  const hasPrefillCredit = Boolean(
    prefillContext && Number(prefillContext.creditNoteId) > 0
  );
  /** Dư trên phiếu sau khi trừ (theo số credit apply trong prefill). */
  const prefillCreditNoteRemaining = useMemo(() => {
    if (!prefillContext || !Number(prefillContext.creditNoteId)) return null;
    const avail = Math.max(0, Number(prefillContext.creditAvailableAmount) || 0);
    const apply = Math.max(0, Number(prefillContext.creditApplyAmount) || 0);
    return Math.max(0, avail - apply);
  }, [prefillContext]);
  const manualCreditMoney = useMemo(() => {
    if (!selectedCreditNote || hasPrefillCredit) return null;
    const avail = Math.max(0, Number(selectedCreditNote.available_amount) || 0);
    const refOld = Math.max(0, Number(selectedCreditNote.refund_amount) || 0);
    const priceNum = Math.max(0, Number(formData[ORDER_FIELDS.PRICE]) || 0);
    const apply = Math.min(avail, priceNum);
    const remaining = Math.max(0, priceNum - apply);
    const noteRemainingAfter = Math.max(0, avail - apply);
    return { avail, refOld, priceNum, apply, remaining, noteRemainingAfter };
  }, [selectedCreditNote, hasPrefillCredit, formData]);
  const creditNoteById = useMemo(() => {
    const m = new Map<number, (typeof availableCreditNotes)[0]>();
    for (const r of availableCreditNotes) {
      const id = Number(r.id);
      if (Number.isFinite(id) && id > 0) {
        m.set(id, r);
      }
    }
    return m;
  }, [availableCreditNotes]);
  const availableCreditOptions = useMemo(
    () =>
      availableCreditNotes.map((r) => {
        const name = (r.customer_name || "—").trim();
        const avail = Math.max(0, Number(r.available_amount) || 0);
        return {
          value: Number(r.id),
          label: `${name} — ${formatCurrency(avail)}`,
        };
      }),
    [availableCreditNotes]
  );

  const reservedOrderCode = String(prefillContext?.reservedOrderCode || "").trim();

  const infoAValue = (formData[ORDER_FIELDS.INFORMATION_ORDER] as string) || "";
  const infoBValue = (formData[ORDER_FIELDS.ID_PRODUCT] as string) || "";
  const registerDateValue =
    (formData[ORDER_FIELDS.ORDER_DATE] as string) || Helpers.getTodayDMY();
  const costValue = formData[ORDER_FIELDS.COST] as string | number | undefined;
  const priceValue = formData[ORDER_FIELDS.PRICE] as
    | string
    | number
    | undefined;
  const registerDateDMY = useMemo(
    () => (formData[ORDER_FIELDS.ORDER_DATE] as string) || Helpers.getTodayDMY(),
    [formData]
  );
  const totalDays = useMemo(
    () => Number(formData[ORDER_FIELDS.DAYS] || 0) || 0,
    [formData]
  );
  const productOptions = useMemo(
    () =>
      products
        .filter((p) => p.is_active !== false)
        .map((p) => ({
          value: p.san_pham,
          label: p.san_pham,
        })),
    [products]
  );
  const supplyOptions = useMemo(
    () =>
      supplies.map((s) => ({
        value: s.id,
        label: s.supplier_name ?? s.source_name,
      })),
    [supplies]
  );
  const selectedSupplyLabel = useMemo(() => {
    if (selectedSupplyId == null) return "";
    const opt = supplyOptions.find((o) => o.value === selectedSupplyId);
    return String(opt?.label ?? "");
  }, [selectedSupplyId, supplyOptions]);
  const isMavrykSupply = useMemo(
    () => isMavrykShopSupplierName(selectedSupplyLabel),
    [selectedSupplyLabel]
  );
  const canSelectCustomerType = useMemo(() => {
    const hasProduct = Boolean(formData[ORDER_FIELDS.ID_PRODUCT]);
    const hasSupply = Boolean(
      selectedSupplyId !== null ||
        ((formData[ORDER_FIELDS.SUPPLY] as string) || "").trim()
    );
    return hasProduct && hasSupply;
  }, [formData, selectedSupplyId]);

  const currentProductPctPromo = useMemo(() => {
    const productName = (formData[ORDER_FIELDS.ID_PRODUCT] as string) || "";
    if (!productName) return null;
    const product = products.find(
      (p) => p.san_pham.toLowerCase() === productName.toLowerCase()
    );
    return product?.pct_promo ?? null;
  }, [products, formData]);

  const hasPromoPrice = useMemo(() => {
    if (currentProductPctPromo === null || currentProductPctPromo === undefined) {
      return false;
    }
    const promoValue = Number(currentProductPctPromo);
    return Number.isFinite(promoValue) && promoValue > 0;
  }, [currentProductPctPromo]);

  const filteredCustomerTypeOptions = useMemo(() => {
    const byKind = orderCodeOptions.filter((option) => {
      if (orderCreationKind === "import") {
        return isImportOrderCodeOption(option);
      }
      return !isImportOrderCodeOption(option);
    });
    return byKind.filter((option) => {
      const value = option.value;
      if (hasPromoPrice) {
        return value !== ORDER_CODE_PREFIXES.CUSTOMER;
      }
      return value !== ORDER_CODE_PREFIXES.PROMO;
    });
  }, [hasPromoPrice, orderCodeOptions, orderCreationKind]);

  useEffect(() => {
    if (hasPromoPrice && customerType === ORDER_CODE_PREFIXES.CUSTOMER) {
      handleCustomerTypeChange({
        target: { value: ORDER_CODE_PREFIXES.PROMO },
      } as unknown as React.ChangeEvent<HTMLSelectElement>);
      return;
    }

    if (!hasPromoPrice && customerType === ORDER_CODE_PREFIXES.PROMO) {
      handleCustomerTypeChange({
        target: { value: ORDER_CODE_PREFIXES.CUSTOMER },
      } as unknown as React.ChangeEvent<HTMLSelectElement>);
      return;
    }

    const isCurrentTypeValid = filteredCustomerTypeOptions.some(
      (opt) => opt.value === customerType
    );
    if (!isCurrentTypeValid && filteredCustomerTypeOptions.length > 0) {
      handleCustomerTypeChange({
        target: { value: filteredCustomerTypeOptions[0].value },
      } as unknown as React.ChangeEvent<HTMLSelectElement>);
    }
  }, [
    filteredCustomerTypeOptions,
    customerType,
    handleCustomerTypeChange,
    hasPromoPrice,
    orderCreationKind,
  ]);

  const handlePriceInput = useCallback(
    (
      field: typeof ORDER_FIELDS.COST | typeof ORDER_FIELDS.PRICE
    ) =>
      (e: React.ChangeEvent<HTMLInputElement>) => {
        const raw = e.target.value || "";
        const digits = raw.replace(/\D/g, "");
        const num = digits ? parseInt(digits, 10) : 0;
        updateForm({ [field]: num } as Partial<Order>);
      },
    [updateForm]
  );

  const handleExpiryDateChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const raw = e.target.value || "";
      const patch: Partial<Order> = {
        [ORDER_FIELDS.EXPIRY_DATE]: raw,
      };

      const regRaw = (formData[ORDER_FIELDS.ORDER_DATE] as string) || "";
      if (isCompleteDMY(raw) && isCompleteDMY(regRaw)) {
        const normExpiry = Helpers.formatDateToDMY(raw) || raw;
        const normReg = Helpers.formatDateToDMY(regRaw) || regRaw;
        const days = Helpers.inclusiveDaysBetween(normReg, normExpiry);
        if (Number.isFinite(days) && days > 0) {
          patch[ORDER_FIELDS.EXPIRY_DATE] = normExpiry;
          patch[ORDER_FIELDS.DAYS] = String(days);
        }
      }

      updateForm(patch);
    },
    [formData, updateForm]
  );

  const handleExpiryDateBlur = useCallback(() => {
    const raw = (formData[ORDER_FIELDS.EXPIRY_DATE] as string) || "";
    const normalized = Helpers.formatDateToDMY(raw);
    const nextExpiry = normalized || raw;
    const patch: Partial<Order> = {
      [ORDER_FIELDS.EXPIRY_DATE]: nextExpiry,
    };
    const regRaw = (formData[ORDER_FIELDS.ORDER_DATE] as string) || "";
    const normReg = Helpers.formatDateToDMY(regRaw) || regRaw;
    if (nextExpiry && normReg) {
      const days = Helpers.inclusiveDaysBetween(normReg, nextExpiry);
      if (Number.isFinite(days) && days > 0) {
        patch[ORDER_FIELDS.DAYS] = String(days);
      }
    }
    updateForm(patch);
  }, [formData, updateForm]);

  const handleRegisterDateChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const raw = e.target.value || "";
      const patch: Partial<Order> = {
        [ORDER_FIELDS.ORDER_DATE]: raw,
      };

      if (isCompleteDMY(raw)) {
        const normalized = Helpers.formatDateToDMY(raw) || raw;
        if (totalDays > 0) {
          const computedExpiry = calculateExpirationDate(normalized, totalDays);
          if (computedExpiry && computedExpiry !== "N/A") {
            patch[ORDER_FIELDS.EXPIRY_DATE] = computedExpiry;
          }
        } else {
          patch[ORDER_FIELDS.EXPIRY_DATE] = normalized;
        }
      }

      updateForm(patch);
    },
    [totalDays, updateForm]
  );

  const handleRegisterDateBlur = useCallback(() => {
    const raw = (formData[ORDER_FIELDS.ORDER_DATE] as string) || "";
    const normalized = Helpers.formatDateToDMY(raw);
    if (!normalized || normalized === raw.trim()) return;
    updateForm({
      [ORDER_FIELDS.ORDER_DATE]: normalized,
    } as Partial<Order>);
  }, [formData, updateForm]);

  useEffect(() => {
    if (!customMode || !customProductTouched) return;
    const months =
      Helpers.parseMonthsFromInfo(infoAValue) ||
      Helpers.parseMonthsFromInfo(infoBValue);
    const registerDate = registerDateValue;

    if (months > 0) {
      const end = Helpers.addMonthsMinusOneDay(registerDate, months);
      const days = Helpers.inclusiveDaysBetween(registerDate, end);
      updateForm({
        [ORDER_FIELDS.DAYS]: String(days),
        [ORDER_FIELDS.EXPIRY_DATE]: end,
      } as Partial<Order>);
    }
  }, [
    customMode,
    customProductTouched,
    infoAValue,
    infoBValue,
    registerDateValue,
    updateForm,
  ]);

  const readyToLoad = useMemo(() => {
    const prod = (formData[ORDER_FIELDS.ID_PRODUCT] as string) || "";
    const src = (formData[ORDER_FIELDS.SUPPLY] as string) || "";
    const info = (formData[ORDER_FIELDS.INFORMATION_ORDER] as string) || "";
    const customer = (formData[ORDER_FIELDS.CUSTOMER] as string) || "";
    return !!prod && !!src && !!info && !!customer;
  }, [formData]);

  useEffect(() => {
    setIsDataLoaded(readyToLoad);
  }, [readyToLoad, setIsDataLoaded]);

  if (!isOpen) return null;

  const isFormComplete = Boolean(
    formData[ORDER_FIELDS.CUSTOMER] &&
      formData[ORDER_FIELDS.ID_PRODUCT] &&
      formData[ORDER_FIELDS.SUPPLY] &&
      formData[ORDER_FIELDS.INFORMATION_ORDER]
  );

  return (
    <ModalPortal>
    <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-slate-950/92 backdrop-blur-sm p-3 sm:p-4">
      <div className="relative w-full max-w-5xl max-h-[84vh] overflow-hidden rounded-[24px] border border-slate-600/70 bg-slate-900 text-slate-100 shadow-[0_28px_70px_-25px_rgba(2,6,23,0.95)] flex flex-col">
        <div className="shrink-0 px-4 sm:px-5 py-3 border-b border-slate-700/70 bg-slate-900 flex items-start justify-between gap-4">
          <div>
            <p className="text-[11px] uppercase tracking-[0.26em] text-cyan-200/70 font-bold">
              Order Builder
            </p>
            <h3 className="mt-1 text-base sm:text-lg font-black text-white tracking-tight">
              Tạo Đơn Hàng Mới
            </h3>
            <p className="mt-2 text-xs text-slate-300/75">
              Hoàn thiện thông tin khách hàng, sản phẩm và chi phí trong một
              form duy nhất.
            </p>
            {reservedOrderCode ? (
              <p className="mt-2 text-[11px] font-semibold text-cyan-200/90">
                Mã đơn dự kiến: {reservedOrderCode}
              </p>
            ) : null}
          </div>
          <div className="mt-1 flex items-center gap-2 shrink-0">
            {orderCreationKind === "sales" && !hasPrefillCredit ? (
              <button
                type="button"
                onClick={toggleCreditMode}
                className={`inline-flex items-center justify-center h-11 px-3.5 rounded-xl border text-sm font-bold transition-colors ${
                  creditMode
                    ? "border-amber-400/60 bg-amber-500/20 text-amber-100 shadow-[0_0_0_1px_rgba(251,191,36,0.2)]"
                    : "border-slate-500/70 bg-slate-800/90 text-slate-200 hover:bg-slate-700 hover:text-white"
                }`}
                title="Chuyển đổi: chọn khách từ phiếu credit còn khả dụng"
              >
                Credit
              </button>
            ) : null}
            <button
              type="button"
              onClick={onClose}
              className="inline-flex items-center justify-center h-11 w-11 rounded-xl border border-slate-500/70 bg-slate-800 text-slate-200 hover:bg-slate-700 hover:text-white transition-colors"
              aria-label="Close"
            >
              <XMarkIcon className="h-6 w-6" />
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-3 sm:px-4 lg:px-4 py-3">
          <form onSubmit={handleSubmit}>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-3 lg:gap-4">
              <CreateOrderProductSection
                customMode={customMode}
                formData={formData}
                selectedSupplyId={selectedSupplyId}
                productOptions={productOptions}
                supplyOptions={supplyOptions}
                customerType={customerType}
                canSelectCustomerType={canSelectCustomerType}
                filteredCustomerTypeOptions={filteredCustomerTypeOptions}
                onToggleCustomMode={() => {
                  setCustomProductTouched(false);
                  setCustomMode((value) => {
                    const next = !value;
                    if (next) {
                      clearSelectedSupplySelection();
                    }
                    return next;
                  });
                }}
                onFieldChange={handleChange}
                onProductSelect={handleProductSelect}
                onSourceSelect={handleSourceSelect}
                onCustomerTypeChange={handleCustomerTypeChange}
                onClearSelectedSupplySelection={clearSelectedSupplySelection}
                onCustomProductBlur={() => setCustomProductTouched(true)}
              />

              <CreateOrderCustomerSection
                formData={formData}
                onFieldChange={handleChange}
                creditMode={Boolean(creditMode && !hasPrefillCredit)}
                creditListLoading={creditListLoading}
                availableCreditOptions={availableCreditOptions}
                onSelectCreditRow={selectCreditNoteRow}
                onClearCreditSelection={clearSelectedCreditNote}
                creditNoteById={creditNoteById}
                selectedCreditNoteId={
                  selectedCreditNote?.id != null &&
                  Number.isFinite(Number(selectedCreditNote.id))
                    ? Number(selectedCreditNote.id)
                    : null
                }
              />

              <CreateOrderPricingSection
                customMode={customMode}
                customerType={customerType}
                formData={formData}
                registerDateDMY={registerDateDMY}
                isMavrykSupply={isMavrykSupply}
                costValue={costValue}
                priceValue={priceValue}
                onRegisterDateChange={handleRegisterDateChange}
                onRegisterDateBlur={handleRegisterDateBlur}
                onExpiryDateChange={handleExpiryDateChange}
                onExpiryDateBlur={handleExpiryDateBlur}
                onCostChange={handlePriceInput(ORDER_FIELDS.COST)}
                onPriceChange={handlePriceInput(ORDER_FIELDS.PRICE)}
              />
            </div>

            {creditMode && !hasPrefillCredit && selectedCreditNote && manualCreditMoney ? (
              <div
                className="mt-4 rounded-2xl border border-amber-400/35 bg-amber-950/35 px-3.5 py-3 text-sm text-amber-50/95 shadow-[inset_0_1px_0_rgba(255,255,255,0.06)]"
                role="status"
              >
                <p className="text-[11px] font-bold uppercase tracking-wider text-amber-200/90">
                  Thanh toán bằng credit — đơn nguồn{" "}
                  <span className="text-amber-50">
                    {selectedCreditNote.source_order_code || "—"}
                  </span>
                </p>
                <ul className="mt-2 space-y-1.5 text-xs leading-relaxed text-slate-200/95 [&_li]:flex [&_li]:justify-between [&_li]:gap-3">
                  <li>
                    <span className="text-slate-400">Giá bán tham chiếu (đơn cũ)</span>
                    <span className="shrink-0 font-semibold text-white">
                      {manualCreditMoney.refOld > 0
                        ? formatCurrency(manualCreditMoney.refOld)
                        : "—"}
                    </span>
                  </li>
                  <li>
                    <span className="text-slate-400">Credit trừ vào đơn này</span>
                    <span className="shrink-0 font-semibold text-emerald-200/90">
                      {formatCurrency(manualCreditMoney.apply)}
                    </span>
                  </li>
                  <li>
                    <span className="text-slate-400">
                      Credit khả dụng (phiếu, lúc mở form)
                    </span>
                    <span className="shrink-0 font-semibold text-slate-100">
                      {formatCurrency(manualCreditMoney.avail)}
                    </span>
                  </li>
                  <li>
                    <span className="text-slate-400">
                      Credit còn lại trên phiếu (sau đơn này)
                    </span>
                    <span className="shrink-0 font-semibold text-amber-100/95">
                      {formatCurrency(manualCreditMoney.noteRemainingAfter)}
                    </span>
                  </li>
                  <li className="!block border-t border-amber-500/25 pt-2.5">
                    <div className="flex items-center justify-between gap-3">
                      <span className="font-semibold text-amber-100/95">
                        Khách còn thanh toán (giá bán)
                      </span>
                      <span className="shrink-0 text-base font-black text-amber-50">
                        {formatCurrency(manualCreditMoney.remaining)}
                      </span>
                    </div>
                    <p className="mt-1.5 text-[11px] text-slate-500/90">
                      Theo ô «Giá bán» sau khi bạn chọn sản phẩm — chọn gói mới, nhập giá, các dòng
                      credit cập nhật tương ứng. «Giá bán tham chiếu» lấy từ số liệu phiếu (hoàn gốc)
                      khi có.
                    </p>
                  </li>
                </ul>
              </div>
            ) : null}

            {prefillContext && Number(prefillContext.creditNoteId) > 0 ? (
              <div
                className="mt-4 rounded-2xl border border-amber-400/35 bg-amber-950/35 px-3.5 py-3 text-sm text-amber-50/95 shadow-[inset_0_1px_0_rgba(255,255,255,0.06)]"
                role="status"
              >
                <p className="text-[11px] font-bold uppercase tracking-wider text-amber-200/90">
                  Thanh toán bằng credit — đơn nguồn{" "}
                  <span className="text-amber-50">
                    {prefillContext.creditSourceOrderCode || "—"}
                  </span>
                </p>
                <ul className="mt-2 space-y-1.5 text-xs leading-relaxed text-slate-200/95 [&_li]:flex [&_li]:justify-between [&_li]:gap-3">
                  <li>
                    <span className="text-slate-400">Giá bán tham chiếu (đơn cũ)</span>
                    <span className="shrink-0 font-semibold text-white">
                      {formatCurrency(
                        Number(prefillContext.sourceOrderListPrice) || 0
                      )}
                    </span>
                  </li>
                  <li>
                    <span className="text-slate-400">Credit trừ vào đơn này</span>
                    <span className="shrink-0 font-semibold text-emerald-200/90">
                      {formatCurrency(prefillContext.creditApplyAmount || 0)}
                    </span>
                  </li>
                  <li>
                    <span className="text-slate-400">
                      Credit khả dụng (phiếu, lúc mở form)
                    </span>
                    <span className="shrink-0 font-semibold text-slate-100">
                      {formatCurrency(prefillContext.creditAvailableAmount || 0)}
                    </span>
                  </li>
                  <li>
                    <span className="text-slate-400">
                      Credit còn lại trên phiếu (sau đơn này)
                    </span>
                    <span className="shrink-0 font-semibold text-amber-100/95">
                      {formatCurrency(prefillCreditNoteRemaining ?? 0)}
                    </span>
                  </li>
                  <li className="!block border-t border-amber-500/25 pt-2.5">
                    <div className="flex items-center justify-between gap-3">
                      <span className="font-semibold text-amber-100/95">
                        Khách còn thanh toán (giá bán)
                      </span>
                      <span className="shrink-0 text-base font-black text-amber-50">
                        {formatCurrency(Number(formData[ORDER_FIELDS.PRICE]) || 0)}
                      </span>
                    </div>
                    <p className="mt-1.5 text-[11px] text-slate-500/90">
                      Theo ô «Giá bán» sau khi bạn chọn sản phẩm — chọn gói mới, nhập giá, số
                      dòng này cập nhật tương ứng.
                    </p>
                  </li>
                </ul>
              </div>
            ) : null}
          </form>
        </div>

        <div className="shrink-0 px-4 sm:px-6 lg:px-8 py-3 border-t border-slate-700/70 bg-slate-900 flex justify-end gap-3">
          <button
            type="button"
            onClick={onClose}
            className="px-6 py-2.5 text-sm font-bold text-slate-100 bg-slate-800 border border-slate-600 rounded-xl hover:bg-slate-700 transition-colors"
          >
            Hủy
          </button>
          <button
            type="submit"
            onClick={handleSubmit}
            className={`px-7 py-2.5 text-sm font-black text-white rounded-xl transition-all ${
              isFormComplete && !isLoading
                ? "bg-emerald-500 hover:bg-emerald-400 shadow-[0_14px_30px_-14px_rgba(16,185,129,0.75)] hover:-translate-y-0.5"
                : "bg-slate-700/80 opacity-60 cursor-not-allowed"
            }`}
            disabled={!isFormComplete || isLoading}
          >
            {isLoading ? "Đang tính giá..." : "Tạo Đơn Hàng"}
          </button>
        </div>
      </div>
    </div>
    </ModalPortal>
  );
};

export default CreateOrderModal;

import { useCallback, useMemo } from "react";
import { ORDER_FIELDS } from "../../../../constants";
import { isMavrykShopSupplierName } from "../../../../shared/utils/supply";
import { CustomerType, Order, Supply, SupplyPrice } from "../types";

type RecalcPrice = (
  supplyId: number,
  productName: string,
  orderId: string,
  registerDate: string,
  fallbackImport?: number,
  options?: { updateCost?: boolean }
) => void;

type UseSupplySelectionParams = {
  supplies: Supply[];
  supplyPrices: SupplyPrice[];
  formData: Partial<Order>;
  customerType: CustomerType;
  productName: string;
  orderId: string;
  registerDate: string;
  setSelectedSupplyId: React.Dispatch<React.SetStateAction<number | null>>;
  setFormData: React.Dispatch<React.SetStateAction<Partial<Order>>>;
  setIsDataLoaded: (v: boolean) => void;
  recalcPrice: RecalcPrice;
};

export const useSupplySelection = ({
  supplies,
  supplyPrices,
  formData,
  customerType,
  productName,
  orderId,
  registerDate,
  setSelectedSupplyId,
  setFormData,
  setIsDataLoaded,
  recalcPrice,
}: UseSupplySelectionParams) => {
  const supplyLookup = useMemo(() => {
    const byId = new Map<number, Supply>();
    const idByName = new Map<string, number>();
    for (const supply of supplies) {
      byId.set(supply.id, supply);
      const name = supply.supplier_name ?? supply.source_name ?? "";
      if (name && !idByName.has(name)) {
        idByName.set(name, supply.id);
      }
    }
    return { byId, idByName };
  }, [supplies]);

  const supplyPriceLookup = useMemo(() => {
    const byId = new Map<number, number>();
    const byName = new Map<string, number>();
    for (const price of supplyPrices) {
      const normalized = Number(price.price);
      if (!Number.isFinite(normalized)) {
        continue;
      }
      if (!byId.has(price.source_id)) {
        byId.set(price.source_id, normalized);
      }
      const maybeName =
        (price as { supplier_name?: string; source_name?: string })
          .supplier_name ??
        (price as { source_name?: string }).source_name;
      if (maybeName && !byName.has(maybeName)) {
        byName.set(maybeName, normalized);
      }
    }
    return { byId, byName };
  }, [supplyPrices]);

  const getSupplyImportPrice = useCallback(
    (sourceId: number, supplyName: string, fallbackCost: number) => {
      if (supplyName) {
        const priceByName = supplyPriceLookup.byName.get(supplyName);
        if (priceByName !== undefined && Number.isFinite(priceByName)) {
          return priceByName;
        }

        const idFromName = supplyLookup.idByName.get(supplyName);
        if (idFromName !== undefined) {
          const byIdFromName = supplyPriceLookup.byId.get(idFromName);
          if (byIdFromName !== undefined && Number.isFinite(byIdFromName)) {
            return byIdFromName;
          }
        }
      }
      if (sourceId !== 0) {
        const byId = supplyPriceLookup.byId.get(sourceId);
        if (byId !== undefined && Number.isFinite(byId)) {
          return byId;
        }
      }
      return fallbackCost;
    },
    [supplyLookup.idByName, supplyPriceLookup.byId, supplyPriceLookup.byName]
  );

  const handleSourceSelect = useCallback(
    (sourceId: number) => {
      const selectedSupply = supplyLookup.byId.get(sourceId);
      const fallbackCost = Number(formData[ORDER_FIELDS.COST] || 0);
      const supplyName =
        selectedSupply?.supplier_name ?? selectedSupply?.source_name ?? "";
      const newBasePrice = isMavrykShopSupplierName(supplyName)
        ? 0
        : getSupplyImportPrice(sourceId, supplyName, fallbackCost);
      setSelectedSupplyId(sourceId === 0 ? null : sourceId);
      setFormData((prev) => {
        return {
          ...prev,
          [ORDER_FIELDS.SUPPLY]: selectedSupply ? supplyName : "",
          [ORDER_FIELDS.COST]: newBasePrice,
        };
      });

      if (!productName || !orderId || !registerDate) {
        setIsDataLoaded(false);
        return;
      }

      recalcPrice(
        sourceId,
        productName,
        orderId,
        registerDate,
        newBasePrice,
        {
          updateCost: true,
        }
      );
    },
    [
      customerType,
      formData,
      getSupplyImportPrice,
      orderId,
      productName,
      recalcPrice,
      registerDate,
      setFormData,
      setIsDataLoaded,
      setSelectedSupplyId,
      supplyLookup.byId,
    ]
  );

  return { handleSourceSelect };
};

import {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
  type Dispatch,
  type SetStateAction,
} from "react";
import {
  API_ENDPOINTS,
  DEFAULT_ORDER_CODE_PREFIX,
  ORDER_CODE_PREFIXES,
  ORDER_FIELDS,
  ORDER_STATUSES,
} from "../../../../constants";
import * as Helpers from "../../../../lib/helpers";
import { apiFetch } from "@/lib/api";
import { resolveOrderType } from "@/features/bill-order/helpers";
import { usePriceCalculation } from "../../CreateOrderModal/hooks/usePriceCalculation";
import type { CustomerType, Order as PricingOrder } from "../../CreateOrderModal/types";
import { Order, Supply, SupplyPrice } from "../types";
import { getSupplyName } from "../utils";

const getCustomerTypeFromIdOrder = (idOrder: string): CustomerType => {
  const upper = String(idOrder || "").trim().toUpperCase();
  if (upper.startsWith(ORDER_CODE_PREFIXES.IMPORT)) {
    return ORDER_CODE_PREFIXES.IMPORT;
  }
  return resolveOrderType(idOrder) ?? DEFAULT_ORDER_CODE_PREFIX;
};

export const useEditOrderLogic = (order: Order | null, isOpen: boolean) => {
  const [formData, setFormData] = useState<Order | null>(null);
  const [productOptions, setProductOptions] = useState<string[]>([]);
  const [supplies, setSupplies] = useState<Supply[]>([]);
  const [supplyPrices, setSupplyPrices] = useState<SupplyPrice[]>([]);
  const baseOrderRef = useRef<Order | null>(order);
  const [isCustomSupply, setIsCustomSupply] = useState(false);

  const setFormDataForPricing = useCallback<
    Dispatch<SetStateAction<Partial<PricingOrder>>>
  >((updater) => {
    setFormData((prev) => {
      if (!prev) return prev;
      const patch =
        typeof updater === "function"
          ? (updater as (p: Partial<PricingOrder>) => Partial<PricingOrder>)({
              ...prev,
            } as Partial<PricingOrder>)
          : updater;
      return { ...prev, ...patch } as Order;
    });
  }, []);

  const customerType = useMemo(
    () =>
      getCustomerTypeFromIdOrder(
        String(formData?.[ORDER_FIELDS.ID_ORDER as keyof Order] ?? "")
      ),
    [formData?.[ORDER_FIELDS.ID_ORDER as keyof Order]]
  );

  const pricingProductName = String(
    formData?.[ORDER_FIELDS.ID_PRODUCT as keyof Order] ?? ""
  );

  const { recalcPrice, infoRef } = usePriceCalculation({
    customerType,
    setFormData: setFormDataForPricing,
    productName: pricingProductName,
  });

  useEffect(() => {
    if (!formData) return;
    infoRef.current = String(
      formData[ORDER_FIELDS.INFORMATION_ORDER as keyof Order] ?? ""
    );
  }, [formData, infoRef]);

  const fetchProductOptions = useCallback(async () => {
    try {
      const response = await apiFetch(API_ENDPOINTS.PRODUCT_PRICES);
      if (!response.ok) throw new Error("Lỗi tải danh sách sản phẩm.");
      const data = (await response.json()) as Array<Record<string, unknown>>;
      const names = data
        .map((item) => {
          const raw = item.san_pham ?? item.id_product ?? item.product_name ?? item.name;
          return String(raw || "").trim();
        })
        .filter(Boolean);
      setProductOptions(Array.from(new Set(names)));
    } catch (error) {
      console.error("Lỗi khi fetch product options:", error);
      setProductOptions([]);
    }
  }, []);

  const mergedProductOptions = useCallback(
    (baseOptions: string[], currentProduct: string) => {
      if (!currentProduct.trim()) return baseOptions;
      if (baseOptions.some((item) => item === currentProduct)) return baseOptions;
      return [currentProduct, ...baseOptions];
    },
    []
  );

  const getCurrentSupplyOption = useCallback((): Supply | null => {
    const currentSupplyName =
      (baseOrderRef.current?.[ORDER_FIELDS.SUPPLY as keyof Order] as string) ||
      "";
    if (!currentSupplyName.trim()) return null;
    return {
      id: -1,
      supplier_name: currentSupplyName,
      source_name: currentSupplyName,
    };
  }, []);

  const mergeCurrentSupply = useCallback(
    (list: Supply[]): Supply[] => {
      const currentSupply = getCurrentSupplyOption();
      if (currentSupply) {
        const exists = list.some(
          (item) => getSupplyName(item) === getSupplyName(currentSupply)
        );
        if (!exists) {
          return [currentSupply, ...list];
        }
      }
      return list;
    },
    [getCurrentSupplyOption]
  );

  const fetchSuppliesForProduct = useCallback(async (productName: string) => {
    if (!productName) {
      const merged = mergeCurrentSupply([]);
      setSupplies(merged);
      return merged;
    }
    try {
      const response = await apiFetch(
        API_ENDPOINTS.SUPPLIES_BY_PRODUCT(productName)
      );
      if (!response.ok) throw new Error("Lỗi tải danh sách nguồn.");
      const data: Supply[] = await response.json();
      const merged = mergeCurrentSupply(data);
      setSupplies(merged);
      return merged;
    } catch (error) {
      console.error("Lỗi khi fetch supplies cho sản phẩm:", error);
      const merged = mergeCurrentSupply([]);
      setSupplies(merged);
      return merged;
    }
  }, [mergeCurrentSupply]);

  const fetchSupplyPricesForProduct = useCallback(
    async (productName: string) => {
      if (!productName) {
        setSupplyPrices([]);
        return [];
      }
      try {
        const response = await apiFetch(
          API_ENDPOINTS.SUPPLY_PRICES_BY_PRODUCT_NAME(productName)
        );
        if (!response.ok) throw new Error("Lỗi tải danh sách giá nguồn.");
        const data: SupplyPrice[] = await response.json();
        setSupplyPrices(data);
        return data;
      } catch (error) {
        console.error("Lỗi khi fetch giá nguồn cho sản phẩm:", error);
        setSupplyPrices([]);
        return [];
      }
    },
    []
  );

  useEffect(() => {
    if (isOpen && order) {
      const normalized: Order = {
        ...order,
        cost: Number(order.cost ?? 0),
        price: Number(order.price ?? 0),
      };
      setFormData(normalized);
      baseOrderRef.current = normalized;
      setSupplies((prev) => mergeCurrentSupply(prev));
      fetchProductOptions();
      const productName = order.id_product as string;
      if (productName) {
        fetchSuppliesForProduct(productName);
        fetchSupplyPricesForProduct(productName);
      }
      setIsCustomSupply(false);
    } else if (!isOpen) {
      setFormData(null);
      setProductOptions([]);
      setSupplies([]);
      setSupplyPrices([]);
      setIsCustomSupply(false);
    }
  }, [
    isOpen,
    order,
    fetchSuppliesForProduct,
    fetchSupplyPricesForProduct,
    fetchProductOptions,
    mergeCurrentSupply,
  ]);

  useEffect(() => {
    if (!isOpen || !formData) return;
    const productName = String(formData.id_product || "").trim();
    const timeoutId = window.setTimeout(() => {
      fetchSuppliesForProduct(productName);
      fetchSupplyPricesForProduct(productName);
    }, 300);
    return () => window.clearTimeout(timeoutId);
  }, [
    isOpen,
    formData,
    fetchSuppliesForProduct,
    fetchSupplyPricesForProduct,
  ]);

  const setFieldValue = useCallback(
    <K extends keyof Order>(key: K, value: Order[K]) => {
      setFormData((prev) => (prev ? { ...prev, [key]: value } : prev));
    },
    []
  );

  const handleProductChange = useCallback(
    (value: string) => {
      const nextProduct = String(value || "");
      setIsCustomSupply(false);
      setFormData((prev) => {
        if (!prev) return prev;
        const prevProduct = String(prev[ORDER_FIELDS.ID_PRODUCT as keyof Order] || "");
        if (prevProduct === nextProduct) return prev;
        return {
          ...prev,
          [ORDER_FIELDS.ID_PRODUCT]: nextProduct,
          [ORDER_FIELDS.SUPPLY]: "",
        };
      });
    },
    []
  );

  const handleSupplySelect = useCallback(
    (supplyId: number) => {
      const selected = supplies.find((s) => s.id === supplyId);
      const supplyName =
        getSupplyName(selected) ||
        (formData?.[ORDER_FIELDS.SUPPLY as keyof Order] as string) ||
        "";
      setIsCustomSupply(false);
      setFieldValue(
        ORDER_FIELDS.SUPPLY as keyof Order,
        (supplyName || "") as Order[keyof Order]
      );
      const matchedPrice =
        Helpers.getImportPriceBySupplyName(
          supplyName,
          supplyPrices,
          supplies
        ) ??
        supplyPrices.find((p) => p.source_id === supplyId)?.price ??
        null;
      const normalizedPrice = Number(matchedPrice);
      const statusText = String(
        formData?.[ORDER_FIELDS.STATUS as keyof Order] ?? ""
      );
      const isUnpaid = statusText === ORDER_STATUSES.CHUA_THANH_TOAN;
      const productName = String(
        formData?.[ORDER_FIELDS.ID_PRODUCT as keyof Order] || ""
      );
      const orderTypePrefix = getCustomerTypeFromIdOrder(
        String(formData?.[ORDER_FIELDS.ID_ORDER as keyof Order] || "")
      );
      let registerDate = String(
        formData?.[ORDER_FIELDS.ORDER_DATE as keyof Order] || ""
      ).trim();
      if (!registerDate) {
        registerDate = Helpers.getTodayDMY();
      }
      if (
        isUnpaid &&
        Number.isFinite(supplyId) &&
        supplyId > 0 &&
        productName &&
        orderTypePrefix
      ) {
        const fallbackImport = Number.isFinite(normalizedPrice)
          ? normalizedPrice
          : undefined;
        recalcPrice(supplyId, productName, orderTypePrefix, registerDate, fallbackImport, {
          updateCost: true,
          onlyPricing: true,
        });
        return;
      }
      if (Number.isFinite(normalizedPrice)) {
        setFieldValue(
          ORDER_FIELDS.COST as keyof Order,
          normalizedPrice as Order[typeof ORDER_FIELDS.COST]
        );
      } else if (baseOrderRef.current) {
        const fallbackCost = Number(
          baseOrderRef.current[ORDER_FIELDS.COST as keyof Order] || 0
        );
        setFieldValue(
          ORDER_FIELDS.COST as keyof Order,
          fallbackCost as Order[typeof ORDER_FIELDS.COST]
        );
      }
    },
    [formData, recalcPrice, setFieldValue, supplies, supplyPrices]
  );

  const handleCustomSupplyChange = useCallback(
    (value: string) => {
      setIsCustomSupply(true);
      setFieldValue(
        ORDER_FIELDS.SUPPLY as keyof Order,
        value as Order[keyof Order]
      );
    },
    [setFieldValue]
  );

  const toggleCustomSupply = useCallback(() => {
    setIsCustomSupply((prev) => {
      const next = !prev;
      if (!next) {
        setFieldValue(
          ORDER_FIELDS.SUPPLY as keyof Order,
          "" as Order[typeof ORDER_FIELDS.SUPPLY]
        );
      }
      return next;
    });
  }, [setFieldValue]);

  const resetForm = useCallback(() => {
    setFormData(baseOrderRef.current);
    const productName = baseOrderRef.current?.id_product as string | undefined;
    if (productName) {
      fetchSuppliesForProduct(productName);
      fetchSupplyPricesForProduct(productName);
    }
  }, [fetchSuppliesForProduct, fetchSupplyPricesForProduct]);

  const currentProduct = String(formData?.[ORDER_FIELDS.ID_PRODUCT] || "");
  const selectableProducts = mergedProductOptions(productOptions, currentProduct);

  return {
    formData,
    productOptions: selectableProducts,
    supplies,
    isCustomSupply,
    supplyPrices,
    handleProductChange,
    handleSupplySelect,
    resetForm,
    setFieldValue,
    handleCustomSupplyChange,
    toggleCustomSupply,
  };
};

