import React, { useMemo, useState } from "react";
import {
  ArrowUpIcon,
  BanknotesIcon,
  ChartBarSquareIcon,
  CubeIcon,
  RocketLaunchIcon,
  ScaleIcon,
} from "@heroicons/react/24/outline";
import ConfirmModal from "@/components/modals/ConfirmModal/ConfirmModal";
import { AddGoalModal } from "./AddGoalModal";
import { EditGoalAmountModal } from "./EditGoalAmountModal";
import { ExpenseBreakdownChart } from "./budgets-goals/ExpenseBreakdownChart";
import { SavingGoalsPanel } from "./budgets-goals/SavingGoalsPanel";
import { WeeklyStatCard } from "./budgets-goals/WeeklyStatCard";
import type { BudgetsGoalsProps } from "./budgets-goals/types";
import { useSavingGoalsActions } from "./budgets-goals/useSavingGoalsActions";
import { useWalletColumnStats } from "./budgets-goals/useWalletColumnStats";
import { formatValue } from "./WalletBalancesCard/utils";

const COLUMN_STAT_ICONS = [
  BanknotesIcon,
  ArrowUpIcon,
  ScaleIcon,
  ChartBarSquareIcon,
  CubeIcon,
] as const;

const calcChangePct = (curr: number, prev: number) => {
  if (prev === 0) {
    if (curr === 0) return 0;
    return curr > 0 ? 100 : -100;
  }
  return Number((((curr - prev) / prev) * 100).toFixed(1));
};

const BudgetsGoals: React.FC<BudgetsGoalsProps> = ({
  budgets,
  savingGoals,
  currencyFormatter,
  walletColumns,
  walletRows,
  onRefetchGoals,
  availableProfit,
}) => {
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [goalEditingAmount, setGoalEditingAmount] = useState<
    BudgetsGoalsProps["savingGoals"][number] | null
  >(null);
  const [goalIdPendingDelete, setGoalIdPendingDelete] = useState<number | null>(null);
  const [goalDeleteSubmitting, setGoalDeleteSubmitting] = useState(false);

  const { handleReorder, handleDelete, handleUpdateTargetAmount } =
    useSavingGoalsActions({
    savingGoals,
    onRefetchGoals,
  });

  const totals = useMemo(() => {
    const latestWalletRow = walletRows?.[0];
    let fundValue = 0;

    if (latestWalletRow) {
      const fundColumn = walletColumns.find((col) => {
        const name = String(col.name || "").toLowerCase();
        return name.includes("quỹ") || name.includes("quy");
      });

      if (fundColumn) {
        fundValue = Number(latestWalletRow.values[fundColumn.field] || 0) || 0;
      }
    }

    const totalTarget = savingGoals.reduce(
      (sum, goal) => sum + (Number(goal.target_amount) || 0),
      0
    );
    const totalSaved = fundValue;
    const totalRemaining = Math.max(0, totalTarget - totalSaved);
    const progress = totalTarget > 0 ? (totalSaved / totalTarget) * 100 : 0;
    return {
      totalSaved,
      totalTarget,
      totalRemaining,
      progress: Math.min(100, Math.max(0, progress)),
    };
  }, [savingGoals, walletRows, walletColumns]);

  const milestones = useMemo(() => {
    if (totals.totalTarget <= 0) return [];
    let accumulated = 0;
    return savingGoals.map((goal, index) => {
      accumulated += Number(goal.target_amount) || 0;
      const pos = (accumulated / totals.totalTarget) * 100;
      const clamped = Math.min(100, Math.max(0, pos));
      return { index: index + 1, position: clamped };
    });
  }, [savingGoals, totals.totalTarget]);

  const columnStats = useWalletColumnStats(walletRows, walletColumns);
  const displayColumnStats = useMemo(() => {
    const availableCurrent = Number(availableProfit?.current || 0);
    const availablePrevious = Number(availableProfit?.previous || 0);

    const availableProfitStat = {
      field: "__available_profit__",
      name: "Lợi nhuận khả dụng",
      assetCode: "VND",
      current: availableCurrent,
      previous: availablePrevious,
      changePct: calcChangePct(availableCurrent, availablePrevious),
    };

    return [availableProfitStat, ...columnStats];
  }, [availableProfit?.current, availableProfit?.previous, columnStats]);

  return (
    <div className="grid grid-cols-1 gap-5 sm:gap-6 xl:grid-cols-[1.7fr_1fr]">
      <div className="rounded-3xl bg-gradient-to-br from-indigo-950/40 via-slate-900/50 to-slate-950/40 border border-indigo-400/20 backdrop-blur-xl p-4 sm:p-5 lg:p-6 space-y-5 sm:space-y-6 shadow-[0_25px_50px_-12px_rgba(0,0,0,0.5)]">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-sm font-semibold text-white">Chi tiêu hàng tháng</p>
            <p className="text-xs text-white/70">Tổng quan tháng hiện tại</p>
          </div>
          <div className="flex items-center gap-2 rounded-full bg-indigo-500/30 px-3 py-1 text-xs font-semibold text-white shadow-inner shadow-indigo-900/30">
            <RocketLaunchIcon className="h-4 w-4" />
            <span>Đang theo dõi</span>
          </div>
        </div>

        <ExpenseBreakdownChart
          budgets={budgets}
          walletColumns={walletColumns}
          walletRows={walletRows}
          currencyFormatter={currencyFormatter}
          availableProfit={Number(availableProfit?.current || 0)}
        />

        <div className="grid gap-3 [grid-template-columns:repeat(auto-fill,minmax(10.5rem,1fr))]">
          {displayColumnStats.map((stat, index) => {
            const Icon = COLUMN_STAT_ICONS[index % COLUMN_STAT_ICONS.length];
            return (
              <WeeklyStatCard
                key={stat.field}
                title={stat.name}
                value={formatValue(
                  stat.current,
                  stat.assetCode,
                  currencyFormatter
                )}
                change={stat.changePct}
                icon={Icon}
              />
            );
          })}
        </div>
      </div>

      <SavingGoalsPanel
        savingGoals={savingGoals}
        totals={totals}
        milestones={milestones}
        currencyFormatter={currencyFormatter}
        onAddGoal={() => setIsAddModalOpen(true)}
        onReorderGoal={handleReorder}
        onEditGoal={(goal) => setGoalEditingAmount(goal)}
        onDeleteGoal={(id) => setGoalIdPendingDelete(id)}
      />

      <AddGoalModal
        isOpen={isAddModalOpen}
        onClose={() => setIsAddModalOpen(false)}
        onSuccess={() => {
          onRefetchGoals?.();
        }}
      />

      <EditGoalAmountModal
        isOpen={goalEditingAmount !== null}
        goal={goalEditingAmount}
        onClose={() => setGoalEditingAmount(null)}
        onSave={async (goalId, amount) => {
          await handleUpdateTargetAmount(goalId, amount);
          setGoalEditingAmount(null);
        }}
      />

      <ConfirmModal
        isOpen={goalIdPendingDelete !== null}
        onClose={() => {
          if (!goalDeleteSubmitting) setGoalIdPendingDelete(null);
        }}
        onConfirm={() => {
          if (goalIdPendingDelete == null) return;
          const id = goalIdPendingDelete;
          setGoalDeleteSubmitting(true);
          void handleDelete(id)
            .then(() => setGoalIdPendingDelete(null))
            .finally(() => setGoalDeleteSubmitting(false));
        }}
        title="Xóa mục tiêu?"
        message="Bạn có chắc muốn xóa mục tiêu tiết kiệm này?"
        confirmLabel="Xóa"
        cancelLabel="Hủy"
        isSubmitting={goalDeleteSubmitting}
      />
    </div>
  );
};

export default BudgetsGoals;

import React, { useCallback, useEffect, useMemo, useState } from "react";
import { ArrowPathIcon } from "@heroicons/react/24/outline";
import { CheckIcon } from "@heroicons/react/24/solid";
import { apiFetch } from "@/shared/api/client";
import {
  addDaysUtc,
  getCostPeriodAmount,
  type PeriodColumn as AllocPeriodColumn,
} from "@/features/dashboard/utils/spreadCostAcrossPeriod";
import {
  buildIdentifierKeys,
  enhancePackageRow,
  normalizeMatchKey,
  normalizeProductCodeValue,
  normalizeSlotKey,
  parseNumericValue,
  readSlotLinkPrefs,
  toCleanString,
  type AugmentedRow,
  type NormalizedOrderRecord,
  type OrderListItem,
  type PackageRow,
} from "@/features/package-product/utils/packageHelpers";
import {
  computeAugmentationForPackage,
  orderBelongsToPackageByProduct,
} from "@/features/package-product/utils/packageMatchUtils";

type ViewMode = "day" | "month";
type FixedColumnKey =
  | "orderCode"
  | "productCode"
  | "term"
  | "startDate"
  | "amount"
  | "slot";

type FixedColumn = {
  key: FixedColumnKey;
  label: string;
  width: number;
  left: number;
};

type PeriodColumn = AllocPeriodColumn;

type OrderListRow = {
  id?: number;
  id_order?: string;
  id_product?: string | number | null;
  product_display_name?: string;
  information_order?: string | null;
  customer?: string | null;
  line_product_id?: number | string | null;
  lineProductId?: number | string | null;
  days?: number | string | null;
  registration_date?: string | null;
  registration_date_str?: string;
  registration_date_display?: string;
  cost?: number | string | null;
  created_at?: string | null;
  created_at_raw?: string | null;
  slot?: string | number | null;
};

type ExpenseFormRow = {
  key: string;
  orderCode: string;
  productCode: string;
  term: string;
  startDate: string;
  slotLabel: string;
  slotStartYmd?: string | null;
  slotEndYmd?: string | null;
  totalCost: number;
  termDays: number;
  startDateYmd: string;
  endDateYmd?: string | null;
};

const START_DATE = new Date(2026, 3, 23);
const DATE_COLUMN_WIDTH = 102;
const MONTH_COLUMN_WIDTH = 124;
/** Cột tổng phân bổ (cuối bảng, sticky phải). */
const TOTAL_COLUMN_WIDTH = 118;
const DATA_ROW_HEIGHT = 37;
const DATA_VISIBLE_ROWS = 10;

const FIXED_COLUMNS: FixedColumn[] = [
  { key: "orderCode", label: "Mã đơn hàng", width: 154, left: 0 },
  { key: "productCode", label: "Mã sản phẩm", width: 154, left: 154 },
  { key: "term", label: "Thời hạn", width: 116, left: 308 },
  { key: "startDate", label: "Ngày bắt đầu", width: 136, left: 424 },
  { key: "amount", label: "Số tiền", width: 142, left: 560 },
  { key: "slot", label: "Slot", width: 96, left: 702 },
];

const LAST_FIXED_COLUMN_KEY: FixedColumnKey = "slot";
const FIXED_COLUMNS_WIDTH = FIXED_COLUMNS.reduce(
  (total, column) => total + column.width,
  0,
);

/** Các cột gom theo đơn (trừ Slot — mỗi slot một dòng). */
const SLOT_COLUMN = FIXED_COLUMNS.find((c) => c.key === "slot")!;
const FIXED_MERGE_COLUMNS = FIXED_COLUMNS.filter((c) => c.key !== "slot");

const totalColCell =
  "sticky right-0 z-[45] border-l-2 border-sky-500/35 bg-[#020617] text-sky-100 shadow-[-12px_0_24px_-12px_rgba(56,189,248,0.12)] transition-colors group-hover:bg-slate-900";
const totalColHead =
  "sticky right-0 z-[100] border-l-2 border-sky-400/40 bg-[#020617] text-sky-100 shadow-[-12px_0_28px_-12px_rgba(56,189,248,0.18)]";
const totalColFoot =
  "sticky right-0 z-[78] border-l-2 border-sky-400/40 bg-[#020617] text-sky-50 shadow-[-12px_0_28px_-12px_rgba(56,189,248,0.15)]";

const moneyFormatter = new Intl.NumberFormat("vi-VN");

const formatMoney = (value: number) =>
  `${moneyFormatter.format(Math.round(value))} đ`;

const getDateKey = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
};

const normalizeYmd = (value: string | null | undefined) => {
  if (!value) return "";
  const match = String(value).match(/^(\d{4})-(\d{2})-(\d{2})/);
  return match ? `${match[1]}-${match[2]}-${match[3]}` : String(value);
};

const doesRangeOverlapColumn = (
  startYmd: string | null | undefined,
  endYmd: string | null | undefined,
  column: PeriodColumn,
) => {
  if (!startYmd) return false;
  const end = endYmd || startYmd;
  if (end < startYmd) return false;
  return startYmd <= column.endKey && end >= column.startKey;
};

const hasSlotInPeriod = (row: ExpenseFormRow, column: PeriodColumn) =>
  Boolean(row.slotLabel) &&
  doesRangeOverlapColumn(
    row.slotStartYmd || row.startDateYmd,
    row.slotEndYmd,
    column,
  );

/**
 * Phần tiền góp vào ô tổng / footer: ngày hiển thị ✓ (slot) không cộng,
 * khớp với tổng các ô đang hiện số (tránh Tổng >> tổng các cột ngày).
 */
const amountForTotals = (row: ExpenseFormRow, column: PeriodColumn): number => {
  if (hasSlotInPeriod(row, column)) return 0;
  return getCostPeriodAmount(row, column) ?? 0;
};

const rowTotalDisplayed = (row: ExpenseFormRow, columns: PeriodColumn[]) =>
  columns.reduce((s, col) => s + amountForTotals(row, col), 0);

const buildDateColumns = (): PeriodColumn[] => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const start = new Date(START_DATE);
  start.setHours(0, 0, 0, 0);
  if (today < start) return [];

  const columns: PeriodColumn[] = [];
  const cursor = new Date(start);

  while (cursor <= today) {
    const key = getDateKey(cursor);
    columns.push({
      key,
      label: `${cursor.getDate()}/${cursor.getMonth() + 1}`,
      year: cursor.getFullYear(),
      startKey: key,
      endKey: key,
    });
    cursor.setDate(cursor.getDate() + 1);
  }

  return columns;
};

const buildMonthColumns = (): PeriodColumn[] => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const start = new Date(START_DATE);
  start.setHours(0, 0, 0, 0);
  if (today < start) return [];

  const columns: PeriodColumn[] = [];
  const cursor = new Date(start.getFullYear(), start.getMonth(), 1);

  while (cursor <= today) {
    const year = cursor.getFullYear();
    const month = cursor.getMonth();
    const monthStart = new Date(year, month, 1);
    const monthEnd = new Date(year, month + 1, 0);
    const effectiveStart = monthStart < start ? start : monthStart;
    const effectiveEnd = monthEnd > today ? today : monthEnd;

    columns.push({
      key: `${year}-${String(month + 1).padStart(2, "0")}`,
      label: `${month + 1}/${year}`,
      year,
      startKey: getDateKey(effectiveStart),
      endKey: getDateKey(effectiveEnd),
    });

    cursor.setMonth(cursor.getMonth() + 1);
  }

  return columns;
};

const buildPackageOrderRecord = (order: OrderListItem): NormalizedOrderRecord => {
  const o = order as Record<string, unknown>;
  const idProduct = (order.id_product ?? o.idProduct ?? "") as string;
  const informationOrder =
    (order.information_order ?? o.informationOrder ?? "") as string;
  const registrationDateYmd = normalizeYmd(
    (o.registration_date as string | null | undefined) ??
      (o.order_date_raw as string | null | undefined) ??
      (o.order_date as string | null | undefined) ??
      (o.created_at_raw as string | null | undefined) ??
      (o.created_at as string | null | undefined) ??
      "",
  );
  const rawLinePid = o.line_product_id ?? o.lineProductId;
  const parsedLineProductId =
    rawLinePid != null && rawLinePid !== "" ? Number(rawLinePid) : NaN;
  const lineProductId =
    Number.isFinite(parsedLineProductId) && parsedLineProductId > 0
      ? parsedLineProductId
      : null;
  const productKeys = buildIdentifierKeys(idProduct);
  const infoKeys = buildIdentifierKeys(informationOrder);

  return {
    base: order,
    productKey: productKeys.normalized,
    productLettersKey: productKeys.lettersOnly,
    infoKey: infoKeys.normalized,
    infoLettersKey: infoKeys.lettersOnly,
    slotDisplay: toCleanString(order.slot),
    slotKey: normalizeSlotKey(order.slot),
    slotMatchKey: normalizeMatchKey(order.slot),
    informationDisplay: toCleanString(informationOrder),
    informationKey: normalizeSlotKey(informationOrder),
    informationMatchKey: normalizeMatchKey(informationOrder),
    customerDisplay: toCleanString(order.customer as string | null),
    productCodeNormalized: normalizeProductCodeValue(idProduct),
    registrationDateYmd: registrationDateYmd || null,
    lineProductId,
  };
};

const buildOrdersByProductCode = (records: NormalizedOrderRecord[]) => {
  const map = new Map<string, NormalizedOrderRecord[]>();
  records.forEach((record) => {
    if (!record.productCodeNormalized) return;
    if (!map.has(record.productCodeNormalized)) {
      map.set(record.productCodeNormalized, []);
    }
    map.get(record.productCodeNormalized)!.push(record);
  });
  return map;
};

const buildComputedPackages = (
  packageRows: PackageRow[],
  packageOrders: OrderListItem[],
): AugmentedRow[] => {
  const prefs = readSlotLinkPrefs();
  const normalizedPackages = packageRows.map((row) =>
    enhancePackageRow(row, prefs),
  );
  const orderRecords = packageOrders.map(buildPackageOrderRecord);
  const ordersByProductCode = buildOrdersByProductCode(orderRecords);

  return normalizedPackages.map((item) => ({
    ...item,
    ...computeAugmentationForPackage({
      item,
      orderMatchers: orderRecords,
      ordersByProductCode,
      ordersReady: true,
    }),
  }));
};

const getImportOrderAccountKeys = (order: OrderListRow) =>
  [
    normalizeMatchKey(order.slot == null ? "" : String(order.slot)),
    normalizeMatchKey(order.information_order ?? ""),
    normalizeMatchKey(order.customer ?? ""),
  ].filter(Boolean);

const getPackageAccountKeys = (pkg: AugmentedRow) =>
  [
    normalizeMatchKey(pkg.informationUser ?? ""),
    normalizeMatchKey(pkg.accountUser ?? ""),
  ].filter(Boolean);

const keysMatch = (a: string, b: string) =>
  Boolean(a && b && (a === b || a.includes(b) || b.includes(a)));

const findPackageForImportOrder = (
  order: OrderListRow,
  packages: AugmentedRow[],
) => {
  const orderRecord = buildPackageOrderRecord(order as OrderListItem);
  const productCandidates = packages.filter((pkg) =>
    orderBelongsToPackageByProduct(orderRecord, pkg),
  );
  if (productCandidates.length === 0) return null;

  const accountKeys = getImportOrderAccountKeys(order);

  if (accountKeys.length > 0) {
    const accountMatched = productCandidates.find((pkg) => {
      const packageKeys = getPackageAccountKeys(pkg);
      return accountKeys.some((orderKey) =>
        packageKeys.some((packageKey) => keysMatch(orderKey, packageKey)),
      );
    });
    if (accountMatched) return accountMatched;
  }

  return null;
};

const buildSlotRowsForImportOrder = (
  order: OrderListRow,
  packages: AugmentedRow[],
): ExpenseFormRow[] => {
  const orderCode = String(order.id_order || "").trim();
  const rawDays = Number(order.days);
  const termDays =
    Number.isFinite(rawDays) && rawDays > 0 ? Math.floor(rawDays) : 0;

  const regYmd = normalizeYmd(order.registration_date ?? undefined);
  const paidFallback = normalizeYmd(order.created_at_raw ?? order.created_at ?? "");
  const product =
    String(order.product_display_name ?? order.id_product ?? "").trim();
  const costNum = Number(order.cost);
  const totalCost = Number.isFinite(costNum) && costNum >= 0 ? costNum : 0;
  const displayStart =
    (order.registration_date_display &&
      String(order.registration_date_display).trim()) ||
    (order.registration_date_str && String(order.registration_date_str).trim()) ||
    (regYmd ? regYmd.split("-").reverse().join("/") : "");

  const matchedPackage = findPackageForImportOrder(order, packages);
  const slotLimitRaw =
    matchedPackage != null ? parseNumericValue(matchedPackage.slotLimit) : null;
  const slotLimit = slotLimitRaw && slotLimitRaw > 0 ? Math.floor(slotLimitRaw) : 1;
  const slotCost = slotLimit > 0 ? totalCost / slotLimit : totalCost;
  const slotAssignments = matchedPackage?.slotAssignments ?? [];
  const baseRow = {
    orderCode,
    productCode: product,
    term: termDays > 0 ? `${termDays} ngày` : "—",
    startDate: displayStart,
    termDays,
    startDateYmd: termDays > 0 ? regYmd : paidFallback || regYmd,
  };

  if (!matchedPackage) {
    return [];
  }

  return Array.from({ length: slotLimit }, (_, index) => {
    const assignment = slotAssignments[index] ?? null;
    const assignedStartYmd = normalizeYmd(assignment?.sourceOrderStartYmd ?? "");
    const scheduledSlotEndYmd =
      baseRow.startDateYmd && baseRow.termDays > 0
        ? addDaysUtc(baseRow.startDateYmd, baseRow.termDays - 1)
        : null;
    const endDateYmd = assignment
      ? assignedStartYmd
        ? addDaysUtc(assignedStartYmd, -1)
        : addDaysUtc(baseRow.startDateYmd, -1)
      : null;
    return {
      key: `ol-${order.id ?? 0}-${orderCode}-slot-${index + 1}`,
      ...baseRow,
      slotLabel: assignment?.slotLabel ? String(assignment.slotLabel).trim() : "",
      slotStartYmd: assignment ? assignedStartYmd || baseRow.startDateYmd : null,
      slotEndYmd: assignment ? scheduledSlotEndYmd : null,
      totalCost: slotCost,
      endDateYmd,
    };
  });
};

const ordersFromOrderList = (
  rows: OrderListRow[],
  packages: AugmentedRow[],
): ExpenseFormRow[] =>
  rows.flatMap((order) => {
    const orderCode = String(order.id_order || "").trim();
    if (!orderCode) return [];
    return buildSlotRowsForImportOrder(order, packages);
  });

const mergeKeyForExpenseRow = (row: ExpenseFormRow) =>
  [
    row.orderCode,
    row.productCode,
    row.term,
    row.startDate,
    String(row.totalCost),
    row.startDateYmd,
    String(row.termDays),
  ].join("\0");

/** rowSpan cho khối cột trước Slot; 0 = dòng tiếp theo cùng nhóm đơn. */
const computeFixedPrefixMergeRowSpans = (rows: ExpenseFormRow[]): number[] => {
  const spans = rows.map(() => 0);
  let i = 0;
  while (i < rows.length) {
    const key = mergeKeyForExpenseRow(rows[i]);
    let j = i + 1;
    while (j < rows.length && mergeKeyForExpenseRow(rows[j]) === key) {
      j += 1;
    }
    spans[i] = j - i;
    i = j;
  }
  return spans;
};

