  );
};

import { useEffect, useState } from "react";
import { ModalPortal } from "@/components/ui/ModalPortal";
import GradientButton from "@/components/ui/GradientButton";
import {
  fetchFormDetail,
  updateForm,
  type CreateFormResponse,
  type InputDto,
} from "@/lib/formsApi";
import type { FormInfoItem } from "./types";
import { FormInputSelectSection } from "./components/FormInputSelectSection";

interface EditFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: (item: CreateFormResponse & { name: string; description: string }) => void;
  inputItems: InputDto[];
  editingItem: FormInfoItem | null;
}

export default function EditFormModal({
  isOpen,
  onClose,
  onSuccess,
  inputItems,
  editingItem,
}: EditFormModalProps) {
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [orderedInputIds, setOrderedInputIds] = useState<number[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [loadDetail, setLoadDetail] = useState(false);
  const [detailError, setDetailError] = useState<string | null>(null);

  useEffect(() => {
    if (!isOpen || !editingItem) {
      return;
    }

    let cancelled = false;
    (async () => {
      setLoadDetail(true);
      setDetailError(null);
      setError(null);
      setName((editingItem.name || "").trim() || "Chưa đặt tên");
      setDescription((editingItem.description || "").trim() || "");
      setOrderedInputIds([]);
      try {
        const detail = await fetchFormDetail(editingItem.id);
        if (cancelled) return;
        setName((detail.name || editingItem.name || "").trim() || "Chưa đặt tên");
        setDescription((detail.description || editingItem.description || "").trim() || "");
        const ordered: number[] = [];
        for (const i of detail.inputs || []) {
          const nid = Number(i.id);
          if (Number.isFinite(nid) && nid > 0) ordered.push(nid);
        }
        setOrderedInputIds(ordered);
      } catch (e) {
        if (!cancelled) {
          setDetailError("Không tải được chi tiết form. Vẫn có thể sửa tên / mô tả.");
        }
      } finally {
        if (!cancelled) setLoadDetail(false);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [isOpen, editingItem?.id]);

  if (!isOpen || !editingItem) return null;

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setError(null);
    const trimmedName = name.trim();
    if (!trimmedName) {
      setError("Vui lòng nhập tên form.");
      return;
    }

    setLoading(true);
    try {
      const updated = await updateForm(editingItem.id, {
        name: trimmedName,
        description: description.trim() || undefined,
        inputIds: orderedInputIds,
      });
      onSuccess({
        ...updated,
        name: updated.name ?? trimmedName,
        description: updated.description ?? "",
      });
      onClose();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Không thể cập nhật form.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <ModalPortal>
    <div
      className="fixed inset-0 z-[9999] flex items-center justify-center bg-slate-950/80 backdrop-blur-sm p-4 overflow-y-auto"
      onClick={onClose}
      role="presentation"
    >
      <div
        className="glass-panel-dark rounded-[32px] shadow-2xl w-full max-w-3xl p-6 sm:p-8 border border-white/10 my-8"
        onClick={(e) => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-labelledby="edit-form-title"
      >
        <h3
          id="edit-form-title"
          className="text-2xl font-bold text-white mb-6 tracking-tight"
        >
          Sửa form
        </h3>
        {detailError && (
          <div className="mb-3 rounded-xl bg-amber-500/15 border border-amber-500/30 px-4 py-2 text-sm text-amber-100">
            {detailError}
          </div>
        )}
        {error && (
          <div className="mb-4 rounded-xl bg-red-500/15 border border-red-500/30 px-4 py-3 text-sm text-red-200">
            {error}
          </div>
        )}
        {loadDetail ? (
          <p className="text-sm text-white/60 py-8 text-center">Đang tải dữ liệu form…</p>
        ) : (
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label
              htmlFor="edit-form-name"
              className="block text-xs font-bold uppercase tracking-widest text-indigo-300/50 mb-2 ml-1"
            >
              Tên form
            </label>
            <input
              id="edit-form-name"
              type="text"
              className="w-full bg-white/5 border border-white/10 rounded-2xl p-3 text-white focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-400 outline-none transition-all placeholder:text-white/30"
              placeholder="Nhập tên form..."
              value={name}
              onChange={(e) => setName(e.target.value)}
              disabled={loading}
            />
          </div>
          <div>
            <label
              htmlFor="edit-form-description"
              className="block text-xs font-bold uppercase tracking-widest text-indigo-300/50 mb-2 ml-1"
            >
              Mô tả form
            </label>
            <textarea
              id="edit-form-description"
              className="w-full bg-white/5 border border-white/10 rounded-2xl p-3 text-white focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-400 outline-none transition-all placeholder:text-white/30 resize-none"
              placeholder="Nhập mô tả (tùy chọn)..."
              rows={2}
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              disabled={loading}
            />
          </div>
          <FormInputSelectSection
            inputItems={inputItems}
            orderedInputIds={orderedInputIds}
            setOrderedInputIds={setOrderedInputIds}
            disabled={loading}
          />
          <div className="flex justify-end gap-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="px-6 py-2.5 text-sm font-bold text-white/40 hover:text-white transition-colors"
              disabled={loading}
            >
              Hủy
            </button>
            <GradientButton type="submit" disabled={loading} className="!py-2.5 !px-8 text-sm">
              {loading ? "Đang lưu..." : "Cập nhật"}
            </GradientButton>
          </div>
        </form>
        )}
      </div>
    </div>
    </ModalPortal>
  );
}

import { useEffect, useState } from "react";
import {
  fetchFormNames,
  fetchFormDetail,
  fetchInputs,
  type FormNameDto,
  type FormDetailDto,
  type FormInputDto,
  type InputDto,
} from "@/lib/formsApi";
import type { FormInfoItem, FormDetailView, FormInfoTab } from "../types";

export function useFormInfo() {
  const [activeTab, setActiveTab] = useState<FormInfoTab>("form");

  const [items, setItems] = useState<FormInfoItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [inputItems, setInputItems] = useState<InputDto[]>([]);
  const [inputLoading, setInputLoading] = useState(false);
  const [inputError, setInputError] = useState<string | null>(null);

  const [viewOpen, setViewOpen] = useState(false);
  const [viewData, setViewData] = useState<FormDetailView | null>(null);
  const [viewLoading, setViewLoading] = useState(false);
  const [viewError, setViewError] = useState<string | null>(null);

  const [createInputOpen, setCreateInputOpen] = useState(false);
  const [createFormOpen, setCreateFormOpen] = useState(false);
  const [editFormOpen, setEditFormOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<FormInfoItem | null>(null);

  useEffect(() => {
    let cancelled = false;

    const load = async () => {
      try {
        setLoading(true);
        setError(null);
        const rows: FormNameDto[] = await fetchFormNames();
        if (cancelled) return;
        const mapped: FormInfoItem[] = rows.map((row) => ({
          id: Number(row.id),
          name: (row.name || "").trim() || "Chưa đặt tên",
          description: (row.description || "").trim() || "Không có mô tả",
        }));
        setItems(mapped);
      } catch (err) {
        if (!cancelled) {
          setError("Không thể tải danh sách form");
          setItems([]);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    };

    void load();

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    let cancelled = false;

    const load = async () => {
      try {
        setInputLoading(true);
        setInputError(null);
        const rows: InputDto[] = await fetchInputs();
        if (cancelled) return;
        setInputItems(rows);
      } catch (err) {
        if (!cancelled) {
          setInputError("Không thể tải danh sách input");
          setInputItems([]);
        }
      } finally {
        if (!cancelled) setInputLoading(false);
      }
    };

    void load();

    return () => {
      cancelled = true;
    };
  }, []);

  const handleView = async (item: FormInfoItem) => {
    setViewOpen(true);
    setViewError(null);
    setViewLoading(true);
    try {
      const detail: FormDetailDto = await fetchFormDetail(item.id);
      setViewData({
        id: detail.id ?? item.id,
        name: (detail.name || "").trim() || item.name,
        description: (detail.description || "").trim() || item.description,
        inputs: Array.isArray(detail.inputs)
          ? (detail.inputs as FormInputDto[])
          : [],
      });
    } catch (err) {
      // Giữ log để debug khi cần
      // eslint-disable-next-line no-console
      console.error("Không thể tải chi tiết form", err);
      setViewError("Không thể tải chi tiết form");
      setViewData({
        id: item.id,
        name: item.name,
        description: item.description,
        inputs: [],
      });
    } finally {
      setViewLoading(false);
    }
  };

  const handleCloseView = () => {
    setViewOpen(false);
    setViewError(null);
    setViewData(null);
  };

  const handleEdit = (item: FormInfoItem) => {
    setEditingItem(item);
    setEditFormOpen(true);
  };

  const handleEditFormClose = () => {
    setEditFormOpen(false);
    setEditingItem(null);
  };

  const handleEditFormSuccess = (updated: {
    id: number;
    name: string | null;
    description: string | null;
  }) => {
    setItems((prev) =>
      prev.map((p) =>
        p.id === updated.id
          ? {
              ...p,
              name: (updated.name || "").trim() || "Chưa đặt tên",
              description: (updated.description || "").trim() || "Không có mô tả",
            }
          : p
      )
    );
    setEditFormOpen(false);
    setEditingItem(null);
  };

  const handleDelete = (item: FormInfoItem) => {
    // TODO: triển khai logic xóa form
    // eslint-disable-next-line no-console
    console.log("Xóa", item);
  };

  const handleCreateForm = () => {
    setCreateFormOpen(true);
  };

  const handleCreateFormClose = () => {
    setCreateFormOpen(false);
  };

  const handleCreateFormSuccess = (item: FormInfoItem & { inputIds?: number[] }) => {
    const mapped: FormInfoItem = {
      id: item.id,
      name: item.name || "Chưa đặt tên",
      description: item.description || "Không có mô tả",
    };
    setItems((prev) => [mapped, ...prev]);
    setCreateFormOpen(false);
  };

  const handleCreateInput = () => {
    setCreateInputOpen(true);
  };

  const handleCreateInputClose = () => {
    setCreateInputOpen(false);
  };

  const handleCreateInputSuccess = (item: InputDto) => {
    setInputItems((prev) => [item, ...prev]);
    setCreateInputOpen(false);
  };

  return {
    activeTab,
    setActiveTab,
    items,
    loading,
    error,
    inputItems,
    inputLoading,
    inputError,
    viewOpen,
    viewData,
    viewLoading,
    viewError,
    createInputOpen,
    createFormOpen,
    editFormOpen,
    editingItem,
    handleView,
    handleCloseView,
    handleEdit,
    handleDelete,
    handleCreateForm,
    handleCreateFormClose,
    handleCreateFormSuccess,
    handleEditFormClose,
    handleEditFormSuccess,
    handleCreateInput,
    handleCreateInputClose,
    handleCreateInputSuccess,
  };
}

import React, { useEffect, useMemo, useState } from "react";
import { XMarkIcon } from "@heroicons/react/24/outline";
import { ModalPortal } from "@/components/ui/ModalPortal";
import * as Helpers from "@/lib/helpers";
import { apiFetch } from "@/lib/api";
import { QR_BANK_INFO } from "../helpers";
import type { MatchableOrder } from "../helpers";

const digitsOnly = (value: string) => value.replace(/\D/g, "");

const formatVndThousands = (digits: string): string => {
  if (!digits) return "";
  const n = Number(digits);
  if (!Number.isFinite(n)) return "";
  return n.toLocaleString("vi-VN");
};

type QrModalProps = {
  open: boolean;
  amount: string;
  note: string;
  matchableOrders: MatchableOrder[];
  onClose: () => void;
  onAmountChange: (value: string) => void;
  onNoteChange: (value: string) => void;
};

type BatchSummary = {
  id: number;
  batchCode: string;
  totalAmount: number;
  orderCount: number;
  status: string;
  paidReceiptId: number | null;
  paidAt: string | null;
  createdAt: string | null;
};

type BatchItem = {
  id: number;
  orderCode: string;
  orderListId: number | null;
  amount: number;
  status: string;
  createdAt: string | null;
};

export const QrModal: React.FC<QrModalProps> = ({
  open,
  amount,
  note,
  matchableOrders,
  onClose,
  onAmountChange,
  onNoteChange,
}) => {
  const [amountDraft, setAmountDraft] = useState(amount);
  const [noteDraft, setNoteDraft] = useState(note);
  const [batchCodesDraft, setBatchCodesDraft] = useState("");
  const [batchLoading, setBatchLoading] = useState(false);
  const [batchError, setBatchError] = useState<string | null>(null);
  const [batchInfo, setBatchInfo] = useState<{
    batchCode: string;
    orderCount: number;
    totalAmount: number;
  } | null>(null);
  const [batchListLoading, setBatchListLoading] = useState(false);
  const [batchListError, setBatchListError] = useState<string | null>(null);
  const [batchList, setBatchList] = useState<BatchSummary[]>([]);
  const [selectedBatchCode, setSelectedBatchCode] = useState<string>("");
  const [selectedBatchItems, setSelectedBatchItems] = useState<BatchItem[]>([]);
  const [selectedBatchLoading, setSelectedBatchLoading] = useState(false);
  const [selectedBatchError, setSelectedBatchError] = useState<string | null>(null);

  useEffect(() => {
    if (open) {
      const digits = digitsOnly(amount);
      setAmountDraft(digits ? formatVndThousands(digits) : "");
      setNoteDraft(note);
      setBatchCodesDraft("");
      setBatchError(null);
      setBatchInfo(null);
      setBatchLoading(false);
      setSelectedBatchCode("");
      setSelectedBatchItems([]);
      setSelectedBatchError(null);
    }
  }, [open, amount, note]);

  useEffect(() => {
    if (!open) return;
    let ignore = false;
    const fetchBatchList = async () => {
      setBatchListLoading(true);
      setBatchListError(null);
      try {
        const response = await apiFetch("/api/payment-receipts/batches?limit=15");
        const body = await response.json().catch(() => ({}));
        if (!response.ok) {
          throw new Error(String(body?.error || "Không thể tải danh sách batch."));
        }
        if (!ignore) {
          const rows = Array.isArray(body?.batches) ? body.batches : [];
          setBatchList(rows);
        }
      } catch (error) {
        if (!ignore) {
          setBatchListError(
            error instanceof Error
              ? error.message
              : "Không thể tải danh sách batch."
          );
          setBatchList([]);
        }
      } finally {
        if (!ignore) setBatchListLoading(false);
      }
    };
    fetchBatchList();
    return () => {
      ignore = true;
    };
  }, [open, batchInfo]);

  const orderHint = useMemo(() => {
    const preview = matchableOrders
      .slice(0, 10)
      .map((item) => item.orderCode)
      .filter(Boolean)
      .join(", ");
    return preview;
  }, [matchableOrders]);

  const parsedAmount = useMemo(() => {
    const digits = digitsOnly(amountDraft);
    if (!digits) return 0;
    const value = Number(digits);
    return Number.isFinite(value) ? value : 0;
  }, [amountDraft]);

  const formattedAmountDisplay =
    parsedAmount > 0
      ? `${parsedAmount.toLocaleString("vi-VN")} VND`
      : "Chưa Cập Nhật";

  const qrImageUrl = useMemo(() => {
    return Helpers.buildSepayQrUrl({
      accountNumber: QR_BANK_INFO.accountNumber,
      bankCode: QR_BANK_INFO.bankCode,
      amount: parsedAmount,
      description: noteDraft.trim(),
      accountName: QR_BANK_INFO.accountHolder,
    });
  }, [parsedAmount, noteDraft]);

  const noteDisplay = noteDraft.trim() || "Chưa có nội dung";

  const commitAmount = () => {
    const digits = digitsOnly(amountDraft);
    setAmountDraft(digits ? formatVndThousands(digits) : "");
    onAmountChange(digits);
  };

  const handleAmountInputChange = (
    event: React.ChangeEvent<HTMLInputElement>
  ) => {
    const digits = digitsOnly(event.target.value);
    if (!digits) {
      setAmountDraft("");
      return;
    }
    setAmountDraft(formatVndThousands(digits));
  };

  const commitNote = () => {
    const nextNote = noteDraft.trim();
    setNoteDraft(nextNote);
    onNoteChange(nextNote);
  };

  const createBatchFromOrders = async () => {
    const orderCodes = (
      batchCodesDraft.toUpperCase().match(/MAV[A-Z0-9]{3,20}/g) || []
    ).filter((code) => !/^MAVG/i.test(code));
    const uniqueOrderCodes = [...new Set(orderCodes)];
    if (uniqueOrderCodes.length === 0) {
      setBatchError("Vui lòng nhập ít nhất 1 mã đơn MAV để tạo mã nhóm.");
      return;
    }
    setBatchLoading(true);
    setBatchError(null);
    setBatchInfo(null);
    try {
      const response = await apiFetch("/api/payment-receipts/batches", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          orderCodes: uniqueOrderCodes,
          note: noteDraft.trim() || null,
        }),
      });
      const body = await response.json().catch(() => ({}));
      if (!response.ok) {
        throw new Error(
          String(body?.error || "Không thể tạo mã biên lai nhóm (MAVG).")
        );
      }
      const nextBatchCode = String(body?.batchCode || "").trim().toUpperCase();
      const nextAmount = Number(body?.totalAmount) || 0;
      if (!nextBatchCode) {
        throw new Error("Không nhận được batchCode từ server.");
      }

      setNoteDraft(nextBatchCode);
      onNoteChange(nextBatchCode);

      if (nextAmount > 0) {
        const nextDigits = String(Math.round(nextAmount));
        setAmountDraft(formatVndThousands(nextDigits));
        onAmountChange(nextDigits);
      }

      setBatchInfo({
        batchCode: nextBatchCode,
        orderCount: Number(body?.orderCount) || uniqueOrderCodes.length,
        totalAmount: nextAmount,
      });
      setSelectedBatchCode(nextBatchCode);
      setSelectedBatchItems([]);
      setSelectedBatchError(null);
    } catch (error) {
      setBatchError(
        error instanceof Error
          ? error.message
          : "Không thể tạo mã biên lai nhóm."
      );
    } finally {
      setBatchLoading(false);
    }
  };

  const openBatchDetail = async (batchCode: string) => {
    const normalized = String(batchCode || "").trim().toUpperCase();
    if (!normalized) return;
    setSelectedBatchCode(normalized);
    setSelectedBatchLoading(true);
    setSelectedBatchError(null);
    try {
      const response = await apiFetch(
        `/api/payment-receipts/batches/${encodeURIComponent(normalized)}`
      );
      const body = await response.json().catch(() => ({}));
      if (!response.ok) {
        throw new Error(String(body?.error || "Không thể tải chi tiết batch."));
      }
      const items = Array.isArray(body?.items) ? body.items : [];
      setSelectedBatchItems(items);
      setBatchCodesDraft(items.map((item: BatchItem) => item.orderCode).join(", "));
      setNoteDraft(normalized);
      onNoteChange(normalized);
      if (body?.batch?.totalAmount) {
        const digits = String(Math.round(Number(body.batch.totalAmount) || 0));
        if (Number(digits) > 0) {
          setAmountDraft(formatVndThousands(digits));
          onAmountChange(digits);
        }
      }
    } catch (error) {
      setSelectedBatchItems([]);
      setSelectedBatchError(
        error instanceof Error ? error.message : "Không thể tải chi tiết batch."
      );
    } finally {
      setSelectedBatchLoading(false);
    }
  };

  if (!open) return null;

  const panelSurface =
    "rounded-2xl border border-white/[0.08] bg-gradient-to-br from-slate-800/35 via-slate-900/50 to-slate-950/60 shadow-[inset_0_1px_0_0_rgba(255,255,255,0.05)]";
  const panelEmerald =
    "rounded-2xl border border-emerald-500/20 bg-gradient-to-br from-emerald-950/25 via-slate-900/45 to-slate-950/55 shadow-[inset_0_1px_0_0_rgba(16,185,129,0.12)]";
  const labelCls =
    "block text-[11px] font-bold uppercase tracking-[0.14em] text-slate-500 mb-1.5";
  const inputCls =
    "w-full rounded-xl border border-white/10 bg-slate-950/75 px-3 py-2.5 text-sm text-white placeholder:text-slate-500 focus:border-sky-400/50 focus:ring-2 focus:ring-sky-500/20 outline-none transition";
  const applyAll = () => {
    commitAmount();
    commitNote();
  };

  return (
    <ModalPortal>
    <div className="fixed inset-0 z-[9999] flex items-start justify-center overflow-y-auto bg-slate-950/80 backdrop-blur-md px-3 py-6 sm:py-10">
      <div className="relative w-full max-w-6xl overflow-hidden rounded-[1.75rem] border border-white/10 bg-gradient-to-b from-[#151c2e] via-[#0f141c] to-[#0a0d12] text-white shadow-[0_32px_96px_-20px_rgba(0,0,0,0.85)] ring-1 ring-white/[0.06]">
        <div
          className="pointer-events-none absolute inset-x-0 top-0 h-px bg-gradient-to-r from-transparent via-sky-400/35 to-transparent"
          aria-hidden
        />
        <button
          type="button"
          className="absolute right-3 top-3 z-10 rounded-full p-2.5 text-slate-400 transition hover:bg-white/10 hover:text-white"
          onClick={onClose}
          aria-label="Đóng"
        >
          <XMarkIcon className="h-5 w-5 sm:h-6 sm:w-6" />
        </button>
        <div className="px-5 py-7 sm:px-9 sm:py-9 space-y-5 sm:space-y-6 pt-14 sm:pt-10">
          <div className="text-center space-y-3 max-w-2xl mx-auto">
            <span className="inline-flex items-center justify-center rounded-full border border-white/10 bg-white/[0.04] px-3.5 py-1 text-[10px] font-bold uppercase tracking-[0.2em] text-sky-300/90">
              VietQR · Sepay
            </span>
            <h2 className="text-[1.35rem] sm:text-2xl font-bold text-white tracking-tight leading-snug">
              Tạo thông tin thanh toán qua QR Code
            </h2>
            <p className="text-sm text-slate-400/95 leading-relaxed max-w-xl mx-auto">
              Trên: nhập số tiền và nội dung hoặc gộp đơn MAVG. Dưới: mã QR và thông tin giao dịch
              khớp với các ô đã nhập.
            </p>
          </div>

          {/* Tài khoản nhận */}
          <div
            className={`${panelSurface} p-3.5 sm:p-4 flex items-center gap-3 sm:gap-4`}
          >
            <img
              src="https://companieslogo.com/img/orig/VPB.VN-b0a9916f.png?t=1722928514"
              alt=""
              className="h-10 w-10 object-contain shrink-0 rounded-xl bg-white/12 p-1.5 ring-1 ring-white/10"
            />
            <div className="min-w-0 flex-1 text-left">
              <p className="text-[10px] font-bold uppercase tracking-wider text-slate-500">
                Tài khoản nhận
              </p>
              <p className="font-mono text-sm font-semibold text-white tracking-tight truncate">
                {QR_BANK_INFO.accountNumber}
              </p>
              <p className="text-xs text-slate-400 truncate">{QR_BANK_INFO.accountHolder}</p>
            </div>
          </div>

          {/* Hàng trên: 2 khối ngang */}
          <div className="grid gap-4 lg:grid-cols-2 lg:items-stretch">
            <div className={`${panelSurface} p-4 sm:p-6 space-y-5 flex flex-col`}>
              <div className="flex items-center gap-2">
                <span className="flex h-7 w-7 items-center justify-center rounded-lg bg-sky-500/15 text-xs font-bold text-sky-300">
                  1
                </span>
                <div>
                  <h3 className="text-sm font-bold text-white tracking-tight">Cập nhật mã QR</h3>
                  <p className="text-xs text-slate-500 mt-0.5">
                    Số tiền và nội dung hiển thị trên VietQR bên dưới.
                  </p>
                </div>
              </div>
              <div>
                <label htmlFor="qr-modal-amount" className={labelCls}>
                  Số tiền (VND)
                </label>
                <input
                  id="qr-modal-amount"
                  type="text"
                  inputMode="numeric"
                  autoComplete="off"
                  placeholder="Ví dụ: 65000"
                  className={inputCls}
                  value={amountDraft}
                  onChange={handleAmountInputChange}
                  onBlur={commitAmount}
                  onKeyDown={(e) => e.key === "Enter" && commitAmount()}
                />
              </div>
              <div>
                <label htmlFor="qr-modal-note" className={labelCls}>
                  Nội dung chuyển khoản
                </label>
                <input
                  id="qr-modal-note"
                  type="text"
                  placeholder="VD: TT NCC kỳ … hoặc mã MAVG"
                  className={inputCls}
                  value={noteDraft}
                  onChange={(event) => setNoteDraft(event.target.value)}
                  onBlur={commitNote}
                  onKeyDown={(e) => e.key === "Enter" && commitNote()}
                />
              </div>
              <button
                type="button"
                className="w-full mt-auto rounded-xl bg-gradient-to-r from-sky-500 to-blue-600 py-3 text-sm font-semibold text-white shadow-md shadow-sky-900/40 transition hover:from-sky-400 hover:to-blue-500 active:scale-[0.99]"
                onClick={applyAll}
              >
                Áp dụng số tiền & nội dung
              </button>
            </div>

            <div className="flex flex-col gap-4 min-h-0">
              <div
                className={`${panelEmerald} p-4 sm:p-6 space-y-4 flex-1 flex flex-col`}
              >
                <div className="flex items-center gap-2">
                  <span className="flex h-7 w-7 items-center justify-center rounded-lg bg-emerald-500/20 text-xs font-bold text-emerald-300">
                    2
                  </span>
                  <div>
                    <h3 className="text-sm font-bold text-emerald-100 tracking-tight">
                      Mã nhóm biên lai (MAVG)
                    </h3>
                    <p className="text-xs text-emerald-200/65 mt-0.5 leading-relaxed">
                      Dán mã đơn MAV… — hệ thống tạo MAVG và điền nội dung + tổng tiền.
                    </p>
                  </div>
                </div>
                <textarea
                  id="qr-modal-batch-codes"
                  rows={3}
                  placeholder="MAVC…, MAVK… (phẩy hoặc xuống dòng)"
                  className={`${inputCls} resize-y min-h-[6rem] border-emerald-500/20 focus:border-emerald-400/50 focus:ring-emerald-500/15 flex-1`}
                  value={batchCodesDraft}
                  onChange={(event) => setBatchCodesDraft(event.target.value)}
                />
                {orderHint ? (
                  <p className="text-[11px] text-slate-500 leading-snug">
                    <span className="text-slate-400 font-semibold">Gợi ý:</span> {orderHint}
                  </p>
                ) : null}
                {batchError ? (
                  <p className="text-xs text-rose-300">{batchError}</p>
                ) : null}
                {batchInfo ? (
                  <p className="text-xs text-emerald-300 font-medium">
                    Đã tạo {batchInfo.batchCode} · {batchInfo.orderCount} đơn ·{" "}
                    {batchInfo.totalAmount.toLocaleString("vi-VN")} VND
                  </p>
                ) : null}
                <button
                  type="button"
                  className="w-full rounded-xl bg-gradient-to-r from-emerald-500 to-teal-600 px-4 py-3 text-sm font-semibold text-white shadow-md shadow-emerald-950/50 transition hover:from-emerald-400 hover:to-teal-500 disabled:opacity-50 disabled:pointer-events-none active:scale-[0.99]"
                  onClick={createBatchFromOrders}
                  disabled={batchLoading}
                >
                  {batchLoading ? "Đang tạo MAVG…" : "Tạo mã MAVG"}
                </button>
              </div>

              <div className={`${panelSurface} p-4 sm:p-5 space-y-3`}>
                <div className="flex items-center justify-between gap-2 border-b border-white/5 pb-2">
                  <h3 className="text-xs font-bold uppercase tracking-wider text-slate-400">
                    MAVG gần đây
                  </h3>
                  {batchListLoading ? (
                    <span className="text-[11px] text-slate-500">Đang tải…</span>
                  ) : null}
                </div>
                {batchListError ? (
                  <p className="text-xs text-rose-300">{batchListError}</p>
                ) : null}
                {!batchListError && batchList.length === 0 && !batchListLoading ? (
                  <p className="text-xs text-slate-500 py-2">Chưa có batch nào.</p>
                ) : null}
                {batchList.length > 0 ? (
                  <div className="max-h-32 overflow-y-auto space-y-1.5 pr-1 scroll-smooth">
                    {batchList.map((batch) => (
                      <button
                        key={batch.id}
                        type="button"
                        className="w-full rounded-xl border border-white/[0.06] bg-white/[0.03] px-3 py-2.5 text-left transition hover:border-emerald-500/35 hover:bg-emerald-500/5"
                        onClick={() => openBatchDetail(batch.batchCode)}
                      >
                        <span className="text-xs font-semibold text-emerald-300">
                          {batch.batchCode}
                        </span>
                        <span className="block text-[11px] text-slate-400 mt-0.5">
                          {batch.orderCount} đơn ·{" "}
                          {(Number(batch.totalAmount) || 0).toLocaleString("vi-VN")} VND
                        </span>
                      </button>
                    ))}
                  </div>
                ) : null}
                {selectedBatchCode ? (
                  <div className="rounded-xl border border-emerald-500/25 bg-emerald-950/20 p-3 space-y-2 mt-1">
                    <p className="text-xs font-semibold text-emerald-200">
                      Chi tiết · {selectedBatchCode}
                    </p>
                    {selectedBatchLoading ? (
                      <p className="text-xs text-slate-400">Đang tải đơn trong batch…</p>
                    ) : null}
                    {selectedBatchError ? (
                      <p className="text-xs text-rose-300">{selectedBatchError}</p>
                    ) : null}
                    {!selectedBatchLoading &&
                    !selectedBatchError &&
                    selectedBatchItems.length === 0 ? (
                      <p className="text-xs text-slate-500">Batch chưa có đơn.</p>
                    ) : null}
                    {selectedBatchItems.length > 0 ? (
                      <ul className="max-h-28 overflow-y-auto space-y-1 text-xs">
                        {selectedBatchItems.map((item) => (
                          <li
                            key={item.id}
                            className="flex justify-between gap-2 rounded-md bg-slate-900/70 px-2 py-1.5"
                          >
                            <span className="text-slate-200 font-medium">{item.orderCode}</span>
                            <span className="text-slate-400 tabular-nums shrink-0">
                              {(Number(item.amount) || 0).toLocaleString("vi-VN")}
                            </span>
                          </li>
                        ))}
                      </ul>
                    ) : null}
                  </div>
                ) : null}
              </div>
            </div>
          </div>

          {/* Hàng dưới: VietQR */}
          <div
            className={`${panelSurface} p-6 sm:p-8 flex flex-col items-center gap-8 relative overflow-hidden`}
          >
            <div
              className="pointer-events-none absolute -top-24 left-1/2 h-48 w-48 -translate-x-1/2 rounded-full bg-sky-500/15 blur-3xl"
              aria-hidden
            />
            <div className="relative flex flex-col items-center text-center space-y-4 w-full">
              <div className="flex items-center gap-2">
                <span className="flex h-7 w-7 items-center justify-center rounded-lg bg-violet-500/20 text-xs font-bold text-violet-200">
                  3
                </span>
                <p className="text-sm font-semibold text-sky-200/95 tracking-tight">
                  Quét mã QR để thanh toán
                </p>
              </div>
              <div className="relative mx-auto">
                <div
                  className="absolute -inset-[3px] rounded-[1.35rem] bg-gradient-to-br from-sky-400/30 via-white/10 to-violet-500/25 opacity-80 blur-[2px]"
                  aria-hidden
                />
                <div className="relative rounded-2xl bg-white p-4 sm:p-5 shadow-[0_20px_50px_-15px_rgba(0,0,0,0.5)]">
                  <img
                    src={qrImageUrl}
                    alt="Mã QR chuyển khoản VietQR"
                    className="h-52 w-52 sm:h-56 sm:w-56 object-contain block mx-auto"
                  />
                </div>
              </div>
              <a
                href={qrImageUrl}
                download
                className="inline-flex items-center justify-center rounded-xl bg-gradient-to-r from-sky-500 to-blue-600 px-6 py-2.5 text-sm font-semibold text-white shadow-lg shadow-sky-900/30 transition hover:from-sky-400 hover:to-blue-500"
              >
                Tải ảnh QR
              </a>
            </div>
            <dl className="relative w-full max-w-lg mx-auto space-y-0 rounded-2xl border border-white/[0.07] bg-slate-950/55 px-4 py-1 divide-y divide-white/[0.06]">
              <div className="flex justify-between gap-4 py-3">
                <dt className="text-slate-500 shrink-0 text-sm">Ngân hàng</dt>
                <dd className="font-medium text-slate-100 text-right text-sm">{QR_BANK_INFO.bankName}</dd>
              </div>
              <div className="flex justify-between gap-4 py-3">
                <dt className="text-slate-500 shrink-0 text-sm">Số tài khoản</dt>
                <dd className="font-mono font-semibold text-slate-100 text-right break-all text-sm">
                  {QR_BANK_INFO.accountNumber}
                </dd>
              </div>
              <div className="flex justify-between gap-4 py-3">
                <dt className="text-slate-500 shrink-0 text-sm">Chủ TK</dt>
                <dd className="font-medium text-slate-100 text-right uppercase text-xs sm:text-sm leading-snug">
                  {QR_BANK_INFO.accountHolder}
                </dd>
              </div>
              <div className="flex justify-between gap-4 py-3 items-baseline">
                <dt className="text-slate-500 shrink-0 text-sm">Số tiền</dt>
                <dd className="font-semibold text-amber-200 tabular-nums text-right text-sm">
                  {formattedAmountDisplay}
                </dd>
              </div>
              <div className="flex justify-between gap-4 py-3 items-start">
                <dt className="text-slate-500 shrink-0 text-sm pt-0.5">Nội dung</dt>
                <dd className="font-medium text-violet-200 text-right break-words max-w-[70%] text-sm">
                  {noteDisplay}
                </dd>
              </div>
            </dl>
          </div>
        </div>
      </div>
    </div>
    </ModalPortal>
  );
};

import React, { useMemo, useState } from "react";
import * as Helpers from "@/lib/helpers";
import {
  extractTransactionCodeFromNote,
  MatchableOrder,
  PaymentReceipt,
  QR_BANK_INFO,
  formatCurrencyVnd,
  resolveSender,
} from "../helpers";

type ReceiptsTableProps = {
  receipts: PaymentReceipt[];
  matchableOrders: MatchableOrder[];
  matchingReceiptId: number | null;
  onMatchReceipt: (receiptId: number, orderCode: string) => Promise<void>;
  enableMatching?: boolean;
  expandedReceiptId: number | null;
  onToggle: (receiptId: number) => void;
  onSelectReceipt?: (receipt: PaymentReceipt) => void;
  showOrderCode?: boolean;
  enableOrderCodeEdit?: boolean;
};

export const ReceiptsTable: React.FC<ReceiptsTableProps> = ({
  receipts,
  matchableOrders,
  matchingReceiptId,
  onMatchReceipt,
  enableMatching = false,
  expandedReceiptId,
  onToggle,
  onSelectReceipt,
  showOrderCode = true,
  enableOrderCodeEdit = false,
}) => {
  const [selectionByReceiptId, setSelectionByReceiptId] = useState<
    Record<number, string>
  >({});
  const [manualCodeByReceiptId, setManualCodeByReceiptId] = useState<
    Record<number, string>
  >({});
  const [rowErrorByReceiptId, setRowErrorByReceiptId] = useState<
    Record<number, string>
  >({});
  const [pendingConfirm, setPendingConfirm] = useState<{
    receiptId: number;
    orderCode: string;
  } | null>(null);
  const [editingReceiptId, setEditingReceiptId] = useState<number | null>(null);
  const [editingOrderCode, setEditingOrderCode] = useState("");

  const visibleColsBase = showOrderCode ? 7 : 6;
  const expandedColSpan = visibleColsBase + (enableMatching ? 1 : 0);
  const expandedGridClass = showOrderCode
    ? "grid grid-cols-1 md:grid-cols-5 gap-6"
    : "grid grid-cols-1 md:grid-cols-4 gap-6";
  const orderOptions = useMemo(() => {
    const seen = new Set<string>();
    return matchableOrders.filter((order) => {
      const key = (order.orderCode || "").toUpperCase();
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }, [matchableOrders]);

  const getSelectedValue = (receipt: PaymentReceipt): string => {
    const stateValue = selectionByReceiptId[receipt.id];
    if (typeof stateValue === "string") return stateValue;
    const currentOrderCode = String(receipt.orderCode || "").trim().toUpperCase();
    return currentOrderCode || "";
  };

  const handleSelectMatch = async (receipt: PaymentReceipt, value: string) => {
    setSelectionByReceiptId((prev) => ({ ...prev, [receipt.id]: value }));
    setRowErrorByReceiptId((prev) => ({ ...prev, [receipt.id]: "" }));
    if (!value || value === "__manual__") return;
    setPendingConfirm({ receiptId: receipt.id, orderCode: value });
  };

  const handleSubmitManualMatch = (receipt: PaymentReceipt) => {
    const manualCode = String(manualCodeByReceiptId[receipt.id] || "")
      .trim()
      .toUpperCase();
    if (!manualCode) {
      setRowErrorByReceiptId((prev) => ({
        ...prev,
        [receipt.id]: "Bạn chưa nhập mã đơn hàng.",
      }));
      return;
    }
    setRowErrorByReceiptId((prev) => ({ ...prev, [receipt.id]: "" }));
    setPendingConfirm({ receiptId: receipt.id, orderCode: manualCode });
  };

  const handleConfirmMatch = async () => {
    if (!pendingConfirm) return;
    const { receiptId, orderCode } = pendingConfirm;
    setPendingConfirm(null);
    try {
      await onMatchReceipt(receiptId, orderCode);
      setSelectionByReceiptId((prev) => ({ ...prev, [receiptId]: orderCode }));
      setManualCodeByReceiptId((prev) => ({ ...prev, [receiptId]: "" }));
    } catch (err) {
      setRowErrorByReceiptId((prev) => ({
        ...prev,
        [receiptId]:
          err instanceof Error ? err.message : "Không thể ghép mã đơn cho biên lai.",
      }));
    }
  };

  const startEditOrderCode = (receipt: PaymentReceipt) => {
    setRowErrorByReceiptId((prev) => ({ ...prev, [receipt.id]: "" }));
    setEditingReceiptId(receipt.id);
    setEditingOrderCode(String(receipt.orderCode || "").trim().toUpperCase());
  };

  const cancelEditOrderCode = () => {
    setEditingReceiptId(null);
    setEditingOrderCode("");
  };

  const saveEditedOrderCode = async (receipt: PaymentReceipt) => {
    const nextCode = String(editingOrderCode || "").trim().toUpperCase();
    if (!nextCode) {
      setRowErrorByReceiptId((prev) => ({
        ...prev,
        [receipt.id]: "Bạn chưa nhập mã đơn hàng.",
      }));
      return;
    }
    try {
      setRowErrorByReceiptId((prev) => ({ ...prev, [receipt.id]: "" }));
      await onMatchReceipt(receipt.id, nextCode);
      cancelEditOrderCode();
    } catch (err) {
      setRowErrorByReceiptId((prev) => ({
        ...prev,
        [receipt.id]:
          err instanceof Error ? err.message : "Không thể cập nhật mã đơn.",
      }));
    }
  };

  return (
    <div className="bg-transparent overflow-visible">
      <div className="overflow-x-auto">
        <table className="min-w-full border-separate border-spacing-y-4 text-white">
          <thead>
            <tr className="[&>th]:px-5 [&>th]:pb-2 [&>th]:text-[11px] [&>th]:font-black [&>th]:uppercase [&>th]:tracking-[0.2em] [&>th]:text-indigo-300/70 [&>th]:text-left">
              {enableMatching ? <th className="w-[320px]">GHÉP MÃ ĐƠN</th> : null}
              {showOrderCode ? <th className="w-[120px]">MÃ ĐƠN</th> : null}
              <th className="w-[180px]">NGƯỜI GỬI</th>
              <th className="w-[180px]">NGƯỜI NHẬN</th>
              <th className="w-[140px]">SỐ TIỀN</th>
              <th>NỘI DUNG CHUYỂN KHOẢN</th>
              <th className="w-[150px]">MÃ GIAO DỊCH</th>
              <th className="w-[150px] text-right pr-6">NGÀY THANH TOÁN</th>
            </tr>
          </thead>
          <tbody className="">
            {receipts.map((receipt) => {
              const isExpanded = expandedReceiptId === receipt.id;
              const selectedValue = getSelectedValue(receipt);
              const isManualInput = selectedValue === "__manual__";
              const rowError = rowErrorByReceiptId[receipt.id] || "";
              const isMatching = matchingReceiptId === receipt.id;
              const isEditingOrderCode =
                enableOrderCodeEdit && editingReceiptId === receipt.id;
              return (
                <React.Fragment key={receipt.id}>
                  <tr
                    className="group/row cursor-pointer transition-all duration-500 relative z-10"
                    onClick={() => onToggle(receipt.id)}
                    onDoubleClick={() =>
                      onSelectReceipt ? onSelectReceipt(receipt) : undefined
                    }
                  >
                    {enableMatching ? (
                      <td className="px-5 py-5 first:rounded-l-[24px] glass-panel border-y border-white/5 group-hover/row:border-indigo-500/30 group-hover/row:bg-indigo-500/5 transition-all duration-500">
                        <div
                          className="space-y-2"
                          onClick={(event) => event.stopPropagation()}
                          onDoubleClick={(event) => event.stopPropagation()}
                        >
                          <select
                            value={selectedValue}
                            onChange={(event) =>
                              void handleSelectMatch(receipt, event.target.value)
                            }
                            disabled={isMatching}
                            className="w-full rounded-xl border border-white/10 bg-slate-950/70 px-3 py-2 text-xs font-semibold text-white outline-none focus:ring-2 focus:ring-indigo-500/40 disabled:opacity-60"
                          >
                            <option value="">Chọn đơn cần ghép...</option>
                            <option value="__manual__">Tự điền mã đơn hàng</option>
                            {orderOptions.map((order) => (
                              <option key={order.orderCode} value={order.orderCode}>
                                {order.orderCode} - {order.status}
                              </option>
                            ))}
                          </select>
                          {String(receipt.orderCode || "").trim() ? (
                            <p className="text-[10px] text-white/55 font-medium leading-snug">
                              CK đã gắn mã parse{" "}
                              <span className="font-bold text-indigo-200/95">
                                {String(receipt.orderCode).trim().toUpperCase()}
                              </span>
                              . Ghép sang đơn khả dụng để đưa vào tab Biên nhận.
                            </p>
                          ) : null}
                          {isManualInput && (
                            <div className="flex items-center gap-2">
                              <input
                                type="text"
                                value={manualCodeByReceiptId[receipt.id] || ""}
                                onChange={(event) =>
                                  setManualCodeByReceiptId((prev) => ({
                                    ...prev,
                                    [receipt.id]: event.target.value.toUpperCase(),
                                  }))
                                }
                                disabled={isMatching}
                                placeholder="Nhập mã đơn (VD: MAVC...)"
                                className="w-full rounded-xl border border-white/10 bg-slate-950/70 px-3 py-2 text-xs font-semibold text-white outline-none focus:ring-2 focus:ring-indigo-500/40 disabled:opacity-60"
                              />
                              <button
                                type="button"
                                onClick={() => void handleSubmitManualMatch(receipt)}
                                disabled={isMatching}
                                className="shrink-0 rounded-xl border border-indigo-400/40 bg-indigo-500/20 px-3 py-2 text-[11px] font-bold uppercase tracking-wider text-indigo-100 disabled:opacity-60"
                              >
                                Ghép
                              </button>
                            </div>
                          )}
                          {isMatching ? (
                            <p className="text-[10px] font-semibold text-indigo-200/70">
                              Đang ghép biên lai...
                            </p>
                          ) : null}
                          {rowError ? (
                            <p className="text-[10px] font-semibold text-rose-300">
                              {rowError}
                            </p>
                          ) : null}
                        </div>
                      </td>
                    ) : null}
                    {showOrderCode ? (
                      <td
                        className={`px-5 py-5 glass-panel border-y border-white/5 group-hover/row:border-indigo-500/30 group-hover/row:bg-indigo-500/5 transition-all duration-500 ${
                          enableMatching ? "" : "first:rounded-l-[24px]"
                        }`}
                      >
                        <div
                          className="space-y-2"
                          onClick={(event) => event.stopPropagation()}
                          onDoubleClick={(event) => event.stopPropagation()}
                        >
                          {isEditingOrderCode ? (
                            <div className="space-y-2">
                              <input
                                type="text"
                                value={editingOrderCode}
                                onChange={(event) =>
                                  setEditingOrderCode(
                                    event.target.value.toUpperCase()
                                  )
                                }
                                disabled={isMatching}
                                placeholder="Nhập mã đơn..."
                                className="w-full rounded-xl border border-white/10 bg-slate-950/70 px-3 py-2 text-xs font-semibold text-white outline-none focus:ring-2 focus:ring-indigo-500/40 disabled:opacity-60"
                              />
                              <div className="flex items-center gap-2">
                                <button
                                  type="button"
                                  onClick={() => void saveEditedOrderCode(receipt)}
                                  disabled={isMatching}
                                  className="rounded-xl border border-emerald-300/40 bg-emerald-500/20 px-3 py-1.5 text-[10px] font-bold uppercase tracking-wider text-emerald-100 disabled:opacity-60"
                                >
                                  Lưu
                                </button>
                                <button
                                  type="button"
                                  onClick={cancelEditOrderCode}
                                  disabled={isMatching}
                                  className="rounded-xl border border-white/20 px-3 py-1.5 text-[10px] font-bold uppercase tracking-wider text-white/80 disabled:opacity-60"
                                >
                                  Hủy
                                </button>
                              </div>
                            </div>
                          ) : (
                            <div className="flex items-center gap-2">
                              <span className="text-sm font-bold text-white tracking-wider uppercase">
                                {receipt.orderCode || "—"}
                              </span>
                              {enableOrderCodeEdit ? (
                                <button
                                  type="button"
                                  onClick={() => startEditOrderCode(receipt)}
                                  disabled={isMatching}
                                  className="rounded-lg border border-indigo-400/40 bg-indigo-500/15 px-2 py-1 text-[10px] font-bold uppercase tracking-wider text-indigo-100 disabled:opacity-60"
                                >
                                  Sửa
                                </button>
                              ) : null}
                            </div>
                          )}
                        </div>
                      </td>
                    ) : null}
                    <td className="px-5 py-5 glass-panel border-y border-white/5 group-hover/row:border-indigo-500/30 group-hover/row:bg-indigo-500/5 transition-all duration-500">
                      <div className="text-sm font-bold text-white tracking-tight">
                        {resolveSender(receipt) || "—"}
                      </div>
                    </td>
                    <td className="px-5 py-5 glass-panel border-y border-white/5 group-hover/row:border-indigo-500/30 group-hover/row:bg-indigo-500/5 transition-all duration-500">
                      <div className="text-xs font-medium text-white/80">
                        {receipt.receiver || QR_BANK_INFO.accountNumber}
                      </div>
                    </td>
                    <td className="px-5 py-5 glass-panel border-y border-white/5 group-hover/row:border-indigo-500/30 group-hover/row:bg-indigo-500/5 transition-all duration-500">
                      <span className="text-sm font-bold text-emerald-400 tracking-tight">
                        {formatCurrencyVnd(receipt.amount)}
                      </span>
                    </td>
                    <td className="px-5 py-5 glass-panel border-y border-white/5 group-hover/row:border-indigo-500/30 group-hover/row:bg-indigo-500/5 transition-all duration-500 max-w-xs">
                      <span className="block truncate text-[13px] text-white/60 font-medium">
                        {receipt.note || "—"}
                      </span>
                    </td>
                    <td className="px-5 py-5 glass-panel border-y border-white/5 group-hover/row:border-indigo-500/30 group-hover/row:bg-indigo-500/5 transition-all duration-500">
                      <span className="text-sm font-bold text-indigo-100/90">
                        {extractTransactionCodeFromNote(receipt.note) || "—"}
                      </span>
                    </td>
                    <td className="px-5 py-5 last:rounded-r-[24px] glass-panel border-y border-white/5 group-hover/row:border-indigo-500/30 group-hover/row:bg-indigo-500/5 transition-all duration-500 text-right pr-6">
                      <span className="text-xs font-bold text-indigo-300/80 tracking-tighter">
                        {receipt.paidAt
                          ? Helpers.formatDateToDMY(receipt.paidAt)
                          : "—"}
                      </span>
                    </td>
                  </tr>
                  {isExpanded && (
                    <tr className="animate-in fade-in slide-in-from-top-2 duration-300 relative z-0">
                      <td colSpan={expandedColSpan} className="px-6 pb-8 pt-2">
                        <div className="rounded-[32px] glass-panel-light p-6 shadow-2xl border border-indigo-500/20">
                          <div className={expandedGridClass}>
                            {showOrderCode ? (
                              <div className="space-y-1">
                                <p className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] leading-none">Mã đơn hàng</p>
                                <p className="text-sm font-black text-white">
                                  {receipt.orderCode || "—"}
                                </p>
                              </div>
                            ) : null}
                            <div className="space-y-1">
                              <p className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] leading-none">Người gửi</p>
                              <p className="text-sm font-bold text-white">
                                {resolveSender(receipt) || "—"}
                              </p>
                            </div>
                            <div className="space-y-1">
                              <p className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] leading-none">Người nhận</p>
                              <p className="text-sm font-medium text-indigo-200/80">
                                {QR_BANK_INFO.accountNumber}
                              </p>
                            </div>
                            <div className="space-y-1">
                              <p className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] leading-none">Mã giao dịch</p>
                              <p className="text-sm font-bold text-indigo-100/90">
                                {extractTransactionCodeFromNote(receipt.note) || "—"}
                              </p>
                            </div>
                            <div className="space-y-1">
                              <p className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] leading-none">Ngày thanh toán</p>
                              <p className="text-sm font-bold text-indigo-100/90">
                                {receipt.paidAt
                                  ? Helpers.formatDateToDMY(receipt.paidAt)
                                  : "—"}
                              </p>
                            </div>
                          </div>

                          <div className="mt-6 pt-6 border-t border-white/5">
                            <div className="space-y-2">
                              <p className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] leading-none">
                                Nội dung chuyển khoản
                              </p>
                              <div className="relative overflow-hidden rounded-2xl bg-slate-950/40 p-4 border border-white/5">
                                <p className="text-[13px] font-medium text-indigo-50 leading-relaxed italic">
                                  "{receipt.note || "Không có nội dung ghi chú đi kèm."}"
                                </p>
                              </div>
                            </div>
                          </div>
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              );
            })}
          </tbody>
        </table>
      </div>
      {pendingConfirm ? (
        <div className="fixed inset-0 z-[120] flex items-center justify-center bg-slate-950/70 p-4">
          <div className="w-full max-w-md rounded-3xl border border-indigo-400/30 bg-slate-900/95 p-6 shadow-2xl">
            <h3 className="text-lg font-black text-white tracking-tight">
              Xác nhận gắn mã đơn
            </h3>
            <p className="mt-3 text-sm text-indigo-100/90 leading-relaxed">
              Bạn có chắc muốn gắn mã đơn{" "}
              <span className="font-black text-white">{pendingConfirm.orderCode}</span>{" "}
              cho biên lai này không?
            </p>
            <p className="mt-2 text-xs text-indigo-200/70 leading-relaxed">
              Khi xác nhận, hệ thống sẽ chạy luồng gán mã đơn (reconcile) và tự động
              cộng/trừ doanh thu, lợi nhuận theo đúng quy tắc đối soát hiện hành.
            </p>
            <div className="mt-6 flex items-center justify-end gap-3">
              <button
                type="button"
                onClick={() => setPendingConfirm(null)}
                className="rounded-xl border border-white/15 px-4 py-2 text-sm font-semibold text-white/80 hover:bg-white/5"
              >
                Hủy
              </button>
              <button
                type="button"
                onClick={() => void handleConfirmMatch()}
                className="rounded-xl border border-indigo-300/30 bg-indigo-600/70 px-4 py-2 text-sm font-bold text-white hover:bg-indigo-500"
              >
                Xác nhận
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
};

import React, { useCallback } from "react";
import {
  ORDER_FIELDS,
  ORDER_STATUSES,
  VIRTUAL_FIELDS,
  Order,
} from "@/constants";
import * as Helpers from "@/lib/helpers";
import { prefetchQrImage } from "@/components/modals/ViewOrderModal/components/OrderPaymentQrSection";
import { buildViewOrderPaymentQrPayload } from "@/components/modals/ViewOrderModal/paymentQr";
import { getOrderQrEligibility } from "@/components/modals/ViewOrderModal/qrEligibility";
import {
  formatCurrency,
  formatOrderCodeShort,
  isGiftOrderCode,
} from "../utils/ordersHelpers";
import { getOrderCodeTheme } from "../utils/orderCodeTheme";
import {
  CheckCircleIcon,
  EyeIcon,
  PlusCircleIcon,
  PencilIcon,
  TrashIcon,
} from "@heroicons/react/24/outline";

type OrderRowProps = {
  order: Order;
  index: number;
  isExpanded: boolean;
  showRemainingColumn: boolean;
  showSupplierRefundColumn: boolean;
  showActionButtons: boolean;
  isCanceled: boolean;
  canEdit: boolean;
  canRenewOrder: boolean;
  totalColumns: number;
  renewingOrderCode: string | null;
  completingOrderCode: string | null;
  onToggleDetails: (orderId: number) => void;
  onView: (order: Order) => void;
  onEdit: (order: Order) => void;
  onDelete: (order: Order) => void;
  onConfirmRefund: (order: Order) => void;
  onCreateTopupOrderFromRefund: (order: Order) => void;
  onMarkPaid: (order: Order) => void;
  onRenew: (order: Order) => void;
};

export const OrderRow = React.memo(function OrderRow({
  order,
  isExpanded,
  showRemainingColumn,
  showSupplierRefundColumn,
  showActionButtons,
  isCanceled,
  canEdit,
  canRenewOrder,
  totalColumns,
  renewingOrderCode,
  completingOrderCode,
  onToggleDetails,
  onView,
  onEdit,
  onDelete,
  onConfirmRefund,
  onCreateTopupOrderFromRefund,
  onMarkPaid,
  onRenew,
}: OrderRowProps) {
  const {
    [VIRTUAL_FIELDS.SO_NGAY_CON_LAI]: soNgayConLai,
    [VIRTUAL_FIELDS.GIA_TRI_CON_LAI]: giaTriConLai,
    [VIRTUAL_FIELDS.HOAN_TU_NCC]: hoanTuNccRaw,
    [VIRTUAL_FIELDS.TRANG_THAI_TEXT]: trangThaiText,
  } = order;

  const costValue = Number.isFinite(Number(order[ORDER_FIELDS.COST]))
    ? Number(order[ORDER_FIELDS.COST])
    : 0;
  const priceValue = Number.isFinite(Number(order[ORDER_FIELDS.PRICE]))
    ? Number(order[ORDER_FIELDS.PRICE])
    : 0;
  const giaTriConLaiSafe = Number.isFinite(Number(giaTriConLai))
    ? Number(giaTriConLai)
    : 0;
  const orderRecord = order as Record<string, unknown>;
  /** Tổng biên lai từ ngày đăng ký (SUM receipt có paid_date >= order_date); ưu tiên khi > 0 (2+ giao dịch cùng chu kỳ). */
  const totalWhRaw = orderRecord.total_webhook_amount;
  const latestWhRaw = orderRecord.latest_webhook_amount ?? orderRecord.webhook_amount;
  const parseWebhookMoney = (v: unknown): number | null => {
    if (v === null || v === undefined) return null;
    if (typeof v === "string" && v.trim() === "") return null;
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  };
  const totalWh = parseWebhookMoney(totalWhRaw);
  const latestWh = parseWebhookMoney(latestWhRaw);
  /**
   * Sau gia hạn, order_date thường được kéo về sau; receipt cũ có paid_date < order_date mới
   * → total_webhook_amount = 0 dù webhook đã về. Trước đây UI ưu tiên total nên 0 − giá bán = chênh âm sai.
   */
  let webhookAmount: number | null = null;
  if (totalWh !== null && totalWh > 0) {
    webhookAmount = totalWh;
  } else if (latestWh !== null) {
    webhookAmount = latestWh;
  }
  const webhookDelta = webhookAmount !== null ? webhookAmount - priceValue : null;
  const webhookDeltaDisplay =
    webhookDelta !== null ? formatCurrency(webhookDelta) : "Chưa có webhook";
  const webhookDeltaClass =
    webhookDelta === null
      ? "text-indigo-100/80"
      : webhookDelta === 0
      ? "text-emerald-300"
      : webhookDelta > 0
      ? "text-amber-300"
      : "text-rose-300";
  /** Đã hủy: cột "Giá trị còn lại" = prorata theo giá bán; `refund` trên DB là theo vốn/NCC — không min với cột refund. */
  const giaTriConLaiForCanceled = isCanceled
    ? Math.max(0, giaTriConLaiSafe)
    : giaTriConLaiSafe;

  const pendingRefundStatus = ORDER_STATUSES.CHO_HOAN;
  const statusText = String(trangThaiText || "").trim();
  const canConfirmRefund = isCanceled && statusText === pendingRefundStatus;
  const canRenew =
    canRenewOrder &&
    statusText === ORDER_STATUSES.ORDER_EXPIRED;
  const canStartProcessing =
    statusText === ORDER_STATUSES.CHUA_THANH_TOAN ||
    statusText === ORDER_STATUSES.CAN_GIA_HAN;
  const canMarkPaid = statusText === ORDER_STATUSES.DANG_XU_LY;

  const orderDateDisplay = order[VIRTUAL_FIELDS.ORDER_DATE_DISPLAY] || "";
  const expiryDateDisplay = order[VIRTUAL_FIELDS.EXPIRY_DATE_DISPLAY] || "";
  const orderCodeText = String(order[ORDER_FIELDS.ID_ORDER] || "").trim();
  const orderCodeDisplay = formatOrderCodeShort(orderCodeText);
  const orderTheme = getOrderCodeTheme(orderCodeText);
  const isRenewing = renewingOrderCode === orderCodeText;
  const isCompleting = completingOrderCode === orderCodeText;

  const remainingValue = Number.isFinite(Number(soNgayConLai))
    ? Number(soNgayConLai)
    : 0;
  const remainingClass = isCanceled
    ? "text-indigo-600"
    : remainingValue <= 0
    ? "text-red-600"
    : remainingValue <= 4
    ? "text-orange-500"
    : "text-green-500";
  const remainingDisplay = isCanceled
    ? formatCurrency(giaTriConLaiForCanceled)
    : remainingValue;

  const hoanTuNccDisplay = Number.isFinite(Number(hoanTuNccRaw))
    ? formatCurrency(Number(hoanTuNccRaw))
    : formatCurrency(0);

  const handleToggle = useCallback(() => {
    if (order.id !== undefined && order.id !== null) {
      onToggleDetails(order.id);
    }
  }, [onToggleDetails, order.id]);

  const stopPropagation =
    (action: (targetOrder: Order) => void) =>
    (event: React.MouseEvent) => {
      event.stopPropagation();
      action(order);
    };

  const cellClass = `order-row__cell px-2 sm:px-4 py-3 sm:py-5 glass-panel border-y transition-all duration-500 ${orderTheme.rowSurfaceClass}`;

  return (
    <React.Fragment>
      <tr
        onClick={handleToggle}
        className={`order-row ${isExpanded ? "order-row--expanded" : ""} group/row cursor-pointer transition-all duration-500 ${isExpanded ? "z-20" : "z-10"}`}
      >
        <td className={`${cellClass} first:rounded-l-[16px] sm:first:rounded-l-[24px] overflow-hidden max-w-0`}>
          <div className="flex flex-col items-center w-full">
            <span
              className="text-xs sm:text-sm font-bold text-white tracking-normal sm:tracking-wider uppercase truncate w-full block text-center"
              title={orderCodeText}
            >
              {orderCodeDisplay}
            </span>
            <span className={`${orderTheme.accentTextClass} text-[10px] sm:text-[11px] font-bold mt-1 uppercase tracking-normal sm:tracking-wider truncate w-full block text-center`}>
              {order[ORDER_FIELDS.ID_PRODUCT] || ""}
            </span>
          </div>
        </td>

        <td className={`${cellClass} overflow-hidden max-w-0`}>
          <div className="flex flex-col items-center w-full">
            <span className="text-indigo-100/90 text-xs font-medium tracking-wide text-center truncate w-full block">
              {order[ORDER_FIELDS.INFORMATION_ORDER] || "—"}
            </span>
            {order[ORDER_FIELDS.SLOT] ? (
              <div className={`mt-1 px-2 py-0.5 rounded-md border text-[11px] font-bold uppercase w-full truncate text-center block ${orderTheme.badgeClass} ${orderTheme.badgeTextClass}`}>
                {order[ORDER_FIELDS.SLOT]}
              </div>
            ) : null}
          </div>
        </td>

        <td className={`${cellClass} overflow-hidden max-w-0`}>
          <div className="flex flex-col items-center w-full">
            <span className="text-sm font-bold text-white tracking-tight truncate w-full block text-center">
              {order[ORDER_FIELDS.CUSTOMER] || "Khách ẩn"}
            </span>
            <span className="text-white/60 text-[11px] font-medium mt-0.5 truncate w-full block text-center">
              {order[ORDER_FIELDS.CONTACT] || ""}
            </span>
          </div>
        </td>

        <td className={`${cellClass} text-center`}>
          <div className="flex flex-col items-center gap-1 w-full min-w-0">
            <div className="inline-flex items-center justify-center gap-1.5 px-2 py-1 rounded-full bg-white/5 border border-white/10 text-[10px] sm:text-[11px] font-bold text-indigo-200 w-full max-w-full truncate">
              <span className="truncate">{orderDateDisplay || "—"}</span>
              <span className="text-white/20 shrink-0">/</span>
              <span className="truncate">{expiryDateDisplay || "—"}</span>
            </div>
            {isCanceled && (
              <span className="text-[10px] sm:text-[11px] font-semibold text-sky-300/95 tabular-nums leading-tight">
                {Number.isFinite(Number(soNgayConLai))
                  ? `${remainingValue} ngày`
                  : "—"}
              </span>
            )}
          </div>
        </td>
        {showRemainingColumn && (
          <td className={`${cellClass} text-center`}>
            <span className={`text-sm font-black transition-all group-hover/row:scale-110 inline-block w-full truncate ${remainingClass}`}>
              {remainingDisplay}
            </span>
          </td>
        )}
        {showSupplierRefundColumn && (
          <td className={`${cellClass} text-center`}>
            <span className="text-sm font-semibold text-violet-200/95 transition-all group-hover/row:scale-105 inline-block w-full truncate tabular-nums">
              {hoanTuNccDisplay}
            </span>
          </td>
        )}

        <td className={`${cellClass} text-center`}>
          <span
            className={`inline-block px-2 py-1 text-[9px] sm:text-[10px] font-bold uppercase tracking-wider rounded-full border shadow-[inset_0_1px_2px_rgba(255,255,255,0.1)] whitespace-nowrap w-full truncate overflow-hidden text-ellipsis ${Helpers.getStatusColor(
              String(trangThaiText || "")
            )}`}
          >
            {String(trangThaiText || "")}
          </span>
        </td>
        <td className={`order-row__actions px-2 sm:px-4 py-3 sm:py-5 glass-panel border-y transition-all duration-500 last:rounded-r-[16px] sm:last:rounded-r-[24px] ${orderTheme.rowSurfaceClass}`}>
          <div className="flex space-x-2 justify-end flex-shrink-0">
            <button
              onClick={stopPropagation(onView)}
              onMouseEnter={() => {
                const code = String(order[ORDER_FIELDS.ID_ORDER] || "");
                const qrEligibility = getOrderQrEligibility(statusText);
                if (!code) return;
                if (!qrEligibility.canUseQr) return;
                const { qrCodeImageUrl, effectiveQrAmount } =
                  buildViewOrderPaymentQrPayload({
                    order: order as Record<string, unknown>,
                    keepOrderPrice: false,
                    calculatedPrice: null,
                    isGift: isGiftOrderCode(code),
                  });
                if (qrCodeImageUrl && effectiveQrAmount > 0) {
                  prefetchQrImage(qrCodeImageUrl);
                }
              }}
              className="w-8 h-8 flex items-center justify-center rounded-xl bg-white/5 border border-white/10 text-indigo-300/60 hover:text-white hover:bg-indigo-500/20 hover:border-indigo-500/40 transition-all flex-shrink-0"
            >
              <EyeIcon className="h-4 w-4" />
            </button>
            {canConfirmRefund && (
              <button
                onClick={stopPropagation(onCreateTopupOrderFromRefund)}
                className="w-8 h-8 flex items-center justify-center rounded-xl bg-cyan-500/10 border border-cyan-500/20 text-cyan-300 hover:bg-cyan-500/30 transition-all flex-shrink-0"
                title="Tạo đơn bù từ credit hoàn tiền"
              >
                <PlusCircleIcon className="h-4 w-4" />
              </button>
            )}
            {canConfirmRefund && (
              <button
                onClick={stopPropagation(onConfirmRefund)}
                className="w-8 h-8 flex items-center justify-center rounded-xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 hover:bg-emerald-500/30 transition-all flex-shrink-0"
                title="Xác nhận đã giải/hoàn tiền"
              >
                <CheckCircleIcon className="h-4 w-4" />
              </button>
            )}
            {canEdit && !isCanceled && (
              <>
                <button
                  onClick={stopPropagation(onEdit)}
                  className="w-8 h-8 flex items-center justify-center rounded-xl bg-amber-500/10 border border-amber-500/20 text-amber-400 hover:bg-amber-500/30 transition-all flex-shrink-0"
                >
                  <PencilIcon className="h-4 w-4" />
                </button>
                <button
                  onClick={stopPropagation(onDelete)}
                  className="w-8 h-8 flex items-center justify-center rounded-xl bg-rose-500/10 border border-rose-500/20 text-rose-400 hover:bg-rose-500/30 transition-all flex-shrink-0"
                  title="Xoá đơn hàng"
                >
                  <TrashIcon className="h-4 w-4" />
                </button>
              </>
            )}
          </div>
        </td>
      </tr>
      {isExpanded && (
        <tr className="order-row__expandable animate-in fade-in slide-in-from-top-2 duration-300">
          <td colSpan={totalColumns} className="order-row__expandable-cell px-6 pb-8 pt-2">
            <div className={`order-row__expandable-content rounded-[32px] glass-panel-light p-6 shadow-2xl border ${orderTheme.expandablePanelClass}`}>
              <div className="order-row__expandable-header mb-4 flex items-center justify-between">
                <div className="flex-1 text-center">
                  <p className="text-sm font-semibold text-indigo-50">
                    Chi tiết đơn hàng
                  </p>
                  <p className="text-xs font-semibold uppercase tracking-wide text-indigo-200">
                    #{order[ORDER_FIELDS.ID_ORDER] || ""}
                  </p>
                </div>
                {showActionButtons && (
                  <div className="ml-4 flex items-center gap-2">
                    {canStartProcessing && (
                      <button
                        className="rounded-full px-3 py-1 text-xs font-semibold text-white bg-gradient-to-r from-emerald-500 to-green-600 hover:from-emerald-600 hover:to-green-700 shadow-md shadow-emerald-900/40"
                        onClick={stopPropagation(onMarkPaid)}
                      >
                        Thanh Toán
                      </button>
                    )}
                    {canMarkPaid && (
                      <button
                        className="rounded-full px-3 py-1 text-xs font-semibold text-white bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-600 hover:to-orange-700 shadow-md shadow-amber-900/40"
                        disabled={isCompleting}
                        onClick={(e) => {
                          e.stopPropagation();
                          if (!isCompleting) {
                            onMarkPaid(order);
                          }
                        }}
                      >
                        {isCompleting ? "Đang Hoàn Thành..." : "Hoàn Thành"}
                      </button>
                    )}
                    {canRenew && (
                      <button
                        className="rounded-full px-3 py-1 text-xs font-semibold text-white bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 shadow-md shadow-indigo-900/40 disabled:opacity-70 disabled:cursor-not-allowed"
                        disabled={isRenewing}
                        onClick={(e) => {
                          e.stopPropagation();
                          if (!isRenewing) {
                            onRenew(order);
                          }
                        }}
                      >
                        {isRenewing ? "Đang Gia Hạn..." : "Gia Hạn"}
                      </button>
                    )}
                  </div>
                )}
              </div>
              <div
                className={`order-row__detail-grid grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3 ${
                  showSupplierRefundColumn ? "xl:grid-cols-7" : "xl:grid-cols-6"
                }`}
              >
                <div className={`order-row__detail-item rounded-xl border p-3 text-center ${orderTheme.detailItemClass}`}>
                  <p className={`text-xs font-medium uppercase tracking-wide ${orderTheme.detailLabelClass}`}>
                    Nguồn
                  </p>
                  <p className="mt-1 text-sm font-semibold text-white">
                    {order[ORDER_FIELDS.SUPPLY] || "N/A"}
                  </p>
                </div>
                <div className={`order-row__detail-item rounded-xl border p-3 text-center ${orderTheme.detailItemClass}`}>
                  <p className={`text-xs font-medium uppercase tracking-wide ${orderTheme.detailLabelClass}`}>
                    Giá nhập
                  </p>
                  <p className="mt-1 text-sm font-semibold text-white">
                    {formatCurrency(costValue)}
                  </p>
                </div>
                <div className={`order-row__detail-item rounded-xl border p-3 text-center ${orderTheme.detailItemClass}`}>
                  <p className={`text-xs font-medium uppercase tracking-wide ${orderTheme.detailLabelClass}`}>
                    Giá bán
                  </p>
                  <p className="mt-1 text-sm font-semibold text-white">
                    {formatCurrency(priceValue)}
                  </p>
                </div>
                <div className={`order-row__detail-item rounded-xl border p-3 text-center ${orderTheme.detailItemClass}`}>
                  <p className={`text-xs font-medium uppercase tracking-wide ${orderTheme.detailLabelClass}`}>
                    Giá trị còn lại
                  </p>
                  <p className="mt-1 text-sm font-semibold text-white">
                    {formatCurrency(giaTriConLaiForCanceled)}
                  </p>
                </div>
                <div className={`order-row__detail-item rounded-xl border p-3 text-center ${orderTheme.detailItemClass}`}>
                  <p className={`text-xs font-medium uppercase tracking-wide ${orderTheme.detailLabelClass}`}>
                    Chênh lệch webhook
                  </p>
                  <p className={`mt-1 text-sm font-semibold ${webhookDeltaClass}`}>
                    {webhookDeltaDisplay}
                  </p>
                </div>
                {showSupplierRefundColumn && (
                  <div className={`order-row__detail-item rounded-xl border p-3 text-center ${orderTheme.detailItemClass}`}>
                    <p className={`text-xs font-medium uppercase tracking-wide ${orderTheme.detailLabelClass}`}>
                      Hoàn từ NCC
                    </p>
                    <p className="mt-1 text-sm font-semibold text-violet-200">
                      {hoanTuNccDisplay}
                    </p>
                  </div>
                )}
                <div className={`order-row__detail-item rounded-xl border p-3 text-center ${orderTheme.detailItemClass}`}>
                  <p className={`text-xs font-medium uppercase tracking-wide ${orderTheme.detailLabelClass}`}>
                    Số ngày
                  </p>
                  <p className="mt-1 text-sm font-semibold text-white">
                    {order[ORDER_FIELDS.DAYS] || 0}
                  </p>
                </div>
                <div
                  className={`order-row__detail-item order-row__detail-item--note rounded-xl border p-3 text-center sm:col-span-2 ${
                    showSupplierRefundColumn ? "xl:col-span-7" : "xl:col-span-6"
                  } flex flex-col items-center justify-center ${orderTheme.detailItemClass}`}
                >
                  <p className={`text-xs font-medium uppercase tracking-wide ${orderTheme.detailLabelClass}`}>
                    Ghi chú
                  </p>
                  <p className="mt-1 text-sm text-indigo-50 text-center">
                    {order[ORDER_FIELDS.NOTE] || "Không có ghi chú."}
                  </p>
                </div>
              </div>
            </div>
          </td>
        </tr>
      )}
    </React.Fragment>
  );
});

OrderRow.displayName = "OrderRow";

﻿import { useCallback, useRef, useState } from "react";
import {
  API_ENDPOINTS,
  ORDER_CODE_PREFIXES,
  ORDER_FIELDS,
  ORDER_STATUSES,
  VIRTUAL_FIELDS,
  Order,
} from "@/constants";
import { apiFetch } from "@/lib/api";
import { emitRefresh } from "@/lib/refreshBus";
import { showAppNotification } from "@/lib/notifications";
import { parseErrorResponse, formatCurrency } from "../utils/ordersHelpers";
import type { EditableOrder } from "../types";
import type { RefundCreatePrefill } from "./useOrdersModals";

export type OrderActionsDeps = {
  fetchOrders: () => Promise<void>;
  closeCreateModal: () => void;
  closeEditModal: () => void;
  closeModal: () => void;
  openCreateModal: (prefill?: RefundCreatePrefill | null) => void;
  handleViewOrder: (order: Order, source: "create" | "view") => void;
  orderToDelete: Order | null;
  setOrderToDelete: (order: Order | null) => void;
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
};

export function useOrderActions(deps: OrderActionsDeps) {
  const {
    fetchOrders,
    closeCreateModal,
    closeEditModal,
    closeModal,
    openCreateModal,
    handleViewOrder,
    orderToDelete,
    setOrderToDelete,
    setOrders,
  } = deps;

  const [renewingOrderCode, setRenewingOrderCode] = useState<string | null>(null);
  const [completingOrderCode, setCompletingOrderCode] = useState<string | null>(null);

  /** Chống double-submit: nếu đã gọi tạo đơn thì bỏ qua lần gọi tiếp theo (tránh 2 đơn trùng mã) */
  const isCreatingOrderRef = useRef(false);

  type CreateOrderPayload = Partial<EditableOrder> | EditableOrder;

  const handleSaveNewOrder = useCallback(
    async (newOrderData: CreateOrderPayload) => {
      if (isCreatingOrderRef.current) return;
      isCreatingOrderRef.current = true;

      closeCreateModal();

      const outgoing: Record<string, unknown> = {
        ...(newOrderData as unknown as Record<string, unknown>),
      };
      const creditSnap = Math.max(0, Number(outgoing.__credit_avail_snapshot) || 0);
      const creditApply = Math.max(0, Number(outgoing.refund_credit_apply_amount) || 0);
      const creditNoteId = Number(outgoing.refund_credit_note_id) || 0;
      delete outgoing.__credit_avail_snapshot;

      try {
        const response = await apiFetch(API_ENDPOINTS.ORDERS, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(outgoing),
        });
        if (!response.ok) {
          const errorData = await response.json();
          throw new Error(
            errorData.error || "Lỗi khi tạo đơn hàng mới từ Máy chủ"
          );
        }
        const createdOrder: Order = await response.json();
        await fetchOrders();
        handleViewOrder(createdOrder, "create");
        emitRefresh(["orders", "dashboard"]);
        if (creditNoteId > 0 && creditApply > 0) {
          const remaining = Math.max(0, creditSnap - creditApply);
          showAppNotification({
            type: "success",
            title: "Đã tạo đơn",
            message:
              creditSnap > 0
                ? `Đã áp dụng ${formatCurrency(
                    creditApply
                  )} credit. Dư trên phiếu (ước tính khi gửi form): ${formatCurrency(
                    remaining
                  )}.`
                : `Đã áp dụng ${formatCurrency(creditApply)} credit vào đơn.`,
          });
        }
      } catch (error) {
        console.error("Lỗi khi tạo đơn hàng:", error);
        showAppNotification({
          type: "error",
          title: "Lỗi tạo đơn hàng",
          message: `Lỗi khi tạo đơn hàng: ${
            error instanceof Error ? error.message : String(error)
          }`,
        });
      } finally {
        isCreatingOrderRef.current = false;
      }
    },
    [closeCreateModal, fetchOrders, handleViewOrder]
  );

  const handleCreateTopupOrderFromRefund = useCallback(
    async (order: Order) => {
      if (!order || !order.id) return;
      try {
        const response = await apiFetch(
          API_ENDPOINTS.ORDER_REFUND_CREDIT_ENSURE(order.id),
          {
            method: "POST",
            headers: { "Content-Type": "application/json" },
          }
        );
        if (!response.ok) {
          const errorMessage = await parseErrorResponse(response);
          throw new Error(errorMessage || "Không thể khởi tạo credit bù đơn.");
        }

        const data = (await response.json()) as {
          credit_note?: {
            id?: number | string;
            available_amount?: number | string;
          };
          preview_order_code?: string;
        };

        const creditNoteId = Number(data?.credit_note?.id || 0);
        if (!Number.isFinite(creditNoteId) || creditNoteId <= 0) {
          throw new Error("Không tìm thấy phiếu credit hợp lệ.");
        }

        const creditAvailableAmount = Math.max(
          0,
          Number(data?.credit_note?.available_amount || 0) || 0
        );
        const basePrice = Math.max(0, Number(order[ORDER_FIELDS.PRICE] || 0) || 0);
        const creditApplyAmount = Math.min(basePrice, creditAvailableAmount);
        // Không prefill sản phẩm / nguồn / thông tin sản phẩm: khách có thể mua gói khác; tự chọn rồi tính giá.

        const prefill: RefundCreatePrefill = {
          initialFormData: {
            [ORDER_FIELDS.ID_PRODUCT]: "",
            [ORDER_FIELDS.INFORMATION_ORDER]: "",
            [ORDER_FIELDS.CUSTOMER]: order[ORDER_FIELDS.CUSTOMER] || "",
            [ORDER_FIELDS.CONTACT]: order[ORDER_FIELDS.CONTACT] || "",
            [ORDER_FIELDS.SLOT]: "",
            [ORDER_FIELDS.SUPPLY]: "",
            [ORDER_FIELDS.COST]: 0,
            [ORDER_FIELDS.PRICE]: 0,
            [ORDER_FIELDS.NOTE]: "",
          },
          creditNoteId,
          creditAvailableAmount,
          creditApplyAmount,
          sourceOrderListPrice: basePrice,
          creditSourceOrderId: Number(order.id),
          creditSourceOrderCode: String(order[ORDER_FIELDS.ID_ORDER] || "").trim(),
          reservedOrderCode: String(data?.preview_order_code || "").trim() || null,
        };

        await fetchOrders();
        emitRefresh(["orders", "dashboard"]);
        openCreateModal(prefill);
      } catch (error) {
        showAppNotification({
          type: "error",
          title: "Lỗi khởi tạo bù đơn",
          message:
            error instanceof Error
              ? error.message
              : "Không thể mở form tạo đơn từ credit hoàn tiền.",
        });
      }
    },
    [fetchOrders, openCreateModal]
  );

  const handleMarkPaid = useCallback(
    async (order: Order) => {
      if (!order || !order.id) return;
      const statusText = String(order[ORDER_FIELDS.STATUS] || "").trim();
      let payload: Partial<Order> | null = null;
      if (statusText === ORDER_STATUSES.CHUA_THANH_TOAN) {
        payload = {
          [ORDER_FIELDS.STATUS]: ORDER_STATUSES.DANG_XU_LY,
        };
      } else if (statusText === ORDER_STATUSES.CAN_GIA_HAN) {
        const orderCode = String(order[ORDER_FIELDS.ID_ORDER] || "").trim();
        if (!orderCode) return;
        setRenewingOrderCode(orderCode);
        try {
          const response = await apiFetch(API_ENDPOINTS.ORDER_RENEW(orderCode), {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ forceRenewal: true }),
          });
          if (!response.ok) {
            const errorMessage = await parseErrorResponse(response);
            throw new Error(
              errorMessage || "Không thể gia hạn thủ công cho đơn hàng."
            );
          }
          const renewBody = (await response.json().catch(() => ({}))) as {
            details?: { MAVN_STOCK_SYNC?: { updated?: number; reason?: string | null } };
          };
          await fetchOrders();
          emitRefresh(["orders", "dashboard", "warehouse", "package-product"]);
          const upperCode = orderCode.trim().toUpperCase();
          if (upperCode.startsWith(ORDER_CODE_PREFIXES.IMPORT)) {
            const sync = renewBody?.details?.MAVN_STOCK_SYNC;
            const stockUpdated = Number(sync?.updated ?? 0);
            showAppNotification({
              type: stockUpdated > 0 ? "success" : "warning",
              title: "Đã thanh toán (nhập hàng)",
              message:
                stockUpdated > 0
                  ? "Đơn MAVN đã gia hạn và chuyển Đã thanh toán. Đã đồng bộ ngày hết hạn trên kho."
                  : `Đơn MAVN đã gia hạn (Đã thanh toán) nhưng không cập nhật được expires_at kho${
                      sync?.reason ? ` (${sync.reason}).` : ". "
                    } Kiểm tra information_order trên đơn trùng account_username trên kho (cùng gói).`,
            });
          }
        } catch (error) {
          showAppNotification({
            type: "error",
            title: "Lỗi gia hạn",
            message: `Không thể gia hạn đơn hàng: ${
              error instanceof Error ? error.message : String(error)
            }`,
          });
        } finally {
          setRenewingOrderCode(null);
        }
        return;
      } else if (statusText === ORDER_STATUSES.DANG_XU_LY) {
        const orderCode = String(order[ORDER_FIELDS.ID_ORDER] || "").trim();
        setCompletingOrderCode(orderCode || String(order.id));
        try {
          const response = await apiFetch(
            API_ENDPOINTS.ORDER_COMPLETE_MANUAL_WEBHOOK(order.id),
            {
              method: "POST",
              headers: { "Content-Type": "application/json" },
            }
          );
          if (!response.ok) {
            const errorMessage = await parseErrorResponse(response);
            throw new Error(
              errorMessage || "Không thể hoàn thành đơn bằng webhook thủ công."
            );
          }
          const data = (await response.json().catch(() => ({}))) as {
            mavn_import_only?: boolean;
          };
          await fetchOrders();
          emitRefresh(["orders", "dashboard", "payments", "supplies"]);
          showAppNotification({
            type: "success",
            title: "Hoàn thành đơn",
            message: data?.mavn_import_only
              ? "Đơn MAVN nhập hàng đã chuyển Đã thanh toán (không tạo receipt / không qua webhook)."
              : "Đã tạo receipt và hoàn thành đơn bằng webhook thủ công.",
          });
        } catch (error) {
          showAppNotification({
            type: "error",
            title: "Lỗi hoàn thành đơn",
            message: `Không thể hoàn thành đơn hàng: ${
              error instanceof Error ? error.message : String(error)
            }`,
          });
        } finally {
          setCompletingOrderCode(null);
        }
        return;
      }

      if (!payload) return;
      try {
        const response = await apiFetch(
          API_ENDPOINTS.ORDER_BY_ID(order.id),
          {
            method: "PUT",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload),
          }
        );
        if (!response.ok) {
          const errorMessage = await parseErrorResponse(response);
          throw new Error(
            errorMessage || "Lỗi khi cập nhật trạng thái từ máy chủ"
          );
        }
        await fetchOrders();
        emitRefresh(["orders", "dashboard"]);
      } catch (error) {
        console.error("Lỗi khi đánh dấu đã thanh toán:", error);
        showAppNotification({
          type: "error",
          title: "Lỗi cập nhật thanh toán",
          message: `Không thể đánh dấu đã thanh toán: ${
            error instanceof Error ? error.message : String(error)
          }`,
        });
      }
    },
    [fetchOrders]
  );

  const handleRenewOrder = useCallback(
    async (order: Order) => {
      if (!order) return;

      const orderCode = String(order[ORDER_FIELDS.ID_ORDER] || "").trim();
      if (!orderCode) return;

      setRenewingOrderCode(orderCode);

      try {
        const response = await apiFetch(
          API_ENDPOINTS.ORDER_RENEW(orderCode),
          {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ forceRenewal: true }),
          }
        );

        if (!response.ok) {
          const errorMessage = await parseErrorResponse(response);
          throw new Error(
            errorMessage || "Không thể gia hạn thủ công cho đơn hàng."
          );
        }

        const renewBody = (await response.json().catch(() => ({}))) as {
          details?: { MAVN_STOCK_SYNC?: { updated?: number; reason?: string | null } };
        };

        await fetchOrders();
        emitRefresh(["orders", "dashboard", "warehouse", "package-product"]);
        const upperRenewCode = orderCode.trim().toUpperCase();
        if (upperRenewCode.startsWith(ORDER_CODE_PREFIXES.IMPORT)) {
          const sync = renewBody?.details?.MAVN_STOCK_SYNC;
          const stockUpdated = Number(sync?.updated ?? 0);
          showAppNotification({
            type: stockUpdated > 0 ? "success" : "warning",
            title: "Gia hạn thành công",
            message:
              stockUpdated > 0
                ? "Đơn MAVN đã gia hạn và chuyển Đã thanh toán. Đã đồng bộ ngày hết hạn trên kho."
                : `Đơn MAVN đã gia hạn (Đã thanh toán) nhưng không cập nhật được expires_at kho${
                    sync?.reason ? ` (${sync.reason}).` : ". "
                  } Kiểm tra information_order trên đơn trùng account_username trên kho (cùng gói).`,
          });
        } else {
          showAppNotification({
            type: "success",
            title: "Gia hạn thành công",
            message:
              "Gia hạn đơn hàng thành công.\nĐơn đã được xử lý renewal thủ công.",
          });
        }
      } catch (error) {
        console.error("Lỗi khi chạy gia hạn thủ công:", error);
        showAppNotification({
          type: "error",
          title: "Lỗi gia hạn",
          message: `Không thể gia hạn đơn hàng: ${
            error instanceof Error ? error.message : String(error)
          }`,
        });
      } finally {
        setRenewingOrderCode(null);
      }
    },
    [fetchOrders]
  );

  const handleConfirmRefund = useCallback(
    async (order: Order) => {
      if (!order || !order.id) return;
      try {
        const response = await apiFetch(
          API_ENDPOINTS.ORDER_CANCELED_REFUND(order.id),
          {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
          }
        );
        if (!response.ok) {
          const errorMessage = await parseErrorResponse(response);
          throw new Error(
            errorMessage || "Lỗi khi xác nhận hoàn tiền từ máy chủ"
          );
        }
        await fetchOrders();
        emitRefresh(["orders", "dashboard"]);
      } catch (error) {
        console.error("Lỗi khi xác nhận hoàn tiền:", error);
        showAppNotification({
          type: "error",
          title: "Lỗi xác nhận hoàn tiền",
          message: `Lỗi khi xác nhận hoàn tiền: ${
            error instanceof Error ? error.message : String(error)
          }`,
        });
      }
    },
    [fetchOrders]
  );

  const handleSaveEdit = useCallback(
    async (updatedOrder: EditableOrder) => {
      closeEditModal();

      const dbFields: Partial<Order> = {
        [ORDER_FIELDS.ID_ORDER]: updatedOrder.id_order,
        [ORDER_FIELDS.ID_PRODUCT]: updatedOrder.id_product,
        [ORDER_FIELDS.INFORMATION_ORDER]: updatedOrder.information_order,
        [ORDER_FIELDS.CUSTOMER]: updatedOrder.customer,
        [ORDER_FIELDS.CONTACT]: updatedOrder.contact,
        [ORDER_FIELDS.SLOT]: updatedOrder.slot,
        [ORDER_FIELDS.SUPPLY]: updatedOrder.supply,
        [ORDER_FIELDS.COST]: Number(updatedOrder.cost ?? 0) || 0,
        [ORDER_FIELDS.PRICE]: Number(updatedOrder.price ?? 0) || 0,
        [ORDER_FIELDS.NOTE]: updatedOrder.note,
        [ORDER_FIELDS.STATUS]: updatedOrder.status,
      };

      try {
        const response = await apiFetch(
          API_ENDPOINTS.ORDER_BY_ID(Number(updatedOrder.id)),
          {
            method: "PUT",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(dbFields),
          }
        );

        if (!response.ok) {
          const errorMessage = await parseErrorResponse(response);
          throw new Error(errorMessage || "Lỗi khi cập nhật đơn hàng từ Máy chủ");
        }
        await fetchOrders();
        emitRefresh(["orders", "dashboard"]);
      } catch (error) {
        console.error("Lỗi khi cập nhật đơn hàng:", error);
        showAppNotification({
          type: "error",
          title: "Lỗi cập nhật đơn hàng",
          message: `Lỗi khi cập nhật đơn hàng: ${
            error instanceof Error ? error.message : String(error)
          }`,
        });
      }
    },
    [closeEditModal, fetchOrders]
  );

  const confirmDelete = useCallback(async () => {
    if (!orderToDelete) return;
    closeModal();

    try {
      const response = await apiFetch(
        API_ENDPOINTS.ORDER_BY_ID(orderToDelete.id),
        {
          method: "DELETE",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            can_hoan: orderToDelete[VIRTUAL_FIELDS.GIA_TRI_CON_LAI],
            gia_tri_con_lai: orderToDelete[VIRTUAL_FIELDS.GIA_TRI_CON_LAI],
          }),
        }
      );

      if (!response.ok) {
        const errorMessage = await parseErrorResponse(response);
        throw new Error(errorMessage || "Lỗi khi xóa đơn hàng từ Máy chủ");
      }

      setOrders((prevOrders) =>
        prevOrders.filter((order) => order.id !== orderToDelete.id)
      );
      emitRefresh(["orders", "dashboard"]);
    } catch (error) {
      console.error("Lỗi khi xóa đơn hàng:", error);
      showAppNotification({
        type: "error",
        title: "Lỗi xóa đơn hàng",
        message: `Lỗi khi xóa đơn hàng: ${
          error instanceof Error ? error.message : String(error)
        }`,
      });
    } finally {
      setOrderToDelete(null);
    }
  }, [closeModal, orderToDelete, setOrderToDelete, setOrders]);

  return {
    handleSaveNewOrder,
    handleMarkPaid,
    handleRenewOrder,
    handleCreateTopupOrderFromRefund,
    handleConfirmRefund,
    handleSaveEdit,
    confirmDelete,
    renewingOrderCode,
    completingOrderCode,
  };
}

import { useEffect, useState } from "react";
import { OrderDatasetKey } from "@/constants";
import { useOrdersFetch } from "./useOrdersFetch";
import { useOrdersList, type OrdersDurationRange } from "./useOrdersList";
import { useOrdersModals } from "./useOrdersModals";
import { useOrderActions } from "./useOrderActions";

export type { EditableOrder } from "../types";

export type UseOrdersDataOptions = {
  durationRange: OrdersDurationRange | null;
};

export function useOrdersData(
  dataset: OrderDatasetKey,
  { durationRange }: UseOrdersDataOptions
) {
  const { orders, setOrders, fetchError, fetchOrders } = useOrdersFetch(dataset);

  const [searchTerm, setSearchTerm] = useState("");
  const [searchField, setSearchField] = useState<string>("all");
  const [statusFilter, setStatusFilter] = useState("all");
  const [currentPage, setCurrentPage] = useState(1);
  const [rowsPerPage, setRowsPerPage] = useState(10);

  const modals = useOrdersModals();

  const list = useOrdersList({
    orders,
    searchTerm,
    searchField,
    statusFilter,
    rowsPerPage,
    currentPage,
    setCurrentPage,
    dataset,
    durationRange,
  });

  const actions = useOrderActions({
    fetchOrders,
    closeCreateModal: modals.closeCreateModal,
    closeEditModal: modals.closeEditModal,
    closeModal: modals.closeModal,
    openCreateModal: modals.openCreateModal,
    handleViewOrder: modals.handleViewOrder,
    orderToDelete: modals.orderToDelete,
    setOrderToDelete: modals.setOrderToDelete,
    setOrders,
  });

  useEffect(() => {
    setOrders([]);
    setSearchTerm("");
    setStatusFilter("all");
    setCurrentPage(1);
    modals.resetModals();
  }, [dataset, setOrders, modals.resetModals]);

  return {
    // List data
    ...list,
    // Filters & pagination state
    searchTerm,
    setSearchTerm,
    searchField,
    setSearchField,
    statusFilter,
    setStatusFilter,
    currentPage,
    setCurrentPage,
    rowsPerPage,
    setRowsPerPage,
    // Modals
    isModalOpen: modals.isModalOpen,
    isViewModalOpen: modals.isViewModalOpen,
    viewModalSource: modals.viewModalSource,
    isEditModalOpen: modals.isEditModalOpen,
    isCreateModalOpen: modals.isCreateModalOpen,
    orderToView: modals.orderToView,
    orderToDelete: modals.orderToDelete,
    orderToEdit: modals.orderToEdit,
    createPrefill: modals.createPrefill,
    openCreateModal: modals.openCreateModal,
    closeCreateModal: modals.closeCreateModal,
    closeViewModal: modals.closeViewModal,
    closeEditModal: modals.closeEditModal,
    closeModal: modals.closeModal,
    handleViewOrder: modals.handleViewOrder,
    handleEditOrder: modals.handleEditOrder,
    handleDeleteOrder: modals.handleDeleteOrder,
    // Actions
    handleSaveNewOrder: actions.handleSaveNewOrder,
    handleSaveEdit: actions.handleSaveEdit,
    handleConfirmRefund: actions.handleConfirmRefund,
    handleCreateTopupOrderFromRefund: actions.handleCreateTopupOrderFromRefund,
    handleMarkPaid: actions.handleMarkPaid,
    handleRenewOrder: actions.handleRenewOrder,
    confirmDelete: actions.confirmDelete,
    renewingOrderCode: actions.renewingOrderCode,
    completingOrderCode: actions.completingOrderCode,
    // Fetch
    fetchError,
    reloadOrders: fetchOrders,
  };
}

import { useEffect, useMemo, useState } from "react";
import { Order, OrderDatasetKey } from "@/constants";
import { useDebounce } from "./useDebounce";
import {
  enrichOrdersWithVirtualFields,
  filterAndSortOrders,
  computeOrderStats,
  getPaginated,
  buildPaginationPages,
} from "../utils/orderListTransform";
import { orderCreatedWithinIsoRange } from "../utils/ordersHelpers";

export type OrdersDurationRange = { from: string; to: string };

export type UseOrdersListParams = {
  orders: Order[];
  searchTerm: string;
  searchField: string;
  statusFilter: string;
  rowsPerPage: number;
  currentPage: number;
  setCurrentPage: (page: number | ((prev: number) => number)) => void;
  dataset: OrderDatasetKey;
  durationRange: OrdersDurationRange | null;
};

export function useOrdersList({
  orders,
  searchTerm,
  searchField,
  statusFilter,
  rowsPerPage,
  currentPage,
  setCurrentPage,
  dataset,
  durationRange,
}: UseOrdersListParams) {
  const debouncedSearchTerm = useDebounce(searchTerm, 300);

  const listData = useMemo(() => {
    const ordersWithVirtual = enrichOrdersWithVirtualFields(orders, dataset);
    const narrowed =
      durationRange?.from && durationRange?.to
        ? ordersWithVirtual.filter((o) =>
            orderCreatedWithinIsoRange(o, durationRange.from, durationRange.to)
          )
        : ordersWithVirtual;

    const filteredOrders = filterAndSortOrders(narrowed, {
      searchTerm: debouncedSearchTerm,
      searchField,
      statusFilter,
      dataset,
    });
    const { updatedStats, totalRecords } = computeOrderStats(narrowed, dataset);
    const { currentOrders, totalPages } = getPaginated(
      filteredOrders,
      currentPage,
      rowsPerPage
    );

    return {
      filteredOrders,
      currentOrders,
      totalPages,
      updatedStats,
      totalRecords,
    };
  }, [
    orders,
    dataset,
    debouncedSearchTerm,
    searchField,
    statusFilter,
    rowsPerPage,
    currentPage,
    durationRange,
  ]);

  useEffect(() => {
    setCurrentPage(1);
  }, [
    debouncedSearchTerm,
    searchField,
    statusFilter,
    rowsPerPage,
    durationRange,
    setCurrentPage,
  ]);

  const paginationPages = useMemo(
    () => buildPaginationPages(currentPage, listData.totalPages),
    [currentPage, listData.totalPages]
  );

  return {
    ...listData,
    paginationPages,
  };
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type React from "react";
import { apiFetch } from "@/lib/api";
import { API_ENDPOINTS } from "@/constants";
import type { WarehouseItem } from "../../../../../Personal/Storage/types";
import type {
  AccountInfo,
  PackageFormValues,
  SlotLinkMode,
} from "../../../utils/packageHelpers";
import {
  EMPTY_FORM_VALUES,
  EMPTY_MANUAL_ENTRY,
} from "../../../utils/packageHelpers";
import {
  normalizeWarehouseId,
  type EditableWarehouseFields,
} from "./shared";

type UsePackageFormStateParams = {
  open: boolean;
  initialValues?: PackageFormValues;
  onSubmit: (values: PackageFormValues) => void;
  /** Bật khi loại gói có trường «activation» — khi false, không bắt buộc kích hoạt dù chọn match theo thông tin đơn. */
  requireActivationForInformation: boolean;
};

export const usePackageFormState = ({
  open,
  initialValues,
  onSubmit,
  requireActivationForInformation,
}: UsePackageFormStateParams) => {
  const mergedInitialValues = useMemo(
    () => ({ ...EMPTY_FORM_VALUES, ...(initialValues ?? {}) }),
    [initialValues]
  );
  const [values, setValues] = useState<PackageFormValues>(mergedInitialValues);
  const [warehouseItems, setWarehouseItems] = useState<WarehouseItem[]>([]);
  const [warehouseLoading, setWarehouseLoading] = useState(false);

  const [stockDropdownOpen, setStockDropdownOpen] = useState(false);
  const [stockSearch, setStockSearch] = useState("");
  const [stockManual, setStockManual] = useState(false);
  const stockRef = useRef<HTMLDivElement>(null);

  const [storageDropdownOpen, setStorageDropdownOpen] = useState(false);
  const [storageSearch, setStorageSearch] = useState("");
  const [storageManual, setStorageManual] = useState(false);
  const storageRef = useRef<HTMLDivElement>(null);

  const formatImportValue = useCallback((raw: string): string => {
    const digitsOnly = raw.replace(/[^0-9]/g, "");
    if (!digitsOnly) return "";
    const numeric = Number(digitsOnly);
    return Number.isFinite(numeric) ? numeric.toLocaleString("vi-VN") : "";
  }, []);

  useEffect(() => {
    if (!open) return;

    setValues({
      ...mergedInitialValues,
      import: formatImportValue(mergedInitialValues.import),
    });
    setStockSearch("");
    setStockDropdownOpen(false);
    setStockManual(false);
    setStorageSearch("");
    setStorageDropdownOpen(false);
    setStorageManual(false);
  }, [open, mergedInitialValues, formatImportValue]);

  useEffect(() => {
    if (!open) return;

    let cancelled = false;
    const fetchWarehouse = async () => {
      setWarehouseLoading(true);
      try {
        const response = await apiFetch(API_ENDPOINTS.WAREHOUSE);
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const data = (await response.json()) as WarehouseItem[];
        if (!cancelled) setWarehouseItems(data);
      } catch {
        if (!cancelled) setWarehouseItems([]);
      } finally {
        if (!cancelled) setWarehouseLoading(false);
      }
    };

    fetchWarehouse();
    return () => {
      cancelled = true;
    };
  }, [open]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (stockRef.current && !stockRef.current.contains(event.target as Node)) {
        setStockDropdownOpen(false);
      }
      if (
        storageRef.current &&
        !storageRef.current.contains(event.target as Node)
      ) {
        setStorageDropdownOpen(false);
      }
    };

    if (stockDropdownOpen || storageDropdownOpen) {
      document.addEventListener("mousedown", handleClickOutside);
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [stockDropdownOpen, storageDropdownOpen]);

  const inStockItems = useMemo(
    () =>
      warehouseItems.filter((item) =>
        (item.status || "").toLowerCase().includes("tồn")
      ),
    [warehouseItems]
  );

  const filterItems = useCallback(
    (search: string) => {
      if (!search.trim()) return inStockItems;
      const query = search.toLowerCase();
      return inStockItems.filter(
        (item) =>
          (item.account || "").toLowerCase().includes(query) ||
          (item.category || "").toLowerCase().includes(query) ||
          (item.note || "").toLowerCase().includes(query)
      );
    },
    [inStockItems]
  );

  const filteredStockItems = useMemo(
    () => filterItems(stockSearch),
    [filterItems, stockSearch]
  );
  const filteredStorageItems = useMemo(
    () => filterItems(storageSearch),
    [filterItems, storageSearch]
  );

  const selectedStockItem = useMemo(() => {
    const targetId = normalizeWarehouseId(values.stockId);
    if (targetId == null) return null;
    return (
      warehouseItems.find((item) => normalizeWarehouseId(item.id) === targetId) ??
      null
    );
  }, [values.stockId, warehouseItems]);

  const selectedStorageItem = useMemo(() => {
    const targetId = normalizeWarehouseId(values.storageId);
    if (targetId == null) return null;
    return (
      warehouseItems.find((item) => normalizeWarehouseId(item.id) === targetId) ??
      null
    );
  }, [values.storageId, warehouseItems]);

  const handleUpdateWarehouseInfo = useCallback(
    async (id: number, fields: EditableWarehouseFields) => {
      const targetId = normalizeWarehouseId(id);
      const currentItem =
        targetId == null
          ? undefined
          : warehouseItems.find(
              (item) => normalizeWarehouseId(item.id) === targetId
            );

      if (!currentItem) throw new Error("WAREHOUSE_ITEM_NOT_FOUND");

      const payload = {
        category: currentItem.category ?? null,
        account: fields.account || null,
        password: fields.password || null,
        backup_email: fields.backup_email || null,
        two_fa: fields.two_fa || null,
        note: fields.note || null,
        status: currentItem.status ?? null,
        expires_at: fields.expires_at?.trim() || null,
        is_verified: currentItem.is_verified ?? false,
      };

      const response = await apiFetch(`${API_ENDPOINTS.WAREHOUSE}/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      if (!response.ok) throw new Error(`HTTP ${response.status}`);

      const updated = (await response.json()) as WarehouseItem;
      setWarehouseItems((prev) =>
        prev.map((item) =>
          normalizeWarehouseId(item.id) === targetId
            ? { ...item, ...updated }
            : item
        )
      );
    },
    [warehouseItems]
  );

  const handleChange = useCallback(
    (
      field: keyof PackageFormValues,
      event: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
    ) => {
      const value = event.target.value;
      if (field === "import") {
        setValues((prev) => ({ ...prev, import: formatImportValue(value) }));
        return;
      }

      setValues((prev) => ({ ...prev, [field]: value }));
    },
    [formatImportValue]
  );

  const handleSelectStock = useCallback((item: WarehouseItem) => {
    setValues((prev) => ({
      ...prev,
      stockId: item.id ?? null,
    }));
    setStockDropdownOpen(false);
    setStockSearch("");
  }, []);

  const handleClearStock = useCallback(() => {
    setValues((prev) => ({ ...prev, stockId: null }));
  }, []);

  const handleToggleStockManual = useCallback(() => {
    setStockManual((prev) => !prev);
    setStockDropdownOpen(false);
    if (!stockManual) {
      setValues((prev) => ({
        ...prev,
        stockId: null,
        manualStock: { ...EMPTY_MANUAL_ENTRY },
      }));
    }
  }, [stockManual]);

  const handleSelectStorage = useCallback((item: WarehouseItem) => {
    setValues((prev) => ({ ...prev, storageId: item.id ?? null }));
    setStorageDropdownOpen(false);
    setStorageSearch("");
  }, []);

  const handleClearStorage = useCallback(() => {
    setValues((prev) => ({ ...prev, storageId: null }));
  }, []);

  const handleToggleStorageManual = useCallback(() => {
    setStorageManual((prev) => !prev);
    setStorageDropdownOpen(false);
    if (!storageManual) {
      setValues((prev) => ({
        ...prev,
        storageId: null,
        manualStorage: { ...EMPTY_MANUAL_ENTRY },
      }));
    }
  }, [storageManual]);

  const matchRequiresAccountError =
    (values.slotLinkMode === "slot" || values.slotLinkMode === "information") &&
    !values.stockId &&
    !stockManual
      ? "Cần chọn tài khoản gốc (kho) để gán gói."
      : null;

  // Khớp với mutation: có storageId hoặc account nhập tay (POST kho khi submit). Không phụ thuộc cờ storageManual để tránh lệch validation vs dữ liệu gửi đi.
  const hasActivation =
    values.storageId != null ||
    Boolean(values.manualStorage?.account?.trim());

  const matchRequiresActivationError =
    values.slotLinkMode === "information" &&
    requireActivationForInformation &&
    !hasActivation
      ? "Chế độ theo thông tin đơn cần chọn tài khoản kích hoạt (kho kích hoạt)."
      : null;

  const handleSubmit = useCallback(
    (event: React.FormEvent) => {
      event.preventDefault();
      if (matchRequiresAccountError) return;
      if (matchRequiresActivationError) return;
      onSubmit(values);
    },
    [
      matchRequiresAccountError,
      matchRequiresActivationError,
      onSubmit,
      values,
    ]
  );

  const handleSlotLinkModeChange = useCallback((mode: SlotLinkMode) => {
    setValues((prev) => ({ ...prev, slotLinkMode: mode }));
  }, []);

  return {
    values,
    setValues,
    warehouseLoading,
    inStockItemsCount: inStockItems.length,
    stockDropdownOpen,
    setStockDropdownOpen,
    stockSearch,
    setStockSearch,
    stockManual,
    stockRef,
    storageDropdownOpen,
    setStorageDropdownOpen,
    storageSearch,
    setStorageSearch,
    storageManual,
    storageRef,
    filteredStockItems,
    filteredStorageItems,
    selectedStockItem,
    selectedStorageItem,
    handleUpdateWarehouseInfo,
    handleChange,
    handleSelectStock,
    handleClearStock,
    handleToggleStockManual,
    handleSelectStorage,
    handleClearStorage,
    handleToggleStorageManual,
    matchRequiresAccountError,
    matchRequiresActivationError,
    handleSubmit,
    handleSlotLinkModeChange,
  };
};

/**
 * PackageCard Component
 * Mobile-friendly card view for package products
 */

import React from "react";
import { EyeIcon, PencilIcon, TrashIcon, BoltIcon } from "@heroicons/react/24/outline";
import {
  AugmentedRow,
  DEFAULT_CAPACITY_LIMIT,
  DEFAULT_SLOT_LIMIT,
  formatCapacityLabel,
  formatDisplayDate,
  getCapacityAvailabilityState,
  getSlotAvailabilityState,
} from "../utils/packageHelpers";

type PackageCardProps = {
  row: AugmentedRow;
  showCapacityColumn: boolean;
  onEdit: (row: AugmentedRow) => void;
  onView: (row: AugmentedRow) => void;
  onDelete: (row: AugmentedRow) => void;
};

export const PackageCard: React.FC<PackageCardProps> = ({
  row,
  showCapacityColumn,
  onEdit,
  onView,
  onDelete,
}) => {
  const totalSlots = row.slotLimit || DEFAULT_SLOT_LIMIT;
  const slotUsed = row.slotUsed;
  const remainingSlots = row.remainingSlots;
  const slotUsedFillRatio =
    totalSlots > 0
      ? Math.min((Math.min(slotUsed, totalSlots) / totalSlots) * 100, 100)
      : 0;
  const slotState = getSlotAvailabilityState(remainingSlots);
  const slotColorClass =
    slotState === "out" ? "bg-red-500" : slotState === "low" ? "bg-yellow-500" : "bg-green-500";
  const slotGlowClass =
    slotState === "out" ? "bg-red-500" : slotState === "low" ? "bg-amber-500" : "bg-emerald-500";

  const showRowCapacity = showCapacityColumn && !!row.hasCapacityField;
  const capacityLimit = row.capacityLimit || DEFAULT_CAPACITY_LIMIT;
  const capacityUsed = row.capacityUsed;
  const remainingCapacity = row.remainingCapacity;
  const capacityUsedFillRatio =
    capacityLimit > 0
      ? Math.min(
          (Math.min(capacityUsed, capacityLimit) / capacityLimit) * 100,
          100
        )
      : 0;
  const capState = getCapacityAvailabilityState(remainingCapacity, capacityLimit);
  const capColorClass =
    capState === "out" ? "bg-red-500" : capState === "low" ? "bg-yellow-500" : "bg-green-500";

  return (
    <div className="package-card relative group overflow-hidden glass-panel rounded-[24px] p-4 transition-all duration-500 hover:border-indigo-500/40 shadow-2xl border border-white/10 bg-slate-900/40 backdrop-blur-xl hover:bg-slate-900/50">
      {/* Glow effect */}
      <div className={`absolute -right-10 -top-10 w-28 h-28 rounded-full blur-3xl opacity-10 transition-all duration-700 group-hover:opacity-20 ${slotGlowClass}`} />

      <div className="relative z-10 flex flex-col gap-3">
        {/* Header: Package name + tags */}
        <div className="flex flex-col gap-2">
          <div className="flex items-center gap-2">
            <span className="w-1.5 h-1.5 rounded-full bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.8)]" />
            <h3 className="text-[12px] sm:text-sm font-bold text-white tracking-widest uppercase truncate leading-none">
              {row.package || "--"}
            </h3>
          </div>

          <div className="flex items-center flex-wrap gap-2">
            {row.informationUser && (
              <div className="inline-flex px-2.5 py-1 rounded-lg bg-indigo-500/10 border border-indigo-500/20 backdrop-blur-md min-w-0">
                <p className="text-[10px] sm:text-[11px] font-bold text-indigo-300 uppercase tracking-wide truncate max-w-[200px]">
                  {row.informationUser}
                </p>
              </div>
            )}
            {row.supplier && (
              <div className="inline-flex px-2.5 py-1 rounded-lg bg-purple-500/10 border border-purple-500/20 backdrop-blur-md min-w-0">
                <p className="text-[10px] sm:text-[11px] font-bold text-purple-300 uppercase tracking-wide truncate max-w-[120px]">
                  NCC: {row.supplier}
                </p>
              </div>
            )}
          </div>
        </div>

        {/* Slot + Capacity info */}
        <div className="flex items-stretch gap-3">
          {/* Slot info */}
          <div className="flex-1 p-3 rounded-2xl bg-white/5 border border-white/5">
            <div className="flex items-center justify-between mb-2">
              <span className="text-[9px] font-black text-white/30 uppercase tracking-[0.2em]">Vị trí</span>
              <span className="text-xs font-bold text-white whitespace-nowrap">
                <span className="text-indigo-400">{slotUsed}</span>
                <span className="text-white/20 mx-0.5">/</span>
                {totalSlots}
              </span>
            </div>
            <div className="w-full bg-white/5 rounded-full h-1.5 overflow-hidden border border-white/5">
              <div
                className={`h-full rounded-full transition-all duration-500 ${slotColorClass} shadow-[0_0_8px_rgba(34,197,94,0.4)]`}
                style={{ width: `${slotUsedFillRatio}%` }}
              />
            </div>
            <p className="text-[10px] font-bold uppercase tracking-wider text-white/40 mt-1.5 whitespace-nowrap">
              Trống: {remainingSlots}
            </p>
          </div>

          {/* Capacity info (if applicable) */}
          {showRowCapacity && (
            <div className="flex-1 p-3 rounded-2xl bg-white/5 border border-white/5">
              <div className="flex items-center justify-between mb-2">
                <span className="text-[9px] font-black text-white/30 uppercase tracking-[0.2em]">Dung lượng</span>
                <span className="text-xs font-bold text-white whitespace-nowrap">
                  <span className="text-purple-400">{capacityUsed}</span>
                  <span className="text-white/20 mx-0.5">/</span>
                  {capacityLimit} GB
                </span>
              </div>
              <div className="w-full bg-white/5 rounded-full h-1.5 overflow-hidden border border-white/5">
                <div
                  className={`h-full rounded-full transition-all duration-500 ${capColorClass} shadow-[0_0_8px_rgba(168,85,247,0.4)]`}
                  style={{ width: `${capacityUsedFillRatio}%` }}
                />
              </div>
              <p className="text-[10px] font-bold uppercase tracking-wider text-white/30 mt-1.5 whitespace-nowrap">
                Trống: {remainingCapacity} GB
              </p>
            </div>
          )}
        </div>

        {/* Price + Expiry info */}
        <div className="flex items-center justify-between gap-4 p-3 rounded-2xl bg-white/5 border border-white/5 backdrop-blur-sm">
          <div className="flex flex-col min-w-0">
            <span className="text-[9px] font-black text-white/30 uppercase tracking-[0.2em] mb-1">Giá nhập</span>
            <p className="text-sm font-black text-indigo-200 tabular-nums">
              {Number(row.import || 0).toLocaleString("vi-VN")} <span className="text-[10px] text-white/40">VND</span>
            </p>
          </div>
          <div className="flex flex-col items-end shrink-0 pl-4 border-l border-white/10">
            <span className="text-[9px] font-black text-white/30 uppercase tracking-[0.2em] mb-1">Hết hạn</span>
            <p className="text-[11px] font-bold text-slate-300 tabular-nums font-mono">
              {formatDisplayDate(row.expired) || "---"}
            </p>
          </div>
        </div>

        {/* Note (if exists) */}
        {row.note && (
          <div className="px-3 py-2 rounded-xl bg-white/[0.03] border border-white/5">
            <p className="text-[11px] text-white/50 truncate" title={row.note}>
              📝 {row.note}
            </p>
          </div>
        )}

        {/* Action buttons */}
        <div className="flex items-center justify-end gap-2 pt-1">
          <button
            className="w-10 h-10 flex items-center justify-center rounded-xl bg-indigo-500/10 border border-indigo-500/20 text-blue-400 hover:bg-blue-500 hover:text-white transition-all duration-300 hover:shadow-[0_0_15px_rgba(99,102,241,0.3)] active:scale-90"
            onClick={() => onEdit(row)}
            title="Sửa"
          >
            <PencilIcon className="h-5 w-5" />
          </button>
          <button
            className="w-10 h-10 flex items-center justify-center rounded-xl bg-purple-500/10 border border-purple-500/20 text-purple-400 hover:bg-purple-500 hover:text-white transition-all duration-300 hover:shadow-[0_0_15px_rgba(168,85,247,0.3)] active:scale-90"
            onClick={() => onView(row)}
            title="Xem"
          >
            <EyeIcon className="h-5 w-5" />
          </button>
          <button
            className="w-10 h-10 flex items-center justify-center rounded-xl bg-rose-500/10 border border-rose-500/20 text-rose-500/70 hover:bg-rose-500 hover:text-white transition-all duration-300 hover:shadow-[0_0_15px_rgba(244,63,94,0.3)] active:scale-90"
            onClick={() => onDelete(row)}
            title="Xóa"
          >
            <TrashIcon className="h-5 w-5" />
          </button>
        </div>
      </div>
    </div>
  );
};

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { apiFetch } from "@/lib/api";
import {
  AugmentedRow,
  OrderListItem,
  PACKAGE_FIELD_OPTIONS,
  PackageField,
  PackageRow,
  PackageTemplate,
  SlotLinkMode,
  SlotLinkPreferenceMap,
  StatusFilter,
  NormalizedOrderRecord,
  buildIdentifierKeys,
  enhancePackageRow,
  getSlotAvailabilityState,
  normalizeMatchKey,
  normalizeProductCodeValue,
  normalizeSlotKey,
  toCleanString,
  readSlotLinkPrefs,
  writeSlotLinkPrefs,
  syncActivationFieldInTemplateFields,
} from "../utils/packageHelpers";
import { computeAugmentationForPackage } from "../utils/packageMatchUtils";
import { onRefresh } from "@/lib/refreshBus";

type UsePackageDataResult = {
  data: {
    rows: PackageRow[];
    templates: PackageTemplate[];
    computedRows: AugmentedRow[];
    filteredRows: AugmentedRow[];
    sortedRows: AugmentedRow[];
    scopedRows: AugmentedRow[];
    selectedPackage: string | null;
    selectedTemplate: PackageTemplate | null;
    packageSummaries: Array<{
      name: string;
      total: number;
      low: number;
      out: number;
    }>;
    slotStats: {
      total: number;
      low: number;
      out: number;
    };
    showCapacityColumn: boolean;
    tableColumnCount: number;
    loading: boolean;
    packagesLoading: boolean;
    ordersLoading: boolean;
    ordersReady: boolean;
    defaultTemplateFields: PackageField[];
  };
  filters: {
    searchTerm: string;
    categoryFilter: string;
    statusFilter: StatusFilter;
  };
  actions: {
    setSearchTerm: React.Dispatch<React.SetStateAction<string>>;
    setCategoryFilter: React.Dispatch<React.SetStateAction<string>>;
    setStatusFilter: React.Dispatch<React.SetStateAction<StatusFilter>>;
    setRows: React.Dispatch<React.SetStateAction<PackageRow[]>>;
    setTemplates: React.Dispatch<React.SetStateAction<PackageTemplate[]>>;
    persistSlotLinkPreference: (id: number | string, mode: SlotLinkMode) => void;
    applySlotLinkPrefs: (row: PackageRow) => PackageRow;
  };
};

export const usePackageData = (): UsePackageDataResult => {
  const [searchTerm, setSearchTerm] = useState("");
  const [categoryFilter, setCategoryFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState<StatusFilter>("all");
  const [rows, setRows] = useState<PackageRow[]>([]);
  const [orders, setOrders] = useState<OrderListItem[]>([]);
  const [templates, setTemplates] = useState<PackageTemplate[]>([]);
  const [packagesLoading, setPackagesLoading] = useState(true);
  const [ordersLoading, setOrdersLoading] = useState(true);
  const [ordersReady, setOrdersReady] = useState(false);
  const [slotLinkPrefs, setSlotLinkPrefs] = useState<SlotLinkPreferenceMap>(
    () => readSlotLinkPrefs()
  );
  const slotLinkPrefsRef = useRef(slotLinkPrefs);
  const isMountedRef = useRef(true);
  const defaultTemplateFields = useMemo(
    () => PACKAGE_FIELD_OPTIONS.map((opt) => opt.value),
    []
  );

  useEffect(() => {
    slotLinkPrefsRef.current = slotLinkPrefs;
  }, [slotLinkPrefs]);

  useEffect(() => {
    return () => {
      isMountedRef.current = false;
    };
  }, []);

  const persistSlotLinkPreference = useCallback(
    (id: number | string, mode: SlotLinkMode) => {
      const key = String(id);
      setSlotLinkPrefs((prev) => {
        if (prev[key] === mode) return prev;
        const next = { ...prev, [key]: mode };
        writeSlotLinkPrefs(next);
        return next;
      });
    },
    []
  );

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        setPackagesLoading(true);
        const res = await apiFetch(`/api/package-products`);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = (await res.json()) as PackageRow[];
        if (!cancelled) {
          if (Array.isArray(data)) {
            const normalizedRows = data.map((row) =>
              enhancePackageRow(row, slotLinkPrefsRef.current)
            );
            setRows(normalizedRows);
          } else {
            setRows([]);
          }
        }
      } catch (error) {
        console.error("Tải sản phẩm gói thất bại:", error);
        if (!cancelled) {
          const { handleNetworkError } = await import("@/lib/errorHandler");
          console.error(handleNetworkError(error));
          setRows([]);
        }
      } finally {
        if (!cancelled) {
          setPackagesLoading(false);
        }
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        setOrdersLoading(true);
        setOrdersReady(false);
        const res = await apiFetch(
          `/api/orders?scope=package_match`
        );
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = (await res.json()) as OrderListItem[];
        if (!cancelled) {
          if (Array.isArray(data)) {
            setOrders(data);
          } else {
            setOrders([]);
          }
          setOrdersReady(true);
        }
      } catch (error) {
        console.error("Tải danh sách đơn hàng thất bại:", error);
        if (!cancelled) {
          setOrders([]);
          setOrdersReady(false);
        }
      } finally {
        if (!cancelled) {
          setOrdersLoading(false);
        }
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const refreshOrders = useCallback(async () => {
    if (!isMountedRef.current) return;
    setOrdersLoading(true);
    setOrdersReady(false);
    try {
      const res = await apiFetch(`/api/orders?scope=package_match`);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = (await res.json()) as OrderListItem[];
      if (!isMountedRef.current) return;
      if (Array.isArray(data)) {
        setOrders(data);
      } else {
        setOrders([]);
      }
      setOrdersReady(true);
    } catch (error) {
      console.error("Failed to refresh orders for packages:", error);
      if (isMountedRef.current) {
        setOrders([]);
        setOrdersReady(false);
      }
    } finally {
      if (isMountedRef.current) {
        setOrdersLoading(false);
      }
    }
  }, []);

  useEffect(
    () => onRefresh(["orders"], () => void refreshOrders()),
    [refreshOrders]
  );

  const packageNames = useMemo(
    () => Array.from(new Set(rows.map((row) => row.package))).sort(),
    [rows]
  );

  useEffect(() => {
    setTemplates((prev) => {
      const map = new Map(prev.map((tpl) => [tpl.name, tpl]));
      let changed = false;
      packageNames.forEach((name) => {
        if (!name) return;
        const firstRow = rows.find((row) => row.package === name);
        const productId = firstRow?.productId ?? null;
        const serverActivation = firstRow?.productRequiresActivation === true;
        const existing = map.get(name);
        if (!existing) {
          map.set(name, {
            name,
            productId,
            fields: syncActivationFieldInTemplateFields(
              defaultTemplateFields,
              serverActivation
            ),
            isCustom: false,
          });
          changed = true;
          return;
        }
        const baseFields =
          existing.fields && existing.fields.length > 0
            ? existing.fields
            : defaultTemplateFields;
        const mergedFields = syncActivationFieldInTemplateFields(
          baseFields,
          serverActivation
        );
        const prevFields =
          existing.fields && existing.fields.length > 0
            ? existing.fields
            : defaultTemplateFields;
        const fieldsEqual =
          mergedFields.length === prevFields.length &&
          mergedFields.every((f, i) => f === prevFields[i]);

        if (!fieldsEqual) {
          map.set(name, {
            ...existing,
            fields: mergedFields,
            productId: existing.productId ?? productId,
          });
          changed = true;
          return;
        }
        if (
          existing.isCustom !== true &&
          existing.productId == null &&
          productId != null
        ) {
          map.set(name, { ...existing, productId });
          changed = true;
        }
      });
      if (!changed) return prev;
      return Array.from(map.values()).sort((a, b) =>
        a.name.localeCompare(b.name)
      );
    });
  }, [packageNames, rows, defaultTemplateFields]);

  const orderMatchers = useMemo<NormalizedOrderRecord[]>(() => {
    return orders.map((order) => {
      const o = order as Record<string, unknown>;
      const idProduct =
        (order.id_product ?? order.idProduct ?? "") as string;
      const informationOrder =
        (order.information_order ?? order.informationOrder ?? "") as string;
      const slot = order.slot;
      const rawLinePid =
        o.line_product_id ?? o.lineProductId;
      const n =
        rawLinePid != null && rawLinePid !== "" ? Number(rawLinePid) : NaN;
      const lineProductId = Number.isFinite(n) && n > 0 ? n : null;
      const productKeys = buildIdentifierKeys(idProduct);
      const infoKeys = buildIdentifierKeys(informationOrder);
      return {
        base: order,
        productKey: productKeys.normalized,
        productLettersKey: productKeys.lettersOnly,
        infoKey: infoKeys.normalized,
        infoLettersKey: infoKeys.lettersOnly,
        slotDisplay: toCleanString(slot),
        slotKey: normalizeSlotKey(slot),
        slotMatchKey: normalizeMatchKey(slot),
        informationDisplay: toCleanString(informationOrder),
        informationKey: normalizeSlotKey(informationOrder),
        informationMatchKey: normalizeMatchKey(informationOrder),
        customerDisplay: toCleanString(order.customer as string | null),
        productCodeNormalized: normalizeProductCodeValue(idProduct),
        lineProductId:
          lineProductId != null && Number.isFinite(lineProductId)
            ? lineProductId
            : null,
      };
    });
  }, [orders]);

  const ordersByProductCode = useMemo(() => {
    const map = new Map<string, NormalizedOrderRecord[]>();
    orderMatchers.forEach((record) => {
      if (!record.productCodeNormalized) return;
      const key = record.productCodeNormalized;
      if (!map.has(key)) {
        map.set(key, []);
      }
      map.get(key)!.push(record);
    });
    return map;
  }, [orderMatchers]);

  const computedRows: AugmentedRow[] = useMemo(
    () =>
      rows.map((item) => ({
        ...item,
        ...computeAugmentationForPackage({
          item,
          orderMatchers,
          ordersByProductCode,
          ordersReady,
        }),
      })),
    [rows, orderMatchers, ordersReady, ordersByProductCode]
  );

  const selectedPackage = categoryFilter !== "all" ? categoryFilter : null;
  const selectedTemplate = useMemo(
    () =>
      selectedPackage
        ? templates.find((tpl) => tpl.name === selectedPackage) ?? null
        : null,
    [templates, selectedPackage]
  );
  const scopedRows = useMemo(
    () =>
      selectedPackage
        ? computedRows.filter((row) => row.package === selectedPackage)
        : computedRows,
    [computedRows, selectedPackage]
  );
  const filteredRows = useMemo(
    () =>
      scopedRows.filter((item) => {
        const term = searchTerm.trim().toLowerCase();
        const infoFields = [
          item.information,
          item.informationUser,
          item.informationMail,
          item.informationPass,
          item.accountUser,
          item.accountMail,
          item.accountPass,
          item.note,
        ];
        const matchesSearch =
          term.length === 0 ||
          infoFields.some((field) => {
            const normalizedValue =
              field === null || field === undefined ? "" : String(field);
            return normalizedValue.toLowerCase().includes(term);
          });
        const matchesCategory =
          categoryFilter === "all" || item.package === categoryFilter;
        const slotState = getSlotAvailabilityState(item.remainingSlots);
        const matchesStatus =
          statusFilter === "all" ||
          (statusFilter === "full" && slotState === "ok") ||
          statusFilter === slotState;
        return matchesSearch && matchesCategory && matchesStatus;
      }),
    [scopedRows, searchTerm, categoryFilter, statusFilter]
  );
  const sortedRows = useMemo(
    () =>
      [...filteredRows].sort((a, b) => {
        const rawA = Number(a.remainingSlots);
        const rawB = Number(b.remainingSlots);
        const slotsA = Number.isFinite(rawA) ? rawA : Number.POSITIVE_INFINITY;
        const slotsB = Number.isFinite(rawB) ? rawB : Number.POSITIVE_INFINITY;
        const normA = slotsA <= 0 ? Number.POSITIVE_INFINITY : slotsA;
        const normB = slotsB <= 0 ? Number.POSITIVE_INFINITY : slotsB;
        if (normA === normB) return 0;
        return normA - normB;
      }),
    [filteredRows]
  );

  const hasCapacityRows = filteredRows.some(
    (row) => row.hasCapacityField ?? false
  );
  const showCapacityColumn =
    hasCapacityRows ||
    (filteredRows.length === 0 &&
      (selectedTemplate?.fields.includes("capacity") ?? false));
  const tableColumnCount = showCapacityColumn ? 9 : 8;

  /** Thống kê cùng phạm vi với bảng: loại gói + tìm kiếm + lọc trạng thái (tránh lệch «Tổng: 1» với 3 dòng bảng). */
  const slotStats = useMemo(() => {
    const low = filteredRows.reduce(
      (total, row) =>
        getSlotAvailabilityState(row.remainingSlots) === "low"
          ? total + 1
          : total,
      0
    );
    const out = filteredRows.reduce(
      (total, row) =>
        getSlotAvailabilityState(row.remainingSlots) === "out"
          ? total + 1
          : total,
      0
    );
    return {
      total: filteredRows.length,
      low,
      out,
    };
  }, [filteredRows]);

  const allPackageNames = useMemo(() => {
    const names = new Set<string>();
    computedRows.forEach((row) => {
      const trimmed = (row.package || "").trim();
      if (trimmed) names.add(trimmed);
    });
    templates.forEach((tpl) => {
      if (tpl.name) names.add(tpl.name);
    });
    return Array.from(names).sort((a, b) => a.localeCompare(b));
  }, [computedRows, templates]);

  const packageSummaries = useMemo(() => {
    const stats = new Map<
      string,
      { total: number; low: number; out: number }
    >();
    allPackageNames.forEach((name) =>
      stats.set(name, { total: 0, low: 0, out: 0 })
    );
    computedRows.forEach((row) => {
      const key = (row.package || "").trim();
      if (!key) return;
      let entry = stats.get(key);
      if (!entry) {
        entry = { total: 0, low: 0, out: 0 };
        stats.set(key, entry);
      }
      entry.total += 1;
      const availability = getSlotAvailabilityState(row.remainingSlots);
      if (availability === "low") entry.low += 1;
      if (availability === "out") entry.out += 1;
    });
    return allPackageNames.map((name) => ({
      name,
      ...(stats.get(name) ?? { total: 0, low: 0, out: 0 }),
    }));
  }, [allPackageNames, computedRows]);

  const applySlotLinkPrefs = useCallback(
    (row: PackageRow) => enhancePackageRow(row, slotLinkPrefsRef.current),
    []
  );

  return {
    data: {
      rows,
      templates,
      computedRows,
      filteredRows,
      sortedRows,
      scopedRows,
      selectedPackage,
      selectedTemplate,
      packageSummaries,
      slotStats,
      showCapacityColumn,
      tableColumnCount,
      loading: packagesLoading || ordersLoading,
      packagesLoading,
      ordersLoading,
      ordersReady,
      defaultTemplateFields,
    },
    filters: {
      searchTerm,
      categoryFilter,
      statusFilter,
    },
    actions: {
      setSearchTerm,
      setCategoryFilter,
      setStatusFilter,
      setRows,
      setTemplates,
      persistSlotLinkPreference,
      applySlotLinkPrefs,
    },
  };
};

import { ORDER_COLS } from "@/lib/tableSql";
import * as Helpers from "@/lib/helpers";

export type PackageField =
  | "supplier"
