export const PACKAGE_FIELD_OPTIONS: Array<{ value: PackageField; label: string }> =
  [
    { value: "supplier", label: "Nhà cung cấp" },
    { value: "import", label: "Giá nhập (VND)" },
    { value: "activation", label: "Tài khoản kích hoạt" },
  ];

/** Đồng bộ cờ activation trong `fields` template với DB (`productRequiresActivation`). */
export function syncActivationFieldInTemplateFields(
  fields: PackageField[],
  serverRequiresActivation: boolean
): PackageField[] {
  const set = new Set(fields);
  if (serverRequiresActivation) set.add("activation");
  else set.delete("activation");
  return PACKAGE_FIELD_OPTIONS.map((o) => o.value).filter((v) => set.has(v));
}

export const DEFAULT_SLOT_LIMIT = 5;
export const DEFAULT_CAPACITY_LIMIT = 2000;
export const DEFAULT_SLOT_CAPACITY_UNIT = 100;
export const LOW_THRESHOLD_RATIO = 0.2;
export const LOW_SLOT_THRESHOLD = 2;

export const SLOT_LINK_OPTIONS: Array<{
  value: SlotLinkMode;
  label: string;
  helper: string;
}> = [
  {
    value: "information",
    label: "Liên kết theo thông tin đơn hàng",
    helper:
      "So cột information_order với username kho lưu trữ (kích hoạt) hoặc kho gói chính (cùng cột «Thông tin gói»); nhãn vị trí lấy từ cột slot trên đơn.",
  },
  {
    value: "slot",
    label: "Liên kết theo vị trí",
    helper:
      "So username tài khoản gốc (kho chính) với cột slot trên đơn; nội dung hiển thị bổ sung từ information_order khi cần.",
  },
];

export type StatusFilter = "all" | "full" | "low" | "out";

export const STATUS_FILTERS: Array<{ value: StatusFilter; label: string }> = [
  { value: "all", label: "Tất cả trạng thái" },
  { value: "full", label: "Còn nhiều" },
  { value: "low", label: "Sắp hết" },
  { value: "out", label: "Đã hết" },
];

export const MATCH_COLUMN_INFORMATION = ORDER_COLS.informationOrder;
export const MATCH_COLUMN_SLOT = ORDER_COLS.slot;

export const SLOT_LINK_PREFS_KEY = "package_slot_link_prefs";

export const getCapacityAvailabilityState = (
  remaining: number,
  limit: number
): AvailabilityState => {
  if (limit <= 0) return "out";
  if (remaining <= 0) return "out";
  const ratio = remaining / limit;
  return ratio <= LOW_THRESHOLD_RATIO ? "low" : "ok";
};

export const getSlotAvailabilityState = (remaining: number): AvailabilityState => {
  if (remaining <= 0) return "out";
  if (remaining < LOW_SLOT_THRESHOLD) return "low";
  return "ok";
};

export const normalizeIdentifier = (value: string | null | undefined): string => {
  return (value || "").toLowerCase().replace(/[^a-z0-9]/g, "");
};

export const buildIdentifierKeys = (value: string | null | undefined) => {
  const normalized = normalizeIdentifier(value);
  return {
    normalized,
    lettersOnly: normalized.replace(/[0-9]/g, ""),
  };
};

export const toCleanString = (value: unknown): string => {
  if (value === null || value === undefined) return "";
  const str = typeof value === "string" ? value : String(value);
  return str.trim();
};

export const formatDisplayDate = (value?: string | null): string => {
  const normalized = Helpers.formatDateToDMY(value ?? "");
  if (normalized) return normalized;

  const trimmed = (value || "").trim();
  if (!trimmed) return "";

  // Accept flexible D/M/YYYY (with or without leading zero) and normalize.
  const looseMatch = trimmed.match(/^(\d{1,2})[/-](\d{1,2})[/-](\d{4})$/);
  if (looseMatch) {
    const [, d, m, y] = looseMatch;
    return `${String(d).padStart(2, "0")}/${String(m).padStart(2, "0")}/${y}`;
  }

  return trimmed;
};

export const normalizeSlotKey = (value: unknown): string => {
  const cleaned = toCleanString(value);
  return cleaned ? cleaned.replace(/\s+/g, " ").trim().toLowerCase() : "";
};

export const normalizeMatchKey = (value: string | null | undefined): string => {
  const trimmed = toCleanString(value);
  return trimmed ? trimmed.toLowerCase().replace(/\s+/g, "") : "";
};

/**
 * Một chuỗi duy nhất tùy chế độ ghép:
 * - `slot` (theo vị trí): **tài khoản gốc** `informationUser` ↔ cột `slot` trên đơn.
 * - `information` (theo thông tin đơn): cột `information_order` trên đơn so với tài khoản kho lưu trữ
 *   `accountUser` (nếu có) **và** tài khoản kho gói chính `informationUser` (cùng cột «Thông tin gói» trên bảng).
 *   Cả hai nguồn để tránh mất match khi chỉ một trong hai dòng kho có username.
 */
export const buildPackageLinkKeys = (
  row: PackageRow,
  mode: SlotLinkMode = "information"
): string[] => {
  if (mode === "slot") {
    const n = normalizeMatchKey(row.informationUser);
    return n ? [n] : [];
  }
  const keys = new Set<string>();
  const a = normalizeMatchKey(row.accountUser);
  const u = normalizeMatchKey(row.informationUser);
  if (a) keys.add(a);
  if (u) keys.add(u);
  return Array.from(keys);
};

export const resolveOrderDisplayValue = (
  record: NormalizedOrderRecord,
  column: "slot" | "information"
): string => {
  if (column === "slot") {
    return (
      record.slotDisplay ||
      record.customerDisplay ||
      record.informationDisplay ||
      ""
    );
  }
  return (
    record.informationDisplay ||
    record.customerDisplay ||
    record.slotDisplay ||
    ""
  );
};

export const buildSlotLabelVariants = (
  record: NormalizedOrderRecord,
  displayColumn: "slot" | "information",
  fallbackLabel: string
): string[] => {
  const cleanedFallback = toCleanString(fallbackLabel);
  if (displayColumn !== "slot") {
    return cleanedFallback ? [cleanedFallback] : [];
  }
  const rawSlotText = record.slotDisplay ?? "";
  const slotPieces = rawSlotText
    .split("|")
    .map((piece) => toCleanString(piece))
    .filter(Boolean);
  if (slotPieces.length >= 1) {
    return slotPieces;
  }
  const customerLabel = toCleanString(record.customerDisplay);
  if (customerLabel) {
    return [customerLabel, `${customerLabel} (2)`];
  }
  return cleanedFallback ? [cleanedFallback] : [];
};

const extractDigitsValue = (text: string | null | undefined): number | null => {
  if (!text) return null;
  const match = text.match(/(\d{2,4})/);
  if (!match) return null;
  const value = Number(match[1]);
  return Number.isFinite(value) ? value : null;
};

export const extractCapacityUnitsFromOrder = (
  packageCode: string,
  record: NormalizedOrderRecord
): number | null => {
  const normalizedProduct = record.productKey;
  let remainder = normalizedProduct;
  if (packageCode) {
    const idx = remainder.indexOf(packageCode);
    if (idx >= 0) {
      remainder = remainder.slice(idx + packageCode.length);
    }
  }
  const normalizedValue = extractDigitsValue(remainder);
  if (normalizedValue) return normalizedValue;
  const fallbackNormalized = normalizeIdentifier(record.base?.id_product ?? "");
  return extractDigitsValue(fallbackNormalized);
};

export const formatCapacityLabel = (units?: number | null): string => {
  const value =
    units && Number.isFinite(units) && units > 0
      ? Math.round(units)
      : DEFAULT_SLOT_CAPACITY_UNIT;
  return `${value} GB`;
};

/** Giá trị cột `match` trên DB: `slot` | `information_order` (bỏ qua hoa thường, khoảng trắng). */
export const normalizeMatchModeDbValue = (value?: string | null): string | null => {
  const s = (value == null ? "" : String(value)).trim().toLowerCase();
  if (!s) return null;
  if (s === "slot") return MATCH_COLUMN_SLOT;
  if (s === "information_order" || s === "informationorder" || s === "information")
    return MATCH_COLUMN_INFORMATION;
  return s;
};

export const toSlotLinkModeFromMatch = (value?: string | null): SlotLinkMode => {
  const n = normalizeMatchModeDbValue(value);
  if (n === MATCH_COLUMN_SLOT) return "slot";
  return "information";
};

export const toMatchColumnValue = (mode: SlotLinkMode): string =>
  mode === "slot" ? MATCH_COLUMN_SLOT : MATCH_COLUMN_INFORMATION;

export const normalizeProductCodeValue = (value?: string | null): string => {
  return normalizeIdentifier(value);
};

export const parseNumericValue = (input: unknown): number | null => {
  if (input === null || input === undefined) return null;
  if (typeof input === "number") {
    return Number.isFinite(input) ? input : null;
  }
  if (typeof input === "string") {
    const cleaned = input.replace(/[^0-9]/g, "");
    if (!cleaned) return null;
    const parsed = Number(cleaned);
    return Number.isFinite(parsed) ? parsed : null;
  }
  return null;
};

export const toInputString = (value: unknown): string => {
  if (value === null || value === undefined) return "";
  return typeof value === "string" ? value : String(value);
};

export const buildInformationSummary = (
  user?: string | null,
  pass?: string | null,
  mail?: string | null
): string => {
  return (
    [
      user && `Tài khoản: ${user}`,
      pass && `Mật khẩu: ${pass}`,
      mail && `Mail 2FA: ${mail}`,
    ]
      .filter(Boolean)
      .join(" | ") || ""
  );
};

export const buildFormValuesFromRow = (
  row: PackageRow | AugmentedRow
): PackageFormValues => {
  const slotValue =
    "slotLimit" in row && typeof row.slotLimit === "number"
      ? String(row.slotLimit)
      : toInputString(row.slot);
  return {
    supplier: row.supplier ?? "",
    import: toInputString(row.import),
    slot: slotValue,
    slotLinkMode: row.slotLinkMode ?? "information",
    stockId: row.stockId ?? null,
    storageId: row.storageId ?? null,
    storageTotal: row.storageTotal != null ? String(row.storageTotal) : "",
    manualStock: { ...EMPTY_MANUAL_ENTRY },
    manualStorage: { ...EMPTY_MANUAL_ENTRY },
  };
};

export const readSlotLinkPrefs = (): SlotLinkPreferenceMap => {
  if (typeof window === "undefined") return {};
  try {
    const raw = window.localStorage.getItem(SLOT_LINK_PREFS_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === "object") return parsed;
    return {};
  } catch {
    return {};
  }
};

export const writeSlotLinkPrefs = (prefs: SlotLinkPreferenceMap) => {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(SLOT_LINK_PREFS_KEY, JSON.stringify(prefs));
  } catch {
    /* ignore */
  }
};

export const enhancePackageRow = (
  row: PackageRow,
  slotLinkPrefs: SlotLinkPreferenceMap
) => {
  const normalizedHasCapacity =
    row.hasCapacityField === undefined
      ? row.storageId != null || row.storageTotal != null
      : Boolean(row.hasCapacityField);
  const rRow = row as Record<string, unknown>;
  const matchRaw =
    row.match ?? row.matchModeValue ?? (rRow.package_match as string | null | undefined) ?? null;
  const matchValue =
    matchRaw != null ? normalizeMatchModeDbValue(String(matchRaw)) : null;
  const prefKey =
    row.id !== undefined && row.id !== null
      ? slotLinkPrefs[String(row.id)]
      : undefined;
  const slotLinkMode: SlotLinkMode =
    matchRaw != null && String(matchRaw).trim() !== ""
      ? toSlotLinkModeFromMatch(matchRaw)
      : (row.slotLinkMode as SlotLinkMode | undefined) ??
        (prefKey === "slot" ? "slot" : "information");
  const rawProductId = rRow.productId ?? rRow.product_id;
  const resolvedProductId =
    rawProductId != null && String(rawProductId).trim() !== "" && Number.isFinite(Number(rawProductId))
      ? Number(rawProductId)
      : row.productId ?? null;
  const productCodes = Array.isArray(row.productCodes)
    ? row.productCodes
        .map((code) => (typeof code === "string" ? code.trim() : ""))
        .filter((code) => Boolean(code))
    : [];
  const normalizedProductCodes = Array.from(
    new Set(
      productCodes.map((code) => normalizeProductCodeValue(code)).filter(Boolean)
    )
  );
  return {
    ...row,
    match: matchValue ?? row.match ?? (rRow.package_match as string | null) ?? null,
    productId: resolvedProductId,
    slot: row.slot ?? DEFAULT_SLOT_LIMIT,
    slotUsed: row.slotUsed ?? 0,
    hasCapacityField: normalizedHasCapacity,
    slotLinkMode,
    matchModeValue: matchValue ?? (matchRaw != null ? String(matchRaw).trim() || null : null),
    productCodes,
    normalizedProductCodes,
  } as PackageRow;
};

/**
 * Package–Order match logic (rule: match column chosen at create/edit;
 * compare package account with exactly one order column: slot or information).
 */
import type {
  AugmentedRow,
  NormalizedOrderRecord,
  PackageRow,
  PackageSlotAssignment,
} from "./packageHelpers";
import {
  buildPackageLinkKeys,
  buildSlotLabelVariants,
  DEFAULT_CAPACITY_LIMIT,
  DEFAULT_SLOT_CAPACITY_UNIT,
  DEFAULT_SLOT_LIMIT,
  extractCapacityUnitsFromOrder,
  normalizeIdentifier,
  parseNumericValue,
  resolveOrderDisplayValue,
} from "./packageHelpers";

const buildOrderLookupKey = (
  record: NormalizedOrderRecord,
  fallbackIndex: number
): string => {
  const base = record.base;
  if (base?.id !== undefined && base?.id !== null) return `id:${base.id}`;
  if (base?.id_order !== undefined && base?.id_order !== null)
    return `code:${base.id_order}`;
  return `${record.productKey || record.infoKey}-${fallbackIndex}`;
};

export function collectOrdersByProductCodes(
  codes: Set<string>,
  orderMap: Map<string, NormalizedOrderRecord[]>
): NormalizedOrderRecord[] {
  if (codes.size === 0) return [];
  const collected = new Map<string, NormalizedOrderRecord>();
  codes.forEach((code) => {
    const records = orderMap.get(code);
    if (!records?.length) return;
    records.forEach((record) => {
      const key = buildOrderLookupKey(record, collected.size);
      if (!collected.has(key)) collected.set(key, record);
    });
  });
  return Array.from(collected.values());
}

/** Match column for link: which order column to compare with package account. */
function getMatchColumn(slotMode: "slot" | "information"): "slot" | "information" {
  return slotMode === "information" ? "information" : "slot";
}

/** Display column (opposite of match). */
function getDisplayColumn(slotMode: "slot" | "information"): "slot" | "information" {
  return slotMode === "information" ? "slot" : "information";
}

/**
 * True if order belongs to package by product.
 * Quan hệ: `package_product.package_id` = `product.id`; `order_list.id_product` = `variant.id`;
 * cùng phạm vi khi `variant.product_id` = `package_id` (ưu tiên: lineProductId trên đơn so với item.productId).
 * Còn lại: (1) tập mã variant (normalizedProductCodes) khớp chuỗi id_product hiển thị, hoặc
 * (2) không có tập mã thì tên gói chuẩn hóa = chuỗi id_product.
 * Không dùng prefix / startsWith / includes.
 */
export function orderBelongsToPackageByProduct(
  record: NormalizedOrderRecord,
  item: PackageRow & { normalizedProductCodes?: string[]; package?: string; productId?: number | null }
): boolean {
  const packageProductId = item.productId;
  if (
    packageProductId != null &&
    Number.isFinite(Number(packageProductId)) &&
    record.lineProductId != null &&
    Number.isFinite(record.lineProductId) &&
    Number(packageProductId) === Number(record.lineProductId)
  ) {
    return true;
  }

  const packageCode = normalizeIdentifier(item.package ?? "");
  const normalizedProductCodes = item.normalizedProductCodes ?? [];
  const productCodeSet =
    normalizedProductCodes.length > 0 ? new Set(normalizedProductCodes) : null;

  if (productCodeSet?.size && record.productCodeNormalized && productCodeSet.has(record.productCodeNormalized))
    return true;

  if (!packageCode || !record.productCodeNormalized) return false;
  const belongs = record.productCodeNormalized === packageCode;
  if (belongs) {
    if (import.meta.env.DEV) {
      // eslint-disable-next-line no-console
      console.debug("[PackageMatch] orderBelongsToPackageByProduct", {
        package: item.package,
        packageCode,
        normalizedProductCodes,
        orderId: record.base.id,
        orderCode: record.base.id_order,
        orderProduct: record.base.id_product,
        productCodeNormalized: record.productCodeNormalized,
      });
    }
  }
  return belongs;
}

/**
 * True if order matches package link: theo `slotLinkMode` — tài khoản gốc (slot) hoặc
 * tài khoản kích hoạt (information) so với đúng cột trên đơn.
 */
export function orderMatchesPackageLink(
  record: NormalizedOrderRecord,
  item: PackageRow & { slotLinkMode?: "slot" | "information" }
): boolean {
  const slotMode = item.slotLinkMode ?? "information";
  const packageLinkKeys = buildPackageLinkKeys(item, slotMode);
  if (packageLinkKeys.length === 0) return false;
  const matchColumn = getMatchColumn(slotMode);
  const linkValue =
    matchColumn === "slot" ? record.slotMatchKey : record.informationMatchKey;
  if (!linkValue) return false;
  const matched = packageLinkKeys.some(
    (pkgKey) =>
      pkgKey === linkValue ||
      pkgKey.includes(linkValue) ||
      linkValue.includes(pkgKey)
  );
  // Debug: log detailed comparison when we have keys but không match
  if (import.meta.env.DEV) {
    if (!matched) {
      // eslint-disable-next-line no-console
      console.debug("[PackageMatch] orderMatchesPackageLink: NO MATCH", {
        packageId: item.id,
        packageName: item.package,
        slotLinkMode: slotMode,
        packageLinkKeys,
        matchColumn,
        orderId: record.base.id,
        orderCode: record.base.id_order,
        slotDisplay: record.slotDisplay,
        slotMatchKey: record.slotMatchKey,
        informationDisplay: record.informationDisplay,
        informationMatchKey: record.informationMatchKey,
        customer: record.customerDisplay,
      });
    } else {
      // eslint-disable-next-line no-console
      console.debug("[PackageMatch] orderMatchesPackageLink: MATCH", {
        packageId: item.id,
        packageName: item.package,
        slotLinkMode: slotMode,
        packageLinkKeys,
        matchColumn,
        orderId: record.base.id,
        orderCode: record.base.id_order,
        slotDisplay: record.slotDisplay,
        slotMatchKey: record.slotMatchKey,
        informationDisplay: record.informationDisplay,
        informationMatchKey: record.informationMatchKey,
        customer: record.customerDisplay,
      });
    }
  }
  return matched;
}

export type ComputeAugmentationInput = {
  item: PackageRow & {
    normalizedProductCodes?: string[];
    productCodes?: string[] | null;
    matchModeValue?: string | null;
    match?: string | null;
  };
  orderMatchers: NormalizedOrderRecord[];
  ordersByProductCode: Map<string, NormalizedOrderRecord[]>;
  ordersReady: boolean;
};

/**
 * Computes slotAssignments, slotUsed, capacity, and related fields for one package row.
 */
export function computeAugmentationForPackage(input: ComputeAugmentationInput): Omit<
  AugmentedRow,
  keyof PackageRow
> & { normalizedProductCodes: string[] } {
  const { item, orderMatchers, ordersByProductCode, ordersReady } = input;
  const includeCapacity = Boolean(item.hasCapacityField);
  const slotLimitRaw = parseNumericValue(item.slot);
  const slotLimit =
    slotLimitRaw && slotLimitRaw > 0
      ? Math.floor(slotLimitRaw)
      : DEFAULT_SLOT_LIMIT;
  const slotUsedRaw = parseNumericValue((item as PackageRow).slotUsed);
  const packageCode = normalizeIdentifier(item.package ?? "");
  const slotMode = item.slotLinkMode ?? "information";
  const displayColumn = getDisplayColumn(slotMode);
  const matchColumn = getMatchColumn(slotMode);
  const packageLinkKeys = buildPackageLinkKeys(item, slotMode);
  const hasRootAccountForLink = packageLinkKeys.length > 0;
  const normalizedProductCodes = item.normalizedProductCodes ?? [];
  const productCodeSet =
    normalizedProductCodes.length > 0 ? new Set(normalizedProductCodes) : null;
  // Phải bật match khi có productId dòng gói (dù tên gói/variant rỗng) để nhánh
  // lineProductId = variant.product_id vẫn chạy; trước đây thiếu tên=chuỗi rỗng + không có mã → tắt cả bước.
  const hasProductIdForScope =
    item.productId != null &&
    Number.isFinite(Number(item.productId)) &&
    Number(item.productId) > 0;
  const hasProductScope =
    (productCodeSet != null && productCodeSet.size > 0) ||
    packageCode.length > 0 ||
    hasProductIdForScope;
  const shouldMatchOrders =
    ordersReady && orderMatchers.length > 0 && hasProductScope;

  const matchesProductRecord = (record: NormalizedOrderRecord) =>
    orderBelongsToPackageByProduct(record, { ...item, normalizedProductCodes });
  const matchesLinkRecord = (record: NormalizedOrderRecord) =>
    orderMatchesPackageLink(record, { ...item, slotLinkMode: slotMode });

  const candidateOrders =
    shouldMatchOrders && productCodeSet?.size
      ? collectOrdersByProductCodes(productCodeSet, ordersByProductCode)
      : null;

  const relevantOrders = shouldMatchOrders
    ? (() => {
        const combined = new Map<string, NormalizedOrderRecord>();
        const addOrder = (record: NormalizedOrderRecord) => {
          const key = buildOrderLookupKey(record, combined.size);
          if (!combined.has(key)) combined.set(key, record);
        };
        candidateOrders?.forEach(addOrder);
        orderMatchers.forEach((record) => {
          if (matchesProductRecord(record)) addOrder(record);
        });
        return Array.from(combined.values()).filter(matchesLinkRecord);
      })()
    : [];

  const seenOrderIds = new Set<string>();
  const slotAssignments: PackageSlotAssignment[] = [];
  if (shouldMatchOrders) {
    relevantOrders.forEach((orderRecord) => {
      const displayValue = resolveOrderDisplayValue(orderRecord, displayColumn);
      const matchValueRaw =
        matchColumn === "slot"
          ? orderRecord.slotDisplay
          : orderRecord.informationDisplay;
      const matchValue =
        matchValueRaw || orderRecord.customerDisplay || "";
      const uniqueKey =
        orderRecord.base?.id !== undefined && orderRecord.base?.id !== null
          ? `id:${orderRecord.base.id}`
          : orderRecord.base?.id_order !== undefined &&
              orderRecord.base?.id_order !== null
            ? `code:${orderRecord.base.id_order}`
            : `${matchValue}-${slotAssignments.length}`;
      if (seenOrderIds.has(uniqueKey)) return;
      seenOrderIds.add(uniqueKey);
      const label = displayValue || matchValue;
      const labelVariants = buildSlotLabelVariants(
        orderRecord,
        displayColumn,
        label
      );
      if (labelVariants.length === 0) return;
      const capacityUnits = includeCapacity
        ? extractCapacityUnitsFromOrder(packageCode, orderRecord)
        : null;
      labelVariants.forEach((slotLabel) => {
        const resolvedLabel = slotLabel || label || "";
        if (!resolvedLabel) return;
        slotAssignments.push({
          slotLabel: resolvedLabel,
          matchValue: matchValue || resolvedLabel,
          sourceOrderId: orderRecord.base?.id ?? null,
          sourceOrderCode:
            (orderRecord.base?.id_order as string | number | null) ?? null,
          sourceOrderStartYmd: orderRecord.registrationDateYmd ?? null,
          displayColumn,
          matchColumn,
          capacityUnits,
          customerLabel: orderRecord.customerDisplay
            ? String(orderRecord.customerDisplay).trim() || null
            : null,
        });
      });
    });
  }

  const slotUsageCount =
    slotAssignments.length > 0
      ? slotAssignments.length
      : hasRootAccountForLink && slotUsedRaw !== null
        ? Math.max(Math.floor(slotUsedRaw), 0)
        : 0;
  const slotUsed = Math.min(slotUsageCount, slotLimit);
  const remainingSlots = Math.max(slotLimit - slotUsed, 0);

  let capacityLimit = 0;
  let capacityUsed = 0;
  let remainingCapacity = 0;
  if (includeCapacity) {
    const capacityLimitRaw = parseNumericValue(item.storageTotal);
    capacityLimit =
      capacityLimitRaw && capacityLimitRaw > 0
        ? Math.floor(capacityLimitRaw)
        : DEFAULT_CAPACITY_LIMIT;
    const capacityUsedRaw = parseNumericValue(
      (item as PackageRow).capacityUsed
    );
    const derivedCapacityUnits =
      slotAssignments.length > 0
        ? slotAssignments.reduce(
            (total, assignment) =>
              total +
              (assignment.capacityUnits ?? DEFAULT_SLOT_CAPACITY_UNIT),
            0
          )
        : slotUsageCount * DEFAULT_SLOT_CAPACITY_UNIT;
    const fallbackCapacityUsed = Math.min(derivedCapacityUnits, capacityLimit);
    capacityUsed = Math.min(
      Math.max(
        capacityUsedRaw !== null ? Math.floor(capacityUsedRaw) : fallbackCapacityUsed,
        0
      ),
      capacityLimit
    );
    remainingCapacity = Math.max(capacityLimit - capacityUsed, 0);
  }

  const matchedOrders = shouldMatchOrders
    ? relevantOrders.map((entry) => entry.base)
    : [];

  return {
    slotUsed,
    slotLimit,
    remainingSlots,
    capacityLimit,
    capacityUsed,
    remainingCapacity,
    slotAssignments,
    matchedOrders,
    packageCode,
    hasCapacityField: includeCapacity,
    productCodes: item.productCodes ?? [],
    normalizedProductCodes,
    matchModeValue: item.matchModeValue ?? item.match ?? null,
  };
}

