};

export function mapSupplyPriceResponse(payload: unknown): {
  items: SupplyPriceItem[];
  highestPrice: number | null;
} {
  const mappedItems: SupplyPriceItem[] = Array.isArray(payload)
    ? payload.map((entry: any, index: number) => ({
        sourceId: Number.isFinite(Number(entry?.sourceId ?? entry?.source_id))
          ? Number(entry?.sourceId ?? entry?.source_id)
          : index,
        sourceName:
          entry?.supplier_name?.toString().trim() ||
          entry?.sourceName?.toString().trim() ||
          entry?.source_name?.toString().trim() ||
          `Nhà Cung Cấp #${Number(entry?.sourceId) || index + 1}`,
        price:
          typeof entry?.price === "number" && Number.isFinite(entry.price)
            ? entry.price
            : null,
        lastOrderDate:
          typeof entry?.last_order_date === "string"
            ? entry.last_order_date
            : null,
      }))
    : [];

  const items = sortSupplyItems(dedupeSupplyItems(mappedItems));
  return {
    items,
    highestPrice: computeHighestSupplyPrice(items, null),
  };
}

export function reconcileFetchedProductPrices(
  rows: ProductPricingRow[],
  productKey: string,
  highestPrice: number
) {
  let changed = false;

  const nextRows = rows.map((row) => {
    if (normalizeProductKey(row.sanPhamRaw) !== productKey) return row;

    const hasSameBase =
      typeof row.baseSupplyPrice === "number" &&
      Number.isFinite(row.baseSupplyPrice) &&
      Math.abs(row.baseSupplyPrice - highestPrice) < 0.00001;
    const hasWholesale =
      typeof row.wholesalePrice === "number" &&
      Number.isFinite(row.wholesalePrice) &&
      row.wholesalePrice > 0;
    const hasRetail =
      typeof row.retailPrice === "number" &&
      Number.isFinite(row.retailPrice) &&
      row.retailPrice > 0;
    const hasStudent =
      typeof row.studentPrice === "number" &&
      Number.isFinite(row.studentPrice) &&
      row.studentPrice > 0;
    const promoNeeded = hasValidPromoRatio(
      row.pctPromo,
      row.pctKhach,
      row.pctCtv
    );
    const hasPromo =
      typeof row.promoPrice === "number" &&
      Number.isFinite(row.promoPrice) &&
      row.promoPrice > 0;

    if (hasSameBase && hasWholesale && hasRetail && hasStudent && (!promoNeeded || hasPromo)) {
      return row;
    }

    changed = true;
    return applyBasePriceToProduct(
      { ...row, baseSupplyPrice: highestPrice },
      highestPrice
    );
  });

  return changed ? nextRows : rows;
}

export function createEmptyNewSupplyRow(): NewSupplyRowState {
  return {
    sourceName: "",
    sourceId: null,
    useCustomName: false,
    price: "",
    error: null,
    isSaving: false,
  };
}

export function updateNewSupplyDraft(
  current: NewSupplyRowState,
  field: SupplyDraftField,
  value: string | number | boolean | null
): NewSupplyRowState {
  let nextValue: string | number | boolean | null = value;

  if (field === "price") {
    nextValue = formatVndInput(String(value ?? ""));
  } else if (field === "sourceId") {
    const numericValue = Number(value);
    nextValue =
      value === null ||
      Number.isNaN(numericValue) ||
      !Number.isFinite(numericValue)
        ? null
        : numericValue;
  } else if (field === "useCustomName") {
    nextValue = Boolean(value);
  } else {
    nextValue = String(value ?? "");
  }

  const nextRow: NewSupplyRowState = {
    ...current,
    [field]: nextValue as never,
    error: null,
  };

  if (field === "useCustomName") {
    if (nextValue) {
      nextRow.sourceId = null;
      nextRow.sourceName = "";
    } else if (!nextRow.sourceName && current.sourceName) {
      nextRow.sourceName = current.sourceName;
    }
  }

  return nextRow;
}

export function validateEditedSupplyDraft(
  rawValue: string | undefined
): PriceValidationResult {
  const trimmedValue = rawValue?.toString().trim() ?? "";
  if (!trimmedValue) {
    return {
      ok: false,
      error: "Vui lòng nhập giá hợp lệ.",
    };
  }

  const parsedPrice = Number(trimmedValue.replace(/\D+/g, ""));
  if (!Number.isFinite(parsedPrice) || parsedPrice < 0) {
    return {
      ok: false,
      error: "Giá nhập không được thấp hơn 0.",
    };
  }

  return {
    ok: true,
    parsedPrice,
  };
}

export function validateNewSupplyDraft(
  current: NewSupplyRowState
): NewSupplyValidationResult {
  const trimmedName = current.sourceName.trim();
  const resolvedSourceId =
    current.useCustomName || current.sourceId === null ? null : current.sourceId;
  const parsedPrice = Number((current.price || "").replace(/\D+/g, ""));

  if (!trimmedName) {
    return {
      ok: false,
      error: "Vui lòng chọn hoặc nhập tên nguồn hợp lệ.",
    };
  }

  if (!Number.isFinite(parsedPrice) || parsedPrice <= 0) {
    return {
      ok: false,
      error: "Giá nhập phải lớn hơn 0.",
    };
  }

  return {
    ok: true,
    trimmedName,
    resolvedSourceId,
    parsedPrice,
  };
}

export function buildEditedSupplyState(
  currentState: SupplyPriceState,
  sourceId: number,
  normalizedPrice: number
): SupplyStateMutationResult {
  const previousMax = computeHighestSupplyPrice(currentState.items, null);
  const currentSupplier = currentState.items.find(
    (supplier) => supplier.sourceId === sourceId
  );
  const previousPrice =
    typeof currentSupplier?.price === "number" ? currentSupplier.price : null;
  const wasHighestSupplier =
    typeof previousPrice === "number" &&
    typeof previousMax === "number" &&
    Math.abs(previousPrice - previousMax) < 0.00001;
  const nextItems = sortSupplyItems(
    currentState.items.map((supplier) =>
      supplier.sourceId === sourceId
        ? { ...supplier, price: normalizedPrice }
        : supplier
    )
  );
  const updatedMax = computeHighestSupplyPrice(nextItems, null);
  const priceChanged = previousPrice === null || previousPrice !== normalizedPrice;
  const validUpdatedMax =
    typeof updatedMax === "number" &&
    Number.isFinite(updatedMax) &&
    updatedMax > 0;

  let nextHighestPrice: number | null = null;
  let shouldRecomputeBase = false;

  if (validUpdatedMax) {
    nextHighestPrice = updatedMax;
    if (updatedMax !== previousMax || (wasHighestSupplier && priceChanged)) {
      shouldRecomputeBase = true;
    }
  } else if (wasHighestSupplier && priceChanged) {
    nextHighestPrice = updatedMax ?? null;
    shouldRecomputeBase = true;
  }

  return {
    nextState: {
      ...currentState,
      items: nextItems,
    },
    nextHighestPrice,
    shouldRecomputeBase,
  };
}

export function buildAddedSupplyState(
  currentState: SupplyPriceState | undefined,
  finalSourceId: number,
  trimmedName: string,
  normalizedPrice: number
): SupplyStateMutationResult {
  const currentItems = currentState?.items ?? [];
  const hasExistingRow = currentItems.some(
    (supplier) => supplier.sourceId === finalSourceId
  );
  const nextItems = sortSupplyItems(
    hasExistingRow
      ? currentItems.map((supplier) =>
          supplier.sourceId === finalSourceId
            ? { ...supplier, price: normalizedPrice }
            : supplier
        )
      : [
          ...currentItems,
          {
            sourceId: finalSourceId,
            sourceName: trimmedName,
            price: normalizedPrice,
            lastOrderDate: null,
          },
        ]
  );
  const previousMax = computeHighestSupplyPrice(currentItems, null);
  const updatedMax = computeHighestSupplyPrice(nextItems, null);
  const shouldRecomputeBase =
    typeof previousMax === "number" && typeof updatedMax === "number"
      ? Math.abs(updatedMax - previousMax) > 0.00001
      : previousMax !== updatedMax;

  return {
    nextState: {
      loading: currentState?.loading ?? false,
      error: null,
      items: nextItems,
      productName: currentState?.productName,
    },
    nextHighestPrice: updatedMax,
    shouldRecomputeBase,
  };
}

export function buildDeletedSupplyState(
  currentState: SupplyPriceState,
  sourceId: number
): SupplyStateMutationResult {
  const nextItems = sortSupplyItems(
    currentState.items.filter((supplier) => supplier.sourceId !== sourceId)
  );
  const previousMax = computeHighestSupplyPrice(currentState.items, null);
  const updatedMax = computeHighestSupplyPrice(nextItems, null);
  const shouldRecomputeBase =
    typeof previousMax === "number" && typeof updatedMax === "number"
      ? Math.abs(updatedMax - previousMax) > 0.00001
      : previousMax !== updatedMax;

  return {
    nextState: {
      ...currentState,
      items: nextItems,
    },
    nextHighestPrice: updatedMax,
    shouldRecomputeBase,
  };
}

export function omitStringKey<T>(record: Record<string, T>, key: string) {
  const next = { ...record };
  delete next[key];
  return next;
}

export function omitNumberKey<T>(record: Record<number, T>, key: number) {
  const next = { ...record };
  delete next[key];
  return next;
}

import { useState } from "react";
import type React from "react";
import { apiFetch } from "@/lib/api";
import { API_ENDPOINTS } from "@/constants";
import type { ProductPricingRow, SupplyPriceState } from "../types";
import {
  buildSupplyRowKey,
  formatVndDisplay,
  formatVndInput,
} from "../utils";
import {
  buildDeletedSupplyState,
  buildEditedSupplyState,
  omitStringKey,
  validateEditedSupplyDraft,
} from "./supplyActionHelpers";

interface UseExistingSupplyRowActionsParams {
  setSupplyPriceMap: React.Dispatch<
    React.SetStateAction<Record<string, SupplyPriceState>>
  >;
  fetchSupplyPricesForProduct: (productName: string) => Promise<void>;
  recomputeProductBasePrice: (
    productId: number,
    nextHighestPrice: number | null
  ) => void;
  refreshProductPricing: () => Promise<void>;
}

export function useExistingSupplyRowActions({
  setSupplyPriceMap,
  fetchSupplyPricesForProduct,
  recomputeProductBasePrice,
  refreshProductPricing,
}: UseExistingSupplyRowActionsParams) {
  const [editingSupplyRows, setEditingSupplyRows] = useState<
    Record<string, boolean>
  >({});
  const [supplyPriceDrafts, setSupplyPriceDrafts] = useState<
    Record<string, string>
  >({});
  const [savingSupplyRows, setSavingSupplyRows] = useState<
    Record<string, boolean>
  >({});
  const [supplyRowErrors, setSupplyRowErrors] = useState<
    Record<string, string | null>
  >({});

  const clearSupplyRowState = (rowKey: string) => {
    setEditingSupplyRows((prev) => omitStringKey(prev, rowKey));
    setSupplyPriceDrafts((prev) => omitStringKey(prev, rowKey));
    setSupplyRowErrors((prev) => omitStringKey(prev, rowKey));
  };

  const handleStartEditingSupply = (
    productId: number,
    sourceId: number,
    currentPrice: number | null
  ) => {
    const rowKey = buildSupplyRowKey(productId, sourceId);
    setEditingSupplyRows((prev) => ({ ...prev, [rowKey]: true }));
    setSupplyPriceDrafts((prev) => ({
      ...prev,
      [rowKey]:
        currentPrice === null || currentPrice === undefined
          ? ""
          : formatVndDisplay(currentPrice),
    }));
    setSupplyRowErrors((prev) => ({ ...prev, [rowKey]: null }));
  };

  const handleSupplyInputChange = (
    productId: number,
    sourceId: number,
    nextValue: string
  ) => {
    const rowKey = buildSupplyRowKey(productId, sourceId);
    setSupplyPriceDrafts((prev) => ({
      ...prev,
      [rowKey]: formatVndInput(nextValue),
    }));
    setSupplyRowErrors((prev) => ({ ...prev, [rowKey]: null }));
  };

  const handleCancelSupplyEditing = (productId: number, sourceId: number) => {
    const rowKey = buildSupplyRowKey(productId, sourceId);
    clearSupplyRowState(rowKey);
    setSavingSupplyRows((prev) => omitStringKey(prev, rowKey));
  };

  const handleConfirmSupplyEditing = async (
    productId: number,
    sourceId: number,
    productKey: string,
    productName: string
  ) => {
    const rowKey = buildSupplyRowKey(productId, sourceId);
    const validation = validateEditedSupplyDraft(supplyPriceDrafts[rowKey]);

    if (!validation.ok) {
      setSupplyRowErrors((prev) => ({
        ...prev,
        [rowKey]: validation.error,
      }));
      return;
    }

    setSavingSupplyRows((prev) => ({ ...prev, [rowKey]: true }));

    try {
      const response = await apiFetch(
        API_ENDPOINTS.UPDATE_SUPPLY_PRICE(productId, sourceId),
        {
          method: "PATCH",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({ price: validation.parsedPrice }),
        }
      );
      const payload = await response.json().catch(() => null);
      if (!response.ok) {
        throw new Error(payload?.error || "Không thể cập nhật giá nguồn.");
      }

      const normalizedPrice = Number.isFinite(Number(payload?.price))
        ? Number(payload?.price)
        : validation.parsedPrice;

      let nextHighestPrice: number | null = null;
      let shouldRecomputeBase = false;

      setSupplyPriceMap((prev) => {
        const currentState = prev[productKey];
        if (!currentState) return prev;

        const nextSupplyState = buildEditedSupplyState(
          currentState,
          sourceId,
          normalizedPrice
        );
        nextHighestPrice = nextSupplyState.nextHighestPrice;
        shouldRecomputeBase = nextSupplyState.shouldRecomputeBase;

        return {
          ...prev,
          [productKey]: nextSupplyState.nextState,
        };
      });

      if (shouldRecomputeBase) {
        recomputeProductBasePrice(productId, nextHighestPrice);
      }

      clearSupplyRowState(rowKey);
      await fetchSupplyPricesForProduct(productName);

      if (shouldRecomputeBase) {
        await refreshProductPricing();
      }
    } catch (err) {
      setSupplyRowErrors((prev) => ({
        ...prev,
        [rowKey]:
          err instanceof Error ? err.message : "Không thể cập nhật giá nguồn.",
      }));
    } finally {
      setSavingSupplyRows((prev) => omitStringKey(prev, rowKey));
    }
  };

  const handleDeleteSupplyRow = async (
    productId: number,
    sourceId: number,
    productKey: string,
    productName: string
  ) => {
    const rowKey = buildSupplyRowKey(productId, sourceId);
    setSupplyRowErrors((prev) => ({ ...prev, [rowKey]: null }));
    setSavingSupplyRows((prev) => ({ ...prev, [rowKey]: true }));

    let nextHighestPrice: number | null = null;
    let shouldRecomputeBase = false;

    try {
      const response = await apiFetch(
        API_ENDPOINTS.DELETE_SUPPLY_PRICE(productId, sourceId),
        {
          method: "DELETE",
        }
      );
      const payload = await response.json().catch(() => null);
      if (!response.ok) {
        throw new Error(payload?.error || "Không thể xóa nguồn này.");
      }

      setSupplyPriceMap((prev) => {
        const currentState = prev[productKey];
        if (!currentState) return prev;

        const nextSupplyState = buildDeletedSupplyState(currentState, sourceId);
        nextHighestPrice = nextSupplyState.nextHighestPrice;
        shouldRecomputeBase = nextSupplyState.shouldRecomputeBase;

        return {
          ...prev,
          [productKey]: nextSupplyState.nextState,
        };
      });

      clearSupplyRowState(rowKey);

      if (shouldRecomputeBase) {
        recomputeProductBasePrice(productId, nextHighestPrice);
      }

      await fetchSupplyPricesForProduct(productName);

      if (shouldRecomputeBase) {
        await refreshProductPricing();
      }
    } catch (err) {
      setSupplyRowErrors((prev) => ({
        ...prev,
        [rowKey]:
          err instanceof Error ? err.message : "Không thể xóa nguồn này.",
      }));
    } finally {
      setSavingSupplyRows((prev) => omitStringKey(prev, rowKey));
    }
  };

  return {
    editingSupplyRows,
    supplyPriceDrafts,
    savingSupplyRows,
    handleStartEditingSupply,
    handleSupplyInputChange,
    handleCancelSupplyEditing,
    handleConfirmSupplyEditing,
    handleDeleteSupplyRow,
  };
}

import { useMemo, useState } from "react";
import type React from "react";
import { apiFetch } from "@/lib/api";
import { API_ENDPOINTS } from "@/constants";
import type {
  CreateProductFormState,
  CreateSupplierEntry,
  ProductEditFormState,
  ProductPricingRow,
} from "../types";
import { createSupplierEntry, formatVndInput, mapProductPriceRow } from "../utils";
import {
  applySelectedSupplierToEntry,
  buildProductEditForm,
  createEmptyCreateForm,
  parseJsonResponseText,
  updateCreateSupplierEntry,
  validateCreateProductForm,
  validateProductEditForm,
  enableCustomSupplierEntry,
} from "./productActionHelpers";
import { convertAmountToVnd } from "../services/exchangeRateService";
import { useDeleteProductActions } from "./useDeleteProductActions";
import { useProductReferenceOptions } from "./useProductReferenceOptions";
import { useProductStatusActions } from "./useProductStatusActions";

interface UseProductActionsParams {
  productPrices: ProductPricingRow[];
  setProductPrices: React.Dispatch<React.SetStateAction<ProductPricingRow[]>>;
  fetchProductPrices: () => Promise<void>;
  statusOverrides: Record<number, boolean>;
  setStatusOverrides: React.Dispatch<
    React.SetStateAction<Record<number, boolean>>
  >;
  updatedTimestampMap: Record<number, string>;
  setUpdatedTimestampMap: React.Dispatch<
    React.SetStateAction<Record<number, string>>
  >;
}

export const useProductActions = ({
  productPrices,
  setProductPrices,
  fetchProductPrices,
  statusOverrides,
  setStatusOverrides,
  updatedTimestampMap,
  setUpdatedTimestampMap,
}: UseProductActionsParams) => {
  const normalizeBasePriceInputByCurrency = (
    rawValue: string,
    currency: ProductEditFormState["basePriceCurrency"]
  ): string => {
    if (currency === "VND") return formatVndInput(rawValue);
    return String(rawValue ?? "")
      .replace(/[^\d.,]/g, "")
      .replace(/,/g, ".");
  };

  const [editingProductId, setEditingProductId] = useState<number | null>(null);
  const [productEditForm, setProductEditForm] =
    useState<ProductEditFormState | null>(null);
  const [productEditError, setProductEditError] = useState<string | null>(null);
  const [isSavingProductEdit, setIsSavingProductEdit] = useState(false);
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [createForm, setCreateForm] = useState<CreateProductFormState>(
    createEmptyCreateForm()
  );
  const [createSuppliers, setCreateSuppliers] = useState<CreateSupplierEntry[]>(
    [createSupplierEntry()]
  );
  const [createError, setCreateError] = useState<string | null>(null);
  const [isSubmittingCreate, setIsSubmittingCreate] = useState(false);

  const productNameOptions = useMemo(() => {
    const seen = new Set<string>();
    return productPrices
      .map((product) => (product.packageName || "").trim())
      .filter(Boolean)
      .filter((name) => {
        const key = name.toLowerCase();
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
      })
      .sort((left, right) =>
        left.localeCompare(right, "vi", { sensitivity: "base" })
      );
  }, [productPrices]);

  const productPackageOptionsByName = useMemo(() => {
    const grouped = new Map<string, { displayName: string; packages: Set<string> }>();
    for (const product of productPrices) {
      const productName = String(product.packageName || "").trim();
      const packageName = String(product.packageProduct || "").trim();
      if (!productName || !packageName) continue;
      const key = productName.toLowerCase();
      if (!grouped.has(key)) {
        grouped.set(key, {
          displayName: productName,
          packages: new Set<string>(),
        });
      }
      grouped.get(key)?.packages.add(packageName);
    }

    const mapped: Record<string, string[]> = {};
    for (const entry of grouped.values()) {
      mapped[entry.displayName] = Array.from(entry.packages).sort((left, right) =>
        left.localeCompare(right, "vi", { sensitivity: "base" })
      );
    }
    return mapped;
  }, [productPrices]);

  const referenceOptions = useProductReferenceOptions({
    isCreateModalOpen,
  });
  const deleteActions = useDeleteProductActions({
    setProductPrices,
    setStatusOverrides,
    setUpdatedTimestampMap,
  });
  const statusActions = useProductStatusActions({
    statusOverrides,
    setStatusOverrides,
    updatedTimestampMap,
    setUpdatedTimestampMap,
    setProductPrices,
  });

  const handleStartProductEdit = (
    event: React.MouseEvent<HTMLButtonElement>,
    product: ProductPricingRow
  ) => {
    event.stopPropagation();
    setIsSavingProductEdit(false);

    if (editingProductId === product.id) {
      setEditingProductId(null);
      setProductEditForm(null);
      setProductEditError(null);
      return;
    }

    setProductEditError(null);
    setEditingProductId(product.id);
    setProductEditForm(buildProductEditForm(product));
  };

  const handleProductEditChange = (
    field: keyof ProductEditFormState,
    value: string
  ) => {
    setProductEditForm((prev) => {
      if (!prev) return prev;

      if (field === "basePrice") {
        return {
          ...prev,
          basePrice: normalizeBasePriceInputByCurrency(
            value,
            prev.basePriceCurrency
          ),
        };
      }

      if (
        field === "pctCtv" ||
        field === "pctKhach" ||
        field === "pctPromo" ||
        field === "pctStu"
      ) {
        return {
          ...prev,
          [field]: formatVndInput(value),
        };
      }

      if (field === "basePriceCurrency") {
        const nextCurrency = (value ||
          "VND") as ProductEditFormState["basePriceCurrency"];
        return {
          ...prev,
          basePriceCurrency: nextCurrency,
          basePrice: normalizeBasePriceInputByCurrency(prev.basePrice, nextCurrency),
        };
      }

      return { ...prev, [field]: value };
    });
  };

  const handleCancelProductEdit = () => {
    setEditingProductId(null);
    setProductEditForm(null);
    setProductEditError(null);
    setIsSavingProductEdit(false);
  };

  const handleSubmitProductEdit = async () => {
    if (!productEditForm || editingProductId === null) return;

    const validation = validateProductEditForm(productEditForm);
    if (!validation.ok) {
      setProductEditError(validation.error);
      return;
    }

    setIsSavingProductEdit(true);
    setProductEditError(null);

    try {
      let resolvedBasePrice = validation.nextBasePrice;
      if (resolvedBasePrice && resolvedBasePrice > 0) {
        const conversion = await convertAmountToVnd(
          resolvedBasePrice,
          productEditForm.basePriceCurrency
        );
        resolvedBasePrice = conversion.convertedAmount;
      }

      const response = await apiFetch(
        API_ENDPOINTS.PRODUCT_PRICE_DETAIL(editingProductId),
        {
          method: "PATCH",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            packageName: validation.normalizedPackageName,
            packageProduct: validation.normalizedPackageProduct,
            sanPham: validation.normalizedSanPham,
            basePrice: resolvedBasePrice,
            pctCtv: validation.nextPctCtv,
            pctKhach: validation.nextPctKhach,
            pctPromo: validation.nextPctPromo,
            pctStu: validation.nextPctStu,
          }),
        }
      );
      const rawBody = await response.text();
      const payload = parseJsonResponseText(rawBody);

      if (!response.ok) {
        const errorMessage =
          payload?.error ||
          rawBody?.trim() ||
          "Không thể cập nhật giá sản phẩm";
        throw new Error(errorMessage);
      }

      const updatedRow = mapProductPriceRow(payload, editingProductId);
      setProductPrices((prev) =>
        prev.map((row) => (row.id === editingProductId ? updatedRow : row))
      );

      if (updatedRow?.id !== undefined) {
        setUpdatedTimestampMap((prev) => ({
          ...prev,
          [updatedRow.id]: updatedRow.lastUpdated || new Date().toISOString(),
        }));
      }

      await fetchProductPrices();
      setEditingProductId(null);
      setProductEditForm(null);
    } catch (err) {
      console.error("Lỗi khi cập nhật giá sản phẩm:", err);
      setProductEditError(
        err instanceof Error ? err.message : "Không thể cập nhật giá sản phẩm"
      );
    } finally {
      setIsSavingProductEdit(false);
    }
  };

  const resetCreateState = () => {
    setCreateForm(createEmptyCreateForm());
    setCreateSuppliers([createSupplierEntry()]);
    setCreateError(null);
    setIsSubmittingCreate(false);
  };

  const handleOpenCreateModal = () => {
    resetCreateState();
    setIsCreateModalOpen(true);

    if (
      referenceOptions.bankOptions.length === 0 &&
      !referenceOptions.isLoadingBanks
    ) {
      referenceOptions.loadBankOptions();
    }
    if (
      referenceOptions.supplierOptions.length === 0 &&
      !referenceOptions.isLoadingSuppliers
    ) {
      referenceOptions.loadSupplierOptions();
    }
  };

  const handleCloseCreateModal = () => {
    setIsCreateModalOpen(false);
    resetCreateState();
  };

  const handleCreateFormChange = (
    field: keyof CreateProductFormState,
    value: string
  ) => {
    const nextValue =
      field === "basePrice" ||
      field === "pctCtv" ||
      field === "pctKhach" ||
      field === "pctPromo" ||
      field === "pctStu"
        ? formatVndInput(value)
        : value;
    setCreateForm((prev) => ({ ...prev, [field]: nextValue }));
  };

  const handleSupplierChange = (
    supplierId: string,
    field: keyof Omit<CreateSupplierEntry, "id">,
    value: string
  ) => {
    setCreateSuppliers((prev) =>
      prev.map((entry) =>
        entry.id === supplierId
          ? updateCreateSupplierEntry(entry, field, value)
          : entry
      )
    );
  };

  const handleSupplierSelectChange = (
    supplierId: string,
    optionValue: string
  ) => {
    const selected =
      referenceOptions.supplierOptions.find(
        (option) =>
          (option.id !== null && optionValue === String(option.id)) ||
          (option.id === null && optionValue === option.name)
      ) || null;

    setCreateSuppliers((prev) =>
      prev.map((entry) =>
        entry.id === supplierId
          ? applySelectedSupplierToEntry(entry, selected)
          : entry
      )
    );
  };

  const handleSupplierPriceInput = (supplierId: string, rawValue: string) => {
    const formatted = formatVndInput(rawValue);
    setCreateSuppliers((prev) =>
      prev.map((entry) =>
        entry.id === supplierId ? { ...entry, price: formatted } : entry
      )
    );
  };

  const handleEnableCustomSupplier = (supplierId: string) => {
    setCreateSuppliers((prev) =>
      prev.map((entry) =>
        entry.id === supplierId ? enableCustomSupplierEntry(entry) : entry
      )
    );
  };

  const handleAddSupplierRow = () => {
    setCreateSuppliers((prev) => [...prev, createSupplierEntry()]);
  };

  const handleRemoveSupplierRow = (supplierId: string) => {
    setCreateSuppliers((prev) =>
      prev.length === 1 ? prev : prev.filter((entry) => entry.id !== supplierId)
    );
  };

  const handleSubmitCreateProduct = async () => {
    const validation = validateCreateProductForm(
      createForm,
      createSuppliers,
      productPrices
    );
    if (!validation.ok) {
      setCreateError(validation.error);
      return;
    }

    setIsSubmittingCreate(true);
    setCreateError(null);

    try {
      const response = await apiFetch(API_ENDPOINTS.PRODUCT_PRICES, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(validation.payload),
      });
      const rawBody = await response.text();
      const payload = parseJsonResponseText(rawBody);

      if (!response.ok) {
        const errorMessage =
          payload?.error || rawBody?.trim() || "Không thể tạo sản phẩm";
        throw new Error(errorMessage);
      }

      await fetchProductPrices();
      handleCloseCreateModal();
    } catch (err) {
      console.error("Lỗi khi tạo sản phẩm:", err);
      setCreateError(
        err instanceof Error ? err.message : "Không thể tạo sản phẩm"
      );
    } finally {
      setIsSubmittingCreate(false);
    }
  };

  return {
    editingProductId,
    productEditForm,
    productEditError,
    isSavingProductEdit,
    isCreateModalOpen,
    createForm,
    createSuppliers,
    createError,
    isSubmittingCreate,
    productNameOptions,
    productPackageOptionsByName,
    supplierOptions: referenceOptions.supplierOptions,
    isLoadingSuppliers: referenceOptions.isLoadingSuppliers,
    refreshSupplierOptions: () =>
      referenceOptions.loadSupplierOptions({ force: true }),
    bankOptions: referenceOptions.bankOptions,
    isLoadingBanks: referenceOptions.isLoadingBanks,
    deleteProductState: deleteActions.deleteProductState,
    handleStartProductEdit,
    handleProductEditChange,
    handleCancelProductEdit,
    handleSubmitProductEdit,
    handleRequestDeleteProduct: deleteActions.handleRequestDeleteProduct,
    confirmDeleteProduct: deleteActions.confirmDeleteProduct,
    closeDeleteProductModal: deleteActions.closeDeleteProductModal,
    handleOpenCreateModal,
    handleCloseCreateModal,
    handleCreateFormChange,
    handleSupplierChange,
    handleSupplierSelectChange,
    handleSupplierPriceInput,
    handleEnableCustomSupplier,
    handleAddSupplierRow,
    handleRemoveSupplierRow,
    handleSubmitCreateProduct,
    handleToggleStatus: statusActions.handleToggleStatus,
  };
};

import { useCallback, useEffect, useMemo, useState } from "react";
import { apiFetch } from "@/lib/api";
import { API_ENDPOINTS } from "@/constants";
import { ProductPricingRow, StatusFilter } from "../types";
import {
  applyBasePriceToProduct,
  mapProductPriceRow,
  toTimestamp,
} from "../utils";

const normalizeSearchText = (value: unknown): string => {
  if (value === null || value === undefined) return "";
  return String(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
};

interface UseProductDataResult {
  currentPage: number;
  setCurrentPage: (value: number) => void;
  rowsPerPage: number;
  setRowsPerPage: (value: number) => void;
  totalRows: number;
  searchTerm: string;
  setSearchTerm: (value: string) => void;
  statusFilter: StatusFilter;
  setStatusFilter: (value: StatusFilter) => void;
  productPrices: ProductPricingRow[];
  setProductPrices: React.Dispatch<React.SetStateAction<ProductPricingRow[]>>;
  isLoading: boolean;
  setIsLoading: (value: boolean) => void;
  error: string | null;
  setError: (value: string | null) => void;
  statusOverrides: Record<number, boolean>;
  setStatusOverrides: React.Dispatch<React.SetStateAction<Record<number, boolean>>>;
  updatedTimestampMap: Record<number, string>;
  setUpdatedTimestampMap: React.Dispatch<React.SetStateAction<Record<number, string>>>;
  expandedProductId: number | null;
  setExpandedProductId: (value: number | null) => void;
  isRefreshing: boolean;
  setIsRefreshing: (value: boolean) => void;
  fetchProductPrices: () => Promise<void>;
  filteredPricing: ProductPricingRow[];
}

export const useProductData = (): UseProductDataResult => {
  const [searchTerm, setSearchTermState] = useState("");
  const [statusFilter, setStatusFilterState] = useState<StatusFilter>("active");
  const [currentPage, setCurrentPage] = useState(1);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [productPrices, setProductPrices] = useState<ProductPricingRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [expandedProductId, setExpandedProductId] = useState<number | null>(
    null
  );
  const [statusOverrides, setStatusOverrides] = useState<
    Record<number, boolean>
  >({});
  const [updatedTimestampMap, setUpdatedTimestampMap] = useState<
    Record<number, string>
  >({});
  const [isRefreshing, setIsRefreshing] = useState(false);

  const setSearchTerm = useCallback((value: string) => {
    setSearchTermState(value);
    setCurrentPage(1);
  }, []);

  const setStatusFilter = useCallback((value: StatusFilter) => {
    setStatusFilterState(value);
    setCurrentPage(1);
  }, []);

  const fetchProductPrices = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await apiFetch(API_ENDPOINTS.PRODUCT_PRICES);
      if (!response.ok) {
        throw new Error("Không thể tải dữ liệu sản phẩm.");
      }
      const payload = await response.json();
      const rows: any[] = Array.isArray(payload)
        ? payload
        : Array.isArray(payload?.items)
        ? payload.items
        : [];
      const normalizedRows = rows.map((row, index) =>
        mapProductPriceRow(row, index)
      );
      const computedRows = normalizedRows.map((row) =>
        applyBasePriceToProduct(row, row.baseSupplyPrice)
      );
      const initialUpdatedMap = computedRows.reduce<Record<number, string>>(
        (acc, row) => {
          if (row.lastUpdated) {
            acc[row.id] = row.lastUpdated;
          }
          return acc;
        },
        {}
      );
      setProductPrices(computedRows);
      setStatusOverrides({});
      setUpdatedTimestampMap(initialUpdatedMap);
    } catch (err) {
      console.error("Lỗi khi tải dữ liệu:", err);
      setProductPrices([]);
      setError(
        err instanceof Error
          ? err.message
          : "Không thể tải dữ liệu pricing."
      );
    } finally {
      setIsLoading(false);
    }
  }, []);

  const searchTokens = useMemo(
    () =>
      normalizeSearchText(searchTerm)
        .split(/\s+/)
        .filter(Boolean),
    [searchTerm]
  );

  const filteredPricing = useMemo(() => {
    return productPrices
      .filter((item) => {
        const resolvedIsActive = statusOverrides[item.id] ?? item.isActive;
        const hasPromo =
          typeof item.promoPrice === "number" &&
          Number.isFinite(item.promoPrice) &&
          item.promoPrice > 0;
        if (statusFilter === "active" && !resolvedIsActive) return false;
        if (statusFilter === "inactive" && resolvedIsActive) return false;
        if (statusFilter === "promo" && !hasPromo) return false;
        if (!searchTokens.length) return true;

        const haystack = normalizeSearchText(
          [
            item.packageName,
            item.packageProduct,
            item.sanPhamRaw,
            item.variantLabel,
          ].join(" ")
        );

        return searchTokens.every((token) => haystack.includes(token));
      })
      .sort((a, b) => {
        const aInactive = !(statusOverrides[a.id] ?? a.isActive);
        const bInactive = !(statusOverrides[b.id] ?? b.isActive);
        if (aInactive !== bInactive) {
          return aInactive ? 1 : -1;
        }
        const aTimestamp = toTimestamp(
          updatedTimestampMap[a.id] ?? a.lastUpdated
        );
        const bTimestamp = toTimestamp(
          updatedTimestampMap[b.id] ?? b.lastUpdated
        );
        if (aTimestamp !== bTimestamp) {
          return bTimestamp - aTimestamp;
        }
        return a.id - b.id;
      });
  }, [
    productPrices,
    searchTokens,
    statusFilter,
    statusOverrides,
    updatedTimestampMap,
  ]);

  const totalRows = filteredPricing.length;

  useEffect(() => {
    const totalPages = Math.max(1, Math.ceil(totalRows / rowsPerPage));
    if (currentPage > totalPages) {
      setCurrentPage(totalPages);
    }
  }, [currentPage, rowsPerPage, totalRows]);

  const pagedPricing = useMemo(() => {
    const start = (currentPage - 1) * rowsPerPage;
    const end = start + rowsPerPage;
    return filteredPricing.slice(start, end);
  }, [filteredPricing, currentPage, rowsPerPage]);

  return {
    currentPage,
    setCurrentPage,
    rowsPerPage,
    setRowsPerPage,
    totalRows,
    searchTerm,
    setSearchTerm,
    statusFilter,
    setStatusFilter,
    productPrices,
    setProductPrices,
    isLoading,
    setIsLoading,
    error,
    setError,
    statusOverrides,
    setStatusOverrides,
    updatedTimestampMap,
    setUpdatedTimestampMap,
    expandedProductId,
    setExpandedProductId,
    isRefreshing,
    setIsRefreshing,
    fetchProductPrices,
    filteredPricing: pagedPricing,
  };
};

import { VARIANT_PRICING_COLS } from "@/lib/tableSql";
import {
  getDiscountRatioInput,
  getMarginRatioInput,
} from "@/shared/utils/pricing";
import {
  CreateSupplierEntry,
  ProductPricingRow,
  RateDescriptionInput,
  SupplyPriceItem,
} from "./types";

export const currencyFormatter = new Intl.NumberFormat("vi-VN", {
  style: "currency",
  currency: "VND",
  maximumFractionDigits: 0,
});

export const createSupplierEntry = (): CreateSupplierEntry => {
  const globalCrypto =
    typeof globalThis !== "undefined" ? (globalThis as any).crypto : null;
  const id =
    globalCrypto && typeof globalCrypto.randomUUID === "function"
      ? globalCrypto.randomUUID()
      : Math.random().toString(36).slice(2);
  return {
    id,
    sourceId: null,
    sourceName: "",
    price: "",
    numberBank: "",
    bankBin: "",
    useCustomName: false,
  };
};

export const roundToNearestThousand = (value?: number | null): number | null => {
  if (typeof value !== "number" || !Number.isFinite(value)) return null;
  const rounded = Math.round(Math.abs(value) / 1000) * 1000;
  return value < 0 ? -rounded : rounded;
};

export const cleanupLabel = (value: unknown): string => {
  if (value === undefined || value === null) return "";
  return String(value).replace(/[_]+/g, " ").replace(/\s+/g, " ").trim();
};

export const formatSkuLabel = (value: string): string => {
  if (!value) return "-";
  return value
    .replace(/[_]+/g, " ")
    .replace(/--/g, " ")
    .replace(/\s+/g, " ")
    .trim();
};

export const extractMonthsLabel = (sanPham: string): string | null => {
  if (!sanPham) return null;
  const match = sanPham.match(/(\d+)\s*m\b/i);
  if (!match) return null;
  const months = Number.parseInt(match[1], 10);
  if (!Number.isFinite(months) || months <= 0) return null;
  return `${months} Tháng`;
};

export const buildVariantLabel = (packageProduct: string, sanPham: string): string => {
  const monthsLabel = extractMonthsLabel(sanPham);
  if (packageProduct && monthsLabel) {
    return `${packageProduct} ${monthsLabel}`;
  }
  if (packageProduct) {
    return packageProduct;
  }
  return monthsLabel || formatSkuLabel(sanPham) || "Không Xác Định";
};

export const toNumberOrNull = (value: unknown): number | null => {
  if (value === undefined || value === null || value === "") return null;
  const num = Number(value);
  return Number.isFinite(num) ? num : null;
};

export const parseBoolean = (value: unknown): boolean => {
  if (typeof value === "boolean") return value;
  if (value === undefined || value === null) return false;
  const normalized = String(value).trim().toLowerCase();
  if (!normalized) return false;
  return ["true", "1", "t", "y", "yes"].includes(normalized);
};

export { getMarginRatioInput, getDiscountRatioInput };

export const hasValidPromoRatio = (
  value?: number | null,
  _pctKhach?: number | null,
  _pctCtv?: number | null
): boolean => {
  return typeof value === "number" && Number.isFinite(value) && value > 0;
};

const normalizeSupplyName = (value: string | null | undefined): string => {
  if (!value) return "";
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
};

export const dedupeSupplyItems = (items: SupplyPriceItem[]): SupplyPriceItem[] => {
  const map = new Map<string, SupplyPriceItem>();
  for (const item of items) {
    const key =
      Number.isFinite(item.sourceId) && item.sourceId > 0
        ? `id:${item.sourceId}`
        : `name:${normalizeSupplyName(item.sourceName)}`;
    const existing = map.get(key);
    if (!existing) {
      map.set(key, item);
      continue;
    }

    const existingPrice = existing.price ?? Number.POSITIVE_INFINITY;
    const candidatePrice = item.price ?? Number.POSITIVE_INFINITY;
    const existingDate = Date.parse(existing.lastOrderDate ?? "") || 0;
    const candidateDate = Date.parse(item.lastOrderDate ?? "") || 0;

    if (candidatePrice < existingPrice || (candidatePrice === existingPrice && candidateDate > existingDate)) {
      map.set(key, item);
    }
  }
  return Array.from(map.values());
};

export const sortSupplyItems = (items: SupplyPriceItem[]): SupplyPriceItem[] => {
  return [...items].sort((a, b) => {
    const priceA = a.price ?? Number.POSITIVE_INFINITY;
    const priceB = b.price ?? Number.POSITIVE_INFINITY;
    if (priceA !== priceB) return priceA - priceB;
    const tsA = Date.parse(a.lastOrderDate ?? "") || 0;
    const tsB = Date.parse(b.lastOrderDate ?? "") || 0;
    if (tsA !== tsB) return tsB - tsA;
    return a.sourceName.localeCompare(b.sourceName);
  });
};

export const buildSupplyRowKey = (productId: number, sourceId: number): string => `${productId}-${sourceId}`;

export const multiplyValue = (value?: number | null, ratio?: number | null): number | null => {
  const direct = toNumberOrNull(ratio);
  if (typeof direct === "number" && Number.isFinite(direct) && direct > 0) {
    return direct;
  }
  return toNumberOrNull(value);
};

export const multiplyBasePrice = (ratio?: number | null, basePrice?: number | null): number | null =>
  multiplyValue(basePrice, ratio);

/** Chỉ tính giá sinh viên khi pct_stu > 0; null/0/âm => không hiển thị giá. */
export const effectiveStudentMarginPct = (
  pctStu?: number | null,
  _pctKhach?: number | null
): number | null => {
  if (
    pctStu !== null &&
    pctStu !== undefined &&
    Number.isFinite(pctStu) &&
    pctStu > 0
  ) {
    return pctStu;
  }
  return null;
};

export const computeStudentPrice = (
  _wholesalePrice?: number | null,
  pctStu?: number | null,
  _pctKhach?: number | null
): number | null => {
  const direct = toNumberOrNull(pctStu);
  return typeof direct === "number" && direct > 0 ? direct : null;
};

export const calculatePromoPrice = (
  _pctKhach?: number | null,
  pctPromo?: number | null,
  _pctCtv?: number | null,
  _wholesalePrice?: number | null,
  _fallbackBasePrice?: number | null
): number | null => {
  const direct = toNumberOrNull(pctPromo);
  return typeof direct === "number" && direct > 0 ? direct : null;
};

export const applyBasePriceToProduct = (product: ProductPricingRow, basePrice: number | null): ProductPricingRow => {
  if (typeof basePrice !== "number" || !Number.isFinite(basePrice) || basePrice <= 0) {
    return product;
  }

  return {
    ...product,
    baseSupplyPrice: basePrice,
  };
};

export const formatVndInput = (raw: string): string => {
  const digits = (raw || "").replace(/\D+/g, "");
  if (!digits) return "";
  const num = Number(digits);
  if (!Number.isFinite(num)) return "";
  return num.toLocaleString("vi-VN");
};

export const formatVndDisplay = (value: string | number): string => {
  if (value === null || value === undefined) return "";
  const raw =
    typeof value === "number" && Number.isFinite(value)
      ? Math.round(value)
      : value;
  const digits = String(raw).replace(/\D+/g, "");
  if (!digits) return "";
  const num = Number(digits);
  if (!Number.isFinite(num)) return "";
  return new Intl.NumberFormat("vi-VN").format(num);
};

export const parseRatioInput = (value: string): number | null => {
  if (value === undefined || value === null) return null;
  const digits = String(value).replace(/\D+/g, "");
  if (!digits) return null;
  const numeric = Number(digits);
  return Number.isFinite(numeric) ? numeric : null;
};

export const calculateProfitPercentBySale = (
  sellingPrice?: number | null,
  costPrice?: number | null
): number | null => {
  if (
    typeof sellingPrice !== "number" ||
    !Number.isFinite(sellingPrice) ||
    sellingPrice <= 0
  ) {
    return null;
  }
  if (
    typeof costPrice !== "number" ||
    !Number.isFinite(costPrice) ||
    costPrice < 0
  ) {
    return null;
  }

  return ((sellingPrice - costPrice) / sellingPrice) * 100;
};

export const formatProfitPercentBySale = (
  sellingPrice?: number | null,
  costPrice?: number | null,
  mode: "short" | "full" = "short"
): string | null => {
  const percent = calculateProfitPercentBySale(sellingPrice, costPrice);
  if (percent === null) return null;

  const rounded = Math.round(percent * 10) / 10;
  const sign = rounded > 0 ? "+" : rounded < 0 ? "-" : "";
  const abs = Math.abs(rounded);
  const hasDecimal = Math.abs(abs - Math.trunc(abs)) > 0;
  const formatted = abs.toLocaleString("vi-VN", {
    minimumFractionDigits: hasDecimal ? 1 : 0,
    maximumFractionDigits: 1,
  });

  if (mode === "full") {
    return `${sign}${formatted}% lợi nhuận theo giá bán`;
  }

  return `${sign}${formatted}%`;
};

export const formatRateDescription = ({ multiplier, price, basePrice }: RateDescriptionInput): string => {
  void multiplier;
  return formatProfitPercentBySale(price, basePrice, "short") ?? "Chưa có % LN";
};

export const formatCurrencyValue = (value?: number | null): string => {
  const rounded = roundToNearestThousand(value);
  if (rounded === null || rounded <= 0) {
    return "-";
  }
  return currencyFormatter.format(rounded);
};

export const formatPromoPercent = (value?: number | null): string | null => {
  void value;
  return null;
};

export const formatDateLabel = (value?: string | null): string => {
  if (!value) return "-";
  const parsed = new Date(value);
  if (!Number.isNaN(parsed.getTime())) {
    return parsed.toLocaleDateString("vi-VN");
  }
  return value;
};

export const normalizeProductKey = (value?: string | null): string => (value || "").trim();

export const formatProfitValue = (value: number | null): string => {
  if (typeof value !== "number" || !Number.isFinite(value)) return "-";
  const rounded = roundToNearestThousand(value) ?? 0;
  if (rounded === 0) return currencyFormatter.format(0);
  return currencyFormatter.format(rounded);
};

export const formatProfitRange = (importPrice?: number | null, wholesalePrice?: number | null, retailPrice?: number | null): string => {
  if (typeof importPrice !== "number" || !Number.isFinite(importPrice)) {
    return "-";
  }
  const wholesaleDiff = typeof wholesalePrice === "number" && Number.isFinite(wholesalePrice) ? wholesalePrice - importPrice : null;
  const retailDiff = typeof retailPrice === "number" && Number.isFinite(retailPrice) ? retailPrice - importPrice : null;

  const wholesaleText = formatProfitValue(wholesaleDiff);
  const retailText = formatProfitValue(retailDiff);

  return `${wholesaleText} - ${retailText}`;
};

export const toTimestamp = (value?: string | null): number => {
  if (!value) return Number.NEGATIVE_INFINITY;
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : Number.NEGATIVE_INFINITY;
};

export const pickCheapestSupplier = (items: SupplyPriceItem[]): SupplyPriceItem | null => {
  if (!items.length) return null;
  return items.reduce<SupplyPriceItem | null>((best, current) => {
    if (!best) return current;
    const bestPrice = best.price ?? Number.POSITIVE_INFINITY;
    const currentPrice = current.price ?? Number.POSITIVE_INFINITY;
    if (currentPrice < bestPrice) return current;
    if (currentPrice > bestPrice) return best;
    const bestTs = toTimestamp(best.lastOrderDate);
    const currentTs = toTimestamp(current.lastOrderDate);
    if (currentTs > bestTs) return current;
    return best;
  }, null);
};

export const computeHighestSupplyPrice = (items: SupplyPriceItem[], fallback?: number | null): number | null => {
  const highest = items.reduce<number>((maxValue, current) => {
    const price = typeof current.price === "number" && Number.isFinite(current.price) ? current.price : Number.NEGATIVE_INFINITY;
    return price > maxValue ? price : maxValue;
  }, Number.NEGATIVE_INFINITY);

  if (Number.isFinite(highest) && highest > 0) {
    return highest;
  }

  if (typeof fallback === "number" && Number.isFinite(fallback) && fallback > 0) {
    return fallback;
  }

  return null;
};

export const toFinitePrice = (value: any): number | null => {
  const num = Number(value);
  return Number.isFinite(num) && num > 0 ? num : null;
};

export const mapProductPriceRow = (row: any, fallbackId: number): ProductPricingRow => {
  const packageName = cleanupLabel(row?.[VARIANT_PRICING_COLS.packageName] ?? row?.package_label);
  const packageProduct = cleanupLabel(row?.[VARIANT_PRICING_COLS.variantName] ?? row?.package_product_label);
  const sanPhamRaw = (row?.[VARIANT_PRICING_COLS.code] ?? row?.id_product_label ?? row?.id_product ?? "").toString().trim();

  const wholesalePrice = toNumberOrNull(
    row?.[VARIANT_PRICING_COLS.pctCtv] ??
      row?.computed_wholesale_price ??
      row?.wholesale_price ??
      row?.gia_si ??
      row?.gia_ctv
  );
  const pctKhach = toNumberOrNull(
    row?.[VARIANT_PRICING_COLS.pctKhach] ??
      row?.computed_retail_price ??
      row?.retail_price ??
      row?.gia_le
  );
  const pctPromo = toNumberOrNull(
    row?.[VARIANT_PRICING_COLS.pctPromo] ??
      row?.computed_promo_price ??
      row?.promo_price ??
      row?.gia_khuyen_mai ??
      row?.gia_km
  );
  const pctStu = toNumberOrNull(
    row?.[VARIANT_PRICING_COLS.pctStu] ??
      row?.student_price
  );

  return {
    id: Number.isFinite(Number(row?.id)) ? Number(row?.id) : fallbackId,
    packageName: packageName || "Không xác định",
    packageProduct,
    sanPhamRaw,
    variantLabel: buildVariantLabel(packageProduct, sanPhamRaw),
    pctCtv: toNumberOrNull(row?.[VARIANT_PRICING_COLS.pctCtv]),
    pctKhach,
    pctPromo,
    pctStu,
    isActive: parseBoolean(row?.[VARIANT_PRICING_COLS.isActive]),
    basePrice: toNumberOrNull(
      row?.[VARIANT_PRICING_COLS.basePrice] ?? row?.base_price
    ),
    baseSupplyPrice: toNumberOrNull(row?.max_supply_price),
    wholesalePrice,
    retailPrice: pctKhach,
    studentPrice: pctStu,
    promoPrice: pctPromo,
    lastUpdated:
      typeof row?.[VARIANT_PRICING_COLS.updatedAt] === "string"
        ? row[VARIANT_PRICING_COLS.updatedAt]
        : typeof row?.updated_at === "string"
        ? row.updated_at
        : typeof row?.updatedAt === "string"
        ? row.updatedAt
        : typeof row?.update === "string"
        ? row.update
        : null,
  };
};

import React, { useState, useEffect } from "react";
import { PencilIcon, TrashIcon, PlusIcon, XMarkIcon, CheckIcon } from "@heroicons/react/24/outline";
import ColorPicker from "@/components/ui/ColorPicker";
import { CategoryItem } from "@/lib/categoryApi";
import { useCategoryManagement } from "../hooks/useCategoryManagement";
import { getCategoryVisualStyle } from "../utils/categoryColors";

interface CategoryTagManagerProps {
  onCategoriesChange?: () => void;
}

const CategoryTagManager: React.FC<CategoryTagManagerProps> = ({ onCategoriesChange }) => {
  const { categories, loading, error, creating, updating, deleting, reload, create, update, remove } = useCategoryManagement();

  const [editingId, setEditingId] = useState<number | null>(null);
  const [editName, setEditName] = useState("");
  const [editColor, setEditColor] = useState("#facc15");

  const [isAdding, setIsAdding] = useState(false);
  const [newName, setNewName] = useState("");
  const [newColor, setNewColor] = useState("#facc15");

  const [deleteConfirmId, setDeleteConfirmId] = useState<number | null>(null);

  useEffect(() => {
    reload();
  }, [reload]);

  const handleStartEdit = (category: CategoryItem) => {
    setEditingId(category.id);
    setEditName(category.name);
    setEditColor(category.color || "#facc15");
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setEditName("");
    setEditColor("#facc15");
  };

  const handleSaveEdit = async () => {
    if (!editingId || !editName.trim()) return;

    try {
      await update(editingId, { name: editName.trim(), color: editColor });
      setEditingId(null);
      setEditName("");
      setEditColor("#facc15");
      onCategoriesChange?.();
    } catch (err) {
      // Error is handled by the hook
    }
  };

  const handleStartAdd = () => {
    setIsAdding(true);
    setNewName("");
    setNewColor("#facc15");
  };

  const handleCancelAdd = () => {
    setIsAdding(false);
    setNewName("");
    setNewColor("#facc15");
  };

  const handleSaveAdd = async () => {
    if (!newName.trim()) return;

    try {
      await create({ name: newName.trim(), color: newColor });
      setIsAdding(false);
      setNewName("");
      setNewColor("#facc15");
      onCategoriesChange?.();
    } catch (err) {
      // Error is handled by the hook
    }
  };

  const handleDelete = async (id: number) => {
    try {
      await remove(id);
      setDeleteConfirmId(null);
      onCategoriesChange?.();
    } catch (err) {
      // Error is handled by the hook
    }
  };

  if (loading && categories.length === 0) {
    return (
      <div className="flex items-center justify-center py-16">
        <div className="text-center">
          <svg className="animate-spin h-8 w-8 text-indigo-400 mx-auto mb-3" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <p className="text-sm text-slate-400">Đang tải danh mục...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h3 className="text-xl font-bold text-white">Quản Lý Danh Mục</h3>
          <p className="text-sm text-slate-400 mt-1">Thêm, sửa, hoặc xóa các danh mục sản phẩm</p>
        </div>
        <button
          type="button"
          onClick={handleStartAdd}
          disabled={isAdding || creating}
          className="inline-flex items-center gap-2 rounded-xl bg-gradient-to-r from-indigo-500 to-purple-600 px-5 py-3 text-sm font-semibold text-white shadow-lg transition-all hover:from-indigo-600 hover:to-purple-700 hover:shadow-xl disabled:opacity-50"
        >
          <PlusIcon className="h-4 w-4" />
          Thêm Danh Mục
        </button>
      </div>

      {/* Error Message */}
      {error && (
        <div className="rounded-xl border border-rose-400/30 bg-rose-500/10 px-5 py-4 text-sm text-rose-200 flex items-start gap-3">
          <svg className="w-5 h-5 flex-shrink-0 mt-0.5" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
          </svg>
          <span>{error}</span>
        </div>
      )}

      {/* Add New Category Form */}
      {isAdding && (
        <div className="rounded-2xl border border-indigo-400/50 bg-gradient-to-br from-indigo-500/10 via-purple-500/10 to-pink-500/10 p-6 space-y-4 shadow-lg">
          <div>
            <label className="text-xs font-semibold text-slate-300 uppercase tracking-wide mb-2 block">
              Tên Danh Mục
            </label>
            <input
              type="text"
              value={newName}
              onChange={(e) => setNewName(e.target.value)}
              placeholder="Nhập tên danh mục..."
              className="w-full rounded-xl border border-white/10 bg-slate-950/40 px-4 py-3 text-sm text-white placeholder:text-slate-400 shadow-inner focus:border-indigo-400 focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all"
              autoFocus
            />
          </div>

          <ColorPicker
            label="Màu Sắc"
            value={newColor}
            onChange={setNewColor}
          />

          <div className="flex items-center justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={handleCancelAdd}
              disabled={creating}
              className="px-5 py-2.5 text-sm font-semibold text-slate-300 hover:text-white transition-colors disabled:opacity-50"
            >
              Hủy
            </button>
            <button
              type="button"
              onClick={handleSaveAdd}
              disabled={!newName.trim() || creating}
              className="inline-flex items-center gap-2 rounded-xl bg-gradient-to-r from-indigo-500 to-purple-600 px-6 py-2.5 text-sm font-semibold text-white shadow-lg transition-all hover:from-indigo-600 hover:to-purple-700 disabled:opacity-50"
            >
              <CheckIcon className="h-4 w-4" />
              {creating ? "Đang tạo..." : "Tạo"}
            </button>
          </div>
        </div>
      )}

      {/* Categories Grid */}
      <div className="grid gap-4 sm:grid-cols-2">
        {categories.map((category) => {
          const isEditing = editingId === category.id;
          const isDeleting = deleteConfirmId === category.id;

          if (isEditing) {
            return (
              <div
                key={category.id}
                className="sm:col-span-2 rounded-2xl border border-indigo-400/50 bg-gradient-to-br from-indigo-500/10 via-purple-500/10 to-pink-500/10 p-6 space-y-4 shadow-lg"
              >
                <div>
                  <label className="text-xs font-semibold text-slate-300 uppercase tracking-wide mb-2 block">
                    Tên Danh Mục
                  </label>
                  <input
                    type="text"
                    value={editName}
                    onChange={(e) => setEditName(e.target.value)}
                    className="w-full rounded-xl border border-white/10 bg-slate-950/40 px-4 py-3 text-sm text-white placeholder:text-slate-400 shadow-inner focus:border-indigo-400 focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all"
                  />
                </div>

                <ColorPicker
                  label="Màu Sắc"
                  value={editColor}
                  onChange={setEditColor}
                />

                <div className="flex items-center justify-end gap-3 pt-2">
                  <button
                    type="button"
                    onClick={handleCancelEdit}
                    disabled={updating}
                    className="px-5 py-2.5 text-sm font-semibold text-slate-300 hover:text-white transition-colors disabled:opacity-50"
                  >
                    Hủy
                  </button>
                  <button
                    type="button"
                    onClick={handleSaveEdit}
                    disabled={!editName.trim() || updating}
                    className="inline-flex items-center gap-2 rounded-xl bg-gradient-to-r from-indigo-500 to-purple-600 px-6 py-2.5 text-sm font-semibold text-white shadow-lg transition-all hover:from-indigo-600 hover:to-purple-700 disabled:opacity-50"
                  >
                    <CheckIcon className="h-4 w-4" />
                    {updating ? "Đang lưu..." : "Lưu"}
                  </button>
                </div>
              </div>
            );
          }

          return (
            <div
              key={category.id}
              className="group rounded-2xl border border-white/15 bg-gradient-to-br from-slate-800/65 via-slate-700/55 to-slate-900/65 p-5 shadow-sm backdrop-blur-sm hover:border-white/25 transition-all"
            >
              <div className="flex items-start gap-4">
                {/* Color Preview */}
                <div
                  className="h-14 w-14 rounded-xl border-2 border-white/20 flex-shrink-0 shadow-md"
                  style={getCategoryVisualStyle(category.color)}
                />

                {/* Category Info */}
                <div className="flex-1 min-w-0">
                  <h4 className="text-base font-semibold text-white truncate">{category.name}</h4>
                  <p className="text-xs text-slate-400 mt-1 font-mono break-all line-clamp-3">
                    {category.color || "#facc15"}
                  </p>
                </div>

                {/* Actions */}
                {isDeleting ? (
                  <div className="flex items-center gap-2">
                    <button
                      type="button"
                      onClick={() => setDeleteConfirmId(null)}
                      disabled={deleting}
                      className="p-2 rounded-lg text-slate-400 hover:text-white hover:bg-white/10 transition-colors disabled:opacity-50"
                      title="Hủy"
                    >
                      <XMarkIcon className="h-4 w-4" />
                    </button>
                    <button
                      type="button"
                      onClick={() => handleDelete(category.id)}
                      disabled={deleting}
                      className="p-2 rounded-lg text-red-400 hover:text-red-300 hover:bg-red-500/20 transition-colors disabled:opacity-50"
                      title="Xác nhận xóa"
                    >
                      <CheckIcon className="h-4 w-4" />
                    </button>
                  </div>
                ) : (
                  <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button
                      type="button"
                      onClick={() => handleStartEdit(category)}
                      disabled={editingId !== null || updating}
                      className="p-2 rounded-lg text-slate-400 hover:text-indigo-400 hover:bg-indigo-500/20 transition-colors disabled:opacity-50"
                      title="Sửa"
                    >
                      <PencilIcon className="h-4 w-4" />
                    </button>
                    <button
                      type="button"
                      onClick={() => setDeleteConfirmId(category.id)}
                      disabled={editingId !== null || deleting}
                      className="p-2 rounded-lg text-slate-400 hover:text-red-400 hover:bg-red-500/20 transition-colors disabled:opacity-50"
                      title="Xóa"
                    >
                      <TrashIcon className="h-4 w-4" />
                    </button>
                  </div>
                )}
              </div>
            </div>
          );
        })}

        {categories.length === 0 && !loading && (
          <div className="sm:col-span-2 text-center py-12">
            <svg className="w-16 h-16 text-slate-600 mx-auto mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" />
            </svg>
            <p className="text-sm text-slate-400 font-medium">Chưa có danh mục nào</p>
            <p className="text-xs text-slate-500 mt-1">Nhấn "Thêm Danh Mục" để tạo danh mục mới</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default CategoryTagManager;

