                      <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                    </svg>
                    <span>{error}</span>
                  </div>
                )}
              </div>
            </div>
          ) : (
            <CategoryTagManager onCategoriesChange={handleCategoriesChange} />
          )}
        </div>

        {/* Footer Actions - Only show for Edit tab */}
        {activeTab === "edit" && (
          <div className="flex items-center justify-end gap-3 border-t border-white/10 px-8 py-5 bg-slate-900/50">
            <button
              type="button"
              className="rounded-xl border border-white/20 bg-transparent px-6 py-3 font-semibold text-white transition-all hover:bg-white/10 disabled:opacity-50"
              onClick={onClose}
              disabled={saving}
            >
              Hủy bỏ
            </button>
            <button
              type="button"
              className="rounded-xl bg-gradient-to-r from-indigo-500 to-purple-600 px-8 py-3 font-semibold text-white shadow-lg transition-all hover:from-indigo-600 hover:to-purple-700 hover:shadow-xl disabled:opacity-50 disabled:cursor-not-allowed"
              onClick={onSave}
              disabled={saving}
            >
              {saving ? (
                <span className="flex items-center gap-2">
                  <svg className="animate-spin h-4 w-4" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Đang lưu...
                </span>
              ) : (
                "Lưu thay đổi"
              )}
            </button>
          </div>
        )}
      </div>
    </div>
    </ModalPortal>
  );
};

import React, { useEffect, useRef, useState } from "react";
import {
  ArrowUturnLeftIcon,
  ArrowUturnRightIcon,
  Bars3BottomLeftIcon,
  Bars3CenterLeftIcon,
  Bars3Icon,
  BoldIcon,
  ChatBubbleBottomCenterTextIcon,
  ItalicIcon,
  LinkIcon,
  ListBulletIcon,
  MinusIcon,
  StrikethroughIcon,
  UnderlineIcon,
} from "@heroicons/react/24/outline";

interface RichTextEditorProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  minHeight?: string;
  helperText?: string;
}

type EditorMode = "visual" | "html";

const RichTextEditor: React.FC<RichTextEditorProps> = ({
  label,
  value,
  onChange,
  placeholder = "Nhập nội dung...",
  minHeight = "200px",
  helperText,
}) => {
  const editorRef = useRef<HTMLDivElement>(null);
  const isUpdatingRef = useRef(false);
  const [mode, setMode] = useState<EditorMode>("visual");

  useEffect(() => {
    if (mode !== "visual") return;
    if (!editorRef.current || isUpdatingRef.current) return;
    if (editorRef.current.innerHTML !== value) {
      editorRef.current.innerHTML = value || "";
    }
  }, [mode, value]);

  const handleInput = () => {
    if (!editorRef.current) return;
    isUpdatingRef.current = true;
    onChange(editorRef.current.innerHTML);
    setTimeout(() => {
      isUpdatingRef.current = false;
    }, 0);
  };

  const ensureVisualMode = () => {
    if (mode !== "visual") {
      setMode("visual");
    }
  };

  const execCommand = (command: string, commandValue?: string) => {
    ensureVisualMode();
    document.execCommand(command, false, commandValue);
    editorRef.current?.focus();
    handleInput();
  };

  const formatBlock = (tag: string) => {
    execCommand("formatBlock", tag);
  };

  const insertLink = () => {
    const url = prompt("Nhập URL liên kết:");
    if (url) {
      execCommand("createLink", url);
    }
  };

  const switchMode = (nextMode: EditorMode) => {
    if (nextMode === mode) return;
    if (nextMode === "html" && editorRef.current) {
      onChange(editorRef.current.innerHTML || "");
    }
    setMode(nextMode);
  };

  const buttonClass =
    "product-edit-editor__button inline-flex min-h-[30px] min-w-[30px] items-center justify-center rounded-md border transition-all";
  const selectClass =
    "product-edit-editor__select min-h-[32px] rounded-md border px-3 text-sm transition-all";

  return (
    <div className="product-edit-editor space-y-3">
      <label className="product-edit-editor__label block text-xs font-semibold uppercase tracking-wide">
        {label}
      </label>
      {helperText ? (
        <p className="product-edit-editor__helper text-xs">{helperText}</p>
      ) : null}

      <div className="product-edit-editor__toolbar">
        <div className="product-edit-editor__toolbar-row product-edit-editor__toolbar-row--compact">
          <div
            className="product-edit-editor__mode-switch"
            role="tablist"
            aria-label={`${label} mode`}
          >
            <button
              type="button"
              className={`product-edit-editor__mode-button ${
                mode === "visual"
                  ? "product-edit-editor__mode-button--active"
                  : ""
              }`}
              onClick={() => switchMode("visual")}
              aria-pressed={mode === "visual"}
            >
              Soạn thảo
            </button>
            <button
              type="button"
              className={`product-edit-editor__mode-button ${
                mode === "html" ? "product-edit-editor__mode-button--active" : ""
              }`}
              onClick={() => switchMode("html")}
              aria-pressed={mode === "html"}
            >
              Mã HTML
            </button>
          </div>

          <div className="product-edit-editor__group">
            <button
              type="button"
              onClick={() => execCommand("undo")}
              className={buttonClass}
              title="Hoàn tác"
              disabled={mode === "html"}
            >
              <ArrowUturnLeftIcon className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => execCommand("redo")}
              className={buttonClass}
              title="Làm lại"
              disabled={mode === "html"}
            >
              <ArrowUturnRightIcon className="h-4 w-4" />
            </button>
          </div>

          <div className="product-edit-editor__group">
            <button
              type="button"
              onClick={insertLink}
              className={buttonClass}
              title="Chèn liên kết"
              disabled={mode === "html"}
            >
              <LinkIcon className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => execCommand("unlink")}
              className={buttonClass}
              title="Gỡ liên kết"
              disabled={mode === "html"}
            >
              <svg
                className="h-4 w-4"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M13.828 10.172a4 4 0 010 5.656l-1.414 1.414a4 4 0 01-5.657-5.657l1.414-1.414M10.172 13.828a4 4 0 010-5.656l1.414-1.414a4 4 0 115.657 5.657l-1.414 1.414"
                />
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M8 8l8 8"
                />
              </svg>
            </button>
          </div>

          <div className="product-edit-editor__group product-edit-editor__group--danger">
            <button
              type="button"
              onClick={() => execCommand("removeFormat")}
              className={`${buttonClass} product-edit-editor__button--danger`}
              title="Xóa định dạng"
              disabled={mode === "html"}
            >
              <svg
                className="h-4 w-4"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />
              </svg>
            </button>
          </div>
        </div>

        <div className="product-edit-editor__toolbar-row product-edit-editor__toolbar-row--actions">
          <div className="product-edit-editor__group">
            <button
              type="button"
              onClick={() => execCommand("bold")}
              className={buttonClass}
              title="In đậm"
              disabled={mode === "html"}
            >
              <BoldIcon className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => execCommand("italic")}
              className={buttonClass}
              title="In nghiêng"
              disabled={mode === "html"}
            >
              <ItalicIcon className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => execCommand("underline")}
              className={buttonClass}
              title="Gạch chân"
              disabled={mode === "html"}
            >
              <UnderlineIcon className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => execCommand("strikeThrough")}
              className={buttonClass}
              title="Gạch ngang"
              disabled={mode === "html"}
            >
              <StrikethroughIcon className="h-4 w-4" />
            </button>
          </div>

          <div className="product-edit-editor__group">
            <button
              type="button"
              onClick={() => execCommand("insertUnorderedList")}
              className={buttonClass}
              title="Danh sách không thứ tự"
              disabled={mode === "html"}
            >
              <ListBulletIcon className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => execCommand("insertOrderedList")}
              className={buttonClass}
              title="Danh sách có thứ tự"
              disabled={mode === "html"}
            >
              <Bars3Icon className="h-4 w-4" />
            </button>
          </div>

          <div className="product-edit-editor__group">
            <button
              type="button"
              onClick={() => execCommand("justifyLeft")}
              className={buttonClass}
              title="Căn trái"
              disabled={mode === "html"}
            >
              <Bars3BottomLeftIcon className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => execCommand("justifyCenter")}
              className={buttonClass}
              title="Căn giữa"
              disabled={mode === "html"}
            >
              <Bars3CenterLeftIcon className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => execCommand("justifyRight")}
              className={buttonClass}
              title="Căn phải"
              disabled={mode === "html"}
            >
              <Bars3BottomLeftIcon className="h-4 w-4 scale-x-[-1]" />
            </button>
          </div>

          <div className="product-edit-editor__group">
            <button
              type="button"
              onClick={() => formatBlock("blockquote")}
              className={buttonClass}
              title="Trích dẫn"
              disabled={mode === "html"}
            >
              <ChatBubbleBottomCenterTextIcon className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => execCommand("insertHorizontalRule")}
              className={buttonClass}
              title="Chèn đường phân cách"
              disabled={mode === "html"}
            >
              <MinusIcon className="h-4 w-4" />
            </button>
          </div>
        </div>

        <div className="product-edit-editor__toolbar-row product-edit-editor__toolbar-row--fields">
          <select
            onChange={(e) => {
              if (e.target.value) {
                formatBlock(e.target.value);
                e.target.value = "";
              }
            }}
            className={`${selectClass} product-edit-editor__select--kind`}
            defaultValue=""
            disabled={mode === "html"}
          >
            <option value="" disabled>
              Kiểu
            </option>
            <option value="h1">H1 - Tiêu đề chính</option>
            <option value="h2">H2 - Tiêu đề section</option>
            <option value="h3">H3 - Tiêu đề mục con</option>
            <option value="h4">H4 - Tiêu đề nhỏ</option>
            <option value="p">P - Đoạn văn bản</option>
          </select>

          <select
            onChange={(e) => {
              if (e.target.value) {
                execCommand("fontName", e.target.value);
                e.target.value = "";
              }
            }}
            className={`${selectClass} product-edit-editor__select--font`}
            defaultValue=""
            disabled={mode === "html"}
          >
            <option value="" disabled>
              Phông
            </option>
            <option value="Arial">Arial</option>
            <option value="Georgia">Georgia</option>
            <option value="Tahoma">Tahoma</option>
            <option value="Times New Roman">Times New Roman</option>
            <option value="Verdana">Verdana</option>
          </select>

          <select
            onChange={(e) => {
              if (e.target.value) {
                execCommand("fontSize", e.target.value);
                e.target.value = "";
              }
            }}
            className={`${selectClass} product-edit-editor__select--size`}
            defaultValue=""
            disabled={mode === "html"}
          >
            <option value="" disabled>
              Cỡ chữ
            </option>
            <option value="2">Nhỏ</option>
            <option value="3">Mặc định</option>
            <option value="4">Vừa</option>
            <option value="5">Lớn</option>
            <option value="6">Rất lớn</option>
          </select>
        </div>
      </div>

      {mode === "html" ? (
        <textarea
          className="product-edit-editor__source w-full border px-4 py-4 text-sm outline-none transition-all"
          style={{ minHeight }}
          value={value}
          onChange={(event) => onChange(event.target.value)}
          placeholder="Nhập mã HTML source..."
          spellCheck={false}
        />
      ) : (
        <div
          ref={editorRef}
          contentEditable
          onInput={handleInput}
          className="product-edit-editor__canvas w-full overflow-y-auto border px-4 py-4 text-sm outline-none transition-all max-w-none"
          style={{ minHeight }}
