      <style>{`
        .product-edit-editor__canvas[data-placeholder]:empty:before {
          content: attr(data-placeholder);
          color: rgba(160, 174, 208, 0.72);
          pointer-events: none;
        }

        .product-edit-editor__canvas h1 {
          font-size: 1.8rem;
