import { API_ENDPOINTS } from "@/constants";
import { apiFetch } from "@/lib/api";
import type { ProductDesc } from "../types";

export async function fetchVariantPricingRows(): Promise<Record<string, any>[]> {
  const response = await apiFetch(API_ENDPOINTS.PRODUCT_PRICES);
  if (!response.ok) throw new Error("Failed to load variant pricing");
  const data = await response.json();
  if (Array.isArray(data)) return data;
  if (data?.items && Array.isArray(data.items)) return data.items;
  return [];
}

export async function fetchProductDescList(): Promise<ProductDesc[]> {
  const response = await apiFetch(API_ENDPOINTS.PRODUCT_DESCRIPTIONS);
  if (!response.ok) throw new Error("Failed to load product_desc");
  const data = await response.json();
  if (!data?.items || !Array.isArray(data.items)) return [];
  return data.items.map((item: Record<string, any>) => ({
    productId: (item.productId || item.product_id || "") as string,
    rules: item.rules ?? "",
    description: item.description ?? "",
  }));
}

import { useEffect, useState } from "react";
import { fetchProductDescList, fetchVariantPricingRows } from "../api/productPriceApi";
import type { ProductDesc } from "../types";

/** Tải bảng giá biến thể + mô tả sản phẩm cho trang báo giá. */
export function useProductPriceCatalog() {
  const [productPrices, setProductPrices] = useState<Record<string, any>[]>([]);
  const [productDescs, setProductDescs] = useState<ProductDesc[]>([]);

  useEffect(() => {
    let isMounted = true;
    (async () => {
      try {
        const rows = await fetchVariantPricingRows();
        if (isMounted) setProductPrices(rows);
      } catch (err) {
        console.error("Không thể tải pricing:", err);
      }
    })();
    (async () => {
      try {
        const items = await fetchProductDescList();
        if (isMounted) setProductDescs(items);
      } catch (err) {
        console.error("Không thể tải product_desc:", err);
      }
    })();
    return () => {
      isMounted = false;
    };
  }, []);

  return { productPrices, productDescs };
}

export const formatCurrency = (value: number): string =>
  value.toLocaleString("vi-VN");

export const displayDate = (iso: string): string => {
  if (!iso) return "";
  const [y, m, d] = iso.split("-");
  if (!y || !m || !d) return iso;
  return `${d}/${m}/${y}`;
};

/** YYYY-MM-DD theo lịch local (hôm nay). */
export function todayYmdLocal(): string {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

export const htmlToPlainText = (value?: string | null): string => {
  if (!value) return "";
  try {
    const parser = new DOMParser();
    const doc = parser.parseFromString(value, "text/html");
    const blockTags = new Set(["DIV", "P", "BR", "LI", "UL", "OL", "SECTION"]);
    const lines: string[] = [];

    const walk = (node: ChildNode, buffer: string[]) => {
      if (node.nodeType === Node.TEXT_NODE) {
        buffer.push((node.textContent || "").replace(/\u00a0/g, " "));
        return;
      }
      if (node.nodeType === Node.ELEMENT_NODE) {
        const el = node as HTMLElement;
        if (el.tagName === "BR") {
          buffer.push("\n");
          return;
        }
        const childBuffer: string[] = [];
        el.childNodes.forEach((child) => walk(child, childBuffer));
        const joined = childBuffer.join("");
        buffer.push(joined);
        if (blockTags.has(el.tagName)) {
          buffer.push("\n");
        }
      }
    };

    const rootBuffer: string[] = [];
    doc.body.childNodes.forEach((child) => walk(child, rootBuffer));
    return rootBuffer
      .join("")
      .replace(/\u00a0/g, " ")
      .replace(/\n{3,}/g, "\n\n")
      .replace(/[ \t]+\n/g, "\n")
      .trim();
  } catch {
    return value || "";
  }
};

import { VARIANT_PRICING_COLS } from "@/lib/tableSql";
import type { ProductDesc, QuoteLine, QuoteProductDescSection } from "../types";
import { htmlToPlainText } from "./quoteFormat";
import {
  normalizeKey,
  normalizeProductKey,
  stripDurationSuffix,
} from "./quoteNormalize";

/** Gói / tên biến thể theo mã sản phẩm (đã chuẩn hóa key). */
export function buildPackageProductMap(
  productPrices: Record<string, any>[]
): Map<string, string> {
  const map = new Map<string, string>();
  productPrices.forEach((row) => {
    const productCode =
      (row?.[VARIANT_PRICING_COLS.code] as string) ||
      (row?.san_pham as string) ||
      "";
    const packageProduct =
      (row?.[VARIANT_PRICING_COLS.variantName] as string) ||
      (row?.package_product as string) ||
      (row?.package_product_label as string) ||
      "";
    const key = normalizeKey(stripDurationSuffix(productCode));
    if (key && packageProduct) {
      map.set(key, packageProduct);
    }
  });
  return map;
}

export function buildProductDescMap(
  productDescs: ProductDesc[]
): Map<string, ProductDesc> {
  const map = new Map<string, ProductDesc>();
  productDescs.forEach((item) => {
    const key = normalizeKey(stripDurationSuffix(item.productId));
    if (key) map.set(key, item);
  });
  return map;
}

export function buildProductDescSections(
  lines: QuoteLine[],
  productDescMap: Map<string, ProductDesc>,
  packageProductMap: Map<string, string>
): QuoteProductDescSection[] {
  const seen = new Set<string>();
  const sections: QuoteProductDescSection[] = [];
  lines.forEach((line) => {
    const rawCode = line.productCode || line.product || "";
    const key = normalizeKey(stripDurationSuffix(rawCode));
    if (!key || seen.has(key)) return;
    seen.add(key);
    const desc = productDescMap.get(key);
    const packageProductName =
      packageProductMap.get(key) || line.packageName || line.product;
    sections.push({
      name: packageProductName,
      rules: htmlToPlainText(desc?.rules),
      description: htmlToPlainText(desc?.description),
    });
  });
  return sections;
}

/** Map normalizeProductKey(value) → option (dùng sau buildProductOptions). */
export function indexProductOptionsByKey<T extends { value: string }>(
  productOptions: T[]
): Map<string, T> {
  const map = new Map<string, T>();
  productOptions.forEach((opt) => {
    map.set(normalizeProductKey(opt.value), opt);
  });
  return map;
}

import { roundGiaBanValue } from "@/lib/helpers";
import { VARIANT_PRICING_COLS } from "@/lib/tableSql";
import {
  calculateSellingPriceFromMarginInput,
  getDiscountRatioInput,
} from "@/shared/utils/pricing";
import type { ApiPriceEntry } from "../types";
import { parseDurationFromSku } from "./quoteApiParsing";
import {
  normalizeProductKey,
  toNumber,
} from "./quoteNormalize";

export const computeLinePricing = (
  apiPricing: ApiPriceEntry | undefined,
  selected: {
    basePrice?: number;
    unitPrice?: number;
    pctPromo?: number;
    pctKhach?: number;
    pctCtv?: number;
    wholesalePrice?: number;
  }
) => {
  if (apiPricing) {
    const unitPrice = roundGiaBanValue(apiPricing.price || 0);
    const promoPrice = roundGiaBanValue(apiPricing.promoPrice || 0);
    const discount =
      promoPrice > 0 && unitPrice > 0 && promoPrice < unitPrice
        ? roundGiaBanValue(unitPrice - promoPrice)
        : 0;
    return { unitPrice, discount };
  }

  const basePrice = selected?.basePrice ?? 0;
  const fallbackRetailPrice = selected?.unitPrice ?? basePrice;
  const wholesalePrice =
    selected?.wholesalePrice && selected.wholesalePrice > 0
      ? selected.wholesalePrice
      : basePrice > 0 && basePrice < fallbackRetailPrice
        ? calculateSellingPriceFromMarginInput(basePrice, selected?.pctCtv) ??
          fallbackRetailPrice
        : fallbackRetailPrice;
  const retailPrice = roundGiaBanValue(
    calculateSellingPriceFromMarginInput(wholesalePrice, selected?.pctKhach) ??
      fallbackRetailPrice
  );
  const pctPromoDecimal = getDiscountRatioInput(selected?.pctPromo) ?? 0;
  const discount =
    pctPromoDecimal > 0
      ? roundGiaBanValue(retailPrice * pctPromoDecimal)
      : 0;
  return { unitPrice: retailPrice, discount };
};

export const buildProductOptions = (
  productPrices: Record<string, any>[],
  priceMap: Record<string, ApiPriceEntry>
) => {
  const seen = new Set<string>();
  const options: Array<{
    value: string;
    productDisplay: string;
    packageDisplay: string;
    label: string;
    durationMonths: number | null;
    durationDays: number | null;
    term: string;
    unitPrice: number;
    discountValue: number;
    pctPromo: number;
    pctKhach: number;
    pctCtv: number;
    wholesalePrice: number;
    productId: string;
    basePrice?: number;
    promoPrice?: number;
  }> = [];

  productPrices.forEach((row) => {
    const sanPham =
      (row?.[VARIANT_PRICING_COLS.code] as string) ||
      (row?.san_pham as string) ||
      "";
    const value = sanPham.trim();
    if (!value) return;
    const key = value.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);

    const durationInfo = parseDurationFromSku(value);

    const pctKhachRaw = toNumber(
      row?.pct_khach ?? row?.[VARIANT_PRICING_COLS.pctKhach]
    );
    const pctCtvRaw = toNumber(
      row?.pct_ctv ?? row?.[VARIANT_PRICING_COLS.pctCtv]
    );
    const pctPromoRaw = toNumber(
      row?.pct_promo ?? row?.[VARIANT_PRICING_COLS.pctPromo]
    );
    const pctPromo = getDiscountRatioInput(pctPromoRaw) ?? 0;
    const baseSupply = toNumber(row?.max_supply_price);
    const wholesaleRaw =
      calculateSellingPriceFromMarginInput(baseSupply, pctCtvRaw) ?? baseSupply;
    const wholesaleRounded =
      wholesaleRaw > 0 ? roundGiaBanValue(wholesaleRaw) : 0;

    const retailBase =
      toNumber(
        row?.computed_retail_price ??
          row?.retail_price ??
          row?.gia_le ??
          row?.gia_ban
      ) || 0;
    const promoBase =
      toNumber(
        row?.computed_promo_price ??
          row?.promo_price ??
          row?.gia_khuyen_mai ??
          row?.gia_km
      ) || 0;

    const retailPriceRaw =
      calculateSellingPriceFromMarginInput(wholesaleRounded, pctKhachRaw) ??
      retailBase ??
      promoBase ??
      wholesaleRounded;
    const retailPrice = roundGiaBanValue(retailPriceRaw);
    const promoPriceRaw = retailPrice * (1 - pctPromo);
    const promoRounded = roundGiaBanValue(promoPriceRaw);
    const promoClamped = Math.min(
      retailPrice,
      wholesaleRounded > 0
        ? Math.max(wholesaleRounded, promoRounded)
        : promoRounded
    );
    const discountValue = promoClamped > 0 ? retailPrice - promoClamped : 0;
    const unitPrice = retailPrice;

    const packageProduct =
      (row?.[VARIANT_PRICING_COLS.variantName] as string) ||
      (row?.package_product as string) ||
      (row?.package_product_label as string) ||
      "";

    const label = packageProduct
      ? `${packageProduct} (${value})`
      : row?.package
        ? `${row?.package} (${value})`
        : value;

    const priceKey = normalizeProductKey(value);
    const apiPrice = priceMap[priceKey];

    options.push({
      productId: value,
      value,
      productDisplay: row?.package || value,
      packageDisplay: packageProduct || row?.package || value,
      label,
      durationMonths: durationInfo.months,
      durationDays: durationInfo.days,
      term: durationInfo.days ? `${durationInfo.days} ngày` : "",
      unitPrice: retailPrice,
      discountValue,
      basePrice: baseSupply || wholesaleRounded || retailBase || retailPrice,
      promoPrice: apiPrice?.promoPrice ?? 0,
      pctPromo: pctPromoRaw,
      pctKhach: pctKhachRaw,
      pctCtv: pctCtvRaw,
      wholesalePrice: wholesaleRounded,
    });
  });

  return options.sort((a, b) => a.label.localeCompare(b.label, "vi"));
};

/**
 * Bảng hiển thị Mã đơn hàng, Tên Khách Hàng, Email, Tình trạng Gói, Hạn Sử Dụng, Thao Tác.
 *
 * Luồng dữ liệu:
 * 1. order_list lọc theo variant_id thuộc hệ thống renew_adobe (product_system)
 * 2. API trả về order_code, information_order, customer, expiry_date, status
 * 3. Join order_user_tracking + mapping (API) → profile, tình trạng gói
 */

import { useCallback, useEffect, useMemo, useState } from "react";
import {
  ArrowPathIcon,
  PencilSquareIcon,
  TrashIcon,
} from "@heroicons/react/24/outline";
import { ResponsiveTable, TableCard } from "@/components/ui/ResponsiveTable";
import Pagination from "@/components/ui/Pagination";
import ConfirmModal from "@/components/modals/ConfirmModal/ConfirmModal";
import type { LicenseStatus } from "@/features/renew-adobe/types";
import {
  deleteTrackingOrder,
  fetchRenewAdobeUserOrders,
} from "@/features/renew-adobe/user-orders/api";
import type {
  DisplayStatus,
  OrderInfo,
  UserOrderRow,
} from "@/features/renew-adobe/user-orders/types";
import { flattenToUserRows } from "@/features/renew-adobe/user-orders/utils";
import { AddTrackingOrdersModal } from "@/features/renew-adobe/components/AddTrackingOrdersModal";
import { EditTrackingOrderModal } from "@/features/renew-adobe/components/EditTrackingOrderModal";
import { getAdobeSystemOption } from "@/features/renew-adobe/user-orders/system-options";
import { renewFixAdesAccount } from "@/features/renew-adobe/fix-ades/api";
import { showAppNotification } from "@/lib/notifications";

const STATUS_LABELS: Record<LicenseStatus, string> = {
  paid: "Còn gói",
  active: "Còn gói",
  expired: "Hết gói",
  unknown: "Chờ gia hạn",
};

/** no_product = chưa cấp quyền Adobe; not_added = chưa gán admin */
const DISPLAY_LABELS: Record<DisplayStatus, string> = {
  ...STATUS_LABELS,
  no_product: "Chưa cấp quyền",
  not_added: "Chưa add",
};

const PAGE_SIZE = 10;

function SystemBadge({ code }: { code: string | null | undefined }) {
  const opt = getAdobeSystemOption(code);
  return (
    <span
      className={`inline-flex items-center whitespace-nowrap rounded-md border px-2 py-0.5 text-[10px] font-semibold uppercase tracking-[0.1em] ${opt.badge}`}
    >
      {opt.label}
    </span>
  );
}

function StatusBadge({ status }: { status: DisplayStatus }) {
  const label = DISPLAY_LABELS[status];
  const colorClasses =
    status === "paid" || status === "active"
      ? "bg-emerald-500/15 text-emerald-300 border-emerald-400/40"
      : status === "expired"
        ? "bg-rose-500/15 text-rose-300 border-rose-400/40"
      : status === "no_product"
        ? "bg-amber-500/15 text-amber-300 border-amber-400/40"
      : status === "not_added"
        ? "bg-slate-500/20 text-slate-300 border-slate-400/35"
        : "bg-amber-500/15 text-amber-300 border-amber-400/40";
  return (
    <span
      className={`inline-flex items-center whitespace-nowrap rounded-full border px-2.5 py-1 text-[11px] font-semibold uppercase tracking-[0.12em] ${colorClasses}`}
    >
      {label}
    </span>
  );
}

export type UserOrdersTableProps = {
  /** Đổi khi load lại danh sách admin → refetch user-orders (join API). */
  accountsRefreshDep?: string;
  onDeleteUser?: (accountId: number, userEmail: string) => void;
  deletingId?: string | null;
  onFixUser?: (userEmail: string) => void;
  fixingId?: string | null;
  /** Fix tuần tự các user đang hiển thị (theo ô tìm kiếm) có accountId === 0 */
  onFixAllUsers?: (emails: string[]) => void;
  fixAllProgress?: { current: number; total: number } | null;
};

export function UserOrdersTable({
  accountsRefreshDep = "",
  onDeleteUser,
  deletingId,
  onFixUser,
  fixingId,
  onFixAllUsers,
  fixAllProgress,
}: UserOrdersTableProps) {
  const [searchTerm, setSearchTerm] = useState("");
  const [page, setPage] = useState(1);
  const [orderData, setOrderData] = useState<OrderInfo[]>([]);
  const [addTrackingOpen, setAddTrackingOpen] = useState(false);
  const [trackingRefreshKey, setTrackingRefreshKey] = useState(0);
  const [editTarget, setEditTarget] = useState<UserOrderRow | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<UserOrderRow | null>(null);
  const [deletingTrackingId, setDeletingTrackingId] = useState<string | null>(
    null
  );
  const [adesRenewTarget, setAdesRenewTarget] = useState<UserOrderRow | null>(
    null
  );
  const [adesRenewingId, setAdesRenewingId] = useState<string | null>(null);

  const reloadOrders = useCallback(() => {
    fetchRenewAdobeUserOrders()
      .then((data) => setOrderData(data))
      .catch(() => setOrderData([]));
  }, []);

  useEffect(() => {
    reloadOrders();
  }, [accountsRefreshDep, reloadOrders, trackingRefreshKey]);

  const handleConfirmDelete = useCallback(async () => {
    if (!deleteTarget) return;
    const code = deleteTarget.order_code;
    setDeletingTrackingId(code);
    try {
      await deleteTrackingOrder(code);
      showAppNotification({
        type: "success",
        title: "Đã xoá khỏi tracking",
        message: `Đơn ${code} đã được xoá khỏi order_user_tracking.`,
      });
      setDeleteTarget(null);
      setTrackingRefreshKey((k) => k + 1);
    } catch (err) {
      showAppNotification({
        type: "error",
        title: "Xoá thất bại",
        message:
          (err as Error)?.message || "Không thể xoá đơn khỏi tracking.",
      });
    } finally {
      setDeletingTrackingId(null);
    }
  }, [deleteTarget]);

  const handleConfirmAdesRenew = useCallback(async () => {
    if (!adesRenewTarget) return;
    const email = adesRenewTarget.email;
    const code = adesRenewTarget.order_code;
    setAdesRenewingId(email);
    try {
      const result = await renewFixAdesAccount(email);
      const user = result?.data?.user;
      const credits = result?.data?.creditsRemaining;
      const expires = user?.expiresAt
        ? new Date(user.expiresAt).toLocaleDateString("vi-VN")
        : "?";
      showAppNotification({
        type: "success",
        title: "Renew Fix Ades thành công",
        message: `${email} — đến ${expires}${
          typeof credits === "number" ? ` (còn ${credits} credit)` : ""
        }`,
      });
      setAdesRenewTarget(null);
      setTrackingRefreshKey((k) => k + 1);
    } catch (err) {
      showAppNotification({
        type: "error",
        title: "Renew Fix Ades thất bại",
        message:
          (err as Error)?.message ||
          `Không thể renew đơn ${code} qua Fix Ades.`,
      });
    } finally {
      setAdesRenewingId(null);
    }
  }, [adesRenewTarget]);

  const allRows = useMemo(() => flattenToUserRows(orderData), [orderData]);

  const filtered = useMemo(() => {
    if (!searchTerm.trim()) return allRows;
    const q = searchTerm.trim().toLowerCase();
    return allRows.filter(
      (r) =>
        r.order_code.toLowerCase().includes(q) ||
        r.customer_name.toLowerCase().includes(q) ||
        r.email.toLowerCase().includes(q)
    );
  }, [allRows, searchTerm]);

  /** Chưa có adobe_account_id (chưa gán admin) */
  const fixableEmailsInView = useMemo(
    () =>
      filtered.filter((r) => r.accountId === 0).map((r) => r.email),
    [filtered]
  );

  const totalItems = filtered.length;
  const start = (page - 1) * PAGE_SIZE;
  const currentRows = filtered.slice(start, start + PAGE_SIZE);

  return (
    <div className="rounded-[18px] bg-gradient-to-br from-slate-800/65 via-slate-700/55 to-slate-900/65 border border-white/15 p-4 lg:p-6 shadow-[0_20px_55px_-30px_rgba(0,0,0,0.7)] backdrop-blur-sm">
      <h3 className="text-sm font-semibold text-white/90 mb-1">
        Danh sách user & đơn hàng
      </h3>
      <p className="text-xs text-white/50 mb-4">
        Mã đơn hàng, Tên Khách Hàng, Email, Profile, Tình trạng Gói, Hạn Sử Dụng
      </p>

      <div className="mb-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <input
          type="text"
          placeholder="Tìm theo mã đơn, tên, email..."
          className="w-full max-w-md px-4 py-2 border border-white/10 rounded-xl bg-slate-950/40 text-sm text-white placeholder:text-slate-400/70 focus:ring-2 focus:ring-indigo-500/50 outline-none"
          value={searchTerm}
          onChange={(e) => {
            setSearchTerm(e.target.value);
            setPage(1);
          }}
        />
        <div className="flex flex-wrap items-center gap-2">
          <button
            type="button"
            onClick={() => setAddTrackingOpen(true)}
            disabled={!!fixingId || !!deletingId || !!fixAllProgress}
            className="shrink-0 rounded-xl bg-emerald-500/20 text-emerald-200 border border-emerald-400/40 px-4 py-2 text-sm font-semibold hover:bg-emerald-500/30 disabled:opacity-50 disabled:cursor-not-allowed whitespace-nowrap"
          >
            + Thêm đơn
          </button>
          {onFixAllUsers && fixableEmailsInView.length > 0 ? (
            <button
              type="button"
              onClick={() => onFixAllUsers(fixableEmailsInView)}
              disabled={!!fixingId || !!deletingId || !!fixAllProgress}
              className="shrink-0 rounded-xl bg-amber-500/20 text-amber-300 border border-amber-400/40 px-4 py-2 text-sm font-semibold hover:bg-amber-500/30 disabled:opacity-50 disabled:cursor-not-allowed whitespace-nowrap"
            >
              {fixAllProgress
                ? `Đang fix ${fixAllProgress.current}/${fixAllProgress.total}...`
                : `Fix all (${fixableEmailsInView.length})`}
            </button>
          ) : null}
        </div>
      </div>

      <AddTrackingOrdersModal
        open={addTrackingOpen}
        onClose={() => setAddTrackingOpen(false)}
        onSaved={() => setTrackingRefreshKey((k) => k + 1)}
      />

      <EditTrackingOrderModal
        open={editTarget !== null}
        orderCode={editTarget?.order_code ?? ""}
        initialSystemNote={editTarget?.systemNote}
        onClose={() => setEditTarget(null)}
        onSaved={() => {
          setEditTarget(null);
          setTrackingRefreshKey((k) => k + 1);
          showAppNotification({
            type: "success",
            title: "Đã cập nhật",
            message: "Hệ thống fix của đơn đã được lưu.",
          });
        }}
      />

      <ConfirmModal
        isOpen={deleteTarget !== null}
        onClose={() => {
          if (!deletingTrackingId) setDeleteTarget(null);
        }}
        onConfirm={handleConfirmDelete}
        title="Xoá đơn khỏi tracking?"
        message={
          deleteTarget
            ? `Xoá đơn ${deleteTarget.order_code} khỏi order_user_tracking?`
            : ""
        }
        secondaryMessage="Chỉ xoá khỏi bảng tracking. Mapping user ↔ admin Adobe vẫn còn — nếu cần xoá hẳn, dùng nút Xóa ở cột Adobe."
        confirmLabel={deletingTrackingId ? "Đang xoá…" : "Xoá"}
        cancelLabel="Hủy"
        isSubmitting={deletingTrackingId !== null}
      />

      <ConfirmModal
        isOpen={adesRenewTarget !== null}
        onClose={() => {
          if (!adesRenewingId) setAdesRenewTarget(null);
        }}
        onConfirm={handleConfirmAdesRenew}
        title="Renew qua Fix Ades?"
        message={
          adesRenewTarget
            ? `Gọi renew cho ${adesRenewTarget.email} (đơn ${adesRenewTarget.order_code})?`
            : ""
        }
        secondaryMessage="Thao tác sẽ trừ 1 credit Ades. Chỉ thực hiện khi tài khoản đến hạn / cần gia hạn — không bấm thử."
        confirmLabel={adesRenewingId ? "Đang renew…" : "Renew"}
        cancelLabel="Hủy"
        isSubmitting={adesRenewingId !== null}
      />

      <div className="rounded-xl border border-white/10 overflow-hidden">
        <ResponsiveTable
          showCardOnMobile
          cardView={
            currentRows.length === 0 ? (
              <div className="p-8 text-center text-white/70">
                Chưa có dữ liệu. Chạy Check để đồng bộ users từ Adobe.
              </div>
            ) : (
              <TableCard
                data={currentRows}
                renderCard={(item) => {
                  const row = item as UserOrderRow;
                  const isActive =
                    row.display_status === "active" ||
                    row.display_status === "paid";
                  const showAdesRenew =
                    !isActive && row.systemNote === "fix_ades";
                  const showAdobeFix =
                    !isActive &&
                    row.systemNote !== "fix_ades" &&
                    row.accountId === 0 &&
                    !!onFixUser;
                  return (
                    <div className="flex flex-col gap-2 rounded-2xl border border-white/10 bg-slate-900/70 p-4">
                      <div className="flex items-center justify-between gap-2">
                        <p className="text-xs text-white/60">Mã đơn: {row.order_code}</p>
                        <SystemBadge code={row.systemNote} />
                      </div>
                      <p className="text-sm font-medium text-white">{row.customer_name}</p>
                      <p className="text-xs text-white/80 break-all">{row.email}</p>
                      <p className="text-xs text-white/60">Profile: {row.profile}</p>
                      <StatusBadge status={row.display_status} />
                      <p className="text-xs text-white/70">Hạn: {row.expiry}</p>
                      <div className="mt-2 flex flex-wrap items-center gap-2">
                        {showAdesRenew && (
                          <button
                            type="button"
                            onClick={() => setAdesRenewTarget(row)}
                            disabled={adesRenewingId === row.email}
                            className="inline-flex items-center gap-1 rounded-lg border border-fuchsia-400/40 bg-fuchsia-500/15 px-2.5 py-1 text-xs font-semibold text-fuchsia-200 hover:bg-fuchsia-500/25 disabled:opacity-40"
                            title="Renew qua Fix Ades"
                          >
                            <ArrowPathIcon className="h-3.5 w-3.5" />
                            {adesRenewingId === row.email
                              ? "Đang renew…"
                              : "Renew Ades"}
                          </button>
                        )}
                        {row.accountId > 0 && onDeleteUser && (
                          <button
                            type="button"
                            onClick={() => onDeleteUser(row.accountId, row.email)}
                            disabled={!!deletingId || !!fixingId || !!fixAllProgress}
                            className="rounded-lg bg-rose-500/20 text-rose-300 border border-rose-400/40 px-3 py-1.5 text-xs font-semibold"
                          >
                            Xóa user
                          </button>
                        )}
                        {showAdobeFix && (
                          <button
                            type="button"
                            onClick={() => onFixUser?.(row.email)}
                            disabled={!!fixingId || !!deletingId || !!fixAllProgress}
                            className="rounded-lg bg-amber-500/20 text-amber-300 border border-amber-400/40 px-3 py-1.5 text-xs font-semibold"
                          >
                            {fixingId === row.email ? "Đang fix..." : "Fix"}
                          </button>
                        )}
                        <button
                          type="button"
                          onClick={() => setEditTarget(row)}
                          disabled={deletingTrackingId === row.order_code}
                          className="inline-flex items-center justify-center rounded-lg border border-indigo-400/40 bg-indigo-500/15 px-2 py-1.5 text-indigo-200 hover:bg-indigo-500/25 disabled:opacity-40"
                          title="Sửa hệ thống fix"
                          aria-label="Sửa"
                        >
                          <PencilSquareIcon className="h-4 w-4" />
                        </button>
                        <button
                          type="button"
                          onClick={() => setDeleteTarget(row)}
                          disabled={deletingTrackingId === row.order_code}
                          className="inline-flex items-center justify-center rounded-lg border border-rose-400/40 bg-rose-500/15 px-2 py-1.5 text-rose-200 hover:bg-rose-500/25 disabled:opacity-40"
                          title="Xoá đơn khỏi tracking"
                          aria-label="Xoá khỏi tracking"
                        >
                          <TrashIcon className="h-4 w-4" />
                        </button>
                      </div>
                    </div>
                  );
                }}
                className="p-4"
              />
            )
          }
        >
