                <th className="min-w-[120px]">MÃ ĐƠN HÀNG</th>
                <th className="min-w-[160px]">TÊN KHÁCH HÀNG</th>
                <th className="min-w-[200px]">EMAIL</th>
                <th className="min-w-[140px]">PROFILE</th>
                <th className="min-w-[140px]">HỆ THỐNG</th>
                <th className="min-w-[12rem] whitespace-nowrap">TÌNH TRẠNG GÓI</th>
                <th className="min-w-[110px]">HẠN SỬ DỤNG</th>
                <th className="min-w-[10rem] text-center">THAO TÁC</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {currentRows.length === 0 ? (
                <tr>
                  <td colSpan={8} className="px-4 py-12 text-center text-white/70">
                    Chưa có dữ liệu. Chạy Check để đồng bộ users từ Adobe.
                  </td>
                </tr>
              ) : (
                currentRows.map((row) => {
                  const isActive =
                    row.display_status === "active" ||
                    row.display_status === "paid";
                  const showAdesRenew =
                    !isActive && row.systemNote === "fix_ades";
                  const showAdobeFix =
                    !isActive &&
                    row.systemNote !== "fix_ades" &&
                    row.accountId === 0 &&
                    !!onFixUser;
                  return (
                  <tr key={row.id}>
                    <td className="px-2 sm:px-4 py-3 text-sm text-white/80 font-mono">
                      {row.order_code}
                    </td>
                    <td className="px-2 sm:px-4 py-3 text-sm text-white/90">
                      {row.customer_name}
                    </td>
                    <td className="px-2 sm:px-4 py-3 text-sm text-white/90 break-all">
                      {row.email}
                    </td>
                    <td className="px-2 sm:px-4 py-3 text-sm text-white/80">
                      {row.profile}
                    </td>
                    <td className="px-2 sm:px-4 py-3">
                      <SystemBadge code={row.systemNote} />
                    </td>
                    <td className="px-2 sm:px-4 py-3">
                      <StatusBadge status={row.display_status} />
                    </td>
                    <td className="px-2 sm:px-4 py-3 text-sm text-white/80">
                      {row.expiry}
                    </td>
                    <td className="px-2 sm:px-4 py-3">
                      <div className="flex items-center justify-center gap-1.5 flex-wrap">
                        {showAdesRenew && (
                          <button
                            type="button"
                            onClick={() => setAdesRenewTarget(row)}
                            disabled={adesRenewingId === row.email}
                            className="inline-flex items-center gap-1 rounded-lg border border-fuchsia-400/40 bg-fuchsia-500/15 px-2.5 py-1 text-xs font-semibold text-fuchsia-200 hover:bg-fuchsia-500/25 disabled:opacity-50 disabled:cursor-not-allowed"
                            title="Renew qua Fix Ades"
                          >
                            <ArrowPathIcon className="h-3.5 w-3.5" />
                            {adesRenewingId === row.email
                              ? "Đang renew…"
                              : "Renew Ades"}
                          </button>
                        )}
                        {row.accountId > 0 && onDeleteUser && (
                          <button
                            type="button"
                            onClick={() => onDeleteUser(row.accountId, row.email)}
                            disabled={!!deletingId || !!fixingId || !!fixAllProgress}
                            className="rounded-lg bg-rose-500/20 text-rose-300 border border-rose-400/40 px-2.5 py-1 text-xs font-semibold hover:bg-rose-500/30 disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                            Xóa user
                          </button>
                        )}
                        {showAdobeFix && (
                          <button
                            type="button"
                            onClick={() => onFixUser?.(row.email)}
                            disabled={!!fixingId || !!deletingId || !!fixAllProgress}
                            className="rounded-lg bg-amber-500/20 text-amber-300 border border-amber-400/40 px-2.5 py-1 text-xs font-semibold hover:bg-amber-500/30 disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                            {fixingId === row.email ? "Đang fix..." : "Fix"}
                          </button>
                        )}
                        <button
                          type="button"
                          onClick={() => setEditTarget(row)}
                          disabled={deletingTrackingId === row.order_code}
                          className="inline-flex h-7 w-7 items-center justify-center rounded-lg border border-indigo-400/40 bg-indigo-500/15 text-indigo-200 hover:bg-indigo-500/25 disabled:opacity-40"
                          title="Sửa hệ thống fix"
                          aria-label="Sửa"
                        >
                          <PencilSquareIcon className="h-3.5 w-3.5" />
                        </button>
                        <button
                          type="button"
                          onClick={() => setDeleteTarget(row)}
                          disabled={deletingTrackingId === row.order_code}
                          className="inline-flex h-7 w-7 items-center justify-center rounded-lg border border-rose-400/40 bg-rose-500/15 text-rose-200 hover:bg-rose-500/25 disabled:opacity-40"
                          title="Xoá đơn khỏi tracking"
                          aria-label="Xoá khỏi tracking"
                        >
                          <TrashIcon className="h-3.5 w-3.5" />
                        </button>
                      </div>
                    </td>
                  </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </ResponsiveTable>

        {totalItems > 0 && (
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 border-t border-white/10 bg-slate-900/85 px-4 py-3">
            <Pagination
              currentPage={page}
              totalItems={totalItems}
              pageSize={PAGE_SIZE}
              onPageChange={setPage}
            />
          </div>
        )}
      </div>
    </div>
  );
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { API_ENDPOINTS } from "@/constants";
import { apiFetch } from "@/lib/api";
import {
  deleteAdobeAdminAccount,
  fetchAdobeAdminAccounts,
  runSchedulerRenewAdobeCheck,
} from "../api/renewAdobeApi";
import type { AdobeAdminAccount } from "../types";
import { normalizeIncomingLicenseStatus } from "../utils/accountUtils";

type CheckAllProgress = {
  total: number;
  completed: number;
  failed: number;
  checkingIds: Set<number>;
};

export function useRenewAdobeAdmin() {
  const [accounts, setAccounts] = useState<AdobeAdminAccount[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [checkingId, setCheckingId] = useState<number | null>(null);
  const [checkError, setCheckError] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [fixingId, setFixingId] = useState<string | null>(null);
  /** Fix lần lượt nhiều user (Fix all); `current` = thứ tự đang chạy (1-based). */
  const [fixAllProgress, setFixAllProgress] = useState<{
    current: number;
    total: number;
  } | null>(null);
  const [deletingAdminAccountId, setDeletingAdminAccountId] = useState<number | null>(null);
  const [adminAccountPendingDelete, setAdminAccountPendingDelete] =
    useState<AdobeAdminAccount | null>(null);
  const [checkAllProgress, setCheckAllProgress] =
    useState<CheckAllProgress | null>(null);
  const [autoAssignPhase, setAutoAssignPhase] = useState<
    "idle" | "running" | "done"
  >("idle");
  const [autoAssignResult, setAutoAssignResult] = useState<{
    assigned: number;
    skipped: number;
  } | null>(null);
  const checkAllAbortRef = useRef<AbortController | null>(null);
  const fixAllInFlightRef = useRef(false);
  const [cronTestLoading, setCronTestLoading] = useState(false);
  const [cronTestBanner, setCronTestBanner] = useState<string | null>(null);

  const isCheckingAll =
    checkAllProgress !== null &&
    checkAllProgress.completed < checkAllProgress.total;

  const loadAccounts = useMemo(
    () => () => {
      setLoading(true);
      setError(null);
      fetchAdobeAdminAccounts()
        .then(setAccounts)
        .catch((err) =>
          setError(err?.message ?? "Không thể tải danh sách tài khoản.")
        )
        .finally(() => setLoading(false));
    },
    []
  );

  useEffect(() => {
    loadAccounts();
  }, [loadAccounts]);

  const dismissCheckAllProgress = useCallback(() => {
    setCheckAllProgress(null);
    setAutoAssignPhase("idle");
    setAutoAssignResult(null);
  }, []);

  const handleCheckAll = useCallback(() => {
    if (isCheckingAll) {
      return;
    }

    setCheckError(null);
    setCronTestBanner(null);

    const abort = new AbortController();
    checkAllAbortRef.current = abort;

    setCheckAllProgress({
      total: 0,
      completed: 0,
      failed: 0,
      checkingIds: new Set(),
    });

    const url = API_ENDPOINTS.RENEW_ADOBE_CHECK_ALL;
    apiFetch(url, { signal: abort.signal })
      .then(async (res) => {
        if (!res.ok) {
          throw new Error(res.statusText || "Check All thất bại");
        }

        const reader = res.body?.getReader();
        if (!reader) {
          throw new Error("Không hỗ trợ streaming");
        }

        const decoder = new TextDecoder();
        let buffer = "";

        while (true) {
          const { done, value } = await reader.read();
          if (done) {
            break;
          }

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split("\n");
          buffer = lines.pop() || "";

          for (const line of lines) {
            if (!line.startsWith("data: ")) {
              continue;
            }

            try {
              const event = JSON.parse(line.slice(6));
              handleSSEEvent(event);
            } catch {}
          }
        }

        if (buffer.startsWith("data: ")) {
          try {
            handleSSEEvent(JSON.parse(buffer.slice(6)));
          } catch {}
        }
      })
      .catch((err) => {
        if (err.name === "AbortError") {
          return;
        }

        setCheckError(err?.message ?? "Lỗi khi chạy Check All.");
      })
      .finally(() => {
        checkAllAbortRef.current = null;
        setCheckAllProgress((prev) =>
          prev ? { ...prev, checkingIds: new Set() } : null
        );
      });

    function handleSSEEvent(event: Record<string, unknown>) {
      switch (event.type) {
        case "start":
          setCheckAllProgress({
            total: event.total as number,
            completed: 0,
            failed: 0,
            checkingIds: new Set(),
          });
          setAutoAssignPhase("idle");
          setAutoAssignResult(null);
          break;
        case "checking":
          setCheckAllProgress((prev) => {
            if (!prev) {
              return prev;
            }

            const ids = new Set(prev.checkingIds);
            ids.add(event.id as number);
            return { ...prev, checkingIds: ids };
          });
          break;
        case "done":
          setAccounts((prev) => {
            if (event.removed_from_db) {
              return prev.filter((account) => account.id !== event.id);
            }
            return prev.map((account) =>
              account.id === event.id
                ? {
                    ...account,
                    org_name: (event.org_name as string) ?? null,
                    user_count:
                      (event.user_count as number) ?? account.user_count,
                    license_status: normalizeIncomingLicenseStatus(
                      event.license_status ?? account.license_status
                    ),
                  }
                : account
            );
          });
          setCheckAllProgress((prev) => {
            if (!prev) {
              return prev;
            }

            const ids = new Set(prev.checkingIds);
            ids.delete(event.id as number);
            return {
              ...prev,
              completed: event.completed as number,
              failed: event.failed as number,
              checkingIds: ids,
            };
          });
          break;
        case "error":
          setAccounts((prev) =>
            prev.map((account) =>
              account.id === event.id
                ? {
                    ...account,
                    license_status: normalizeIncomingLicenseStatus(
                      event.license_status ?? account.license_status
                    ),
                  }
                : account
            )
          );
          setCheckAllProgress((prev) => {
            if (!prev) {
              return prev;
            }

            const ids = new Set(prev.checkingIds);
            ids.delete(event.id as number);
            return {
              ...prev,
              completed: event.completed as number,
              failed: event.failed as number,
              checkingIds: ids,
            };
          });
          break;
        case "complete":
          setCheckAllProgress((prev) =>
            prev
              ? {
                  ...prev,
                  completed: event.completed as number,
                  failed: event.failed as number,
                  checkingIds: new Set(),
                }
              : null
          );
          loadAccounts();
          break;
        case "auto_assign_start":
          setAutoAssignPhase("running");
          break;
        case "auto_assign_done":
          setAutoAssignPhase("done");
          setAutoAssignResult({
            assigned: (event.assigned as number) ?? 0,
            skipped: (event.skipped as number) ?? 0,
          });
          loadAccounts();
          break;
        case "auto_assign_error":
          setAutoAssignPhase("done");
          setCheckError(`Auto-assign: ${event.error as string}`);
          break;
        case "auto_assign_progress":
          break;
        case "fatal":
          setCheckError(event.error as string);
          break;
      }
    }
  }, [isCheckingAll, loadAccounts]);

  const handleCancelCheckAll = useCallback(() => {
    checkAllAbortRef.current?.abort();
    setCheckAllProgress(null);
  }, []);

  const handleTestCronJob = useCallback(() => {
    if (cronTestLoading || isCheckingAll || checkingId !== null) {
      return;
    }
    setCheckError(null);
    setCronTestBanner(null);
    setCronTestLoading(true);
    runSchedulerRenewAdobeCheck()
      .then(() => {
        setCronTestBanner(
          "Đã chạy xong job giống cron (check all + auto-assign) trên process API. Cron thật chạy trong `scheduler` — xem log service đó để so sánh."
        );
        loadAccounts();
      })
      .catch((err) =>
        setCheckError(
          err?.message ?? "Lỗi khi chạy test job cron (scheduler/run-adobe-check)."
        )
      )
      .finally(() => setCronTestLoading(false));
  }, [checkingId, cronTestLoading, isCheckingAll, loadAccounts]);

  const handleDeleteUser = useCallback(
    (accountId: number, userEmail: string) => {
      setCheckError(null);
      const key = `acc-${accountId}-${userEmail}`;
      setDeletingId(key);

      apiFetch(
        API_ENDPOINTS.RENEW_ADOBE_ACCOUNT_AUTO_DELETE_USERS(accountId),
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ userEmails: [userEmail] }),
        }
      )
        .then((res) => res.json())
        .then((data) => {
          if (data?.success === false) {
            throw new Error(data?.error ?? data?.message ?? "Xóa thất bại");
          }
          if (Array.isArray(data?.failed) && data.failed.length > 0) {
            const firstError = data.failed[0]?.error;
            throw new Error(firstError ?? "Xóa thất bại");
          }
          loadAccounts();
        })
        .catch((err) => setCheckError(err?.message ?? "Lỗi khi xóa user."))
        .finally(() => setDeletingId(null));
    },
    [loadAccounts]
  );

  const handleFixUser = useCallback(
    (userEmail: string) => {
      if (fixAllInFlightRef.current) {
        return;
      }
      setCheckError(null);
      setFixingId(userEmail);

      apiFetch(API_ENDPOINTS.RENEW_ADOBE_FIX_USER, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email: userEmail }),
      })
        .then((res) => res.json())
        .then((data) => {
          if (data?.success) {
            loadAccounts();
          } else {
            throw new Error(data?.error ?? "Fix thất bại");
          }
        })
        .catch((err) => setCheckError(err?.message ?? "Lỗi khi fix user."))
        .finally(() => setFixingId(null));
    },
    [loadAccounts]
  );

  const handleFixAllUsers = useCallback(
    async (emails: string[]) => {
      const unique = [
        ...new Set(
          emails
            .map((e) => String(e || "").trim().toLowerCase())
            .filter(Boolean)
        ),
      ];
      if (unique.length === 0 || fixAllInFlightRef.current) {
        return;
      }

      fixAllInFlightRef.current = true;
      setCheckError(null);
      setFixAllProgress({ current: 0, total: unique.length });

      try {
        const res = await apiFetch(
          API_ENDPOINTS.RENEW_ADOBE_FIX_USERS_ROUND,
          {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ emails: unique }),
          }
        );
        const data = (await res.json().catch(() => ({}))) as {
          success?: boolean;
          error?: string;
          total_added?: number;
          added_count?: number;
        };

        if (!data?.success) {
          const msg =
            typeof data?.error === "string" ? data.error : "Fix thất bại";
          throw new Error(msg);
        }

        const total =
          Number(data.total_added) ||
          Number(data.added_count) ||
          0;
        setFixAllProgress({
          current: Math.min(total, unique.length),
          total: unique.length,
        });
      } catch (err) {
        setCheckError(
          err instanceof Error ? err.message : "Lỗi khi fix hàng loạt."
        );
      } finally {
        fixAllInFlightRef.current = false;
        setFixingId(null);
        setFixAllProgress(null);
        loadAccounts();
      }
    },
    [loadAccounts]
  );

  const handleSaveUrlAccess = useCallback((accountId: number, url: string) => {
    apiFetch(API_ENDPOINTS.RENEW_ADOBE_URL_ACCESS(accountId), {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ access_url: url }),
    })
      .then((res) => res.json())
      .then((data) => {
        if (data?.success) {
          setAccounts((prev) =>
            prev.map((account) =>
              account.id === accountId
                ? { ...account, access_url: url || null }
                : account
            )
          );
        }
      })
      .catch(() => {});
  }, []);

  const openDeleteAdminModal = useCallback((account: AdobeAdminAccount) => {
    setCheckError(null);
    setAdminAccountPendingDelete(account);
  }, []);

  const closeDeleteAdminModal = useCallback(() => {
    if (deletingAdminAccountId !== null) return;
    setAdminAccountPendingDelete(null);
  }, [deletingAdminAccountId]);

  const confirmDeleteAdminAccount = useCallback(() => {
    const account = adminAccountPendingDelete;
    if (!account) return;
    setCheckError(null);
    setDeletingAdminAccountId(account.id);
    deleteAdobeAdminAccount(account.id)
      .then(() => {
        loadAccounts();
        setAdminAccountPendingDelete(null);
      })
      .catch((err) =>
        setCheckError(err?.message ?? "Lỗi khi xóa tài khoản admin.")
      )
      .finally(() => setDeletingAdminAccountId(null));
  }, [adminAccountPendingDelete, loadAccounts]);

  const handleCheck = useCallback(
    (account: AdobeAdminAccount) => {
      setCheckError(null);
      setCheckingId(account.id);

      apiFetch(API_ENDPOINTS.RENEW_ADOBE_ACCOUNT_CHECK(account.id), {
        method: "POST",
        headers: { "Content-Type": "application/json" },
      })
        .then((res) => {
          if (!res.ok) {
            throw new Error(res.statusText || "Check thất bại");
          }
          return res.json();
        })
        .then((data) => {
          if (data.success) {
            loadAccounts();
          } else {
            throw new Error(data.error || "Check thất bại");
          }
        })
        .catch((err) => setCheckError(err?.message ?? "Lỗi khi chạy check."))
        .finally(() => setCheckingId(null));
    },
    [loadAccounts]
  );

  return {
    accounts,
    loading,
    error,
    checkingId,
    checkError,
    deletingAdminAccountId,
    adminAccountPendingDelete,
    openDeleteAdminModal,
    closeDeleteAdminModal,
    confirmDeleteAdminAccount,
    deletingId,
    fixingId,
    fixAllProgress,
    checkAllProgress,
    autoAssignPhase,
    autoAssignResult,
    isCheckingAll,
    cronTestLoading,
    cronTestBanner,
    loadAccounts,
    dismissCheckAllProgress,
    handleCheckAll,
    handleCancelCheckAll,
    handleTestCronJob,
    handleDeleteUser,
    handleFixUser,
    handleFixAllUsers,
    handleSaveUrlAccess,
    handleCheck,
  };
}

import { useMemo, useState } from "react";
import ConfirmModal from "@/components/modals/ConfirmModal/ConfirmModal";
import { RenewAdobeAccountsTable } from "@/features/renew-adobe/components/RenewAdobeAccountsTable";
import { AddUserByEmail } from "@/features/renew-adobe/components/AddUserByEmail";
import { AddAdminAccountModal } from "@/features/renew-adobe/components/AddAdminAccountModal";
import { RenewAdobeHeader } from "@/features/renew-adobe/components/RenewAdobeHeader";
import { RenewAdobeProgressPanel } from "@/features/renew-adobe/components/RenewAdobeProgressPanel";
import { UserOrdersTable } from "@/features/renew-adobe/components/UserOrdersTable";
import type { AdobeAdminAccount } from "@/features/renew-adobe/types";
import { useRenewAdobeAdmin } from "@/features/renew-adobe/hooks/useRenewAdobeAdmin";

const PAGE_SIZE = 10;

export default function RenewAdobeAdmin() {
  const [searchTerm, setSearchTerm] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [addAdminOpen, setAddAdminOpen] = useState(false);
  const {
    accounts,
    loading,
    error,
    checkingId,
    checkError,
    deletingAdminAccountId,
    adminAccountPendingDelete,
    closeDeleteAdminModal,
    confirmDeleteAdminAccount,
    deletingId,
    fixingId,
    fixAllProgress,
    checkAllProgress,
    autoAssignPhase,
    autoAssignResult,
    isCheckingAll,
    cronTestLoading,
    cronTestBanner,
    loadAccounts,
    dismissCheckAllProgress,
    handleCheckAll,
    handleCancelCheckAll,
    handleTestCronJob,
    handleDeleteUser,
    handleFixUser,
    handleFixAllUsers,
    handleSaveUrlAccess,
    handleCheck,
    openDeleteAdminModal,
  } = useRenewAdobeAdmin();

  const filtered = useMemo(() => {
    if (!searchTerm.trim()) return accounts;
    const q = searchTerm.trim().toLowerCase();
    return accounts.filter(
      (item) =>
        item.email.toLowerCase().includes(q) ||
        (item.alias ?? "").toLowerCase().includes(q) ||
        (item.org_name ?? "").toLowerCase().includes(q) ||
        (item.id_product ?? "").toLowerCase().includes(q)
    );
  }, [accounts, searchTerm]);

  const totalItems = filtered.length;
  const currentRows = filtered.slice(
    (currentPage - 1) * PAGE_SIZE,
    currentPage * PAGE_SIZE
  );

  return (
    <div className="space-y-6">
      <AddAdminAccountModal
        open={addAdminOpen}
        onClose={() => setAddAdminOpen(false)}
        onCreated={loadAccounts}
      />
      <RenewAdobeHeader
        isCheckingAll={isCheckingAll}
        loading={loading}
        accountCount={accounts.length}
        checkingId={checkingId}
        cronTestLoading={cronTestLoading}
        onCheckAll={handleCheckAll}
        onCancelCheckAll={handleCancelCheckAll}
        onTestCronJob={handleTestCronJob}
        onAddAdmin={() => setAddAdminOpen(true)}
      />

      {cronTestBanner && (
        <p className="rounded-lg border border-emerald-500/30 bg-emerald-500/10 px-4 py-3 text-sm text-emerald-100/95">
          {cronTestBanner}
        </p>
      )}

      {checkAllProgress && checkAllProgress.total > 0 && (
        <RenewAdobeProgressPanel
          total={checkAllProgress.total}
          completed={checkAllProgress.completed}
          failed={checkAllProgress.failed}
          isCheckingAll={isCheckingAll}
          autoAssignPhase={autoAssignPhase}
          autoAssignResult={autoAssignResult}
          onClose={dismissCheckAllProgress}
        />
      )}

      <RenewAdobeAccountsTable
        accounts={accounts}
        currentRows={currentRows}
        currentPage={currentPage}
        totalItems={totalItems}
        pageSize={PAGE_SIZE}
        searchTerm={searchTerm}
        loading={loading}
        error={error}
        checkError={checkError}
        checkingId={checkingId}
        deletingAdminAccountId={deletingAdminAccountId}
        isCheckingAll={isCheckingAll}
        checkingIds={checkAllProgress?.checkingIds}
        onSearchTermChange={(value) => {
          setSearchTerm(value);
          setCurrentPage(1);
        }}
        onPageChange={setCurrentPage}
        onCheck={handleCheck}
        onDeleteAdmin={openDeleteAdminModal}
        onSaveUrlAccess={handleSaveUrlAccess}
        onRefresh={loadAccounts}
      />

      <div className="mt-6 space-y-6">
        <UserOrdersTable
          accountsRefreshDep={accounts
            .map(
              (a) =>
                `${a.id}:${a.tracking_user_count ?? 0}:${a.user_count}:${a.license_status}`
            )
            .join("|")}
          onDeleteUser={handleDeleteUser}
          deletingId={deletingId}
          onFixUser={handleFixUser}
          fixingId={fixingId}
          onFixAllUsers={handleFixAllUsers}
          fixAllProgress={fixAllProgress}
        />
        <AddUserByEmail onAdded={loadAccounts} />
      </div>

      <ConfirmModal
        isOpen={adminAccountPendingDelete !== null}
        onClose={closeDeleteAdminModal}
        onConfirm={confirmDeleteAdminAccount}
        title="Xóa tài khoản admin?"
        message={
          adminAccountPendingDelete
            ? `Xóa tài khoản ${adminAccountPendingDelete.email} khỏi danh sách?`
            : ""
        }
        secondaryMessage="Gán user ↔ đơn hàng với account này sẽ được gỡ. (Không tự xóa user trên Adobe.)"
        confirmLabel="Xóa"
        cancelLabel="Hủy"
        isSubmitting={deletingAdminAccountId !== null}
      />
    </div>
  );
}

import type { AdobeAdminAccount, LicenseStatus } from "../types";

/** Chuẩn hóa trạng thái gói từ API/SSE (DB có thể là Paid, paid, …). */
export function normalizeIncomingLicenseStatus(raw: unknown): LicenseStatus {
  const status = String(raw ?? "unknown").toLowerCase();
  if (status === "paid") return "paid";
  if (status === "active") return "active";
  if (status === "expired") return "expired";
  return "unknown";
}

export function maskPassword(_raw: string): string {
  return "••••••••";
}

export function hasNoAccountInfo(account: AdobeAdminAccount): boolean {
  const orgName = (account.org_name ?? "").toString().trim();
  return orgName === "" || orgName === "—" || orgName === "-";
}

export function normalizeAdobeAdminAccount(
  row: Record<string, unknown>
): AdobeAdminAccount {
  const licenseStatus = normalizeIncomingLicenseStatus(row.license_status);

  const aliasRaw = row.alias;
  const rawOtpSource = String(row.otp_source ?? "imap").trim().toLowerCase();
  const otpSource: "imap" | "tinyhost" | "hdsd" =
    rawOtpSource === "tinyhost" || rawOtpSource === "hdsd"
      ? rawOtpSource
      : "imap";
  return {
    id: Number(row.id) || 0,
    email: String(row.email ?? ""),
    password_encrypted: String(row.password_encrypted ?? row.password_enc ?? ""),
    otp_source: otpSource,
    alias:
      aliasRaw != null && String(aliasRaw).trim() !== ""
        ? String(aliasRaw).trim()
        : null,
    org_name: row.org_name != null ? String(row.org_name) : null,
    user_count: Number(row.user_count) ?? 0,
    tracking_user_count:
      row.tracking_user_count != null &&
      Number.isFinite(Number(row.tracking_user_count))
        ? Number(row.tracking_user_count)
        : 0,
    license_status: licenseStatus,
    order_code: row.order_code != null ? String(row.order_code) : null,
    last_checked_at: row.last_checked_at != null ? String(row.last_checked_at) : null,
    access_url: row.access_url != null ? String(row.access_url) : null,
    id_product:
      row.id_product != null && String(row.id_product).trim() !== ""
        ? String(row.id_product).trim()
        : null,
  };
}

import React, { useState, useMemo } from "react";
import { XMarkIcon } from "@heroicons/react/24/outline";
import { ModalPortal } from "@/components/ui/ModalPortal";
import * as Helpers from "@/lib/helpers";
