    month: number;
    orders: Array<{
      orderListId: number;
      idOrder: string;
      importCost: number;
      refundAmount: number;
      nccPaymentStatus: string;
      loggedAt: string;
    }>;
  }> = overview?.logOrdersByMonth || [];
  const selectedPayment = unpaidPayments.find((p) => p.id === selectedPaymentId) || unpaidPayments[0] || null;

  // useMemo phải được gọi trước conditional return
  // Còn nợ âm = NCC trả mình → QR dùng STK của tôi; số tiền = số dương.
  const qrImageUrl = useMemo(() => {
    if (!supply || !selectedPayment) return null;
    const raw = Number(selectedPayment.totalImport ?? selectedPayment.import_value ?? 0);
    const paid = Number(selectedPayment.paid ?? 0);
    const supplierName = String(supply.sourceName || "").trim() || "NCC";
    const isNegative = raw < 0;
    const desc = buildNccTransferContentByBalance({
      balanceSigned: raw,
      supplierName,
    });
    const amount = isNegative ? Math.abs(raw) : Math.max(0, raw - paid);
    if (amount <= 0) return null;
    if (isNegative) {
      return Helpers.buildSepayQrUrl({
        accountNumber: ACCOUNT_NO,
        bankCode: BANK_SHORT_CODE,
        amount,
        description: desc,
        accountName: ACCOUNT_NAME,
      });
    }
    if (!supply.numberBank || !supply.binBank) return null;
    return Helpers.buildSepayQrUrl({
      accountNumber: supply.numberBank,
      bankCode: supply.binBank,
      amount,
      description: desc,
      accountName: supply.nameBank || supply.sourceName || "",
    });
  }, [supply, selectedPayment]);

  const amountDueForPayment = (p: { totalImport?: number; import_value?: number; paid?: number }) => {
    const raw = Number(p.totalImport ?? p.import_value ?? 0);
    const paid = Number(p.paid ?? 0);
    if (raw < 0) return Math.max(0, Math.abs(raw) - paid);
    return Math.max(0, raw - paid);
  };

  const paymentContentForConfirm = (p: {
    totalImport?: number;
    import_value?: number;
  }) => {
    const raw = Number(p.totalImport ?? p.import_value ?? 0);
    const supplierName = String(supply?.sourceName || "").trim() || "NCC";
    return buildNccTransferContentByBalance({
      balanceSigned: raw,
      supplierName,
    });
  };

  const handleConfirmPayment = async (p: {
    id: number;
    totalImport?: number;
    import_value?: number;
    paid?: number;
  }) => {
    if (p.id == null || !Number.isFinite(Number(p.id))) return;
    const result = await confirmPayment(p.id, {
      paidAmount: amountDueForPayment(p),
      paymentContent: paymentContentForConfirm(p),
      supplyId: supply?.id,
    });
    if (!result.success) {
      setError(result.error || "Không thể thanh toán chu kỳ");
    }
  };

  const handleClose = () => {
    setSelectedPaymentId(null);
    setExpandedMonth(null);
    onClose();
  };

  // Early return sau khi tất cả hooks đã được gọi
  if (!isOpen || !supplyId) return null;

  const totals = unpaidPayments.reduce(
    (acc, p) => {
      const raw = Number(p.totalImport ?? p.import_value ?? 0);
      const due = amountDueForPayment(p);
      if (raw < 0) {
        acc.supplierRefundToShop += due;
      } else {
        acc.payableToSupplier += due;
      }
      return acc;
    },
    { payableToSupplier: 0, supplierRefundToShop: 0 }
  );
  const totalUnpaid = totals.payableToSupplier;
  const totalSupplierRefund = totals.supplierRefundToShop;
  const monthlyLogOrders = logOrdersByMonth
    .map((item) => ({
      month: Number(item.month) || 0,
      orders: Array.isArray(item.orders) ? item.orders.length : 0,
    }))
    .filter((item) => item.month > 0)
    .sort((a, b) => a.month - b.month);
  const logOrdersByMonthMap = new Map<number, Array<{
    orderListId: number;
    idOrder: string;
    importCost: number;
    refundAmount: number;
    nccPaymentStatus: string;
    loggedAt: string;
  }>>(
    logOrdersByMonth.map((item) => [item.month, item.orders || []])
  );
  const statusLabel = supply?.isActive ? "Đang hoạt động" : "Tạm dừng";
  const statusClass = supply?.isActive ? "bg-emerald-500/20 text-emerald-200" : "bg-gray-500/20 text-gray-200";
  const bankNameResolved =
    supply?.bankName ||
    banks.find((b) => (b.bin || "").trim() === (supply?.binBank || "").trim())?.name ||
    supply?.binBank ||
    "--";
  const statCards = [
    { label: "Tổng đơn", value: stats?.totalOrders ?? 0 },
    { label: "Đã thanh toán", value: stats?.paidOrders ?? 0 },
    { label: "Chưa thanh toán", value: stats?.unpaidOrders ?? 0 },
    { label: "Đã hủy", value: stats?.canceledOrders ?? 0 },
  ];

  return (
    <ModalPortal>
      <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/60 p-2" onClick={handleClose}>
        <div
          className="glass-panel-dark border border-white/5 p-5 md:p-6 rounded-[32px] text-white w-full max-w-4xl max-h-[95vh] shadow-2xl overflow-y-auto custom-scroll"
          onClick={(e) => e.stopPropagation()}
        >
          <div className="flex items-center justify-between">
            <div className="flex-1" />
            <h2 className="text-xl font-bold text-center">Chi tiết Nhà Cung Cấp</h2>
            <div className="flex-1 flex justify-end">
              <button onClick={handleClose} className="p-2 rounded-full hover:bg-white/10 transition text-white/70" aria-label="Đóng">
                <XMarkIcon className="h-6 w-6" />
              </button>
            </div>
          </div>

          {loading ? (
            <div className="mt-6 text-center text-white/70">Đang tải chi tiết...</div>
          ) : error ? (
            <div className="mt-6 bg-rose-500/10 text-rose-200 border border-rose-500/40 rounded-xl p-4 flex items-center justify-between gap-3">
              <span>{error}</span>
              <button onClick={fetchOverview} className="px-3 py-1 rounded-lg bg-rose-500 text-white text-sm hover:bg-rose-600">
                Thử lại
              </button>
            </div>
          ) : (
            <>
              <div className="grid md:grid-cols-2 gap-3 mt-5">
                <div className="bg-white/5 rounded-2xl border border-white/5 p-5 space-y-4">
                  <h3 className="text-[11px] font-bold uppercase tracking-[0.2em] text-indigo-300/80">Thông tin chung</h3>
                  <div className="text-sm text-white/80 space-y-2">
                    <div className="flex justify-between items-center border-b border-white/5 pb-2">
                      <span className="text-white/40">Tên NCC</span>
                      <span className="font-bold text-white">{supply?.sourceName || "--"}</span>
                    </div>
                    <div className="flex justify-between items-center border-b border-white/5 pb-2">
                      <span className="text-white/40">Ngân hàng</span>
                      <span className="font-semibold text-white">{bankNameResolved}</span>
                    </div>
                    <div className="flex justify-between items-center border-b border-white/5 pb-2">
                      <span className="text-white/40">Số tài khoản</span>
                      <span className="font-mono font-semibold text-white">{supply?.numberBank || "--"}</span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-white/40">Trạng thái</span>
                      <span className={`px-2 py-0.5 rounded-full text-[11px] font-bold uppercase ${supply?.isActive ? "text-emerald-400 bg-emerald-500/10" : "text-white/50 bg-white/5"}`}>{statusLabel}</span>
                    </div>
                  </div>
                </div>
                <div className="bg-white/5 rounded-2xl border border-white/5 p-5 space-y-4">
                  <h3 className="text-[11px] font-bold uppercase tracking-[0.2em] text-indigo-300/80">Tổng quan thanh toán</h3>
                  <div className="grid grid-cols-2 gap-3 text-sm text-white/80">
                    <div className="bg-white/5 rounded-xl p-3 border border-white/5 transition-colors hover:bg-white/10">
                      <p className="text-white/50 text-[11px] font-bold uppercase tracking-wider">Đã trả</p>
                      <p className="text-lg font-bold text-white mt-1">{Helpers.formatCurrency(stats?.totalPaidAmount || 0)}</p>
                    </div>
                    <div className="bg-white/5 rounded-xl p-3 border border-white/5 transition-colors hover:bg-white/10">
                      <p className="text-white/50 text-[11px] font-bold uppercase tracking-wider">Còn nợ</p>
                      <p className="text-lg font-bold text-orange-400 mt-1">{Helpers.formatCurrency(totalUnpaid)}</p>
                    </div>
                    <div className="bg-white/5 rounded-xl p-3 border border-white/5 transition-colors hover:bg-white/10">
                      <p className="text-white/50 text-[11px] font-bold uppercase tracking-wider">NCC hoàn tiền</p>
                      <p className="text-lg font-bold text-rose-400 mt-1">{Helpers.formatCurrency(totalSupplierRefund)}</p>
                    </div>
                    <div className="bg-white/5 rounded-xl p-3 border border-white/5 transition-colors hover:bg-white/10">
                      <p className="text-white/50 text-[11px] font-bold uppercase tracking-wider">Nợ đơn</p>
                      <p className="text-lg font-bold text-white mt-1">{stats?.unpaidOrders ?? 0}</p>
                    </div>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-2 mt-3">
                {statCards.map((card) => (
                  <div key={card.label} className="bg-white/5 rounded-lg p-3 border border-white/5">
                    <p className="text-white/50 text-xs">{card.label}</p>
                    <p className="text-xl font-semibold">{card.value}</p>
                  </div>
                ))}
              </div>

              <div className="grid md:grid-cols-2 gap-3 mt-3 items-start">
                {/* Chu kỳ chưa thanh toán + QR code */}
                <div className="bg-white/5 rounded-xl border border-white/10 p-4">
                  <div className="flex items-center justify-between mb-3">
                    <h3 className="text-sm font-semibold text-white/80">Chu kỳ chưa thanh toán</h3>
                    <span className="text-xs text-white/60">
                      Trả NCC {Helpers.formatCurrency(totalUnpaid)} | NCC hoàn {Helpers.formatCurrency(totalSupplierRefund)}
                    </span>
                  </div>
                  {unpaidPayments.length === 0 ? (
                    <p className="text-white/50 text-sm">Không có chu kỳ nợ.</p>
                  ) : (
                    <>
                      {/* Danh sách chu kỳ với nút thanh toán */}
                      <div className="space-y-1.5 max-h-28 overflow-y-auto custom-scroll scroll-overlay mb-3">
                        {unpaidPayments.map((p) => (
                          <div
                            key={p.id}
                            onClick={() => setSelectedPaymentId(p.id)}
                            className={`w-full flex items-center justify-between rounded-lg px-3 py-2 border transition cursor-pointer ${
                              (selectedPayment?.id === p.id) 
                                ? "border-indigo-500 bg-indigo-500/20" 
                                : "border-white/5 bg-white/5 hover:bg-white/10"
                            }`}
                          >
                            <div className="min-w-0 flex-1">
                              <p className="font-semibold text-sm truncate">{p.round || "Chu kỳ"}</p>
                              <p className="text-xs text-white/60">{p.status}</p>
                            </div>
                            <div className="text-right text-sm mr-2">
                              {(() => {
                                const raw = Number(p.totalImport ?? p.import_value ?? 0);
                                const display = amountDueForPayment(p);
                                return (
                                  <>
                                    <p className={raw < 0 ? "text-emerald-400 font-semibold" : "text-rose-400 font-semibold"}>
                                      {Helpers.formatCurrency(display)}{raw < 0 ? " (NCC trả bạn)" : ""}
                                    </p>
                                    <p className="text-white/40 text-xs">Đã trả: {Helpers.formatCurrency(p.paid || 0)}</p>
                                  </>
                                );
                              })()}
                            </div>
                            <button
                              disabled={confirmingId === p.id}
                              onClick={(e) => { e.stopPropagation(); void handleConfirmPayment(p); }}
                              className="px-3 py-1.5 text-xs rounded-lg bg-emerald-500 text-white hover:bg-emerald-600 disabled:opacity-60 font-semibold transition flex-shrink-0"
                            >
                              {confirmingId === p.id ? "..." : "Thanh toán"}
                            </button>
                          </div>
                        ))}
                      </div>

                      {/* QR Code hiển thị trực tiếp */}
                      {selectedPayment && (
                        <div className="flex justify-center mt-2">
                          {qrImageUrl ? (
                            <img src={qrImageUrl} alt="QR" className="w-64 rounded-lg shadow-lg" />
                          ) : (
                            <div className="w-64 h-64 bg-white/10 rounded-lg flex items-center justify-center text-xs text-center p-2">
                              {Number(selectedPayment.totalImport ?? selectedPayment.import_value ?? 0) < 0
                                ? "QR Shop chưa sẵn sàng"
                                : "Thiếu thông tin NH NCC"}
                            </div>
                          )}
                        </div>
                      )}
                    </>
                  )}
                </div>

                {/* Đơn theo tháng */}
                <div className="bg-white/5 rounded-xl border border-white/10 p-4">
                  <div className="flex items-center justify-between mb-3">
                    <h3 className="text-sm font-semibold text-white/80">Đơn theo tháng</h3>
                    <span className="text-xs text-white/60">{monthlyLogOrders.length} tháng</span>
                  </div>
                  {monthlyLogOrders.length === 0 ? (
                    <p className="text-white/50 text-sm">Chưa có dữ liệu đơn trong log.</p>
                  ) : (
                    <div className="space-y-1.5 max-h-80 overflow-y-auto custom-scroll scroll-overlay">
                      {monthlyLogOrders.map((m) => {
                        const monthLogOrders = logOrdersByMonthMap.get(m.month) || [];
                        const isExpanded = expandedMonth === m.month;
                        return (
                          <div key={m.month} className="rounded-lg border border-white/5 bg-white/5">
                            <button
                              type="button"
                              onClick={() => setExpandedMonth((prev) => (prev === m.month ? null : m.month))}
                              className="w-full flex items-center justify-between px-3 py-2 hover:bg-white/5 transition"
                            >
                              <span className="text-sm font-semibold">Tháng {m.month}</span>
                              <span className="text-sm">{m.orders} đơn</span>
                            </button>
                            {isExpanded && (
                              <div className="border-t border-white/5 px-3 py-2 space-y-1.5 bg-black/10">
                                {monthLogOrders.length === 0 ? (
                                  <p className="text-xs text-white/50">Chưa có đơn log trong tháng này.</p>
                                ) : (
                                  monthLogOrders.map((order) => (
                                    <div key={`${m.month}-${order.orderListId}-${order.idOrder}`} className="rounded-md border border-white/10 px-2 py-1.5">
                                      <p className="text-xs font-semibold text-white/90 truncate">{order.idOrder || `#${order.orderListId}`}</p>
                                      <p className="text-[11px] text-white/60 truncate">{order.nccPaymentStatus || "—"}</p>
                                      <p className="text-[11px] text-emerald-300 mt-0.5">
                                        Chi phí: {Helpers.formatCurrency(order.importCost)}
                                      </p>
                                    </div>
                                  ))
                                )}
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              </div>

              <div className="mt-4 text-right">
                <button onClick={handleClose} className="px-10 py-2.5 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 text-white font-bold transition-all active:scale-95">
                  Đóng
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    </ModalPortal>
  );
};

export default SupplierDetailModal;

import React from "react";
import { PowerIcon, EyeIcon, PencilSquareIcon, TrashIcon } from "@heroicons/react/24/outline";
import * as Helpers from "@/lib/helpers";
import { Supply } from "../types";
import PaymentHistoryTable from "./PaymentHistoryTable";

const formatCurrency = Helpers.formatCurrency;
const formatDate = (date: string | null) => (date ? Helpers.formatDateToDMY(date) : "--");

interface Props {
  supplies: Supply[];
  loading: boolean;
  expandedId: number | null;
  onToggle: (id: number) => void;
  onEdit: (supply: Supply) => void;
  onDelete: (supply: Supply) => void;
  onView: (supply: Supply) => void;
  onToggleStatus: (supply: Supply) => void;
  onRefreshSupplies: () => void;
}

import { ResponsiveTable, TableCard } from "@/components/ui/ResponsiveTable";
import { SupplyCard } from "./SupplyCard";

const SupplyList: React.FC<Props> = ({
  supplies,
  loading,
  expandedId,
  onToggle,
  onEdit,
  onDelete,
  onView,
  onToggleStatus,
  onRefreshSupplies,
}) => {
  return (
    <div className="supply-list glass-panel-dark border border-white/5 rounded-[32px] overflow-hidden shadow-2xl backdrop-blur-xl">
      <ResponsiveTable
        className="supply-list__inner"
        showCardOnMobile={true}
        cardView={
            loading ? (
                <div className="p-8 text-center text-white/50">Đang tải...</div>
            ) : supplies.length === 0 ? (
                <div className="p-8 text-center text-white/50">Chưa có nhà cung cấp nào</div>
            ) : (
                <TableCard
                    data={supplies as unknown as Record<string, unknown>[]}
                    renderCard={(item) => (
                        <SupplyCard
                            supply={item as unknown as Supply}
                            onToggleStatus={onToggleStatus}
                            onView={onView}
                        /*... callback props ...*/
                            onEdit={onEdit}
                            onDelete={onDelete}
                        />
                    )}
                    className="p-4"
                />
            )
        }
      >
        <table className="supply-list__table w-full text-left">
          <thead className="supply-list__head bg-white/5 text-[10px] uppercase text-indigo-300/40 font-bold tracking-[0.2em]">
            <tr>
              <th className="supply-list__th px-4 py-3">Nhà cung cấp</th>
              <th className="px-4 py-3">Tài khoản</th>
              <th className="px-4 py-3">Tháng này</th>
              <th className="px-4 py-3">Lần cuối</th>
              <th className="px-4 py-3">Đã trả</th>
              <th className="px-4 py-3">Chưa Thanh Toán</th>
              <th className="px-4 py-3 text-center">TT</th>
              <th className="px-4 py-3 text-right">Thao tác</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-white/5">
            {loading ? (
              <tr>
                <td colSpan={8} className="text-center py-8 text-white/50">
                  Đang tải...
                </td>
              </tr>
            ) : supplies.length === 0 ? (
                <tr>
                    <td colSpan={8} className="text-center py-8 text-white/50">
                        Chưa có nhà cung cấp nào
                    </td>
                </tr>
            ) : (
              supplies.map((supply) => (
                <SupplyRow
                  key={supply.id}
                  supply={supply}
                  isExpanded={expandedId === supply.id}
                  onToggle={onToggle}
                  onEdit={onEdit}
                  onDelete={onDelete}
                  onView={onView}
                  onToggleStatus={onToggleStatus}
                  onRefreshSupplies={onRefreshSupplies}
                />
              ))
            )}
          </tbody>
        </table>
      </ResponsiveTable>
    </div>
  );
};

const SupplyRow = ({
  supply,
  isExpanded,
  onToggle,
  onEdit,
  onDelete,
  onView,
  onToggleStatus,
  onRefreshSupplies,
}: {
  supply: Supply;
  isExpanded: boolean;
  onToggle: (id: number) => void;
  onEdit: (supply: Supply) => void;
  onDelete: (supply: Supply) => void;
  onView: (supply: Supply) => void;
  onToggleStatus: (supply: Supply) => void;
  onRefreshSupplies: () => void;
}) => {
  const netUnpaid = Number(supply.totalUnpaidImport ?? 0);

  return (
    <>
      <tr
        className="bg-gradient-to-r from-indigo-950/70 via-slate-900/60 to-indigo-950/70 hover:bg-white/5 cursor-pointer transition border-b border-white/5"
        onClick={() => onToggle(supply.id)}
      >
        <td className="px-4 py-4">
          <div className="font-medium text-white">{supply.sourceName || "Không Tên"}</div>
          <div className="text-xs text-white/60">Tổng đơn: {supply.totalOrders}</div>
        </td>
        <td className="px-4 py-4 text-white/80 text-sm">
          <div>{supply.numberBank || "--"}</div>
          <div className="text-xs text-white/50">{supply.bankName}</div>
        </td>
        <td className="px-4 py-4 text-white/80 text-sm">
          <div>{supply.monthlyOrders} Đơn</div>
          <div className="text-xs text-emerald-400">{formatCurrency(supply.monthlyImportValue)}</div>
        </td>
        <td className="px-4 py-4 text-white/80 text-sm">{formatDate(supply.lastOrderDate)}</td>
        <td className="px-4 py-4 text-white/80 text-sm">{formatCurrency(supply.totalPaidImport)}</td>
        <td className="px-4 py-4 text-sm">
          {netUnpaid === 0 ? (
            <span className="text-white/60">0 ₫</span>
          ) : (
            <span
              className={`font-semibold tabular-nums ${
                netUnpaid > 0 ? "text-emerald-400" : "text-rose-400"
              }`}
            >
              {formatCurrency(netUnpaid)}
            </span>
          )}
        </td>
        <td className="px-4 py-4 text-center">
          <button
            onClick={(e) => {
              e.stopPropagation();
              onToggleStatus(supply);
            }}
            className={`w-8 h-8 rounded-xl flex items-center justify-center transition-all active:scale-90 ${
              supply.isActive ? "bg-emerald-500 text-white shadow-[0_0_12px_rgba(16,185,129,0.3)]" : "bg-white/5 text-white/30 border border-white/10"
            }`}
          >
            <PowerIcon className="h-4 w-4" />
          </button>
        </td>
        <td className="px-4 py-4 text-right">
          <div className="flex justify-end gap-2">
            <button
              onClick={(e) => {
                e.stopPropagation();
                onView(supply);
              }}
              className="p-1.5 rounded-lg bg-white/5 text-blue-400 border border-white/10 hover:bg-blue-500/10 hover:border-blue-500/30 transition-all active:scale-90"
            >
              <EyeIcon className="h-4 w-4" />
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onEdit(supply);
              }}
              className="p-1.5 rounded-lg bg-white/5 text-emerald-400 border border-white/10 hover:bg-emerald-500/10 hover:border-emerald-500/30 transition-all active:scale-90"
            >
              <PencilSquareIcon className="h-4 w-4" />
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onDelete(supply);
              }}
              className="p-1.5 rounded-lg bg-white/5 text-rose-400 border border-white/10 hover:bg-rose-500/10 hover:border-rose-500/30 transition-all active:scale-90"
            >
              <TrashIcon className="h-4 w-4" />
            </button>
          </div>
        </td>
      </tr>

      {isExpanded && (
        <tr>
          <td colSpan={8} className="px-0 pb-4 pt-0 bg-indigo-950/30">
            <div className="p-4 border-b border-white/10 shadow-inner">
              <PaymentHistoryTable supplyId={supply.id} />
            </div>
          </td>
        </tr>
      )}
    </>
  );
};

export default SupplyList;

import React, { useCallback, useEffect, useRef, useState } from "react";
import { PencilIcon } from "@heroicons/react/24/outline";
import * as Helpers from "@/lib/helpers";
import { apiFetch } from "@/lib/api";
import {
  fetchSupplyOrderCosts,
  type SupplyOrderCostAggregates,
  type SupplyOrderCostRow,
} from "@/lib/suppliesApi";
import ExternalImportLogModal from "./ExternalImportLogModal";
import EditTraceCodeModal from "./EditTraceCodeModal";
import { ResponsiveTable } from "@/components/ui/ResponsiveTable";
import type { Supply } from "../types";
import { showAppNotification } from "@/lib/notifications";

const formatCurrency = Helpers.formatCurrency;
const formatUpdateDate = (row: SupplyOrderCostRow) => {
  const raw = row.canceledAt || row.orderDate;
  if (!raw) return "--";
  return Helpers.formatDateToDMY(raw) || String(raw);
};

const PAGE_SIZE = 80;

const EMPTY_AGG: SupplyOrderCostAggregates = {
  orderCount: 0,
  totalCost: 0,
  totalRefund: 0,
};

type Props = {
  supplies: Supply[];
  onAggregatesChange?: (aggregates: SupplyOrderCostAggregates) => void;
};

type ExternalImportLogItem = {
  id: number;
  amount: number;
  reason: string;
  linkedOrderCode: string | null;
  expenseDate: string | null;
  createdAt: string | null;
  expenseType: "external_import" | "mavn_import" | string;
  traceCode: string | null;
};

const SupplyOrderCostsPanel: React.FC<Props> = ({ supplies, onAggregatesChange }) => {
  const onAggregatesRef = useRef(onAggregatesChange);
  onAggregatesRef.current = onAggregatesChange;
  const [activeTab, setActiveTab] = useState<"nccCosts" | "externalImport">("nccCosts");

  const [supplyId, setSupplyId] = useState<string>("");
  const [q, setQ] = useState("");
  const [qApplied, setQApplied] = useState("");
  const [offset, setOffset] = useState(0);
  const [rows, setRows] = useState<SupplyOrderCostRow[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);
  const [createLogOpen, setCreateLogOpen] = useState(false);
  const [externalLogs, setExternalLogs] = useState<ExternalImportLogItem[]>([]);
  const [externalLoading, setExternalLoading] = useState(false);
  const [externalError, setExternalError] = useState<string | null>(null);
  const [editTraceTarget, setEditTraceTarget] =
    useState<ExternalImportLogItem | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const sid =
        supplyId !== "" && supplyId !== "all"
          ? Number.parseInt(supplyId, 10)
          : null;
      const data = await fetchSupplyOrderCosts({
        limit: PAGE_SIZE,
        offset,
        supplyId: sid != null && Number.isFinite(sid) ? sid : null,
        q: qApplied,
      });
      setRows(data.rows || []);
      setTotal(Number(data.total) || 0);
      onAggregatesRef.current?.(data.aggregates ?? EMPTY_AGG);
    } catch (e) {
      showAppNotification({
        type: "error",
        title: "Lỗi tải dữ liệu",
        message: e instanceof Error ? e.message : "Không thể tải danh sách chi phí NCC.",
      });
      setRows([]);
      setTotal(0);
      onAggregatesRef.current?.(EMPTY_AGG);
    } finally {
      setLoading(false);
    }
  }, [offset, qApplied, supplyId]);

  useEffect(() => {
    if (activeTab !== "nccCosts") return;
    void load();
  }, [activeTab, load]);

  const loadExternalLogs = useCallback(async () => {
    setExternalLoading(true);
    setExternalError(null);
    try {
      const response = await apiFetch(
        "/api/store-profit-expenses?expense_type=external_import,mavn_import"
      );
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`);
      }
      const payload = await response.json();
      const items = Array.isArray(payload?.items) ? payload.items : [];
      setExternalLogs(
        items.map((item) => ({
          id: Number(item.id || 0),
          amount: Number(item.amount || 0),
          reason: String(item.reason || ""),
          linkedOrderCode: item.linkedOrderCode ? String(item.linkedOrderCode) : null,
          expenseDate: item.expenseDate || null,
          createdAt: item.createdAt || null,
          expenseType: String(item.expenseType || "external_import"),
          traceCode: item.traceCode ? String(item.traceCode) : null,
        }))
      );
    } catch (error) {
      console.error("Failed to load external import logs:", error);
      setExternalLogs([]);
      setExternalError("Không thể tải log nhập hàng ngoài luồng.");
    } finally {
      setExternalLoading(false);
    }
  }, []);

  useEffect(() => {
    if (activeTab !== "externalImport") return;
    void loadExternalLogs();
  }, [activeTab, loadExternalLogs]);

  const onSearch = () => {
    setOffset(0);
    setQApplied(q.trim());
  };

  const canPrev = offset > 0;
  const canNext = offset + rows.length < total;

  return (
    <div className="space-y-4">
      <div className="rounded-2xl border border-indigo-500/25 bg-indigo-950/25 p-2 backdrop-blur-xl">
        <div className="grid min-h-[2.75rem] grid-cols-2 gap-2">
          {(
            [
              { key: "nccCosts" as const, label: "Chi phí NCC theo đơn" },
              { key: "externalImport" as const, label: "Nhập hàng ngoài luồng" },
            ] as const
          ).map((tab) => {
            const isActive = activeTab === tab.key;
            return (
              <button
                key={tab.key}
                type="button"
                onClick={() => setActiveTab(tab.key)}
                className={`w-full rounded-xl px-3 py-2.5 text-xs font-bold uppercase tracking-[0.08em] transition-all sm:text-sm ${
                  isActive
                    ? "border border-indigo-300/40 bg-gradient-to-br from-indigo-500/85 via-indigo-600/55 to-violet-700/45 text-white shadow-[0_10px_28px_-6px_rgba(99,102,241,0.45)]"
                    : "border border-transparent text-indigo-200/65 hover:border-indigo-500/25 hover:bg-indigo-900/25 hover:text-indigo-100/95"
                }`}
              >
                {tab.label}
              </button>
            );
          })}
        </div>
      </div>

      <div className="flex flex-col gap-3 sm:flex-row sm:flex-wrap sm:items-end">
        {activeTab === "nccCosts" ? (
          <>
            <label className="flex min-w-[200px] flex-col gap-1 text-xs text-white/50">
              Nhà cung cấp
              <select
                value={supplyId === "" ? "all" : supplyId}
                onChange={(e) => {
                  const v = e.target.value;
                  setSupplyId(v === "all" ? "" : v);
                  setOffset(0);
                }}
                className="rounded-xl border border-white/10 bg-slate-950/60 px-3 py-2 text-sm text-white focus:border-indigo-400/60 focus:outline-none"
              >
                <option value="all">Tất cả NCC</option>
                {supplies.map((s) => (
                  <option key={s.id} value={String(s.id)}>
                    {s.sourceName}
                  </option>
                ))}
              </select>
            </label>
            <label className="flex min-w-[180px] flex-1 flex-col gap-1 text-xs text-white/50">
              Mã đơn
              <input
                type="text"
                value={q}
                onChange={(e) => setQ(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") onSearch();
                }}
                placeholder="Tìm theo mã đơn..."
                className="rounded-xl border border-white/10 bg-slate-950/60 px-3 py-2 text-sm text-white placeholder:text-white/30 focus:border-indigo-400/60 focus:outline-none"
              />
            </label>
          </>
        ) : (
          <div className="min-w-[280px] flex-1 rounded-xl border border-white/10 bg-slate-950/45 px-3 py-2 text-sm text-white/70">
            Danh sách log nhập hàng ngoài luồng
          </div>
        )}
        <div className="flex gap-2">
          <button
            type="button"
            onClick={() => setCreateLogOpen(true)}
            className="rounded-xl border border-emerald-400/40 bg-emerald-600/25 px-4 py-2 text-sm font-semibold text-white hover:bg-emerald-500/40"
          >
            Tạo log nhập hàng
          </button>
          {activeTab === "nccCosts" ? (
            <>
              <button
                type="button"
                onClick={onSearch}
                className="rounded-xl border border-indigo-400/40 bg-indigo-600/40 px-4 py-2 text-sm font-semibold text-white hover:bg-indigo-500/50"
              >
                Tìm
              </button>
              <button
                type="button"
                onClick={() => {
                  setQ("");
                  setQApplied("");
                  setSupplyId("");
                  setOffset(0);
                }}
                className="rounded-xl border border-white/15 px-4 py-2 text-sm text-white/80 hover:bg-white/5"
              >
                Xóa lọc
              </button>
            </>
          ) : null}
        </div>
      </div>

      <ExternalImportLogModal
        isOpen={createLogOpen}
        onClose={() => setCreateLogOpen(false)}
        onSuccess={() => {
          setCreateLogOpen(false);
          if (activeTab === "externalImport") {
            void loadExternalLogs();
          }
          showAppNotification({
            type: "success",
            title: "Đã tạo log nhập hàng",
            message: "Log chi phí ngoài luồng đã được ghi nhận.",
          });
        }}
      />

      <EditTraceCodeModal
        isOpen={Boolean(editTraceTarget)}
        expenseId={editTraceTarget?.id ?? 0}
        initialTraceCode={editTraceTarget?.traceCode ?? ""}
        initialReason={editTraceTarget?.reason ?? ""}
        onClose={() => setEditTraceTarget(null)}
        onSaved={() => {
          setEditTraceTarget(null);
          void loadExternalLogs();
          showAppNotification({
            type: "success",
            title: "Đã lưu mã trace",
            message: "Mã trace cho log nhập hàng đã được cập nhật.",
          });
        }}
      />

      <div className="glass-panel-dark border border-white/5 rounded-[32px] overflow-hidden shadow-2xl backdrop-blur-xl">
        <ResponsiveTable className="supply-order-costs__inner" showCardOnMobile={false}>
          <table className="w-full text-left">
            {activeTab === "nccCosts" ? (
              <>
                <thead className="bg-white/5 text-[10px] uppercase text-indigo-300/40 font-bold tracking-[0.2em]">
                  <tr>
                    <th className="px-4 py-3 w-14">STT</th>
                    <th className="px-4 py-3">NCC</th>
                    <th className="px-4 py-3">Đơn</th>
                    <th className="px-4 py-3">Tiền nhập</th>
                    <th className="px-4 py-3">Tiền hoàn</th>
                    <th className="px-4 py-3">Trạng thái</th>
                    <th className="px-4 py-3">Ngày cập nhật</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {loading ? (
                    <tr>
                      <td colSpan={7} className="px-4 py-10 text-center text-white/50">
                        Đang tải...
                      </td>
                    </tr>
                  ) : rows.length === 0 ? (
                    <tr>
                      <td colSpan={7} className="px-4 py-10 text-center text-white/50">
                        Không có dòng nào.
                      </td>
                    </tr>
                  ) : (
                    rows.map((row, idx) => (
                      <tr key={row.orderPk || `${row.idOrder}-${idx}`} className="text-sm text-white/90">
                        <td className="px-4 py-3 text-white/50">{offset + idx + 1}</td>
                        <td className="px-4 py-3">{row.supplierName || "—"}</td>
                        <td className="px-4 py-3 font-mono text-xs">{row.idOrder || "—"}</td>
                        <td className="px-4 py-3 text-emerald-300/90">{formatCurrency(row.cost)}</td>
                        <td className="px-4 py-3 text-amber-200/90">{formatCurrency(row.refund)}</td>
                        <td className="px-4 py-3">
                          <span
                            className={
                              String(row.nccPaymentStatus || "").includes("Đã")
                                ? "rounded-lg bg-emerald-500/20 px-2 py-0.5 text-xs font-semibold text-emerald-200"
                                : "rounded-lg bg-amber-500/15 px-2 py-0.5 text-xs font-semibold text-amber-100/90"
                            }
                          >
                            {row.nccPaymentStatus || "Chưa Thanh Toán"}
                          </span>
                        </td>
                        <td className="px-4 py-3 text-white/70">{formatUpdateDate(row)}</td>
                      </tr>
                    ))
                  )}
                </tbody>
              </>
            ) : (
              <>
                <thead className="bg-white/5 text-[10px] uppercase text-indigo-300/40 font-bold tracking-[0.2em]">
                  <tr>
                    <th className="px-4 py-3 w-14">STT</th>
                    <th className="px-4 py-3">Ngày tạo</th>
                    <th className="px-4 py-3">Nguồn</th>
                    <th className="px-4 py-3">Số tiền nhập</th>
                    <th className="px-4 py-3">Mã đơn liên kết</th>
                    <th className="px-4 py-3">Lý do</th>
                    <th className="px-4 py-3">Mã trace</th>
                    <th className="px-4 py-3 w-20 text-center">Thao tác</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {externalLoading ? (
                    <tr>
                      <td colSpan={8} className="px-4 py-10 text-center text-white/50">
                        Đang tải log nhập hàng...
                      </td>
                    </tr>
                  ) : externalError ? (
                    <tr>
                      <td colSpan={8} className="px-4 py-10 text-center text-rose-200">
                        {externalError}
                      </td>
                    </tr>
                  ) : externalLogs.length === 0 ? (
                    <tr>
                      <td colSpan={8} className="px-4 py-10 text-center text-white/50">
                        Chưa có log nhập hàng ngoài luồng.
                      </td>
                    </tr>
                  ) : (
                    externalLogs.map((log, idx) => {
                      const isMavnImport = log.expenseType === "mavn_import";
                      return (
                        <tr key={log.id || idx} className="text-sm text-white/90">
                          <td className="px-4 py-3 text-white/50">{idx + 1}</td>
                          <td className="px-4 py-3 text-white/70">
                            {Helpers.formatDateToDMY(log.expenseDate || log.createdAt || "") || "—"}
                          </td>
                          <td className="px-4 py-3">
                            <span
                              className={
                                isMavnImport
                                  ? "rounded-lg bg-violet-500/15 px-2 py-0.5 text-[11px] font-semibold uppercase tracking-[0.08em] text-violet-200"
                                  : "rounded-lg bg-emerald-500/15 px-2 py-0.5 text-[11px] font-semibold uppercase tracking-[0.08em] text-emerald-200"
                              }
                            >
                              {isMavnImport ? "MAVN AUTO" : "MANUAL"}
                            </span>
                          </td>
                          <td className="px-4 py-3 text-emerald-300/90">
                            {formatCurrency(log.amount)}
                          </td>
                          <td className="px-4 py-3 font-mono text-xs text-indigo-200/90">
                            {log.linkedOrderCode || "—"}
                          </td>
                          <td className="px-4 py-3">{log.reason || "—"}</td>
                          <td className="px-4 py-3 font-mono text-xs text-amber-200/90">
                            {log.traceCode || "—"}
                          </td>
                          <td className="px-4 py-3 text-center">
                            <button
                              type="button"
                              onClick={() => setEditTraceTarget(log)}
                              title="Sửa mã trace"
                              aria-label="Sửa mã trace"
                              className="inline-flex items-center justify-center rounded-lg border border-amber-400/30 bg-amber-500/10 p-1.5 text-amber-200 transition-colors hover:border-amber-300/60 hover:bg-amber-500/20"
                            >
                              <PencilIcon className="h-4 w-4" />
                            </button>
                          </td>
                        </tr>
                      );
                    })
                  )}
                </tbody>
              </>
            )}
          </table>
        </ResponsiveTable>
        {activeTab === "nccCosts" ? (
          <div className="flex flex-wrap items-center justify-between gap-2 border-t border-white/5 px-4 py-3 text-xs text-white/50">
            <span>
              {total > 0 ? (
                <>
                  Hiển thị {offset + 1}–{offset + rows.length} / {total}
                </>
              ) : (
                <>Không có bản ghi</>
              )}
            </span>
            <div className="flex gap-2">
              <button
                type="button"
                disabled={!canPrev || loading}
                onClick={() => setOffset((o) => Math.max(0, o - PAGE_SIZE))}
                className="rounded-lg border border-white/10 px-3 py-1.5 text-white/80 enabled:hover:bg-white/5 disabled:opacity-40"
              >
                Trước
              </button>
              <button
                type="button"
                disabled={!canNext || loading}
                onClick={() => setOffset((o) => o + PAGE_SIZE)}
                className="rounded-lg border border-white/10 px-3 py-1.5 text-white/80 enabled:hover:bg-white/5 disabled:opacity-40"
              >
                Sau
              </button>
            </div>
          </div>
        ) : (
          <div className="border-t border-white/5 px-4 py-3 text-xs text-white/50">
            Tổng log ngoài luồng: {externalLogs.length}
          </div>
        )}
      </div>
    </div>
  );
};

export default SupplyOrderCostsPanel;

import { useEffect, useState } from "react";
import { apiFetch } from "@/lib/api";
import type { BankOption } from "../types";

export function useBanks() {
  const [banks, setBanks] = useState<BankOption[]>([]);

  useEffect(() => {
    let cancelled = false;

    apiFetch("/api/banks")
      .then((response) => response.json())
      .then((data) => {
        if (!cancelled && Array.isArray(data)) {
          setBanks(
            data.map((bank: any) => ({
              bin: bank.bin,
              name:
                bank.bank_name ||
                bank.bankName ||
                bank.name ||
                bank.bank ||
                bank.bin,
            }))
          );
        }
      })
      .catch(console.error);

    return () => {
      cancelled = true;
    };
  }, []);

  return { banks };
}

import { useState } from "react";
import { apiFetch } from "@/lib/api";
import { buildSepayQrUrl } from "../utils/supplies";
import {
  ACCOUNT_NAME,
  ACCOUNT_NO,
  BANK_SHORT_CODE,
} from "@/components/modals/ViewOrderModal/constants";
import { buildNccTransferContentByBalance } from "@/features/supply/utils/supplierPaymentContent";

export interface QrPayment {
  id: number;
  amount: number;
  url: string;
  round: string;
}

interface PaymentInput {
  id: number;
  totalImport?: number;
  paid?: number;
  round?: string;
}

interface SupplyBankInfo {
  numberBank?: string | null;
  binBank?: string | null;
  sourceName?: string | null;
  nameBank?: string | null;
}

export const usePayments = ({
  supply,
  fetchOverview,
  onRefreshList,
}: {
  supply?: SupplyBankInfo | null;
  fetchOverview: () => Promise<void> | void;
  onRefreshList?: () => void;
}) => {
  const [confirmingId, setConfirmingId] = useState<number | null>(null);
  const [qrPayment, setQrPayment] = useState<QrPayment | null>(null);

  const confirmPayment = async (
    paymentId: number,
    opts?: { paidAmount?: number; paymentContent?: string; supplyId?: number }
  ) => {
    setConfirmingId(paymentId);
    try {
      const paidAmount = opts?.paidAmount;
      const paymentContent = typeof opts?.paymentContent === "string"
        ? opts.paymentContent.trim()
        : "";
      const bodyPayload: Record<string, unknown> = {};
      if (paidAmount != null && Number.isFinite(paidAmount) && paidAmount > 0) {
        bodyPayload.paidAmount = Math.round(paidAmount);
      }
      if (paymentContent) {
        bodyPayload.paymentContent = paymentContent;
      }
      if (opts?.supplyId != null && Number.isFinite(opts.supplyId) && opts.supplyId > 0) {
        bodyPayload.supplyId = Math.round(opts.supplyId);
      }
      const body =
        Object.keys(bodyPayload).length > 0
          ? JSON.stringify(bodyPayload)
          : undefined;
      const res = await apiFetch(`/api/payment-supply/${paymentId}/confirm`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        ...(body !== undefined ? { body } : {}),
      });
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data?.error || "Không thể thanh toán chu kỳ");
      }
      await fetchOverview();
      setQrPayment(null);
      onRefreshList?.();
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err?.message || "Không thể thanh toán chu kỳ" };
    } finally {
      setConfirmingId(null);
    }
  };

  const showQrForPayment = (payment: PaymentInput) => {
    const diff = (payment.totalImport || 0) - (payment.paid || 0);
    const amount = Math.abs(diff);
    const isPositive = diff > 0;
    const supplierName = String(supply?.sourceName || "").trim() || "NCC";

    const accountNumber = isPositive ? supply?.numberBank || "" : ACCOUNT_NO;
    const bankCode = isPositive ? supply?.binBank || "" : BANK_SHORT_CODE; // VietQR short code
    const accountName = isPositive ? supply?.nameBank || "" : ACCOUNT_NAME;

    const description = buildNccTransferContentByBalance({
      balanceSigned: diff,
      supplierName,
    });

    const url = buildSepayQrUrl({
      accountNumber,
      bankCode,
      amount,
      description,
      accountName,
    });

    setQrPayment({
      id: payment.id,
      amount,
      url,
      round: payment.round || "",
    });
  };

  return { confirmingId, qrPayment, confirmPayment, showQrForPayment, setQrPayment };
};

import { useCallback, useEffect, useState } from "react";
import { apiFetch } from "@/lib/api";

export const useSupplyDetail = (supplyId: number | null, isOpen: boolean) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [overview, setOverview] = useState<any>(null);

  const fetchOverview = useCallback(async () => {
    if (!supplyId) return;
    setLoading(true);
    setError(null);
    try {
      const res = await apiFetch(`/api/supplies/${supplyId}/overview`);
      const data = await res.json();
      if (!res.ok) throw new Error(data?.error || "Không tải được chi tiết");
      setOverview(data);
    } catch (err: any) {
      setError(err?.message || "Đã có lỗi xảy ra");
    } finally {
      setLoading(false);
    }
  }, [supplyId]);

  useEffect(() => {
    if (isOpen && supplyId) {
      fetchOverview();
    } else if (!isOpen) {
      setOverview(null);
      setError(null);
    }
  }, [isOpen, supplyId, fetchOverview]);

  return { overview, loading, error, fetchOverview, setError };
};

import { useCallback, useState } from "react";
import { apiFetch } from "@/lib/api";
import { Supply, SupplyStats } from "../types";
import { showAppNotification } from "@/lib/notifications";

export const useSupplyList = () => {
  const [supplies, setSupplies] = useState<Supply[]>([]);
  const [stats, setStats] = useState<SupplyStats>({
    totalSuppliers: 0,
    activeSuppliers: 0,
    monthlyOrders: 0,
    totalImportValue: 0,
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchSupplies = useCallback(async () => {
    setLoading(true);
    try {
      const res = await apiFetch("/api/supply-insights");
      if (!res.ok) throw new Error("Lỗi tải dữ liệu");
      const data = await res.json();

      const items: Supply[] = (data.supplies || []).map((item: any) => {
        const isActive = item.isActive ?? (item.status !== "inactive" && item.status !== "tạm dừng");
        return {
          ...item,
          isActive,
          status: isActive ? "active" : "inactive",
          products: Array.isArray(item.products) ? item.products.filter(Boolean) : [],
        };
      });

      setSupplies(items);
      setStats({
        totalSuppliers: Number(data.stats?.totalSuppliers) || 0,
        activeSuppliers: Number(data.stats?.activeSuppliers) || items.filter((i) => i.isActive).length,
        monthlyOrders: Number(data.stats?.monthlyOrders) || 0,
        totalImportValue: Number(data.stats?.totalImportValue) || 0,
      });
    } catch (err) {
      setError(err instanceof Error ? err.message : "Lỗi không xác định");
    } finally {
      setLoading(false);
    }
  }, []);

  const toggleStatus = async (id: number, currentStatus: boolean) => {
    setSupplies((prev) =>
      prev.map((s) => (s.id === id ? { ...s, isActive: !currentStatus, status: !currentStatus ? "active" : "inactive" } : s))
    );
    try {
      await apiFetch(`/api/supplies/${id}/active`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ isActive: !currentStatus }),
      });
      await fetchSupplies();
    } catch {
      setSupplies((prev) =>
        prev.map((s) =>
          s.id === id
            ? {
                ...s,
                isActive: currentStatus,
                status: currentStatus ? "active" : "inactive",
              }
            : s
        )
      );
      showAppNotification({
        type: "error",
        title: "Lỗi cập nhật trạng thái",
        message: "Không thể cập nhật trạng thái",
      });
    }
  };

  return { supplies, stats, loading, error, fetchSupplies, setSupplies, toggleStatus };
};

import type { Order } from "@/constants";
import { apiGet } from "@/lib/api";

export const TAX_ORDER_START_DATE = "2026-04-22";
const TAX_ORDER_PREFIXES = ["MAVC", "MAVL", "MAVK", "MAVS"];

export type TaxOrder = Pick<
  Order,
  | "id"
  | "id_order"
  | "id_product"
  | "product_display_name"
  | "order_date"
  | "registration_date"
  | "registration_date_display"
  | "days"
  | "price"
  | "cost"
  | "status"
  | "canceled_at"
> & {
  created_at?: string | null;
  created_at_raw?: string | null;
  /** Tiền hoàn trên đơn (DB `order_list.refund`). */
  refund?: string | number | null;
};

export const fetchTaxOrders = (
  from: string = TAX_ORDER_START_DATE
): Promise<TaxOrder[]> =>
  apiGet<TaxOrder[]>(`/api/orders/tax?from=${encodeURIComponent(from)}`);

const normalizeYmd = (value: unknown) => {
  if (value == null) return "";
  const match = String(value).match(/^(\d{4})-(\d{2})-(\d{2})/);
  return match ? `${match[1]}-${match[2]}-${match[3]}` : "";
};

const getTaxOrderDate = (order: TaxOrder) =>
  normalizeYmd(order.created_at_raw || order.created_at) ||
  normalizeYmd(order.registration_date || order.order_date);

const isTaxOrderCode = (order: TaxOrder) => {
  const orderCode = String(order.id_order || "").trim().toUpperCase();
  return TAX_ORDER_PREFIXES.some((prefix) => orderCode.startsWith(prefix));
};

export const fetchTaxOrdersWithFallback = async (
  from: string = TAX_ORDER_START_DATE
): Promise<TaxOrder[]> => {
  try {
    return await fetchTaxOrders(from);
  } catch (error) {
    const legacyOrders = await apiGet<TaxOrder[]>("/api/orders");
    return legacyOrders.filter((order) => {
      const orderDate = getTaxOrderDate(order);
      return orderDate >= from && isTaxOrderCode(order);
    });
  }
};

import React, { useMemo } from "react";
import { ArrowPathIcon } from "@heroicons/react/24/outline";
import type { TaxOrder } from "../api/taxApi";

type FixedColumnKey = "orderCode" | "productCode" | "term" | "startDate" | "amount";

type FixedColumn = {
  key: FixedColumnKey;
  label: string;
  width: number;
  left: number;
};

export type TaxViewMode = "day" | "month";
export type TaxMetric = "revenue" | "profit" | "refund";

type PeriodColumn = {
  key: string;
  label: string;
  year: number;
  startKey: string;
  endKey: string;
};

type TaxFormRow = {
  id: string;
  orderCode: string;
  productCode: string;
  term: string;
  termDays: number;
  startDate: string;
  refundDate: string;
  status: string;
  price: number;
  cost: number;
  refund: number;
};

const TAX_START_DATE = new Date(2026, 3, 22);

const FIXED_COLUMNS: FixedColumn[] = [
  { key: "orderCode", label: "Mã Đơn Hàng", width: 154, left: 0 },
  { key: "productCode", label: "Mã Sản Phẩm", width: 154, left: 154 },
  { key: "term", label: "Thời hạn", width: 116, left: 308 },
  { key: "startDate", label: "Ngày bắt đầu", width: 136, left: 424 },
  { key: "amount", label: "Số tiền", width: 142, left: 560 },
];

const DATE_COLUMN_WIDTH = 102;
const REMAINING_COLUMN_WIDTH = 136;
const DATA_ROW_HEIGHT = 37;
const DATA_VISIBLE_ROWS = 10;
const FIXED_COLUMNS_WIDTH = FIXED_COLUMNS.reduce(
  (total, column) => total + column.width,
  0
);

const moneyFormatter = new Intl.NumberFormat("vi-VN");

const getDateKey = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
};

const buildDateColumns = (): PeriodColumn[] => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const start = new Date(TAX_START_DATE);
  start.setHours(0, 0, 0, 0);

  if (today < start) {
    return [];
  }

  const columns: PeriodColumn[] = [];
  const cursor = new Date(start);

  while (cursor <= today) {
    columns.push({
      key: getDateKey(cursor),
      label: `${cursor.getDate()}/${cursor.getMonth() + 1}`,
      year: cursor.getFullYear(),
      startKey: getDateKey(cursor),
      endKey: getDateKey(cursor),
    });
    cursor.setDate(cursor.getDate() + 1);
  }

  return columns;
};

const buildMonthColumns = (): PeriodColumn[] => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const start = new Date(TAX_START_DATE);
  start.setHours(0, 0, 0, 0);

  if (today < start) {
    return [];
  }

  const columns: PeriodColumn[] = [];
  const cursor = new Date(start.getFullYear(), start.getMonth(), 1);

  while (cursor <= today) {
    const year = cursor.getFullYear();
    const month = cursor.getMonth();
    const monthStart = new Date(year, month, 1);
    const monthEnd = new Date(year, month + 1, 0);
    const effectiveStart = monthStart < start ? start : monthStart;
    const effectiveEnd = monthEnd > today ? today : monthEnd;

    columns.push({
      key: `${year}-${String(month + 1).padStart(2, "0")}`,
      label: `${month + 1}/${year}`,
      year,
      startKey: getDateKey(effectiveStart),
      endKey: getDateKey(effectiveEnd),
    });

    cursor.setMonth(cursor.getMonth() + 1);
  }

  return columns;
};

const normalizeYmd = (value: string | null | undefined) => {
  if (!value) return "";
  const match = String(value).match(/^(\d{4})-(\d{2})-(\d{2})/);
  return match ? `${match[1]}-${match[2]}-${match[3]}` : String(value);
};

const isRefundedStatus = (status: string) => {
  const normalized = status.trim().toLowerCase();
  return normalized === "đã hoàn" || normalized === "da hoan" || normalized === "refunded";
};

const formatTerm = (days: TaxOrder["days"]) => {
  const value = Number(days);
  if (!Number.isFinite(value) || value <= 0) {
    return "";
  }
  return `${value} ngày`;
};

const toMoneyNumber = (value: unknown) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : 0;
};

const toTermDays = (days: TaxOrder["days"]) => {
  const value = Number(days);
  return Number.isFinite(value) && value > 0 ? value : 0;
};

const addDays = (ymd: string, days: number) => {
  const [year, month, day] = ymd.split("-").map(Number);
  if (![year, month, day].every(Number.isFinite)) return "";
  const date = new Date(Date.UTC(year, month - 1, day));
  date.setUTCDate(date.getUTCDate() + days);
  const y = date.getUTCFullYear();
  const m = String(date.getUTCMonth() + 1).padStart(2, "0");
  const d = String(date.getUTCDate()).padStart(2, "0");
  return `${y}-${m}-${d}`;
};

const countDaysInclusive = (from: string, to: string) => {
  const [fy, fm, fd] = from.split("-").map(Number);
  const [ty, tm, td] = to.split("-").map(Number);
  if (![fy, fm, fd, ty, tm, td].every(Number.isFinite)) return 0;
  const start = Date.UTC(fy, fm - 1, fd);
  const end = Date.UTC(ty, tm - 1, td);
  if (end < start) return 0;
  return Math.floor((end - start) / (24 * 60 * 60 * 1000)) + 1;
};

const getMetricAmount = (row: TaxFormRow, metric: TaxMetric) => {
  if (metric === "profit") {
    return row.price - row.cost;
  }

  if (metric === "refund") {
    return row.refund;
  }

  return row.price;
};

const isDateInPeriod = (dateKey: string, column: PeriodColumn) =>
  Boolean(dateKey) && dateKey >= column.startKey && dateKey <= column.endKey;

const getPeriodAmount = (
  row: TaxFormRow,
  column: PeriodColumn,
  metric: TaxMetric
) => {
  const amount = getMetricAmount(row, metric);

  if (metric === "refund") {
    if (!isRefundedStatus(row.status) || amount <= 0 || !row.refundDate) {
      return null;
    }

    return isDateInPeriod(row.refundDate, column) ? amount : null;
  }

  if (!row.startDate || row.termDays <= 0 || amount === 0) {
    return null;
  }

  const endDate = addDays(row.startDate, row.termDays - 1);
  if (!endDate) {
    return null;
  }

  const overlapStart = column.startKey > row.startDate ? column.startKey : row.startDate;
  const overlapEnd = column.endKey < endDate ? column.endKey : endDate;
  const daysInPeriod = countDaysInclusive(overlapStart, overlapEnd);

  if (daysInPeriod <= 0) {
    return null;
  }

  return (amount / row.termDays) * daysInPeriod;
};

const formatMoney = (value: number) => `${moneyFormatter.format(Math.round(value))} đ`;

const getAllocatedAmount = (
  row: TaxFormRow,
  columns: PeriodColumn[],
  metric: TaxMetric
) =>
  columns.reduce((sum, column) => {
    const periodAmount = getPeriodAmount(row, column, metric);
    return sum + (periodAmount ?? 0);
  }, 0);

const getRemainingAmount = (
  row: TaxFormRow,
  columns: PeriodColumn[],
  metric: TaxMetric
) => {
  const amount = getMetricAmount(row, metric);
  const remaining = amount - getAllocatedAmount(row, columns, metric);
  return amount >= 0 ? Math.max(0, remaining) : remaining;
};

const formatRemaining = (
  row: TaxFormRow,
  columns: PeriodColumn[],
  metric: TaxMetric
) => {
  const amount = getMetricAmount(row, metric);
  const allocated = getAllocatedAmount(row, columns, metric);

  if (!amount && !allocated) {
    return "";
  }

  return formatMoney(getRemainingAmount(row, columns, metric));
};

const toTaxFormRows = (orders: TaxOrder[]): TaxFormRow[] =>
  orders.map((order) => {
    const rowId = String(order.id);
    const termDays = toTermDays(order.days);
    return {
      id: rowId,
      orderCode: order.id_order ?? "",
      productCode:
        order.product_display_name || order.id_product || "",
      term: formatTerm(order.days),
      termDays,
      startDate: normalizeYmd(order.registration_date || order.order_date),
      refundDate: normalizeYmd(order.canceled_at),
      status: String(order.status || ""),
      price: toMoneyNumber(order.price),
      cost: toMoneyNumber(order.cost),
      refund: toMoneyNumber(order.refund),
    };
  });

type TaxDailyFormTableProps = {
  orders: TaxOrder[];
  loading: boolean;
  error: string | null;
  viewMode: TaxViewMode;
  onViewModeChange: (viewMode: TaxViewMode) => void;
  metric: TaxMetric;
};

export const TaxDailyFormTable: React.FC<TaxDailyFormTableProps> = ({
  orders,
  loading,
  error,
  viewMode,
  onViewModeChange,
  metric,
}) => {
  const allRows = useMemo(() => toTaxFormRows(orders), [orders]);
  const rows = useMemo(
    () =>
      metric === "refund"
        ? allRows.filter(
            (row) =>
              isRefundedStatus(row.status) &&
              row.refund > 0 &&
              Boolean(row.refundDate)
          )
        : allRows,
    [allRows, metric]
  );
  const dayColumns = useMemo(() => buildDateColumns(), []);
  const monthColumns = useMemo(() => buildMonthColumns(), []);
  const periodColumns = viewMode === "day" ? dayColumns : monthColumns;
  const displayPeriodColumns = useMemo(
    () =>
      metric === "refund"
        ? periodColumns.filter((column) =>
            rows.some((row) => isDateInPeriod(row.refundDate, column))
          )
        : periodColumns,
    [metric, periodColumns, rows]
  );
  const showRemainingColumn = metric !== "refund";
  const periodColumnWidth = viewMode === "day" ? DATE_COLUMN_WIDTH : 124;
  const yearLabel = useMemo(() => {
    const years = Array.from(
      new Set(displayPeriodColumns.map((column) => column.year))
    );
    return years.length > 0 ? years.join(" - ") : "2026";
  }, [displayPeriodColumns]);
  const tableMinWidth =
    FIXED_COLUMNS_WIDTH +
    displayPeriodColumns.length * periodColumnWidth +
    (showRemainingColumn ? REMAINING_COLUMN_WIDTH : 0);
  const periodTotals = useMemo(
    () =>
      displayPeriodColumns.map((column) =>
        rows.reduce(
          (sum, row) => sum + (getPeriodAmount(row, column, metric) ?? 0),
          0
        )
      ),
    [displayPeriodColumns, metric, rows]
  );
  const amountTotal = useMemo(
    () => rows.reduce((sum, row) => sum + getMetricAmount(row, metric), 0),
    [metric, rows]
  );
  const remainingTotal = useMemo(
    () =>
      rows.reduce(
        (sum, row) => sum + getRemainingAmount(row, periodColumns, metric),
        0
      ),
    [metric, periodColumns, rows]
  );
  const dynamicColumnCount =
    displayPeriodColumns.length + (showRemainingColumn ? 1 : 0);
  const totalColumnCount = FIXED_COLUMNS.length + dynamicColumnCount;
  const renderColGroup = () => (
    <colgroup>
      {FIXED_COLUMNS.map((column) => (
        <col key={column.key} style={{ width: column.width }} />
      ))}
      {displayPeriodColumns.map((column) => (
        <col key={column.key} style={{ width: periodColumnWidth }} />
      ))}
      {showRemainingColumn && <col style={{ width: REMAINING_COLUMN_WIDTH }} />}
    </colgroup>
  );

  return (
    <section className="rounded-2xl border border-indigo-500/25 bg-slate-950/58 shadow-[0_24px_70px_-26px_rgba(79,70,229,0.45),inset_0_1px_0_rgba(255,255,255,0.06)] backdrop-blur-xl">
      <div className="flex flex-col gap-3 border-b border-white/[0.08] px-4 py-4 sm:flex-row sm:items-center sm:justify-between sm:px-6">
        <div className="min-w-0">
          <p className="text-xs font-bold uppercase tracking-[0.18em] text-sky-300/80">
            {viewMode === "day" ? "Bảng thuế theo ngày" : "Bảng thuế theo tháng"}
          </p>
          <h2 className="mt-1 text-xl font-bold text-white">
            Form phân bổ thuế
          </h2>
        </div>

        <button
          type="button"
          onClick={() =>
            onViewModeChange(viewMode === "day" ? "month" : "day")
          }
          disabled={loading}
          className="inline-flex h-10 items-center justify-center gap-2 rounded-xl border border-sky-300/25 bg-sky-400/12 px-4 text-sm font-semibold text-sky-100 transition hover:border-sky-200/45 hover:bg-sky-400/18 disabled:cursor-wait disabled:opacity-60"
        >
          <ArrowPathIcon className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} />
          {viewMode === "day" ? "Theo tháng" : "Theo ngày"}
        </button>
      </div>

      {error && (
        <div className="border-b border-rose-300/20 bg-rose-500/10 px-4 py-3 text-sm font-medium text-rose-100 sm:px-6">
          {error}
        </div>
      )}

      <div className="overflow-hidden">
        <div
          className="relative isolate overflow-auto"
          style={{
            maxHeight: 84 + DATA_ROW_HEIGHT * DATA_VISIBLE_ROWS + 54,
          }}
        >
          <table
            className="relative z-0 min-w-full table-fixed border-separate border-spacing-0 text-sm"
            style={{ width: tableMinWidth, minWidth: tableMinWidth }}
          >
            {renderColGroup()}
            <thead className="text-slate-100">
              <tr>
                {FIXED_COLUMNS.map((column) => (
                  <th
                    key={column.key}
                    rowSpan={2}
                    scope="col"
                    className={`sticky top-0 z-[80] border-b border-r border-indigo-300/25 bg-[#020617] px-3 py-4 text-left align-middle text-xs font-bold uppercase tracking-[0.08em] ${
                      column.key === "amount"
                        ? "shadow-[18px_0_30px_-24px_rgba(148,163,184,0.95)]"
                        : ""
                    }`}
                    style={{
                      left: column.left,
                      width: column.width,
                      minWidth: column.width,
                    }}
                  >
                    {column.label}
                  </th>
                ))}
                {dynamicColumnCount > 0 && (
                  <th
                    scope="col"
                    colSpan={dynamicColumnCount}
                    className="sticky top-0 z-[10] border-b border-r border-indigo-300/25 bg-slate-950 px-3 py-3 text-center text-xs font-bold uppercase tracking-[0.1em]"
                  >
                    {yearLabel}
                  </th>
                )}
              </tr>
              <tr>
                {displayPeriodColumns.map((column) => (
                  <th
                    key={column.key}
                    scope="col"
                    className="sticky top-[45px] z-[10] border-b border-r border-indigo-300/25 bg-slate-950 px-3 py-3 text-center text-xs font-semibold"
                    style={{
                      width: periodColumnWidth,
                      minWidth: periodColumnWidth,
                    }}
                  >
                    {column.label}
                  </th>
                ))}
                {showRemainingColumn && (
                <th
                  scope="col"
                  className="sticky top-[45px] z-[10] border-b border-r border-indigo-300/25 bg-slate-950 px-3 py-3 text-center text-xs font-semibold"
                  style={{
                    width: REMAINING_COLUMN_WIDTH,
                    minWidth: REMAINING_COLUMN_WIDTH,
                  }}
                >
                  Còn lại
                </th>
                )}
              </tr>
            </thead>

            <tbody>
              {loading && rows.length === 0 && (
                <tr>
                  <td
                    colSpan={totalColumnCount}
                    className="border-b border-indigo-300/15 bg-slate-950 px-4 py-10 text-center text-sm font-semibold text-slate-300"
                  >
                    Đang tải đơn tính thuế...
                  </td>
                </tr>
              )}

              {!loading && rows.length === 0 && !error && (
                <tr>
                  <td
                    colSpan={totalColumnCount}
                    className="border-b border-indigo-300/15 bg-slate-950 px-4 py-10 text-center text-sm font-semibold text-slate-300"
                  >
                    Không có đơn từ ngày 22/4/2026 trở lên.
                  </td>
                </tr>
              )}

              {rows.map((row, rowIndex) => (
                <tr
                  key={row.id}
                  className="group"
                  style={{ height: DATA_ROW_HEIGHT }}
                >
                  {FIXED_COLUMNS.map((column) => (
                    <td
                      key={column.key}
                      className={`sticky z-[60] border-b border-r border-indigo-300/15 bg-[#020617] px-2 py-2 transition-colors group-hover:bg-slate-900 focus-within:z-[75] ${
                        column.key === "amount"
                          ? "shadow-[18px_0_30px_-24px_rgba(148,163,184,0.8)]"
                          : ""
                      }`}
                      style={{
                        left: column.left,
                        width: column.width,
                        minWidth: column.width,
                      }}
                    >
                      <span className="block truncate px-1 text-sm font-semibold text-white">
                          {column.key === "amount"
                            ? formatMoney(getMetricAmount(row, metric))
                            : row[column.key]}
                      </span>
                    </td>
                  ))}

                  {displayPeriodColumns.map((column) => {
                    const periodAmount = getPeriodAmount(row, column, metric);

                    return (
                      <td
                        key={column.key}
                        className="relative z-0 border-b border-r border-indigo-300/15 bg-slate-950 px-3 py-2 text-right text-sm font-semibold text-cyan-100 transition-colors group-hover:bg-slate-900"
                        style={{
                          width: periodColumnWidth,
                          minWidth: periodColumnWidth,
                        }}
                      >
                        {periodAmount != null ? formatMoney(periodAmount) : ""}
                      </td>
                    );
                  })}

                  {showRemainingColumn && (
                    <td
                      className="relative z-0 border-b border-r border-indigo-300/15 bg-slate-950 px-3 py-2 text-right text-sm font-semibold text-emerald-200 transition-colors group-hover:bg-slate-900"
                      style={{
                        width: REMAINING_COLUMN_WIDTH,
                        minWidth: REMAINING_COLUMN_WIDTH,
                      }}
                    >
                      {formatRemaining(row, periodColumns, metric)}
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
            {rows.length > 0 && (
              <tfoot>
                <tr>
                  {FIXED_COLUMNS.map((column, index) => (
                    <td
                      key={column.key}
                      className={`sticky bottom-0 z-[70] border-t border-r border-indigo-300/25 bg-[#020617] px-3 py-4 text-sm font-black text-white ${
                        column.key === "amount"
                          ? "shadow-[18px_0_30px_-24px_rgba(148,163,184,0.95)]"
                          : ""
                      }`}
                      style={{
                        left: column.left,
                        width: column.width,
                        minWidth: column.width,
                      }}
                    >
                      {index === 0
                        ? "Tổng cộng"
                        : column.key === "amount"
                          ? formatMoney(amountTotal)
                          : ""}
                    </td>
                  ))}

                  {periodTotals.map((total, index) => (
                    <td
                      key={displayPeriodColumns[index].key}
                      className="sticky bottom-0 z-[20] border-t border-r border-indigo-300/25 bg-slate-950 px-3 py-4 text-right text-sm font-black text-cyan-100"
                      style={{
                        width: periodColumnWidth,
                        minWidth: periodColumnWidth,
                      }}
                    >
                      {total > 0 ? formatMoney(total) : ""}
                    </td>
                  ))}

                  {showRemainingColumn && (
                    <td
                      className="sticky bottom-0 z-[20] border-t border-r border-indigo-300/25 bg-slate-950 px-3 py-4 text-right text-sm font-black text-emerald-200"
                      style={{
                        width: REMAINING_COLUMN_WIDTH,
                        minWidth: REMAINING_COLUMN_WIDTH,
                      }}
                    >
                      {formatMoney(remainingTotal)}
                    </td>
                  )}
                </tr>
              </tfoot>
            )}
          </table>
        </div>
      </div>
    </section>
  );
};

import React, { useEffect, useMemo, useState } from "react";
import { apiFetch } from "@/lib/api";
import { API_ENDPOINTS } from "@/constants";
import ConfirmModal from "@/components/modals/ConfirmModal/ConfirmModal";
import { StorageHeader } from "./components/StorageHeader";
import { SearchBar } from "./components/SearchBar";
import { StorageTable } from "./components/StorageTable";
import { WarehouseItem, normalizeText } from "./types";

export default function Storage() {
  const [items, setItems] = useState<WarehouseItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [editingId, setEditingId] = useState<number | "new" | null>(null);
  const [draft, setDraft] = useState<WarehouseItem | null>(null);
  const [warehouseIdPendingDelete, setWarehouseIdPendingDelete] = useState<number | null>(null);
  const [warehouseDeleteSubmitting, setWarehouseDeleteSubmitting] = useState(false);

  useEffect(() => {
    let mounted = true;

    const parsePayload = (payload: any) => {
      if (!payload) return [];
      if (Array.isArray(payload)) return payload;
      if (Array.isArray(payload.items)) return payload.items;
      return [];
    };

    const load = async () => {
      setLoading(true);
      setError(null);
      try {
        let res = await apiFetch(API_ENDPOINTS.WAREHOUSE);
        if (res.status === 404) {
          res = await apiFetch("/api/warehouses");
        }
        if (!res.ok) {
          throw new Error(`Không thể tải dữ liệu (${res.status})`);
        }
        const data = await res.json();
        const parsed = parsePayload(data);
        if (mounted) {
          setItems(parsed);
        }
      } catch (err: any) {
        if (mounted) setError(err?.message || "Lỗi không xác định");
      } finally {
        if (mounted) setLoading(false);
      }
    };
    load();
    return () => {
      mounted = false;
    };
  }, []);

  const startEdit = (item: WarehouseItem) => {
    setEditingId(item.id ?? null);
    setDraft({ ...item });
  };

  const cancelEdit = () => {
    setEditingId(null);
    setDraft(null);
  };

  const updateDraft = (key: keyof WarehouseItem, value: string) => {
    const parsed = key === "is_verified" ? value === "true" : value;
    setDraft((prev) => ({ ...(prev || {}), [key]: parsed }));
  };

  const saveEdit = async (id?: number) => {
    if ((!id && editingId !== "new") || !draft) return;
    setLoading(true);
    setError(null);
    try {
      if (editingId === "new") {
        const res = await apiFetch(API_ENDPOINTS.WAREHOUSE, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(draft),
        });
        if (!res.ok) throw new Error(`Tạo mới thất bại (${res.status})`);
        const created = await res.json();
        setItems((prev) => [...prev, created]);
        cancelEdit();
      } else {
        const res = await apiFetch(`${API_ENDPOINTS.WAREHOUSE}/${id}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(draft),
        });
        if (!res.ok) {
          throw new Error(`Cập nhật thất bại (${res.status})`);
        }
        const updated = await res.json();
        setItems((prev) =>
          prev.map((it) => (it.id === id ? { ...it, ...updated } : it))
        );
        cancelEdit();
      }
    } catch (err: any) {
      setError(err?.message || "Lỗi khi cập nhật");
    } finally {
      setLoading(false);
    }
  };

  const requestDeleteRow = (id?: number) => {
    if (!id) return;
    setWarehouseIdPendingDelete(id);
  };

  const confirmDeleteRow = async () => {
    const id = warehouseIdPendingDelete;
    if (!id) return;
    setWarehouseDeleteSubmitting(true);
    setLoading(true);
    setError(null);
    try {
      const res = await apiFetch(`${API_ENDPOINTS.WAREHOUSE}/${id}`, {
        method: "DELETE",
      });
      if (!res.ok) {
        throw new Error(`Xoá thất bại (${res.status})`);
      }
      setItems((prev) => prev.filter((it) => it.id !== id));
      if (editingId === id) cancelEdit();
      setWarehouseIdPendingDelete(null);
    } catch (err: any) {
      setError(err?.message || "Lỗi khi xóa");
    } finally {
      setLoading(false);
      setWarehouseDeleteSubmitting(false);
    }
  };

  const startCreate = () => {
    setEditingId("new");
    setDraft({
      category: "",
      account: "",
      password: "",
      backup_email: "",
      two_fa: "",
      note: "",
      status: "Tồn",
      expires_at: "",
      is_verified: false,
    });
  };

  const filtered = useMemo(() => {
    return items
      .filter((item) => {
        if (!search.trim()) return true;
        const q = normalizeText(search);
        return [
          item.category,
          item.account,
          item.password,
          item.backup_email,
          item.two_fa,
          item.note,
          item.status,
        ].some((field) => normalizeText(field).includes(q));
      })
      .sort((a, b) => {
        const nameA = normalizeText(a.category);
        const nameB = normalizeText(b.category);
        return nameA.localeCompare(nameB, "vi");
      });
  }, [items, search]);

  return (
    <div className="p-4 lg:p-6 space-y-5 w-full min-w-0 max-w-[1400px]">
      <StorageHeader totalItems={items.length} />

      <SearchBar
        search={search}
        onSearchChange={setSearch}
        onCreate={startCreate}
        loading={loading}
        error={error}
      />

      <StorageTable
        items={filtered}
        draft={draft}
        editingId={editingId}
        loading={loading}
        onDraftChange={updateDraft}
        onSave={saveEdit}
        onDelete={requestDeleteRow}
        onCancel={cancelEdit}
        onStartEdit={startEdit}
        onStartCreate={startCreate}
      />

      <ConfirmModal
        isOpen={warehouseIdPendingDelete !== null}
        onClose={() => {
          if (!warehouseDeleteSubmitting) setWarehouseIdPendingDelete(null);
        }}
        onConfirm={() => void confirmDeleteRow()}
        title="Xóa bản ghi?"
        message="Bạn có chắc muốn xóa bản ghi kho này? Hành động không thể hoàn tác."
        confirmLabel="Xóa"
        cancelLabel="Hủy"
        isSubmitting={warehouseDeleteSubmitting}
      />
    </div>
  );
}

import { apiFetch } from "./api";

export interface FormNameDto {
  id: number;
  name: string | null;
  description: string | null;
  createdAt?: string | null;
  updatedAt?: string | null;
}

export interface FormInputDto {
  id: number;
  name: string | null;
  type: string | null;
  sortOrder?: number | null;
}

export interface FormDetailDto {
  id: number;
  name: string | null;
  description: string | null;
  inputs: FormInputDto[];
}

interface FormsResponse {
  items?: FormNameDto[];
}

const FORM_INFO_BASE = "/api/form-info";

export async function fetchFormNames(): Promise<FormNameDto[]> {
  const res = await apiFetch(`${FORM_INFO_BASE}/forms`);
  if (!res.ok) {
    throw new Error("Không thể tải danh sách form");
  }
  const data: FormsResponse = await res.json().catch(
    () => ({} as FormsResponse)
  );
  if (!data || !Array.isArray(data.items)) {
    return [];
  }
  return data.items;
}

export interface CreateFormData {
  name: string;
  description?: string;
  inputIds: number[];
}

export interface CreateFormResponse {
  id: number;
  name: string | null;
  description: string | null;
  inputIds: number[];
  createdAt?: string | null;
}

export async function updateForm(
  formId: number,
  data: CreateFormData
): Promise<CreateFormResponse> {
  const res = await apiFetch(`${FORM_INFO_BASE}/forms/${formId}`, {
    method: "PUT",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      name: data.name?.trim() ?? "",
      description: (data.description ?? "").trim() || null,
      inputIds: Array.isArray(data.inputIds) ? data.inputIds : [],
    }),
  });
  if (!res.ok) {
    const errData = await res.json().catch(() => null);
    const msg = errData?.error ?? "Không thể cập nhật form";
    throw new Error(msg);
  }
  return res.json();
}

export async function createForm(data: CreateFormData): Promise<CreateFormResponse> {
  const res = await apiFetch(`${FORM_INFO_BASE}/forms`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      name: data.name?.trim() ?? "",
      description: (data.description ?? "").trim() || null,
      inputIds: Array.isArray(data.inputIds) ? data.inputIds : [],
    }),
  });
  if (!res.ok) {
    const errData = await res.json().catch(() => null);
    const msg = errData?.error ?? "Không thể tạo form";
    throw new Error(msg);
  }
  return res.json();
}

interface InputsResponse {
  items?: InputDto[];
}

export interface InputDto {
  id: number;
  name: string | null;
  type: string | null;
  createdAt?: string | null;
}

export async function fetchInputs(): Promise<InputDto[]> {
  const res = await apiFetch(`${FORM_INFO_BASE}/inputs`);
  if (!res.ok) {
    throw new Error("Không thể tải danh sách input");
  }
  const data: InputsResponse = await res.json().catch(() => ({} as InputsResponse));
  if (!data || !Array.isArray(data.items)) {
    return [];
  }
  // Knex/Postgres đôi khi trả id dạng string; cần số thống nhất (Set, checkbox, v.v.)
  return data.items.map((it) => ({
    ...it,
    id: Number(it.id),
  }));
}

export interface CreateInputData {
  name: string;
  type: string;
}

export async function createInput(data: CreateInputData): Promise<InputDto> {
  const res = await apiFetch(`${FORM_INFO_BASE}/inputs`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      name: data.name?.trim() ?? "",
      type: (data.type ?? "text").trim().toLowerCase(),
    }),
  });
  if (!res.ok) {
    const errData = await res.json().catch(() => null);
    const msg = errData?.error ?? "Không thể tạo input";
    throw new Error(msg);
  }
  const created = (await res.json()) as InputDto;
  return { ...created, id: Number(created.id) };
}

export async function fetchFormDetail(
  formId: number
): Promise<FormDetailDto> {
  const res = await apiFetch(`${FORM_INFO_BASE}/forms/${formId}`);
  if (!res.ok) {
    if (res.status === 404) {
      throw new Error("Form không tồn tại");
    }
    throw new Error("Không thể tải chi tiết form");
  }
  const data = (await res.json().catch(() => null)) as
    | Partial<FormDetailDto & { inputs?: any[] }>
    | null;

  const safeInputs: FormInputDto[] = Array.isArray(data?.inputs)
    ? data!.inputs.map((raw) => ({
        id: Number((raw as any).id ?? (raw as any).inputId ?? 0),
        name: ((raw as any).name ??
          (raw as any).inputName ??
          "") as string | null,
        type: ((raw as any).type ??
          (raw as any).inputType ??
          "") as string | null,
        sortOrder:
          typeof (raw as any).sortOrder === "number"
            ? (raw as any).sortOrder
            : null,
      }))
    : [];

  return {
    id: Number(data?.id ?? formId),
    name: (data?.name ?? null) as string | null,
    description: (data?.description ?? null) as string | null,
    inputs: safeInputs,
  };
}

import { apiFetch } from "./api";
import { normalizeErrorMessage } from "./textUtils";

export interface ProductDescription {
  id: number;
  /** id bản ghi product.desc_variant (dùng chung khi nhiều variant trỏ cùng id). */
  descVariantId?: number | null;
  productId: string;
  productName?: string | null;
  rules: string;
  rulesHtml?: string | null;
  description: string;
  descriptionHtml?: string | null;
  shortDescription?: string | null;
  imageUrl?: string | null;
  /** Ảnh gói (product) — API trả về để so với ảnh biến thể */
  packageImageUrl?: string | null;
}

export interface ProductDescriptionResponse {
  items: ProductDescription[];
  count: number;
  total?: number;
  offset?: number;
  limit?: number;
}

export interface ProductDescriptionQuery {
  search?: string;
  limit?: number;
  offset?: number;
  /**
   * `desc_variant`: chỉ lấy variant đã có bản ghi mô tả (INNER JOIN desc_variant).
   * Mặc định rỗng — dùng cho tab gội / merge toàn bộ variant.
   */
  scope?: "desc_variant";
}

export interface ProductDescriptionSavePayload {
  /** Mã hiển thị variant; bỏ trống khi chỉ cập nhật theo descVariantId (chưa gắn variant). */
  productId?: string;
  /** Gán variant sang desc_variant có sẵn (dùng chung nội dung); bỏ qua cập nhật text trong request này. */
  descVariantId?: number | null;
  rules?: string;
  description?: string;
  shortDesc?: string;
  imageUrl?: string | null;
}

/** Tạo bản ghi desc_variant; không truyền productId => chỉ INSERT, nối variant sau. */
export type CreateProductDescriptionPayload = {
  productId?: string;
  rules?: string;
  description?: string;
  shortDesc?: string;
};

export interface ProductSeoAuditPayload {
  shortDesc?: string;
  rulesHtml?: string;
  descriptionHtml?: string;
}

export interface ProductSeoAuditCheck {
