  level: "critical" | "warning" | "good" | "excellent";
  readyCount: number;
  heading: string;
  slug: string;
  shortDescription: string;
  descriptionPlainText: string;
  rulesPlainText: string;
  titlePreview: string;
  metaPreview: string;
  imageAlt: string;
}

export interface ProductImageUploadResponse {
  url: string;
  fileName?: string;
}

export interface ProductImageItem {
  fileName: string;
  url: string;
}

export interface ProductImageListResponse {
  items: ProductImageItem[];
  count: number;
}

const normalizeSavedProductDescription = (
  data: Record<string, unknown>
): ProductDescription => ({
  id: Number((data as any).id) || 0,
  descVariantId: (() => {
    const v =
      (data as any).descVariantId ?? (data as any).desc_variant_id ?? null;
    if (v == null || v === "") return null;
    const n = Number(v);
    return Number.isFinite(n) && n > 0 ? n : null;
  })(),
  productId: (data as any).productId || (data as any).product_id || "",
  productName:
    (data as any).productName ?? (data as any).product_name ?? null,
  rules: (data as any).rules || "",
  rulesHtml: (data as any).rulesHtml || (data as any).rules || "",
  description: (data as any).description || "",
  descriptionHtml:
    (data as any).descriptionHtml || (data as any).description || "",
  shortDescription:
    (data as any).shortDescription ??
    (data as any).shortDesc ??
    (data as any).short_desc ??
    null,
  imageUrl: (data as any).imageUrl ?? (data as any).image_url ?? null,
  packageImageUrl:
    (data as any).packageImageUrl ?? (data as any).package_image_url ?? null,
});

export const createProductDescription = async (
  payload: CreateProductDescriptionPayload
): Promise<ProductDescription> => {
  const trimmedPid = payload.productId?.trim();
  const response = await apiFetch("/api/product-descriptions/create", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      ...(trimmedPid ? { productId: trimmedPid } : {}),
      rules: payload.rules ?? "",
      description: payload.description ?? "",
      shortDesc: payload.shortDesc ?? "",
    }),
  });
  if (!response.ok) {
    const message = await response.text().catch(() => "");
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Không thể tạo desc_variant.",
      })
    );
  }
  const data = (await response.json().catch(() => null)) as Record<
    string,
    unknown
  > | null;
  if (!data || typeof data !== "object") {
    throw new Error("Phản hồi không hợp lệ từ server.");
  }
  return normalizeSavedProductDescription(data);
};

export const saveProductDescription = async (
  payload: ProductDescriptionSavePayload
): Promise<ProductDescription> => {
  const response = await apiFetch("/api/product-descriptions", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload),
  });
  if (!response.ok) {
    const message = await response.text().catch(() => "");
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Không thể lưu product_desc.",
      })
    );
  }
  const data = (await response.json().catch(() => null)) as
    | ProductDescription
    | null;
  if (!data || typeof data !== "object") {
    throw new Error("Phản hồi không hợp lệ từ server.");
  }
  return normalizeSavedProductDescription(data as Record<string, unknown>);
};

export const deleteProductDescriptionRecord = async (
  descVariantId: number
): Promise<void> => {
  const id = Number(descVariantId);
  if (!Number.isFinite(id) || id <= 0) {
    throw new Error("ID desc_variant không hợp lệ.");
  }
  const response = await apiFetch(
    `/api/product-descriptions/desc-variant/${encodeURIComponent(String(id))}`,
    { method: "DELETE" }
  );
  if (!response.ok) {
    const message = await response.text().catch(() => "");
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Không thể xóa desc_variant.",
      })
    );
  }
};

export const auditProductSeo = async (
  payload: ProductSeoAuditPayload,
  signal?: AbortSignal
): Promise<ProductSeoAuditResult> => {
  const response = await apiFetch("/api/product-descriptions/seo-audit", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload),
    signal,
  });
  if (!response.ok) {
    const jsonPayload = (await response.json().catch(() => null)) as
      | { error?: string; message?: string }
      | null;
    const message =
      jsonPayload?.error ||
      jsonPayload?.message ||
      (await response.text().catch(() => ""));
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Không thể audit SEO từ Website.",
      })
    );
  }
  const body = (await response.json().catch(() => null)) as
    | { data?: ProductSeoAuditResult }
    | ProductSeoAuditResult
    | null;
  const data =
    body && typeof body === "object" && "data" in body ? body.data : body;

  if (!data || typeof data !== "object") {
    throw new Error("Phản hồi SEO audit không hợp lệ.");
  }

  return data as ProductSeoAuditResult;
};

export const uploadProductImage = async (
  file: File
): Promise<ProductImageUploadResponse> => {
  const body = new FormData();
  body.append("image", file);
  const response = await apiFetch("/api/product-descriptions/upload-image", {
    method: "POST",
    body,
  });
  if (!response.ok) {
    const message = await response.text().catch(() => "");
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Upload failed.",
      })
    );
  }
  const data = (await response.json().catch(() => null)) as
    | ProductImageUploadResponse
    | null;
  if (!data || typeof data.url !== "string") {
    throw new Error("Invalid upload response.");
  }
  return data;
};

export const fetchProductImages = async (): Promise<ProductImageListResponse> => {
  const response = await apiFetch("/api/product-descriptions/images");
  if (!response.ok) {
    const message = await response.text().catch(() => "");
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Failed to load images.",
      })
    );
  }
  const data = (await response.json().catch(() => null)) as
    | ProductImageListResponse
    | null;
  if (!data || !Array.isArray(data.items)) {
    return { items: [], count: 0 };
  }
  return {
    items: data.items,
    count:
      typeof data.count === "number" && Number.isFinite(data.count)
        ? data.count
        : data.items.length,
  };
};

export const deleteProductImage = async (fileName: string): Promise<void> => {
  const encoded = encodeURIComponent(fileName || "");
  const response = await apiFetch(
    `/api/product-descriptions/images/${encoded}`,
    {
      method: "DELETE",
    }
  );
  if (!response.ok) {
    const message = await response.text().catch(() => "");
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Delete failed.",
      })
    );
  }
};

export const fetchProductDescriptions = async (
  params: ProductDescriptionQuery = {}
): Promise<ProductDescriptionResponse> => {
  const searchParams = new URLSearchParams();
  if (params.search) {
    searchParams.set("search", params.search);
  }
  if (params.limit !== undefined) {
    searchParams.set("limit", String(params.limit));
  }
  if (params.offset !== undefined) {
    searchParams.set("offset", String(params.offset));
  }
  if (params.scope === "desc_variant") {
    searchParams.set("scope", "desc_variant");
  }
  const qs = searchParams.toString();
  const response = await apiFetch(
    `/api/product-descriptions${qs ? `?${qs}` : ""}`
  );
  if (!response.ok) {
    const message = await response.text().catch(() => "");
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Không thể tải thông tin sản phẩm.",
      })
    );
  }
  const data = (await response.json().catch(() => null)) as
    | ProductDescriptionResponse
    | null;
  if (!data || !Array.isArray(data.items)) {
    return {
      items: [],
      count: 0,
      total: 0,
      offset: 0,
      limit: params.limit,
    };
  }
  const normalizedCount =
    typeof data.count === "number" && Number.isFinite(data.count)
      ? data.count
      : data.items.length;
  const normalizedTotal =
    typeof data.total === "number" && Number.isFinite(data.total)
      ? data.total
      : normalizedCount;
  const normalizedItems = data.items.map((item: any) => ({
    id: Number(item?.id) || 0,
    descVariantId: (() => {
      const raw =
        item?.descVariantId ?? item?.desc_variant_id ?? null;
      if (raw === null || raw === "") return null;
      const n = Number(raw);
      if (!Number.isFinite(n) || n <= 0) return null;
      return n;
    })(),
    productId: item?.productId || item?.product_id || "",
    productName: item?.productName ?? item?.product_name ?? null,
    rules: item?.rules || "",
    rulesHtml: item?.rulesHtml || item?.rules_html || item?.rules || "",
    description: item?.description || "",
    descriptionHtml:
      item?.descriptionHtml ||
      item?.description_html ||
      item?.description ||
      "",
    shortDescription:
      item?.shortDescription ??
      item?.shortDesc ??
      item?.short_desc ??
      null,
    imageUrl: item?.imageUrl ?? item?.image_url ?? null,
    packageImageUrl:
      item?.packageImageUrl ?? item?.package_image_url ?? null,
  }));
  return {
    ...data,
    items: normalizedItems,
    count: normalizedCount,
    total: normalizedTotal,
    offset:
      typeof data.offset === "number" && Number.isFinite(data.offset)
        ? data.offset
        : params.offset ?? 0,
    limit:
      typeof data.limit === "number" && Number.isFinite(data.limit)
        ? data.limit
        : params.limit ?? data.items.length,
  };
};

import { apiFetch } from "./api";
import { normalizeErrorMessage } from "./textUtils";

export interface ProductDeleteResponse {
  success: boolean;
  message?: string;
}

export type ProductPriceUpdatePayload = {
  packageName?: string | null;
  packageProduct?: string | null;
  categoryIds?: number[];
  categoryColors?: Record<number, string> | Array<{ id: number; color?: string | null }>;
  /** Ảnh gói (product.image_url) — upload qua /api/product-images */
  imageUrl?: string | null;
  /** Ảnh biến thể (variant.image_url) — upload qua /api/variant-images */
  variantImageUrl?: string | null;
};

export const updateProductPrice = async (
  productId: number,
  payload: ProductPriceUpdatePayload
): Promise<any> => {
  const response = await apiFetch(`/api/product-prices/${productId}`, {
    method: "PATCH",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload || {}),
  });
  if (!response.ok) {
    const message = await response.text();
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Cannot update product categories.",
      })
    );
  }
  return response.json().catch(() => ({}));
};

export const deleteProductPrice = async (
  productId: number
): Promise<ProductDeleteResponse> => {
  const response = await apiFetch(`/api/product-prices/${productId}`, {
    method: "DELETE",
    headers: { "Content-Type": "application/json" },
  });
  if (!response.ok) {
    const message = await response.text();
    throw new Error(
      normalizeErrorMessage(message, {
        fallback: "Không thể xóa sản phẩm khỏi bảng giá.",
        blockPatterns: [/(cannot\s+delete)/i],
      })
    );
  }
  const data = await response.json().catch(() => null);
  if (data && typeof data.success === "boolean") {
    return data;
  }
  return { success: true };
};

const isDev =
  typeof import.meta !== "undefined" && (import.meta as any).env?.DEV === true;

const RAW_API_BASE: string = (() => {
  if (isDev) return "";

  const metaBase =
    typeof import.meta !== "undefined"
      ? ((import.meta as any).env?.VITE_API_BASE_URL as string) || ""
      : "";
  if (metaBase) return metaBase;

  const envBase =
    typeof process !== "undefined"
      ? ((process as any).env?.VITE_API_BASE_URL as string) || ""
      : "";
  if (envBase) return envBase;

  return "http://localhost:3001";
})();

function normalizeBaseUrl(value: string): string {
  const normalized = (value || "").trim();
  if (!normalized) return "";
  if (/^:\d+/.test(normalized)) return `http://localhost${normalized}`;
  if (/^localhost:\d+/.test(normalized)) return `http://${normalized}`;
  if (!/^https?:\/\//i.test(normalized)) return `http://${normalized}`;
  return normalized;
}

export const API_BASE_URL: string = normalizeBaseUrl(RAW_API_BASE);

let _csrfToken: string | null = null;

const buildUrl = (input: string): string => {
  if (input.startsWith("http")) return input;
  const base = API_BASE_URL.replace(/\/+$/, "");
  const path = input.replace(/^\/+/, "");
  return `${base}/${path}`;
};

const MUTATING_METHODS = new Set(["POST", "PUT", "PATCH", "DELETE"]);

function injectCsrfHeader(init: RequestInit): RequestInit {
  const method = (init.method || "GET").toUpperCase();
  if (!_csrfToken || !MUTATING_METHODS.has(method)) return init;

  const headers = new Headers(init.headers);
  if (!headers.has("X-CSRF-Token")) {
    headers.set("X-CSRF-Token", _csrfToken);
  }
  return { ...init, headers };
}

function captureCsrfToken(res: Response): void {
  const token = res.headers.get("X-CSRF-Token");
  if (token) _csrfToken = token;
}

function handleUnauthorized(input: string, res: Response): void {
  if (res.status !== 401) return;
  if (/\/auth\/(login|me|csrf-token)/i.test(input)) return;
  if (typeof window !== "undefined") {
    window.location.href = "/login";
  }
}

export async function apiFetch(
  input: string,
  init?: RequestInit,
): Promise<Response> {
  const url = buildUrl(input);
  const baseInit: RequestInit = {
    credentials: init?.credentials ?? "include",
    ...init,
  };
  const finalInit = injectCsrfHeader(baseInit);

  try {
    const res = await fetch(url, finalInit);
    captureCsrfToken(res);
    handleUnauthorized(input, res);
    return res;
  } catch (error) {
    if (!input.startsWith("http")) {
      try {
        const res = await fetch(`http://127.0.0.1:3001${input}`, finalInit);
        captureCsrfToken(res);
        handleUnauthorized(input, res);
        return res;
      } catch {}

      try {
        const res = await fetch(input, finalInit);
        captureCsrfToken(res);
        handleUnauthorized(input, res);
        return res;
      } catch {}
    }

    throw error as Error;
  }
}

export async function apiRequest<T = unknown>(
  input: string,
  init?: RequestInit,
): Promise<T> {
  const res = await apiFetch(input, init);
  if (!res.ok) {
    let message = `HTTP ${res.status}`;
    try {
      const body = await res.json();
      message = body.error || body.message || message;
    } catch {}
    throw Object.assign(new Error(message), { status: res.status });
  }
  return res.json();
}

export const apiGet = <T = unknown>(url: string): Promise<T> =>
  apiRequest<T>(url);

export const apiPost = <T = unknown>(url: string, data?: unknown): Promise<T> =>
  apiRequest<T>(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: data != null ? JSON.stringify(data) : undefined,
  });

export const apiPut = <T = unknown>(url: string, data?: unknown): Promise<T> =>
  apiRequest<T>(url, {
    method: "PUT",
    headers: { "Content-Type": "application/json" },
    body: data != null ? JSON.stringify(data) : undefined,
  });

export const apiPatch = <T = unknown>(url: string, data?: unknown): Promise<T> =>
  apiRequest<T>(url, {
    method: "PATCH",
    headers: { "Content-Type": "application/json" },
    body: data != null ? JSON.stringify(data) : undefined,
  });

export const apiDelete = <T = unknown>(url: string): Promise<T> =>
  apiRequest<T>(url, { method: "DELETE" });

import { useState, useEffect, useCallback, useMemo, useRef } from "react";
import { ORDER_CODE_PREFIXES } from "@/constants";
import { apiFetch } from "../api/client";

export interface PricingTier {
  id: number;
  key: string;
  prefix: string;
  label: string;
  pricing_rule: "markup" | "discount" | "fixed_zero" | "cost";
  base_tier_key: string | null;
  sort_order: number;
  is_active: boolean;
}

/** Option cho dropdown mã / loại đơn (CreateOrder, v.v.) — kèm key tier để lọc theo nghiệp vụ. */
export type OrderCodeSelectOption = {
  value: string;
  label: string;
  /** Khóa tier trong bảng pricing: ví dụ `import` = nhập hàng (MAVN), không phụ thuộc cách lưu `prefix`. */
  tierKey: string;
};

/** Loại «nhập hàng»: theo `key` tier (ổn định) hoặc prefix MAVN (kể cả lệch hoa thường từ API). */
export function isImportOrderCodeOption(
  o: OrderCodeSelectOption
): boolean {
  if (o.tierKey === "import") return true;
  return (
    String(o.value || "").trim().toUpperCase() ===
    String(ORDER_CODE_PREFIXES.IMPORT).toUpperCase()
  );
}

const STALE_MS = 10 * 60_000;

let _sharedCache: PricingTier[] | null = null;
let _sharedTs = 0;

export function usePricingTiers() {
  const [tiers, setTiers] = useState<PricingTier[]>(_sharedCache ?? []);
  const [loading, setLoading] = useState(!_sharedCache);
  const [error, setError] = useState<string | null>(null);
  const mounted = useRef(true);

  const fetchTiers = useCallback(async (force = false) => {
    if (!force && _sharedCache && Date.now() - _sharedTs < STALE_MS) {
      setTiers(_sharedCache);
      setLoading(false);
      return;
    }
    setLoading(true);
    try {
      const res = await apiFetch("/api/pricing-tiers");
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data: PricingTier[] = await res.json();
      _sharedCache = data;
      _sharedTs = Date.now();
      if (mounted.current) {
        setTiers(data);
        setError(null);
      }
    } catch (err: any) {
      if (mounted.current) setError(err.message ?? "Fetch failed");
    } finally {
      if (mounted.current) setLoading(false);
    }
  }, []);

  useEffect(() => {
    mounted.current = true;
    fetchTiers();
    return () => { mounted.current = false; };
  }, [fetchTiers]);

  const prefixMap = useMemo(() => {
    const map: Record<string, string> = {};
    for (const t of tiers) {
      if (t.is_active) map[t.key] = t.prefix;
    }
    return map;
  }, [tiers]);

  const orderCodeOptions = useMemo(
    () =>
      tiers
        .filter((t) => t.is_active)
        .map(
          (t): OrderCodeSelectOption => ({
            value: t.prefix,
            label: t.label,
            tierKey: t.key,
          })
        ),
    [tiers]
  );

  return { tiers, loading, error, refetch: fetchTiers, prefixMap, orderCodeOptions };
}
